-- Poems batch 402
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-972','红罗袄','陈允平','宋','宋词','song-ci','红罗袄','[]','别来书渐少，家远梦徒归。',63,'宋词/ci.song.16000.json','["别来书渐少，家远梦徒归。", "念去燕来鸿，愁随秋到，旧盟新约，心与天知。", "楚江上、木落林稀。", "西风尚隔心期。", "水阔草离离。", "更皓月照影伤悲。"]'),
('song-ci-973','少年游','陈允平','宋','宋词','song-ci','少年游','[]','兰屏香暖，松醪味滑，湖蟹荐香橙。',62,'宋词/ci.song.16000.json','["兰屏香暖，松醪味滑，湖蟹荐香橙。", "雁宇秋高，凤台人远，明月自吹笙。", "轻寒翦翦生襟袖，银漏渐催更。", "暗忆年时，桂风庭院，笑并玉肩行。"]'),
('song-ci-974','少年游','陈允平','宋','宋词','song-ci','少年游','[]','斜阳冉冉水边楼。',60,'宋词/ci.song.16000.json','["斜阳冉冉水边楼。", "珠箔水晶钩。", "拍点红牙，萧吹紫玉，低按小梁州。", "双鸾已误青楼约，谁伴月中游。", "倦蝶残花，寒螀落叶，长是替人愁。"]'),
('song-ci-975','少年游','陈允平','宋','宋词','song-ci','少年游','[]','画楼深映小屏山。',60,'宋词/ci.song.16000.json','["画楼深映小屏山。", "帘幕护轻寒。", "比翼香囊，合欢罗帕，都做薄情看。", "如今已误梨花约，何处滞归鞍。", "待约青鸾，彩云同去，飞梦到长安。"]'),
('song-ci-976','少年游','陈允平','宋','宋词','song-ci','少年游','[]','翠罗裙解缕金丝。',60,'宋词/ci.song.16000.json','["翠罗裙解缕金丝。", "罗扇掩芳姿。", "柳色凝寒，花情殢雨，生怕踏青迟。", "碧纱窗外莺声嫩，春在海棠枝。", "别后相思，许多憔悴，惟有落红知。"]'),
('song-ci-977','还京乐','陈允平','宋','宋词','song-ci','还京乐','[]','彩鸾去，适怨清和，锦瑟谁共理。',126,'宋词/ci.song.16000.json','["彩鸾去，适怨清和，锦瑟谁共理。", "奈春光渐老，万金难买，榆钱空费。", "岸草烟无际。", "落花满地芳尘委。", "翠袖里，红粉溅溅，东风吹泪。", "任鸳帏底。", "宝香寒、金兽慵熏绣被，依依离别意味。", "琼钗暗画心期。", "倩啼鹃、为催行李。", "黯销魂，但梦逐巫山，情牵渭水。", "待得归来后，灯前深诉憔悴。"]'),
('song-ci-978','解连环','陈允平','宋','宋词','song-ci','解连环','[]','寸心谁托。',132,'宋词/ci.song.16000.json','["寸心谁托。", "望潇湘暮碧，水遥云邈。", "自绣带、同翦合欢，奈鸳枕梦单，凤帏寒薄。", "澹月梨花，别后伴、情怀萧索。", "念伤春渐懒，病酒未忺，两愁无药。", "魂销翠兰紫若。", "任钗沉鬓影，香沁眉角。", "怅画阁、尘满妆台，但玉佩依然，宝筝闲却。", "旧约无凭，误共赏、西园桃萼。", "正天涯、数声杜宇，断肠院落。"]'),
('song-ci-979','绮寮怨','陈允平','宋','宋词','song-ci','绮寮怨','[]','满院荼䕷开尽，杜鹃啼梦醒。',129,'宋词/ci.song.16000.json','["满院荼䕷开尽，杜鹃啼梦醒。", "记晓月、绿水桥边，东风又、折柳旗亭。", "蒙茸轻烟草色，疏帘净、乱织罗带青。", "对一尊、别酒初斟，征衫上、点滴香泪盈。", "几度恨沉断云，飞鸾何处，连环尚结双琼。", "一曲琵琶，湓江上、惯曾听。", "依依翠屏香冷，听夜雨、动离情。", "春深小楼，无心对锦瑟、空涕零。"]'),
('song-ci-980','玲珑四犯','陈允平','宋','宋词','song-ci','玲珑四犯','[]','金屋春深，似灼灼娉婷，真真娇艳。',121,'宋词/ci.song.16000.json','["金屋春深，似灼灼娉婷，真真娇艳。", "洗净铅华，依旧曲眉丰脸。", "犹记舞歇凉州，渐缥缈、碧云缭乱。", "白玉环、宝镜偷换。", "别后甚时重见。", "鸾帏凤席鸳鸯荐。", "但空馀、蕙芳兰茜。", "天涯柳色青青恨，不入东风眼。", "惆怅二十四桥，任落絮、飞花乱点。", "奈翠屏、一枕云雨梦，谁惊散。"]'),
('song-ci-981','丹凤吟','陈允平','宋','宋词','song-ci','丹凤吟','[]','暗柳烟深何处，翡翠帘栊，鸳鸯楼阁。',138,'宋词/ci.song.16000.json','["暗柳烟深何处，翡翠帘栊，鸳鸯楼阁。", "芹泥融润，飞燕竞穿珠幕。", "秋千倦倚，还思少年，袜步尘轻，衫裁罗薄。", "陡顿芳心暗老，强理新妆，离思都占眉角。", "过了几番花信，晓来剗地寒意恶。", "可煞东风，甚把夭桃艳杏，故故凌铄。", "伤春憔悴，泪矗粉腮香落。", "挑脱金宽双玉腕，怕人猜偷握。", "渐芳草，恨画阑、休傍著。"]'),
('song-ci-982','忆旧游','陈允平','宋','宋词','song-ci','忆旧游','[]','又眉峰碧聚，记得邮亭，人别中宵。',124,'宋词/ci.song.16000.json','["又眉峰碧聚，记得邮亭，人别中宵。", "翦烛西窗下，听林梢叶坠，雾漠烟潇。", "彩鸾梦逐云去，环佩人扶遥。", "但镜裂鸳奁，钗分燕股，粉腻香销。", "迢迢。", "旧游处，向柳下维舟，花底扬镖。", "更忆西风里，采芙蓉江上，双桨频招。", "怨红一叶应到，明月赤阑桥。", "渐泪浥琼腮，胭脂澹薄羞嫩桃。"]'),
('song-ci-983','拜星月慢','陈允平','宋','宋词','song-ci','拜星月慢','[]','漏阁闲签，琴窗倦谱，露湿宵萤欲暗。',125,'宋词/ci.song.16000.json','["漏阁闲签，琴窗倦谱，露湿宵萤欲暗。", "雁咽凉声，寂寞芙蓉院。", "画檐外，树色惊霜渐改，澹碧云疏星烂。", "旧约桐阴，问何时重见。", "倚银屏、更忆秋娘面。", "想凌波、共立河桥畔。", "重念酒污罗襦，渐金篝香散。", "翦孤灯、伴宿西风馆。", "黄花梦、对发凄凉叹。", "但怅望、一水家山，被红尘隔断。"]'),
('song-ci-984','倒犯','陈允平','宋','宋词','song-ci','倒犯','[]','百尺凤皇楼，碧天暮云初扫。',123,'宋词/ci.song.16000.json','["百尺凤皇楼，碧天暮云初扫。", "冰华散缟。", "双鸾驾镜悬空窈。", "婆娑桂影，香满西风阑干悄。", "渐玉魄金辉，飞度千山表。", "饵玄霜、醉琼醥。", "身在九霄，独步丹梯，飘飘轻雾窵。", "缥缈广寒殿，觉世山河小。", "爱十二、琼楼好。", "算谁知、消息盈虚道。", "任地久天长，今古无私照。", "但仙娥不老。"]'),
('song-ci-985','解语花','陈允平','宋','宋词','song-ci','解语花','[]','鳌峰溯碧，贝阙缘云，桂魄寒光射。',124,'宋词/ci.song.16000.json','["鳌峰溯碧，贝阙缘云，桂魄寒光射。", "凤檐鸳瓦。", "星河际、缥缈绣帘高下。", "笙箫奏雅。", "爱雪柳、蛾儿笑把。", "琼佩摇、珠翠盈盈，迤逦飘兰麝。", "陆地金莲照夜。", "富绮罗妆艳，春态容冶。", "笼纱鞍帕。", "香尘过、禁陌宝车骄马。", "游人静也。", "东风里、万红初谢。", "沉醉归、残角霜天，渐落梅声罢。"]'),
('song-ci-986','过秦楼','陈允平','宋','宋词','song-ci','过秦楼','[]','倦听蛩砧，初抛纨扇，隔浦乱钟催晚。',138,'宋词/ci.song.16000.json','["倦听蛩砧，初抛纨扇，隔浦乱钟催晚。", "湘蒲簟冷，楚竹帘稀，窗下乍闻裁翦。", "倦柳梳烟，枯莲蘸水，芙蓉翠深红浅。", "对半床灯火，虚堂凄寂，近书思遍。", "夜漏永、玉宇尘收，银河光烂。", "梦断楚天空远。", "婆娑月树，缥缈仙香，身在广寒宫殿。", "无奈离愁乱织，籍酒销磨，倩花排遣。", "渐江空霜晓，黄芦漠漠，一声来雁。"]'),
('song-ci-987','过秦楼','陈允平','宋','宋词','song-ci','过秦楼','[]','翠约苹香。',135,'宋词/ci.song.16000.json','["翠约苹香。", "绿抟槐阴，隔水晚蝉声断。", "壶冰避暖，钏玉敧凉，倦暑懒拈歌扇。", "云浪缥缈鱼鳞，新月开弦，落星沉箭。", "恨经年闲阔，柔笺空寄，梦随天远。", "憔悴损、臂薄烟绡，腰宽霞缕，锦瑟暗尘侵染。", "韩香犹在，秦镜空圆。", "薄幸旧盟俱变。", "虚蠹春华，为谁容改芳徽，魂飞娇倩。", "凭危楼望断，江外青山乱点。"]'),
('song-ci-988','解蹀躞','陈允平','宋','宋词','song-ci','解蹀躞','[]','岸柳飘残黄叶，尚学纤腰舞。',90,'宋词/ci.song.16000.json','["岸柳飘残黄叶，尚学纤腰舞。", "谢他终日，亭前伴羁旅。", "无奈历历寒蝉，为谁唤老西风，伴人吟苦。", "闷无绪。", "记得芙蓉江上，萧娘旧相遇。", "如今憔悴，黄花惯风雨。", "把酒东望家山，醉来一沉闲窗，梦随秋去。"]'),
('song-ci-989','蕙兰芳引','陈允平','宋','宋词','song-ci','蕙兰芳引','[]','虹雨乍收，楚天霁、乱飞秋鹜。',104,'宋词/ci.song.16000.json','["虹雨乍收，楚天霁、乱飞秋鹜。", "渐草色衰残，墙外土花暗绿。", "故山鹤怨，流水自、菊篱茅屋。", "日暮诗吟就，澹墨闲题修竹。", "更忆飘蓬，霜绨风葛，几度凉燠。", "叹归去来兮，何日甬东一曲。", "黄芦满望，白云在目。", "但月明月长夜，伴人清独。"]'),
('song-ci-990','六么令','陈允平','宋','宋词','song-ci','六么令','[]','授衣时节，犹未定寒燠。',113,'宋词/ci.song.16000.json','["授衣时节，犹未定寒燠。", "长空雨收云霁，湛碧秋容沐。", "还是鲈肥蟹美，橡栗村村熟。", "不堪追逐。", "龙山梦远，惆怅田园自黄菊。", "醉中还念倦旅，触景伤心目。", "羞破帽、把茱萸，更忆尊前玉。", "愁立梧桐影下，月转回廊曲。", "归期将卜，西风吹雁，懒寄斜封但相嘱。"]'),
('song-ci-991','红林擒近','陈允平','宋','宋词','song-ci','红林擒近','[]','飞絮迷芳意，落梅销暗香。',94,'宋词/ci.song.16000.json','["飞絮迷芳意，落梅销暗香。", "皓鹤泪空碧，白鸥避寒塘。", "妨它踏青斗草，便放晓日东窗。", "先自懒弄晨妆。", "谁奈靓笙簧。", "望帘寻酒市，看钓认渔乡。", "控持紫燕，芹泥未上雕梁。", "想梁园谢馆，群花较晚，但陪玉树频举觞。"]'),
('song-ci-992','红林擒近','陈允平','宋','宋词','song-ci','红林擒近','[]','三万六千顷，玉壶天地寒。',95,'宋词/ci.song.16000.json','["三万六千顷，玉壶天地寒。", "庾岭封的皪，淇园折琅玕。", "漠漠梨花烂漫，纷纷柳絮飞残。", "直疑潢潦惊翻，斜风溯狂澜。", "对此频胜赏，一醉饱清欢。", "呼䣔童翦韭，和冰先荐春盘。", "怕东风吹散，留尊待月，倚阑莫惜今夜看。"]'),
('song-ci-993','满路花・促拍满路花','陈允平','宋','宋词','song-ci','满路花・促拍满路花','[]','离歌泣断云，别舞愁飞雪。',101,'宋词/ci.song.16000.json','["离歌泣断云，别舞愁飞雪。", "凤皇台上望，琼箫绝。", "钗分玉燕，寸寸回肠折。", "碧空归雁阔。", "犹有疏梅，岁寒独伴高节。", "鲛绡罗帕，泪洒胭脂血。", "悠悠江上水，天连接。", "朱楼遍倚，万里空情切。", "此恨凭谁说。", "天若有情，料天须有区别。"]'),
('song-ci-994','满路花・促拍满路花','陈允平','宋','宋词','song-ci','满路花・促拍满路花','[]','寒轻菊未残，春小梅初破。',101,'宋词/ci.song.16000.json','["寒轻菊未残，春小梅初破。", "兽炉闲拨尽，松明火。", "青毡锦幄，四壁新妆裹。", "重暖香篝，绣被拥银屏，彩鸾空伴云卧。", "相思何处，梦入蓝桥左。", "归期还细数，愁眉锁。", "薄情孤雁，不向楼西过。", "故人应怪我。", "怪我无书，有书还倩谁呵。"]'),
('song-ci-995','氐州第一','陈允平','宋','宋词','song-ci','氐州第一','["\u897f\u6e56"]','闲倚江楼，凉生半臂，天高过雁来小。',126,'宋词/ci.song.16000.json','["闲倚江楼，凉生半臂，天高过雁来小。", "紫芡波寒，青芜烟澹，南浦云帆缥缈。", "潮带离愁，去冉冉、夕阳空照。", "寂寞东篱，白衣人远，渐黄花老。", "见说西湖鸥鹭少。", "孤山路、醉魂飞绕。", "荻蟹初肥，莼鲈更美，尽酒怀诗抱。", "待南枝、春信早。", "巡檐对梅花索笑。", "月落乌啼，渐霜天、钟残梦晓。"]'),
('song-ci-996','尉迟杯','陈允平','宋','宋词','song-ci','尉迟杯','[]','长亭路。',129,'宋词/ci.song.16000.json','["长亭路。", "望渭北、漠漠春天树。", "殷勤别酒重斟，明日相思何处。", "晴丝扬暖，芳草外、斜阳自南浦。", "望孤帆、影接天涯，一江潮带愁去。", "回首杜若汀州，叹泛梗飘萍，乍散还聚。", "满径残红春归后，犹自有、杨花乱舞。", "怅金徽、梁尘暗锁，算谁是、知音堪共语。", "尽天涯、梦断东风，彩云鸾凤无侣。"]'),
('song-ci-997','塞翁吟','陈允平','宋','宋词','song-ci','塞翁吟','[]','睡起鸾钗亸，金约鬓影胧□',114,'宋词/ci.song.16000.json','["睡起鸾钗亸，金约鬓影胧□", "桅佩冷，玉丁东。", "镜里对芙蓉。", "秦筝倦理梁尘暗，惆怅燕子楼空。", "山万叠，水千重。", "一叶漫题红。", "忽忽。", "从别后，残云断雨，馀香在、鲛绡帐中。", "更懊恨、灯花无准，写幽愫、锦织回文，小字斜封。", "无人为托，欲倩宾鸿。", "立尽西风。"]'),
('song-ci-998','绕佛阁','陈允平','宋','宋词','song-ci','绕佛阁','[]','暮烟半敛。',122,'宋词/ci.song.16000.json','["暮烟半敛。", "云护澹月，斜照楼馆。", "春夜偏短。", "一床耿耿，孤灯晃帏幔。", "玉壶漏满。", "天外渐觉，归雁声远。", "离思凄婉。", "重怀执手，东风翠苹岸。", "料想凤楼人，倦绣回文停彩线。", "憔悴泪积，香销娇粉面。", "叹暗老年光，隙驹流箭。", "梦中空见。", "漫惹起相思，芳意迷乱。", "锦笺重向纱窗展。"]'),
('song-ci-999','庆春宫・高阳台','陈允平','宋','宋词','song-ci','庆春宫・高阳台','[]','孤鹜披霞，归鞍卸日，晚香菊自寒城。',126,'宋词/ci.song.16000.json','["孤鹜披霞，归鞍卸日，晚香菊自寒城。", "虚馆灯闲，征衫尘浣，夜深何处砧声。", "乱蛩催怨，月明里、依稀数星。", "云山迢递，犹误归期，方寸遍萦。", "秋风燕送鸿迎。", "最怜堤柳，白露先零。", "倦倚楼高，恨随天远，桂风和梦俱清。", "故人千里，记翦烛、西窗赋成。", "相如憔悴，宋玉凄凉，酒恨花情。"]'),
('song-ci-0','满江红','陈允平','宋','宋词','song-ci','满江红','[]','目断江横，相思字、难凭雁足。',115,'宋词/ci.song.17000.json','["目断江横，相思字、难凭雁足。", "从别后、倦歌慵绣，悄无拘束。", "烟柳翠迷星眼恨，露桃红沁霞腮肉。", "傍琐窗、终日对文枰，翻新局。", "频暗把，归期卜。", "芳草恨，阑干曲。", "谢多情海燕，伴愁华屋。", "明月自圆双蝶梦，彩云空伴孤鸾宿。", "任画帘、不卷玉钩闲，扬花扑。"]'),
('song-ci-1','丁香结','陈允平','宋','宋词','song-ci','丁香结','[]','尘拥妆台，翠闲歌扇，金井碧梧风陨。',121,'宋词/ci.song.17000.json','["尘拥妆台，翠闲歌扇，金井碧梧风陨。", "听豆虫声小，伴寂寞、冷逼莓墙苍润。", "料凄凉宋玉，悲秋恨、此际怎忍。", "莲塘风露，渐入粉艳，红衣落尽。", "勾引。", "记舞歇弓弯，几度柳围花阵。", "酒薄愁浓，霞腮泪渍，月眉香晕。", "空对秦镜尚缺，暗结回肠寸。", "念纤腰柔弱，都为相如瘦损。"]'),
('song-ci-2','西河','陈允平','宋','宋词','song-ci','西河','["\u957f\u6c5f"]','形胜地。',125,'宋词/ci.song.17000.json','["形胜地。", "西陵往事重记。", "溶溶王气满东南，英雄闲起。", "凤游何处古台空，长江缥缈无际。", "石头城上试倚。", "吴襟楚带如系。", "乌衣巷陌几斜阳，燕闲旧垒。", "后庭玉树委歌尘，凄凉遗恨流水。", "买花问酒锦绣市。", "醉新亭、芳草千里。", "梦醒觉非今世。", "对三山、半落青天，数点白鹭，飞来西风里。"]'),
('song-ci-3','一寸金','陈允平','宋','宋词','song-ci','一寸金','[]','吾爱吾庐，甬水东南半村郭。',133,'宋词/ci.song.17000.json','["吾爱吾庐，甬水东南半村郭。", "试倚楼极目，千山拱翠，舟横沙觜，江迷城脚。", "水满苹风作。", "阑干外、夕阳半落。", "荒烟瞑、几点昏鸦，野色青芜自空廓。", "浩叹飘蓬，春光几度，依依柳边泊。", "念水行云宿，栖迟羁旅，鸥盟鹭伴，归来重约。", "满室凝尘澹，无心处、宦情最薄。", "何时遂、钓笠耕蓑，静观天地乐。"]'),
('song-ci-4','瑞鹤仙','陈允平','宋','宋词','song-ci','瑞鹤仙','[]','故庐元负郭。',126,'宋词/ci.song.17000.json','["故庐元负郭。", "爱树色参差，湖光渺漠。", "楼危万山落。", "俯阑干十二，亸檐飞角。", "花娇柳弱。", "映轻黄、浅黛依约。", "与沙鸥、共结新盟，伴我醉眠醒酌。", "萧散云根石上，瀹茗松泉，注书芸阁。", "莺窥燕幕。", "檐外竹、圃中药。", "念耕烟钓雪，已成活计，一任风波自恶。", "但无心、万事由天，梦中更乐。"]'),
('song-ci-5','浪淘沙慢','陈允平','宋','宋词','song-ci','浪淘沙慢','[]','暮烟愁，鸦归古树，雁过空堞。',162,'宋词/ci.song.17000.json','["暮烟愁，鸦归古树，雁过空堞。", "南浦牙樯渐发。", "阳关歌尽半阕。", "便恨入回肠千万结。", "长亭柳、寸寸攀折。", "望日下长安近，莫遣鳞鸿成闲绝。", "凄切。", "去帆浪远江阔。", "怅顿解连环，西窗下、对烛频哽咽。", "叹百岁光阴，几度离别。", "翠销粉竭。", "信乍圆易散，彩云明月。", "浙水吴山重重叠。", "流苏帐、阳台梦歇。", "暗尘锁、孤鸾秦镜缺。", "羞人问、怕说相思，正满院杨花，落尽东风雪。"]'),
('song-ci-6','西平乐慢・西平乐','陈允平','宋','宋词','song-ci','西平乐慢・西平乐','[]','泛梗飘萍，入山登陆，迢递雾迥烟赊。',167,'宋词/ci.song.17000.json','["泛梗飘萍，入山登陆，迢递雾迥烟赊。", "漠漠蒹葭，依依杨柳，天涯总是愁遮。", "叹寂寞尘埃满眼，梦逐孤云缥缈，春潮带雨，鸥迎远溆，雁别平沙。", "寒食梨花素约，肠断处，对景暗伤嗟。", "晚钟烟寺，晨鸡月店，征褐萧疏，破帽敧斜。", "忆几度、微吟马上，长啸舟中，惯踏新丰巷陌，旧酒犹香，憔悴东风自岁华。", "重忆少年，樱桃渐熟，松粉初黄，短楫欢呼，日日江南，烟村八九人家。"]'),
('song-ci-7','南乡子','陈允平','宋','宋词','song-ci','南乡子','[]','归雁转西楼。',66,'宋词/ci.song.17000.json','["归雁转西楼。", "薄幸音书日日收。", "旧恨却凭红叶去，飕飕。", "春水多情日夜流。", "杨柳曲江头。", "烟里青青恨不休。", "九十韶光风雨半，回眸。", "一片花飞一片愁。"]'),
('song-ci-8','望江南・忆江南','陈允平','宋','宋词','song-ci','望江南・忆江南','[]','娇滴滴，聪隽在秋波。',64,'宋词/ci.song.17000.json','["娇滴滴，聪隽在秋波。", "六幅香裙拖细縠，一钩尘袜翦轻罗。", "春意动人多。", "临宝鉴，石黛拂修蛾。", "燕子楼头蝴蝶梦，桃花扇底竹枝歌。", "杨柳月婆娑。"]'),
('song-ci-9','望江南・忆江南','陈允平','宋','宋词','song-ci','望江南・忆江南','[]','烟漠漠，湖外绿杨堤。',64,'宋词/ci.song.17000.json','["烟漠漠，湖外绿杨堤。", "满地落花春雨后，一帘飞絮夕阳西。", "梁燕落香泥。", "流水恨，和泪入桃溪。", "鹦鹉洲边鹦鹉恨，杜鹃枝上杜鹃啼。", "归思越凄凄。"]'),
('song-ci-10','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','自别萧郎锦帐寒。',48,'宋词/ci.song.17000.json','["自别萧郎锦帐寒。", "凤楼日日望平安。", "杏花枝上露才乾。", "眉皱但嫌钿翠堕，臂销惟觉钏金宽。", "薄情杨柳殢征鞍。"]'),
('song-ci-11','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','一枕华胥梦不成。',48,'宋词/ci.song.17000.json','["一枕华胥梦不成。", "碧筒香润玉醪倾。", "日长花影过池亭。", "雪藕臂寒鹦较怯，采菱歌发鹭频惊。", "白苹洲上雨初晴。"]'),
('song-ci-12','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','约臂金圆隐绛缯。',48,'宋词/ci.song.17000.json','["约臂金圆隐绛缯。", "枕痕斜印曲花藤。", "玉肌娇软莹如冰。", "护日帘栊迷晓梦，舞风琼佩弄秋声。", "倦妆鸾鉴不忺凭。"]'),
('song-ci-13','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','宝镜奁开素月空。',48,'宋词/ci.song.17000.json','["宝镜奁开素月空。", "晚妆慵结绣芙蓉。", "殢人娇语更憁憁。", "倦浴金莲轻衫步，捧笙玉笋半当胸。", "枕痕又露一丝红。"]'),
('song-ci-14','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','双倚妆楼宝髻垂。',48,'宋词/ci.song.17000.json','["双倚妆楼宝髻垂。", "佩环依约下瑶池。", "鬓边斜插碧蝉儿。", "不嫁东风苏小恨，未圆明月柳娘悲。", "舞休愁叠缕金衣。"]'),
('song-ci-15','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','斗鸭阑干燕子飞。',48,'宋词/ci.song.17000.json','["斗鸭阑干燕子飞。", "一堤春水漾晴晖。", "女郎何处踏青归。", "生色鞋儿销凤稳，碧罗衫子唾花微。", "后期应待牡丹时。"]'),
('song-ci-16','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','六幅蒲帆晓渡平。',48,'宋词/ci.song.17000.json','["六幅蒲帆晓渡平。", "一江星斗渐西倾。", "离家才是两三程。", "浦外野花如唤客，树头春鸟自呼名。", "五云深处锦官城。"]'),
('song-ci-17','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','柳底征鞍花底车。',48,'宋词/ci.song.17000.json','["柳底征鞍花底车。", "两行香泪湿红襦。", "别来莺燕已春馀。", "梳洗楼台愁独倚，笙歌庭院醉谁扶。", "卷帘闲看玉储胥。"]'),
('song-ci-18','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','十二珠帘绣带垂。',48,'宋词/ci.song.17000.json','["十二珠帘绣带垂。", "柳烟迷暗楚江涯。", "自携玉笛凭丹梯。", "写恨鸾笺凝粉泪，踏青鸳袜溅金泥。", "落红深处乱莺啼。"]'),
('song-ci-19','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','睡起朦腾小篆香。',48,'宋词/ci.song.17000.json','["睡起朦腾小篆香。", "素纨轻度玉肌凉。", "竹深荷净少炎光。", "雨过乱蝉嘶古柳，日斜双鹭立闲塘。", "更将心事自商量。"]'),
('song-ci-20','点绛唇','陈允平','宋','宋词','song-ci','点绛唇','[]','眉叶颦愁，泪痕红透兰襟润。',50,'宋词/ci.song.17000.json','["眉叶颦愁，泪痕红透兰襟润。", "雁声将近。", "须带平安信。", "独倚江楼，落叶风成阵。", "情怀闷。", "蝶随蜂趁。", "满地黄花恨。"]'),
('song-ci-21','点绛唇','陈允平','宋','宋词','song-ci','点绛唇','[]','别后长亭，翠芜寂寞分襟地。',50,'宋词/ci.song.17000.json','["别后长亭，翠芜寂寞分襟地。", "雁书空寄。", "归梦频东里。", "一曲秋风，写尽渊明意。", "凝情际。", "雨襟烟袂。", "都是黄花泪。"]'),
('song-ci-22','点绛唇','陈允平','宋','宋词','song-ci','点绛唇','[]','分袂情怀，快风一箭轻帆举。',50,'宋词/ci.song.17000.json','["分袂情怀，快风一箭轻帆举。", "暮烟云浦。", "芳草斜阳路。", "输与闲鸥，朝暮潮来去。", "空凝伫。", "小桥樊素。", "金屋春深处。"]'),
('song-ci-23','点绛唇','陈允平','宋','宋词','song-ci','点绛唇','[]','莺语愁春，海棠风里胭脂雨。',50,'宋词/ci.song.17000.json','["莺语愁春，海棠风里胭脂雨。", "酒怀慵举。", "闲扑亭前絮。", "漠漠斜阳，截断愁来路。", "凭阑伫。", "满怀离苦。", "分付楼南鼓。"]'),
('song-ci-24','夜游宫','陈允平','宋','宋词','song-ci','夜游宫','[]','愁厌眉峰成敛。',71,'宋词/ci.song.17000.json','["愁厌眉峰成敛。", "几回皱、落花钿点。", "镜里芳容自羞见。", "又黄昏，听南楼，度更箭。", "月引桐阴转。", "珠帘动、影摇花乱。", "雁过西风楚天远。", "待归来，把愁眉，印郎面。"]'),
('song-ci-25','夜游宫','陈允平','宋','宋词','song-ci','夜游宫','[]','窄索楼儿傍水。',71,'宋词/ci.song.17000.json','["窄索楼儿傍水。", "渐秋到、渔村橘里。", "薄幸江南倦游子。", "恣轻狂，恋高阳，歌酒市。", "独自帘儿底。", "香罗带、翠闲金坠。", "为恼情怀怕拈起。", "对西风，搵啼红，印窗纸。"]'),
('song-ci-26','诉衷情','陈允平','宋','宋词','song-ci','诉衷情','[]','绿云凤髻不忺盘。',54,'宋词/ci.song.17000.json','["绿云凤髻不忺盘。", "情味胜思酸。", "晓色露桃烟杏，空照脸霞丹。", "花渐老，径苔闲。", "锦斓斑。", "怨红一叶，流水东风，好去人间。"]'),
('song-ci-27','诉衷情','陈允平','宋','宋词','song-ci','诉衷情','[]','嫩寒侵帐弄微霜。',54,'宋词/ci.song.17000.json','["嫩寒侵帐弄微霜。", "客泪不成行。", "料得黄花憔悴，何日赋归装。", "楼独倚，漏声长。", "暗情伤。", "凄凉况味，一半悲秋，一半思乡。"]'),
('song-ci-28','一落索','陈允平','宋','宋词','song-ci','一落索','[]','澹澹双蛾疏秀。',56,'宋词/ci.song.17000.json','["澹澹双蛾疏秀。", "为谁频皱。", "落花何处不春愁，料不是、因花瘦。", "锦字香笺封久。", "鳞鸿稀有。", "舞腰销减不禁愁，怕一似、章台柳。"]'),
('song-ci-29','一落索','陈允平','宋','宋词','song-ci','一落索','[]','欲寄相思情苦。',56,'宋词/ci.song.17000.json','["欲寄相思情苦。", "倩流红去。", "满怀写不尽离愁，都化作、无情雨。", "渺渺暮云春树。", "澹烟横素。", "夕阳西下杜鹃啼，怨截断、春归处。"]'),
('song-ci-30','迎春乐','陈允平','宋','宋词','song-ci','迎春乐','[]','垂杨影下黄金屋。',65,'宋词/ci.song.17000.json','["垂杨影下黄金屋。", "东风渐、粉香熟。", "恨当年、有约骖鸾速。", "误一枕、红云宿。", "带眼宽移腰似束。", "怪何事、褪红销绿。", "背面立秋千，羞人问、连环玉。"]'),
('song-ci-31','迎春乐','陈允平','宋','宋词','song-ci','迎春乐','[]','江湖十载疏狂迹。',65,'宋词/ci.song.17000.json','["江湖十载疏狂迹。", "红尘里、倦游客。", "驻雕鞍、问柳东风陌。", "花底帽、任敧侧。", "斗酒百篇呼太白。", "傲人世、醉中一息。", "何日归赋来，水之南、云之北。"]'),
('song-ci-32','迎春乐','陈允平','宋','宋词','song-ci','迎春乐','[]','依依一树多情柳。',64,'宋词/ci.song.17000.json','["依依一树多情柳。", "都未识行人手。", "对青青、共结同心就。", "更共饮、旗亭酒。", "褥上芙蓉铺软绣。", "香不散、彩云春透。", "今岁又相逢，是燕子、归来后。"]'),
('song-ci-33','虞美人','陈允平','宋','宋词','song-ci','虞美人','[]','春衫薄薄寒犹恋。',66,'宋词/ci.song.17000.json','["春衫薄薄寒犹恋。", "芳草连天远。", "嫩红和露入桃腮。", "柳外东边楼阁、燕飞来。", "霓裳一曲凭谁按。", "错□□重看。", "金虬闲暖麝檀煤。", "银烛替人垂泪、共心灰。"]'),
('song-ci-34','虞美人','陈允平','宋','宋词','song-ci','虞美人','[]','夕阳楼上都凭遍。',66,'宋词/ci.song.17000.json','["夕阳楼上都凭遍。", "柳下风吹面。", "强搴罗袖倚重门。", "懒傍玉台鸾镜、暗尘昏。", "离情脉脉如飞絮。", "此恨凭谁语。", "一天明月一江云。", "云外月明、应照凤楼人。"]'),
('song-ci-35','虞美人','陈允平','宋','宋词','song-ci','虞美人','[]','疏林远带寒山小。',66,'宋词/ci.song.17000.json','["疏林远带寒山小。", "月落霜天晓。", "棹歌初发浦烟中。", "自叹疏狂踪迹、似萍蓬。", "江边衰柳迷津堠。", "归兴浓於酒。", "断烟流水自寒塘。", "十里蒹葭、鸥鹭两三双。"]'),
('song-ci-36','虞美人','陈允平','宋','宋词','song-ci','虞美人','[]','彩云别后房栊悄。',66,'宋词/ci.song.17000.json','["彩云别后房栊悄。", "愁立西风晓。", "倚阑无语对黄花。", "惆怅玉郎应在、楚江涯。", "钿筝空贮芳尘满。", "寂寞朱弦断。", "夜来一点帐前灯。", "频吐银花双烬、照罗屏。"]'),
('song-ci-37','虞美人','陈允平','宋','宋词','song-ci','虞美人','[]','玉奁香细流苏暖。',66,'宋词/ci.song.17000.json','["玉奁香细流苏暖。", "寒日花梢短。", "翠罗尘暗缕金销。", "□□东□华屋、自藏娇。", "当时携手鸳鸯径。", "一笑蔷薇影。", "如今眉黛镇愁封。", "欲问归期消息、望宾鸿。"]'),
('song-ci-38','醉桃源・阮郎归','陈允平','宋','宋词','song-ci','醉桃源・阮郎归','[]','金闺平帖被青青。',56,'宋词/ci.song.17000.json','["金闺平帖被青青。", "宝街球路绫。", "晓风吹枕泪成冰。", "梅梢霜露零。", "金鸭暖，宝熏腾。", "晴窗粘冻蝇。", "梦魂空趁断云行。", "江山千里程。"]'),
('song-ci-39','醉桃源・阮郎归','陈允平','宋','宋词','song-ci','醉桃源・阮郎归','[]','青青杨柳拂堤沙。',56,'宋词/ci.song.17000.json','["青青杨柳拂堤沙。", "溪头沽酒家。", "吟成醉笔走龙蛇。", "春风双鬓华。", "歌楚女，舞吴娃。", "轻烟笼翠霞。", "倦春娇困宝钗斜。", "绿垂云髻鸦。"]'),
('song-ci-40','凤来朝','陈允平','宋','宋词','song-ci','凤来朝','[]','百媚春风面。',65,'宋词/ci.song.17000.json','["百媚春风面。", "凤箫催、绿么舞遍。", "玉鸾钗、半溜乌云乱。", "悄疑是、梦中见。", "曲叹弓弯袖敛。", "绣芙蓉、香尘未断。", "买一笑、千金拼。", "共醉倚、画屏暖。"]'),
('song-ci-41','垂丝钓','陈允平','宋','宋词','song-ci','垂丝钓','[]','鬓蝉似羽。',81,'宋词/ci.song.17000.json','["鬓蝉似羽。", "轻纨低映娇妩。", "凭阑看花，仰蜂粘絮。", "春未许。", "宝筝闲玉柱。", "东风暮。", "武陵溪上路。", "娉婷婀娜。", "刘郎依约曾遇。", "鸳俦凤侣。", "重记相逢处。", "云隔阳台雨。", "花解语。", "旧梦还记否。"]'),
('song-ci-42','芳草渡・系裙腰','陈允平','宋','宋词','song-ci','芳草渡・系裙腰','[]','芳草渡。',110,'宋词/ci.song.17000.json','["芳草渡。", "渐迤逦分飞，鸳俦凤侣。", "洒一枝香泪，梨花寂寞春雨。", "惜别情思苦。", "匆匆深盟诉。", "翠浪远，六幅蒲帆，缥缈东去。", "远顾。", "夕阳冉冉，恨逐潮回南浦路。", "漫空念、归来燕子，双栖旧庭户。", "市桥细柳，尚不减、少年张绪。", "渐瘦损，懒照秦鸾对舞。"]'),
('song-ci-43','相思引','陈允平','宋','宋词','song-ci','相思引','[]','金谷园林锦绣香。',54,'宋词/ci.song.17000.json','["金谷园林锦绣香。", "踏青挑菜又相将。", "凤台人远，离思入三湘。", "花著雨添红粉重，柳随风曳碧丝长。", "薄情鸾燕，春去怎商量。"]'),
('song-ci-44','谒金门','胡仲弓','宋','宋词','song-ci','谒金门','[]','蛾黛浅。',53,'宋词/ci.song.17000.json','["蛾黛浅。", "只为晚寒妆懒。", "润逼镜鸾红雾满。", "额花留半面。", "渐次梅花开遍。", "花外行人已远。", "欲寄一枝嫌梦短。", "湿云和恨翦。"]'),
('song-ci-45','水龙吟','施岳','宋','宋词','song-ci','水龙吟','[]','翠鳌涌出沧溟，影横栈壁迷烟墅。',126,'宋词/ci.song.17000.json','["翠鳌涌出沧溟，影横栈壁迷烟墅。", "楼台对起，阑干重凭，山川自古。", "梁苑平芜，汴堤疏柳，几番晴雨。", "看天低四远，江空万里，登临处、分吴楚。", "两岸花飞絮舞。", "度春风、满城箫鼓。", "英雄暗老，昏潮晓汐，归帆过舻。", "淮水东流，塞云北渡，夕阳西去。", "正凄凉望极，中原路杳，月来南浦。"]'),
('song-ci-46','清平乐','施岳','宋','宋词','song-ci','清平乐','[]','水遥花瞑。',26,'宋词/ci.song.17000.json','["水遥花瞑。", "隔岸炊烟冷。", "十里垂杨摇嫩影。", "宿酒和愁都醒。"]'),
('song-ci-47','解语花','施岳','宋','宋词','song-ci','解语花','[]','云容冱雪，暮色添寒，楼台共临眺。',121,'宋词/ci.song.17000.json','["云容冱雪，暮色添寒，楼台共临眺。", "翠丛深窅。", "无人处、数蕊弄春犹小。", "幽姿谩好。", "遥相望、含情一笑。", "花解语，因甚无言，心事应难表。", "莫待墙阴暗老。", "称琴边月夜，笛里霜晓。", "护香须早。", "东风度、咫尺画阑琼沼。", "归来梦绕。", "歌云坠、依然惊觉。", "想恁时，小几银屏冷未了。"]'),
('song-ci-48','曲游春','施岳','宋','宋词','song-ci','曲游春','[]','画舸西泠落，占柳阴花影，芳意如织。',128,'宋词/ci.song.17000.json','["画舸西泠落，占柳阴花影，芳意如织。", "小楫冲波，度麴尘扇底，粉香帘隙。", "岸转斜阳隔。", "又过尽、别船箫笛。", "傍断桥、翠绕红围，相对半篙晴色。", "顷刻。", "千山暮碧。", "向沽酒楼前，犹系金勒。", "乘月归来，正梨花夜缟，海棠烟幕。", "院宇明寒食。", "醉乍醒、一庭春寂。", "任满身、露湿东风，欲眠未得。"]'),
('song-ci-49','兰陵王','施岳','宋','宋词','song-ci','兰陵王','["\u897f\u6e56"]','柳花白。',158,'宋词/ci.song.17000.json','["柳花白。", "飞入青烟巷陌。", "凭高处，愁锁断桥，十里东风正无力。", "西湖路咫尺。", "犹阻仙源信息。", "伤心事，还似去年，中酒恹恹度寒食。", "闲窗掩春寂。", "但粉指留红，茸唾凝碧。", "歌尘不散蒙香泽。", "念鸾孤金镜，雁空瑶瑟。", "芳时凉夜尽怨忆。", "梦魂省难觅。", "鳞鸿，渺踪迹。", "纵罗帕亲题，锦字谁织。", "缄情欲寄重城隔。", "又流水斜照，倦箫残笛。", "楼台相望，对暮色，恨无极。"]'),
('song-ci-50','步月','施岳','宋','宋词','song-ci','步月','[]','玉宇薰风，宝阶明月，翠丛万点晴雪。',117,'宋词/ci.song.17000.json','["玉宇薰风，宝阶明月，翠丛万点晴雪。", "炼霜不就，散广寒霏屑。", "采珠蓓、绿萼露滋，嗔银艳、小莲冰洁。", "花痕在，纤指嫩痕，素英重结。", "枝头香未绝。", "还是过中秋，丹桂时节。", "醉乡冷境，怕翻成消歇。", "玩芳味、春焙旋熏。", "贮秾韵、水沉频爇。", "堪怜处，输与夜凉睡蝶。"]'),
('song-ci-51','醉落魄・一斛珠','薛梦桂','宋','宋词','song-ci','醉落魄・一斛珠','[]','单衣乍著。',67,'宋词/ci.song.17000.json','["单衣乍著。", "滞寒更傍东风作。", "珠帘压定银钩索。", "雨弄新晴，轻旋玉尘落。", "花唇巧借妆红约。", "娇羞才放三分萼。", "樽前不用多评泊。", "春浅春深，都向杏梢觉。"]'),
('song-ci-52','眼儿媚','薛梦桂','宋','宋词','song-ci','眼儿媚','[]','碧筒新展绿蕉芽。',58,'宋词/ci.song.17000.json','["碧筒新展绿蕉芽。", "黄露洒榴花。", "蘸烟染就，和云卷起，秋水人家。", "只因一朵芙蓉月，生怕黛帘遮。", "燕衔不去，雁飞不到，愁满天涯。"]'),
('song-ci-53','三姝媚','薛梦桂','宋','宋词','song-ci','三姝媚','[]','蔷薇花谢去。',121,'宋词/ci.song.17000.json','["蔷薇花谢去。", "更无情、连夜送春风雨。", "燕子呢喃，似念人憔悴，往来朱户。", "涨绿烟深，早零落、点池萍絮。", "暗忆年华，罗帐分钗，又惊春暮。", "芳草凄迷征路。", "待去也，还将画轮留住。", "纵使重来，怕粉容销腻，却羞郎觑。", "细数盟言犹在，怅青楼何处。", "绾尽垂杨，争似相思寸缕。"]'),
('song-ci-54','浣溪纱・浣溪沙','薛梦桂','宋','宋词','song-ci','浣溪纱・浣溪沙','[]','柳映疏帘花映林。',48,'宋词/ci.song.17000.json','["柳映疏帘花映林。", "春光一半几销魂。", "新诗未了枕先温。", "燕子说将千万恨，海棠开到二三分。", "小窗银烛又黄昏。"]'),
('song-ci-55','大有','潘希白','宋','宋词','song-ci','大有','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','戏马台前，采花篱下，问岁华、还是重九。',122,'宋词/ci.song.17000.json','["戏马台前，采花篱下，问岁华、还是重九。", "恰归来、南山翠色依旧。", "帘栊昨夜听风雨，都不似、登归时候。", "一片宋玉情怀，十分卫郎清瘦。", "红萸佩、空对酒。", "砧杆动微寒，暗欺罗袖。", "秋已无多，早是败荷衰柳。", "强整帽檐敧侧，曾经向、天涯搔首。", "几回忆、故国莼鲈，霜前雁后。"]'),
('song-ci-56','贺新郎','文及翁','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','一勺西湖水。',142,'宋词/ci.song.17000.json','["一勺西湖水。", "渡江来、百年歌舞，百年酣醉。", "回首洛阳花世界，烟渺黍离之地。", "更不复、新亭坠泪。", "簇乐红妆摇画艇，问中流、击楫谁人是。", "千古恨，几时洗。", "余生自负澄清志。", "更有谁、磻溪未遇，传严未起。", "国事如今谁倚仗，衣带一江而已。", "便都道、江神堪恃。", "借问孤山林处士，但掉头、笑指梅花蕊。", "天下事，可知矣。"]'),
('song-ci-57','失调名','文及翁','宋','宋词','song-ci','失调名','[]','朗吟飞过。',5,'宋词/ci.song.17000.json','["朗吟飞过。"]'),
('song-ci-58','击梧桐','李珏','宋','宋词','song-ci','击梧桐','[]','枫叶浓於染。',134,'宋词/ci.song.17000.json','["枫叶浓於染。", "秋正老、江上征衫寒浅。", "又是秦鸿过，霁烟外，写出离愁几点。", "年来岁去，朝生暮落，人似吴潮展转。", "怕听阳关曲，奈短笛唤起，天涯情远。", "双屐行春，扁舟啸晚。", "忆昔鸥湖莺苑。", "鹤帐梅花屋，霜月后、记把山扉牢掩。", "惆怅明朝何处，故人相望，但碧云半敛。", "定苏堤、重来时候，芳草如翦。"]'),
('song-ci-59','木兰花慢','李珏','宋','宋词','song-ci','木兰花慢','[]','故人知健否，又过了、一番秋。',123,'宋词/ci.song.17000.json','["故人知健否，又过了、一番秋。", "记十载心期，暮苔茅屋，杜若芳洲。", "天遥梦飞不到，但滔滔、岁月水东流。", "南浦春波旧别，西山暮雨新愁。", "吴钩。", "光透黑貂裘。", "客思晚悠悠。", "更何处相逢，残更听雁，落日呼鸥。", "沧江白云无数，约他年、携手上扁舟。", "鸦阵不知人意，黄昏飞向城头。"]'),
('song-ci-60','步蟾宫','钟过','宋','宋词','song-ci','步蟾宫','[]','东风又送酴醿信。',68,'宋词/ci.song.17000.json','["东风又送酴醿信。", "早吹得、愁成潘鬓。", "花开犹似十年前，人不似、十年前俊。", "水边珠翠香成阵。", "也消得、燕窥莺认。", "归来沉醉月朦胧，觉花气、满襟犹润。"]'),
('song-ci-61','水调歌头','谭方平','宋','宋词','song-ci','水调歌头','[]','富贵在何许，五十已平头。',114,'宋词/ci.song.17000.json','["富贵在何许，五十已平头。", "人生得失且笑，休遣两眉愁。", "管甚轮云世变，管甚风波世态，沙渚且盟鸥。", "止即尽教止，流即尽教流。", "田坷秫，山可簌，又何求。", "问天只觅穷健，游戏八千秋。", "好对梅花如粉，细剪烛花如豆，不改旧时游。", "翠袖更能舞，骑鹤上扬州。"]'),
('song-ci-62','水调歌头','马廷鸾','宋','宋词','song-ci','水调歌头','[]','把酒对湘浦，独吊大夫醒。',114,'宋词/ci.song.17000.json','["把酒对湘浦，独吊大夫醒。", "当年皇览初度，饮露更餐英。", "服以高冠长佩，扈以江蓠薜芷，御气独乘清。", "谁意椒兰辈，从臾武关盟。", "哭东门，哀郢路，悄无宁。", "人世纷纷起灭，遗臭与留馨。", "一笑还游轻举，三叹道长世短，晦朔自秋春。", "洗眼看物变，朝菌共灵椿。"]'),
('song-ci-63','齐天乐','马廷鸾','宋','宋词','song-ci','齐天乐','[]','老夫耄矣，怪新年顿尔，□衰俱现。',124,'宋词/ci.song.17000.json','["老夫耄矣，怪新年顿尔，□衰俱现。", "排闷篇诗，浇愁盏酒，自读离骚自劝。", "长安日远。", "怅旧国禾宫，故侯瓜畹。", "风景不殊，江涛如此世缘浅。", "莫莫休休□□，□□乾坤毁，幽怀无限。", "弱羽填波，轻装浮海，其奈沧溟潋滟。", "年华婉娩。", "况六十平头，底须顽健。", "戏唱高词，作还丹九转。"]'),
('song-ci-64','沁园春','马廷鸾','宋','宋词','song-ci','沁园春','[]','杨柳依依，我生之辰，与公共之。',139,'宋词/ci.song.17000.json','["杨柳依依，我生之辰，与公共之。", "叹袅娜章台，歌翻轻吹，飘零灞岸，影弄斜晖。", "花萼楼深，灵和殿古，人自凄凉柳自垂。", "相逢处，记吾侬坠地，嘉定明时。", "何须梦得君知。", "便稳道人生七十稀。", "笑桓大将军，枝条如此，陶潜处士，门巷归兮。", "几阵花飞，一池萍碎，又向先生把寿卮。", "年年好，祝东风万楼，老翠云齐。"]'),
('song-ci-65','水调歌头','马廷鸾','宋','宋词','song-ci','水调歌头','[]','老子早知退，鸥鹭未盟寒。',114,'宋词/ci.song.17000.json','["老子早知退，鸥鹭未盟寒。", "痴顽逾六望七，宁以寿为欢。", "风有黍离伤咽，雅有蓼莪憔悴，使我不能餐。", "更把南陔读，泪落广陵澜。", "踏峨峰，腾华顶，卧王宫。", "青山与汝卒岁，紫茹可登盘。", "乞得白翁归处，莫学缁郎更误，危梦倚栏干。", "多谢长生曲，颜面怕人看。"]'),
('song-ci-66','失调名','马廷鸾','宋','宋词','song-ci','失调名','[]','东晋纤儿撞坏，桑令人间受祸。',14,'宋词/ci.song.17000.json','["东晋纤儿撞坏，桑令人间受祸。"]'),
('song-ci-67','桂殿秋','李仁本','宋','宋词','song-ci','桂殿秋','[]','飞翠盖，走篮舆。',32,'宋词/ci.song.17000.json','["飞翠盖，走篮舆。", "乱山千叠为先驱。", "洞天迎目深且窈，满耳天风吹步虚。"]'),
('song-ci-68','桂殿秋','李仁本','宋','宋词','song-ci','桂殿秋','[]','巑兽石，错虬松。',32,'宋词/ci.song.17000.json','["巑兽石，错虬松。", "黛岚终日下天风。", "杖藜携我恣遥望，缥缈霓裳飞碧空。"]'),
('song-ci-69','桂殿秋','李仁本','宋','宋词','song-ci','桂殿秋','[]','金带重，紫袍宽。',32,'宋词/ci.song.17000.json','["金带重，紫袍宽。", "到头不似羽衣闲。", "君王若许供香火，神武门前早挂冠。"]'),
('song-ci-70','沁园春','谢枋得','宋','宋词','song-ci','沁园春','[]','十五年来，逢寒食节，皆在天涯。',139,'宋词/ci.song.17000.json','["十五年来，逢寒食节，皆在天涯。", "叹雨濡露润，还思宰柏，风柔日媚，羞看飞花。", "麦饭纸钱，只鸡斗酒，几误林间噪喜鸦。", "天笑道，此不由乎我，也不由他。", "鼎中炼熟丹砂。", "把紫府清都作一家。", "想前人鹤驭，常游绛阙，浮生蝉蜕，岂恋黄沙。", "帝命守坟，王令修墓，男子正当如是邪。", "又何必，待过家上冢，画锦荣华。"]'),
('song-ci-71','满江红','莫起炎','宋','宋词','song-ci','满江红','[]','法在先天，玄妙处、无言可说。',114,'宋词/ci.song.17000.json','["法在先天，玄妙处、无言可说。", "其要在、守乎中正，灵台莹彻。", "太极神居黄谷内，先天气在玄关穴。", "寂然不动感而通，凭刚烈。", "运风雷，祈雨雪。", "役鬼神，驱妖孽。", "只此是、非咒非符非罡诀。", "寂定神归元谷府，功成行满仙班列。", "玩太虚、稳稳驾祥云，朝金阙。"]'),
('song-ci-72','木兰花慢','牟巘','宋','宋词','song-ci','木兰花慢','[]','山城如斗大，君肯为、两年留。',122,'宋词/ci.song.17000.json','["山城如斗大，君肯为、两年留。", "问读易堂前，け然松竹，留得君不。", "天边乍传消息，趁春风、归侍翠云裘。", "留取去思无限，江离香满汀洲。", "不妨无蟹有监州。", "臭味喜相投。", "怪底事朝来，骊歌催唱，唤起离愁。", "羡君戏衫脱却，一身轻、无事也无忧。", "昨夜梦随杖履，道林岳林同游。"]'),
('song-ci-73','千秋岁','牟巘','宋','宋词','song-ci','千秋岁','[]','平分敏手。',87,'宋词/ci.song.17000.json','["平分敏手。", "更觉山城小。", "聊岸帻，时舒啸。", "当年湓浦月，偏照香山老。", "头未白，而今半百才逾九。", "共说东园好。", "问春馀多少。", "红药晚，金沙早。", "花须风日耐，人看功名久。", "催洗盏，对花一笑为君寿。"]'),
('song-ci-74','鹧鸪天','牟巘','宋','宋词','song-ci','鹧鸪天','[]','鸠杖庞眉鹤发仙。',64,'宋词/ci.song.17000.json','["鸠杖庞眉鹤发仙。", "诗中有史笔如椽。", "爱莲自是平生趣，吟到梅花晚更坚。", "珍九鼎，食万钱。", "谁如有子采衣鲜。", "蜀陈旧事君须记，贵盛还当具庆年。"]'),
('song-ci-75','渔家傲','牟巘','宋','宋词','song-ci','渔家傲','[]','病枕逢逢惊晓鼓。',72,'宋词/ci.song.17000.json','["病枕逢逢惊晓鼓。", "那堪送客江头路。", "莫唱骊驹催客去。", "风又雨。", "花飞一片愁千缕。", "折柳凄然无胜语。", "加餐更把篝衣护。", "泥滑篮舆须稳度。", "云飞处。", "亲闱安问应旁午。"]'),
('song-ci-76','水调歌头','牟巘','宋','宋词','song-ci','水调歌头','[]','表海归来后，眠食喜清安。',114,'宋词/ci.song.17000.json','["表海归来后，眠食喜清安。", "身轻於鹄，上下山北与山南。", "何必交梨火枣，自是霜筠雪柏，岁晚越坚完。", "摩诘本无病，微笑指蒲团。", "天有意，留一老，殿诸贤。", "平生出处何似，试把二苏看。", "惟有黄门最贵，况是庞眉寿□，九秩阅人间。", "持此为公寿，即是寿元元。"]'),
('song-ci-77','念奴娇','牟巘','宋','宋词','song-ci','念奴娇','[]','山之天目，蔚苕嶢、第一最佳泉石。',120,'宋词/ci.song.17000.json','["山之天目，蔚苕嶢、第一最佳泉石。", "见说老龙高卧处，正拥深深寒碧。", "独閟云扉，人思霖雨，未许无心出。", "苍崖赤子，而今谁为苏息。", "昨夜凉透西风，玉绳晚澹，喜见归鸿入。", "十二虚皇凝伫久，飞下陆离宸画。", "绣卣使名，洪枢衔位，催缀新班立。", "旗常婀娜，要陪沙路清跸。"]'),
('song-ci-78','贺新郎','牟巘','宋','宋词','song-ci','贺新郎','[]','云拥油幢碧。',142,'宋词/ci.song.17000.json','["云拥油幢碧。", "眷蓬莱、宿缘一纪，竟须公出。", "上界清高仙地位。", "耿耿为民还切。", "此自是、平生愿力。", "雨后新飙凉如濯，喜湖山、千里皆生色。", "便乘此，问阊阖。", "殷勤好与摩铜狄。", "炯精神、依然未老，鹤标龟息。", "造物生贤非无意，偏近中元时节。", "试记取、平园莱国。", "况有盘洲当家样，酉年秋、拾级升枢极。", "继盛事，看今日。"]'),
('song-ci-79','满江红','牟巘','宋','宋词','song-ci','满江红','[]','七荚新春，问底事、以人为日。',115,'宋词/ci.song.17000.json','["七荚新春，问底事、以人为日。", "记贞观、郑公恰至，名因人得。", "况是今朝生上相，老天著意尤端的。", "便唤为、人日岂徒哉，公人杰。", "宇宙要，公扶植。", "善类要，公收拾。", "愿我公千岁，长陪丹极。", "山立扬休人正健，耐寒彩胜篸华发。", "看年年、天际不曾阴，真奇特。"]'),
('song-ci-80','水调歌头','牟巘','宋','宋词','song-ci','水调歌头','[]','叔父茅封贵，先帝棣华亲。',114,'宋词/ci.song.17000.json','["叔父茅封贵，先帝棣华亲。", "平生为善最乐，夙德宛天人。", "玉叶金枝方茂，瑶沼丹壶如画，光景镇长新。", "五福一日寿，万象总皆春。", "正秋分，记初度，绂缠麟。", "传宣来自绛阙，瑞采蔚轮囷。", "乐有钧天九奏，尊有仙家九酝，翠釜紫驼珍。", "笑把南山指，还以祝严宸。"]'),
('song-ci-81','瑞鹤仙','徐理','宋','宋词','song-ci','瑞鹤仙','[]','暮霞红映沼。',126,'宋词/ci.song.17000.json','["暮霞红映沼。", "恨柳枝疏瘦，不禁风搅。", "投林数归鸟。", "更枯茎敲荻，糁红堆蓼。", "江寒浪小。", "雁来多、音书苦少。", "试看尽，水边红叶，不见有诗流到。", "烦恼。", "凭阑人去，枕水亭空，路遥天杳。", "情深恨渺。", "无计诉与伊道。", "漏声催，门外霜清风细，月色今霄最好。", "怎割舍，美景良时，等闲睡了。"]'),
('song-ci-82','醉蓬莱','吴季子','宋','宋词','song-ci','醉蓬莱','[]','正淡烟疏雨，梅子黄时，清和天气。',120,'宋词/ci.song.17000.json','["正淡烟疏雨，梅子黄时，清和天气。", "阿母当年，暂辍瑶池会。", "霞帔星冠，霓旌羽纛，下碧霄云际。", "恰与瞿昙，同时共日，降人间世。", "裼寝开祥，斑衣祝寿，一种灵椿，两枝仙桂。", "满引玻璃，且向今霄醉。", "待看阶庭，蓝袍交映，奉板舆游戏。", "到得蟠桃，熟时归去，已三千岁。"]'),
('song-ci-83','念奴娇','吴季子','宋','宋词','song-ci','念奴娇','[]','雪罗初试，过赐衣时节，才三四日。',120,'宋词/ci.song.17000.json','["雪罗初试，过赐衣时节，才三四日。", "记得延陵公子宅，麟角当年新绂。", "半刺名家，一经奥学，是青云人物。", "如何华发，蒲轮未聘遗逸。", "问讯怨鹤惊猿，不妨俱隐，且逍遥丈室。", "有子传家经可教，况有东皋种秫。", "醉里乾坤，闲中日月，便是长生术。", "瑶池宴后，剩看几度桃实。"]'),
('song-ci-84','声声慢','何梦桂','宋','宋词','song-ci','声声慢','[]','人间六月。',117,'宋词/ci.song.17000.json','["人间六月。", "好是王母瑶池，吹下冰雪。", "一片清凉，仙界蕊宫珠阙。", "金猊水沉未冷，看瑶阶、九开蓂荚。", "尚记得，那年时手种，蟠桃千叶。", "庭下阿儿痴绝。", "争戏舞、绿袍环玦。", "笑捧金卮，满砌兰芽初茁。", "七十古来稀有，且高歌、万事休说。", "天未老，尚看他、儿辈事业。"]'),
('song-ci-85','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','对芙蓉峰晓，雪初消、云□霭烟霏。',119,'宋词/ci.song.17000.json','["对芙蓉峰晓，雪初消、云□霭烟霏。", "是阿谁寿母，紫鸾笙里，玉液琼枝。", "元是云翘仙子，珥节度瑶池。", "手种碧莲子，长记年时。", "此地神仙宫阙，几花封玉诰，金帔霞衣。", "但寿星堂上，七十古来稀。", "捧寿觞、莫辞满饮，愿年年、对鹤发蛾眉。", "年年有，麻姑麟脯，王母玄梨。"]'),
('song-ci-86','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','对千峰未晓，听西风、吹角下谯楼。',117,'宋词/ci.song.17000.json','["对千峰未晓，听西风、吹角下谯楼。", "拥貔貅千骑，旌□十里，送客芳洲。", "曾是灯棋月柝，赞画坐清油。", "折尽长亭柳，莫系行舟。", "忆昔相逢何处，看飞鸿雪迹，休更回头。", "百年心事，长逐水东流。", "愿君如游龙万里，我如云、终泊此林丘。", "相思梦，明年雁到，尚讯南州。"]'),
('song-ci-87','满庭芳','何梦桂','宋','宋词','song-ci','满庭芳','[]','燕子芹乾，龙孙箨老，绿阴深锁林塘。',117,'宋词/ci.song.17000.json','["燕子芹乾，龙孙箨老，绿阴深锁林塘。", "午风庭院，人试薄罗裳。", "数尽落红飞絮，摘青梅、煮酒初尝。", "重门静，一帘疏雨，消尽水沉香。", "把当年团扇，恩情犹在，未是相忘。", "笑衰翁鬓发，早已苍苍。", "说与乘鸾彩女，看世间、多少炎凉。", "都休怨，百年一梦，且共醉霞觞。"]'),
('song-ci-88','踏莎行','何梦桂','宋','宋词','song-ci','踏莎行','[]','夜月楼台，夕阳庭院。',68,'宋词/ci.song.17000.json','["夜月楼台，夕阳庭院。", "都将前事思量遍。", "当初识面待寻常，争知识后情如线。", "只怕梅梢，参横斗转。", "催人归去天涯远。", "断肠当在别离时，未曾说著肠先断。"]'),
('song-ci-89','摸鱼儿','何梦桂','宋','宋词','song-ci','摸鱼儿','[]','记年时、人人何处，长亭曾共尊酒。',140,'宋词/ci.song.17000.json','["记年时、人人何处，长亭曾共尊酒。", "酒阑归去行人远，折不尽长亭柳。", "渐白首。", "待把酒送君，恰又清明后。", "青条似旧。", "问江北江南，离愁如我，还更有人否。", "留不住，强把蔬盘瀹韭。", "行舟又报潮候。", "风急岸花飞尽也，一曲啼红满袖。", "春波皱。", "青草外，人间此恨年年有。", "留连握手。", "叹人世相逢，百年欢笑，能得几回又。"]'),
('song-ci-90','摸鱼儿','何梦桂','宋','宋词','song-ci','摸鱼儿','[]','把人间、古今勋业，一时都付杯酒。',140,'宋词/ci.song.17000.json','["把人间、古今勋业，一时都付杯酒。", "青山行遍人华发，老尽门前青柳。", "试回首。", "记晓雨征衫，又过年时候。", "相逢故旧。", "浪说南楼北，亭花纵好、能似少年否。", "还自笑，应是山林厌韭。", "忘却儿童迎候。", "兴来谩学长沙舞，要舞更无长袖。", "眉休皱。", "欢笑外，风涛世上时时有。", "共君握手。", "且尽日尊前，相拌一醉，醉后明朝又。"]'),
('song-ci-91','意难忘','何梦桂','宋','宋词','song-ci','意难忘','[]','避暑林塘。',114,'宋词/ci.song.17000.json','["避暑林塘。", "数元戎小队，一簇红妆。", "旌□云影动，帘幕水沉香。", "金缕彻，玉肌凉。", "慢拍舞轻扬。", "更一般，轻弦细管，孤竹空桑。", "风姨昨夜痴狂。", "向华峰吹落，云锦天裳。", "波神藏不得，散作满池芳。", "移彩鹢，柳阴傍。", "拚一醉淋浪。", "向晚来、歌阑饮散，月在纱窗。"]'),
('song-ci-92','喜迁莺','何梦桂','宋','宋词','song-ci','喜迁莺','[]','留春不住。',126,'宋词/ci.song.17000.json','["留春不住。", "又早是清明，杨花飞絮。", "杜宇声声，黄昏庭院，那更半帘风雨。", "劝春且休归去。", "芳草天涯无路。", "悄无语。", "倚阑干立尽，落红无数。", "谁诉。", "长门事，记得当年，曾趁梨园舞。", "霓羽香消，梁州声歇，昨梦转头今古。", "金屋玉楼何在，尚有花钿尘土。", "君不顾。", "怕伤心，休上危楼高处。"]'),
('song-ci-93','临江仙','何梦桂','宋','宋词','song-ci','临江仙','[]','十月江南风信早，梅枝早閟先春。',70,'宋词/ci.song.17000.json','["十月江南风信早，梅枝早閟先春。", "田园剩得老来身。", "浪言陶处士，犹是晋朝臣。", "人道革爻居四九，谁知数在邅迍。", "明年五十志当伸。", "低头羞老妇，且结会稽盟。"]'),
('song-ci-94','满江红','何梦桂','宋','宋词','song-ci','满江红','[]','春色三分，怎禁得、几番风力。',115,'宋词/ci.song.17000.json','["春色三分，怎禁得、几番风力。", "又早见、亭台绿水，柳摇金色。", "满眼春愁无著处，知心惟有幽禽识。", "望青山、目断夕阳边，孤云隔。", "琴酒我，成三一。", "湖外舫，山头屐。", "且莫教春去，乱红堆积。", "记得年时陪宴赏，重门深处桃花碧。", "待修书、欲寄楚天遥，无行客。"]'),
('song-ci-95','忆秦娥','何梦桂','宋','宋词','song-ci','忆秦娥','[]','伤离别。',56,'宋词/ci.song.17000.json','["伤离别。", "江南雁断音书绝。", "音书绝。", "两行珠泪，寸肠千结。", "伤心长记中秋节。", "今年还似前年月。", "前年月。", "那知今夜，月圆人缺。"]'),
('song-ci-96','西江月','何梦桂','宋','宋词','song-ci','西江月','[]','犹记春风庭院，柳阴深锁帘帷。',58,'宋词/ci.song.17000.json','["犹记春风庭院，柳阴深锁帘帷。", "东君去后雨丝丝。", "空认紫骝嘶处。", "梦断箫台无据，十年往事休追。", "忽然拈起旧来书。", "依旧长亭双泪。"]'),
('song-ci-97','小重山','何梦桂','宋','宋词','song-ci','小重山','[]','吹断笙箫春梦寒。',70,'宋词/ci.song.17000.json','["吹断笙箫春梦寒。", "倚楼思往事，泪偷弹。", "别时容易见时难。", "相看处，惟有玉连环。", "人在万重山。", "近来应不似，旧时颜。", "重门深院柳阴间。", "曾携手，休去倚危阑。"]'),
('song-ci-98','沁园春','何梦桂','宋','宋词','song-ci','沁园春','[]','光岳储精，宇宙呈祥，锺英俊材。',139,'宋词/ci.song.17000.json','["光岳储精，宇宙呈祥，锺英俊材。", "想春秋夹谷，前生夫子，婆娑南赡，见在如来。", "龙角标辰，蟾胎煜丙，好是生朝华宴开。", "笙歌里，看儿童拜舞，春满行台。", "重重好事相催。", "便对把黄封酌寿罍。", "更愿公殿上，早纡衮绣，愿公堂下，长戏衣莱。", "昨夜瑶池，亲逢阿母，欲寄蟠桃桃始栽。", "三千岁，待开花结子，岁岁衔杯。"]'),
('song-ci-99','满江红','何梦桂','宋','宋词','song-ci','满江红','[]','睡起纱窗，问春信、几番风候。',115,'宋词/ci.song.17000.json','["睡起纱窗，问春信、几番风候。", "待去做、踏青鞋履，懒拈纤手。", "尘满翠微低ぢ叶，离愁推去来还又。", "把菱花、独对泪阑干，羞蓬首。", "回鸾子，空怀袖。", "金缕曲，无心奏。", "记碧桃花下，夜参横斗。", "六幅罗裙香凝处，痕痕都是尊前酒。", "到如今、肠断怕回头，长门柳。"]'),
('song-ci-100','沁园春','何梦桂','宋','宋词','song-ci','沁园春','[]','衮衣绣裳，彤弓卢矢，山西将门。',139,'宋词/ci.song.17000.json','["衮衣绣裳，彤弓卢矢，山西将门。", "自雪岭蓬婆，夷成坦道，炎州蜓獠，剗去连营。", "吴越儿童，江淮草木，七见元戎识姓名。", "争知道，这一隅斗大，尚借麾旌。", "西风吹下天声。", "看万骑貔貅入井陉。", "彼山棚魍魉，雷霆震击，海濒赤子，天日开明。", "事业方来，乾坤无尽，千古英雄不偶生。", "从兹去，看云台翼轸，麟阁丹青。"]'),
('song-ci-101','水龙吟','何梦桂','宋','宋词','song-ci','水龙吟','[]','倚窗闲嗅梅花，霜风入袖寒初透。',126,'宋词/ci.song.17000.json','["倚窗闲嗅梅花，霜风入袖寒初透。", "吾年如此，年年十月，见梅如旧。", "白发青衫，苍头玄鹤，花前尊酒。", "问梅花与我，是谁瘦绝，正风雨、年时候。", "不怕参横月落，怕人生、芳盟难又。", "高楼何处，寒英吹落，玉龙休奏。", "前日花魁，后来羹鼎，总归严岫。", "但逋仙流落，诗香留与，孤山同寿。"]'),
('song-ci-102','酹江月・念奴娇','何梦桂','宋','宋词','song-ci','酹江月・念奴娇','[]','三分春色，更消得风雨，几番零落。',120,'宋词/ci.song.17000.json','["三分春色，更消得风雨，几番零落。", "年少不来春老去，空负省薇阶药。", "燕子飞忙，杜鹃啼杀，总为谁悲乐。", "临春结绮，旧家何处楼阁。", "一任年去年来，怅歌阑舞断，尘生帘幕。", "千古雷塘浑一梦，人世到头俱错。", "百岁心期，一春光景，付与闲杯酌。", "青蛇犹在，莫教雷雨飞却。"]'),
('song-ci-103','酹江月・念奴娇','何梦桂','宋','宋词','song-ci','酹江月・念奴娇','[]','问春何去，乱随风飞坠，杨花篱落。',120,'宋词/ci.song.17000.json','["问春何去，乱随风飞坠，杨花篱落。", "罗袜香囊无觅处，谁有返魂灵药。", "细柳重门，碧桃深巷，回首曾行乐。", "玉龙吟断，夜深人在江阁。", "因念壁月琼枝，对玉人何处，绣帘珠幕。", "一半青铜尘满匣，空抚鸾刀金错。", "薇露烟销，莲膏花凝，不寐还孤酌。", "一春心事，总将愁里消却。"]'),
('song-ci-104','沁园春','何梦桂','宋','宋词','song-ci','沁园春','[]','老去无心，看尽青山，山前暮云。',139,'宋词/ci.song.17000.json','["老去无心，看尽青山，山前暮云。", "问重来海燕，乌衣安在，乍归辽鹤，华表空存。", "世路悠悠，风尘渺渺，白发相催乌兔频。", "浮生事，算天涯海角，谁是闲人。", "几番甲子庚申。", "看青草年年秋又春。", "笑武陵源上，桃花未实，昆仑山下，瑶树长新。", "霓羽飘零，蛾眉萧飒，欲觅神仙隔两尘。", "草堂在，但休教山鬼，夜半移文。"]'),
('song-ci-105','摸鱼儿','何梦桂','宋','宋词','song-ci','摸鱼儿','[]','把心期、半生孤负。',140,'宋词/ci.song.17000.json','["把心期、半生孤负。", "玉堂元在何处。", "朱弦弹绝无人听，空操离鸾烈女。", "遇不遇。", "休更问、悠悠世事都如许。", "人生草露。", "看百岁勋名，青铜鬓影，抚剑泪如雨。", "知谁语。", "落落江空岁暮。", "人间一梦今古。", "雷塘十里斜阳外，野草寒鸦无数。", "身世寓。", "聊尔耳、江山有恨谁堪付。", "冰心更苦。", "都说与梅花，参横月落，一醉且归去。"]'),
('song-ci-106','洞仙歌','何梦桂','宋','宋词','song-ci','洞仙歌','[]','天涯何处，望苍江渺渺。',100,'宋词/ci.song.17000.json','["天涯何处，望苍江渺渺。", "纵算解飞人不到。", "笑双丸乌兔，两鬓霜蓬，聊尔耳，那是人间三岛。", "黄梁初梦觉，起看孤云，还自长歌自长啸。", "不记桃源何地，橘渚何年，生涯事、惟有炉烟茶灶。", "问先生谁友，有白石青松，共成三老。"]'),
('song-ci-107','喜迁莺','何梦桂','宋','宋词','song-ci','喜迁莺','[]','东君别后。',126,'宋词/ci.song.17000.json','["东君别后。", "见说道花枝，也成消瘦。", "夜雨帘栊，柳边庭院，烦恼有谁撋就。", "犹记旧看承处，梅子枝头如豆。", "最苦是，向重门人静，月明时候。", "知否。", "人不见，纵有音书，争似重携手。", "旧日沉腰，如今潘鬓，怎奈许多僝僽。", "极目万山深处，肠断不堪回首。", "情寸寸，到如今，只在长亭烟柳。"]'),
('song-ci-108','沁园春','何梦桂','宋','宋词','song-ci','沁园春','[]','尚书当年，蓬矢桑弧，初度佳期。',140,'宋词/ci.song.17000.json','["尚书当年，蓬矢桑弧，初度佳期。", "是词林老虎，文场威凤，人中祥瑞，天下英奇。", "太守买臣，中书坡老，五十二年回首非。", "人间事，且开眉一笑，醉倒金卮。", "阿婆还忆年时。", "也曾趁鸿胪拜玉墀。", "念青衫荷叶，嫁衣尚在，青铜菱影，破镜犹遗。", "半席寒毡，一官俯首，造物还应戏小儿。", "问天道，看是他谁戏我，我戏他谁。"]'),
('song-ci-109','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','倚阑干立尽，看东风、吹度柳绵飞。',119,'宋词/ci.song.17000.json','["倚阑干立尽，看东风、吹度柳绵飞。", "怕杜鹃啼杀，江南雁杳，游子何之。", "梦断扬州芍药，落尽簇红丝。", "歌吹今何在，一曲沾衣。", "往事不堪重省，记柳边深巷，花外幽墀。", "把菱花独照，脂粉总慵施。", "怅春归、留春未住，奈春归、不管玉颜衰。", "伤心事，都将分付，榆砌苔矶。"]'),
('song-ci-110','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','自辽东鹤去，算何人、插得翅能飞。',119,'宋词/ci.song.17000.json','["自辽东鹤去，算何人、插得翅能飞。", "笑平生错铸，儒冠误识，者也焉之。", "谩道寒蚕冰底，瓮茧解成丝。", "何许丝千丈，补得龙衣。", "镜里不堪勋业，纵梦中八翼，不到天墀。", "看墦间富贵，妻妾笑施施。", "对青山、千年不老，但梅花、头白伴人衰。", "严陵路，年年潮水，不上渔矶。"]'),
('song-ci-111','贺新郎','何梦桂','宋','宋词','song-ci','贺新郎','["\u957f\u6c5f"]','世事浑无定。',142,'宋词/ci.song.17000.json','["世事浑无定。", "问人间、翻来覆去，阿谁能忍。", "海怒惊涛山相拍，选甚鱼龙不任。", "看今古、英雄销尽。", "坐对青山闲白日，付长江、流送千年恨。", "天有意，唯何甚。", "待将洗耳泉边枕。", "正梅花、霜寒月白，斗回西柄。", "自寿一觞花前醉，醉亸彩幡金胜。", "笑儿辈、汾阳中令。", "倚遍层楼干阑曲，慨乾坤、渺渺青云影。", "无限事，尊前兴。"]'),
('song-ci-112','贺新郎','何梦桂','宋','宋词','song-ci','贺新郎','[]','花落风初定。',142,'宋词/ci.song.17000.json','["花落风初定。", "倚危阑、衷情欲诉，踌躇不忍。", "把酒问春春无语，吹落游尘怎任。", "待泪雨、红妆蔫尽。", "不道燕衔春将去，误啼鹃、唤起年年恨。", "芳草路，人愁甚。", "浮生一梦黄梁枕。", "且不妨、狂歌醉舞，麈谈挥柄。", "金谷平泉俱尘土，谁是当年豪胜。", "但五柳、依然陶令。", "千古兴亡东流水，望孤鸿、没处残阳影。", "无限意，伤春兴。"]'),
('song-ci-113','贺新郎','何梦桂','宋','宋词','song-ci','贺新郎','[]','更静钟初定。',142,'宋词/ci.song.17000.json','["更静钟初定。", "卷珠帘、人人独立，怨怀难忍。", "欲拨金猊添沉水，病力厌厌不任。", "任蝶粉、蜂黄消尽。", "亭北海棠还开否，纵金钗、犹在成长恨。", "花似我，瘦应甚。", "凄凉无寐闲衾枕。", "看夜深、紫垣华盖，低摇杠柄。", "重拂罗裳蹙金线，尘满双鸳花胜。", "孤负我、花期春令。", "不怕镜中羞华发，怕镜中、舞断孤鸾影。", "天尽处，悠悠兴。"]'),
('song-ci-114','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','叹人生聊尔，便晨风、翼倦也回飞。',120,'宋词/ci.song.17000.json','["叹人生聊尔，便晨风、翼倦也回飞。", "况自骑款段，欲追骐骥，千里安之。", "种得玄芝瑶草，不染满头丝。", "一醉梅花下，笑舞青衣。", "说甚封侯万里，待朱门画战，大第崇墀。", "人世何时□足，造物任隆施。", "怪周公、如今不梦，意周公、政自怪吾衰。", "归来去，夕阳牛陇，夜月鸥矶。"]'),
('song-ci-115','洞仙歌','何梦桂','宋','宋词','song-ci','洞仙歌','[]','青衫白发，独倚江楼小。',103,'宋词/ci.song.17000.json','["青衫白发，独倚江楼小。", "待欲题诗压崔颢。", "慨凤台今在否，白鹭沙洲，芳草外、剩得闲身江表。", "醉来疑梦里，梦入梅花，歌彻青衣听清窈。", "起着飞鸿没尽，白鸟玄驹，谁能数、曹瞒袁绍。", "待明年、七十问何如，笑只是今朝，浣花堂老。"]'),
('song-ci-116','玉漏迟','何梦桂','宋','宋词','song-ci','玉漏迟','[]','问春先开未，江南野水，得春初小。',115,'宋词/ci.song.17000.json','["问春先开未，江南野水，得春初小。", "独殿群芳，却道花前开早。", "长苦冰霜压尽，更说甚、风标清窈。", "些子好。", "孤香冷艳，有谁知道。", "年年吹落还开，听画角楼头，送他昏晓。", "何处玉堂，满地苍苔不扫。", "谁是肝肠铁石，与共说、岁寒怀抱。", "花未老。", "无奈酒阑情好。"]'),
('song-ci-117','蓦山溪','何梦桂','宋','宋词','song-ci','蓦山溪','[]','飞仙欲下，水殿严妆早。',102,'宋词/ci.song.17000.json','["飞仙欲下，水殿严妆早。", "娇湿怕春知，跨白虬、天门未晓。", "霓裳零乱，肌骨自清妍，梅檐月，柳桥风，世上红尘杳。", "重门深闭，忘却山阴道。", "呼酒嚼琼花，任醉来、玉山倾倒。", "无言相对，这岁暮心期，茅舍外，玉堂前，处处风流好。"]'),
('song-ci-118','蓦山溪','何梦桂','宋','宋词','song-ci','蓦山溪','[]','春工未觉，何处琼英早。',102,'宋词/ci.song.17000.json','["春工未觉，何处琼英早。", "夜半翦银河，到人间、楼台初晓。", "霏霏脉脉，不是不多情，金帐暖，玉堂深，却怪音尘杳。", "天公谪下，暂落红尘道。", "颜色自还怜，怕轻狂、随风颠倒。", "冰心谁诉，但吹入梅花，明月地，白云阶，相照天寒好。"]'),
('song-ci-119','蓦山溪','何梦桂','宋','宋词','song-ci','蓦山溪','[]','蓬蓬窣窣，睡梦惊回早。',102,'宋词/ci.song.17000.json','["蓬蓬窣窣，睡梦惊回早。", "谁为散天花，遍人间，夜深分晓。", "虚空幻出，富贵照乾坤，琼万顷，玉千株，莫道壶天杳。", "平明三尺，不拣江南道。", "只怕不坚牢，被天工、小儿翻倒。", "凝冰泮水，世态总无凭，明日事，昨朝人，谁丑还谁好。"]'),
('song-ci-120','沁园春','何梦桂','宋','宋词','song-ci','沁园春','[]','孔盖霓旌，月佩云裳，人间女仙。',140,'宋词/ci.song.17000.json','["孔盖霓旌，月佩云裳，人间女仙。", "问韶光九十，何如今待，明朝最处，好是明年。", "戏舞称觞，一堂家庆，眼见儿孙曾又玄。", "奇绝处，看菱花白发，不改朱颜。", "当年。", "手种红莲。", "笑几度桑田沧海乾。", "想蟾胎炼就，紫皇灵药，龙髯飞坠，玉女云軿。", "青鸟重来，红霞俨在，一曲云和犹未闲。", "羞尘世，把蛾眉蝉鬓，空为谁妍。"]'),
('song-ci-121','浣溪沙','何梦桂','宋','宋词','song-ci','浣溪沙','[]','细柳连营绿荫重。',48,'宋词/ci.song.17000.json','["细柳连营绿荫重。", "暖风旗影扬蛇龙。", "昼闲吟思入千峰。", "紫绶金牌人绿发，绣鞯丝辔马青骢。", "会将三箭取侯封。"]'),
('song-ci-122','浣溪沙','何梦桂','宋','宋词','song-ci','浣溪沙','[]','金紫山前山万重。',48,'宋词/ci.song.17000.json','["金紫山前山万重。", "山高云密下苍龙。", "春来好雨遍三峰。", "芳草郊原眠茧犊，垂杨营垒系花骢。", "趣归行有紫泥封。"]'),
('song-ci-123','蝶恋花','何梦桂','宋','宋词','song-ci','蝶恋花','[]','风信花残吹柳絮。',70,'宋词/ci.song.17000.json','["风信花残吹柳絮。", "柳外池塘，乳燕时飞度。", "漠漠轻云山约住。", "半村烟树鸠呼雨。", "竹院深深深几许。", "深处人闲，谁识闲中趣。", "弹彻瑶琴移玉柱。", "苍苔满地花阴午。"]'),
('song-ci-124','大江东去・念奴娇','何梦桂','宋','宋词','song-ci','大江东去・念奴娇','[]','半生习气，被风霜、销尽头颅如许。',120,'宋词/ci.song.17000.json','["半生习气，被风霜、销尽头颅如许。", "七十年来都铸错，回首邯郸何处。", "杜曲桑麻，柴桑松菊，归计成迟暮。", "一樽自寿，不妨沉醉狂舞。", "休问沧海桑田，看朱颜白发，转次全故。", "乌兔相催天也老，千古英雄坏土。", "汾水悲歌，雍江苦调，堕泪真儿女。", "兴亡一梦，大江依旧东注。"]'),
('song-ci-125','玉漏迟','何梦桂','宋','宋词','song-ci','玉漏迟','[]','青衫华发，对风霜、倚遍危楼孤啸。',115,'宋词/ci.song.17000.json','["青衫华发，对风霜、倚遍危楼孤啸。", "恶浪平波，看尽世间多少。", "忘却金闺故步，都付与、野花啼鸟。", "祗自笑。", "悠悠心事，无人知道。", "扰扰世路红尘，看销尽英雄，青山亦老。", "宇宙无穷，事业到头谁了。", "高楼一声画角，把千古、梦中吹觉。", "天欲晓。", "起看蕊梅春小。"]'),
('song-ci-126','玉漏迟','何梦桂','宋','宋词','song-ci','玉漏迟','[]','自怜翠袖，向天寒、独倚孤篁吟啸。',115,'宋词/ci.song.17000.json','["自怜翠袖，向天寒、独倚孤篁吟啸。", "半世虚名，孤负白云多少。", "欲问梅翁旧约，怕误我、沙头鸥鸟。", "时一笑。", "行行且止，人间蜀道。", "休怪岁月无情，叹尘世浮生，闲忙闲老。", "待趁黑头，万里封侯都了。", "今古勋名一梦，听未彻、钧天还觉。", "羌管晓。", "楼角曙星稀小。"]'),
('song-ci-127','水龙吟','何梦桂','宋','宋词','song-ci','水龙吟','[]','分知白首天寒，千林摇落寻真隐。',124,'宋词/ci.song.17000.json','["分知白首天寒，千林摇落寻真隐。", "天工付与，冰肌雪骨，暗香寒凝。", "自许负心，肯教色界，软红尘近。", "怅绿衣舞断，参横梦觉，依稀旧家犹认。", "不为角声落，向花前、为伊悲恨。", "玉堂茅舍，风流随处，年年孤另。", "不是人间，肝肠铁石，相逢休问。", "算知心、只许东风，漏泄一分春信。"]'),
('song-ci-128','八声甘州','何梦桂','宋','宋词','song-ci','八声甘州','[]','恨公来较晚，早归朝、骢马去难留。',119,'宋词/ci.song.17000.json','["恨公来较晚，早归朝、骢马去难留。", "是朱轮华毂，联珪叠组，家世公侯。", "今在玉堂深处，借重护偏州。", "好把青毡拂，奕世勋猷。", "明日东津归路，正梅花霜暧，春上枝头。", "看连旗列鼓，送客下江楼。", "对云山、千年不老，向楼前、阅尽几行舟。", "留名在，严陵滩下，日夜东流。"]'),
('song-ci-129','传言玉女','何梦桂','宋','宋词','song-ci','传言玉女','[]','阿母今朝，飞下琼楼金阙。',91,'宋词/ci.song.17000.json','["阿母今朝，飞下琼楼金阙。", "先教玉女，为传言细说。", "蟠桃手种，尚记此春时节。", "三千春后，开花初结。", "宴罢瑶池，洗娥眉、已半雪。", "九旬偷度，笑韶光一映。", "仙翁日月，算与人间全别。", "从今一岁，年年三月。"]'),
('song-ci-130','最高楼','何梦桂','宋','宋词','song-ci','最高楼','[]','南山老，还记少陵诗。',100,'宋词/ci.song.17000.json','["南山老，还记少陵诗。", "七十古来稀。", "清池拥出红蕖坠，西风吹上碧梧枝。", "趁今朝，斟寿酒，记生时。", "也不羡、鲲鹏飞击水。", "也不羡、蛟龙行得雨。", "人世事，总危机。", "扶床正好看孙戏，舞衫不要笑儿痴。", "更埙篪，三老子，鬓如丝。"]'),
('song-ci-131','摸鱼子','赵必','宋','宋词','song-ci','摸鱼子','[]','倚西风、招鸿送燕，年华今已如客。',140,'宋词/ci.song.17000.json','["倚西风、招鸿送燕，年华今已如客。", "青奴一饷贪凉梦，昨夜酒红无力。", "愁似织。", "听鸣叶寒蝉，话到情无极。", "舞衣春入。", "欢带眼偷移，琴心不断，襟袖旧时窄。", "红尘陌。", "谁寄佳人消息。", "任他珠网瑶瑟。", "金钗两鬓霓裳曲，总是浪歌闲拍。", "长夜笛。", "且慢析轻匀，留醉酒垆侧。", "烟青雾白。", "望残照关河，晴云楼阁，何处是秋色。"]'),
('song-ci-132','西江月','林自然','宋','宋词','song-ci','西江月','[]','二十馀年访道，经游万水千山。',58,'宋词/ci.song.17000.json','["二十馀年访道，经游万水千山。", "明师未遇肯安闲。", "几度拈香一瓣。", "幸遇至人说破，虚无妙用循环。", "工夫只在片时间。", "遍体神光灿烂。"]'),
('song-ci-133','酹江月・念奴娇','林自然','宋','宋词','song-ci','酹江月・念奴娇','["\u957f\u6c5f"]','凿开混沌，见钱塘南控、长江凝碧。',120,'宋词/ci.song.17000.json','["凿开混沌，见钱塘南控、长江凝碧。", "今古词人图此景，谁解推原端的。", "岁去年来，日庚月甲，因甚无差忒。", "如今说破，要知天地来历。", "道散有一强名，五行颠倒，互列乾坤历。", "坎水逆流朝丙户，随月盈亏消息。", "气到中秋，金能生水，倍涌千重雪。", "神仙妙用，与潮没个差别。"]'),
('song-ci-134','念奴娇','奚岊','宋','宋词','song-ci','念奴娇','[]','踏破秋痕，向虚堂、细问新凉踪迹。',120,'宋词/ci.song.17000.json','["踏破秋痕，向虚堂、细问新凉踪迹。", "野客从来无管领，独鹤自还空碧。", "红日重开，翠华曾到，应恨湖光窄。", "游龙别后，两山依旧南北。", "无语野草闲花，似嗔人问，万事今非昔。", "古木苍烟无限意，只有吟魂知得。", "歌舞百年，是非一醉，未必西风识。", "浩歌归去，满船风雨凄恻。"]'),
('song-ci-135','长相思慢','奚岊','宋','宋词','song-ci','长相思慢','[]','日折霜檐，寒欺雾幕，晴枝浅弄春华。',128,'宋词/ci.song.17000.json','["日折霜檐，寒欺雾幕，晴枝浅弄春华。", "惊回绮梦，独拥绫衾，腮痕微印朝霞。", "倦起心情，念风移霜换，依旧天涯。", "雁影水云斜。", "算相思、一点愁赊。", "问橘楚橙吴，旧香犹在，别后襟袖输他。", "琴心知未许，想钿钗、流落谁家。", "怕上高楼，归思还、斜阳暮鸦。", "几多年、江湖浪识，知心只许梅花。"]'),
('song-ci-136','声声慢','奚岊','宋','宋词','song-ci','声声慢','[]','秋声淅沥，楚棹吴鞭，相逢易老颜色。',119,'宋词/ci.song.17000.json','["秋声淅沥，楚棹吴鞭，相逢易老颜色。", "桐竹鸣骚音韵，水云空觅。", "炎凉自今自古，信浮生、有谁禁得。", "漫回首，问黄花还念，故人犹客。", "莫管红香狼籍。", "兰蕙冷，偏他露知霜识。", "木落山空心事，对秋明白。", "征衣暗尘易染，算江湖、随人宽窄。", "正无据，看寒蟾、飞上暮碧。"]'),
('song-ci-137','解连环','奚岊','宋','宋词','song-ci','解连环','[]','霁环新掠。',132,'宋词/ci.song.17000.json','["霁环新掠。", "正风回浪影，时摇城脚。", "叹天涯、春草无伦，似凝伫当时，柳颦花弱。", "步锦珠沉，谩一眸、千年如昨。", "信龙楼凤阁，无奈都由，笑歌休却。", "斜阳柳边自落。", "听幽禽两两，沙际停泊。", "道世问、多少闲愁，总输与扁舟，五湖游乐。", "便买蓑衣，又生怕、鱼龙风恶。", "把从前、万事对酒，且休问著。"]'),
('song-ci-138','醉蓬莱','奚岊','宋','宋词','song-ci','醉蓬莱','[]','又扁舟东下，水树青圆，雨榴红薄。',120,'宋词/ci.song.17000.json','["又扁舟东下，水树青圆，雨榴红薄。", "燕子愁多，在重重帘幕。", "杖屧山阴，而今休更问，月尖眉约。", "双杏盟寒，七香珠坠，歌尘飘泊。", "莫倚危阑，怨深黄竹，一鹤归来，乱峰飞落。", "笑色凌波，任雾抽烟邈。", "飘渺生香池冷，湘水外，片云如削。", "昨夜离人，游仙梦远，天风吹觉。"]'),
('song-ci-139','永遇乐','奚岊','宋','宋词','song-ci','永遇乐','[]','一雁斜阳，乱蛩衰草，天净秋远。',128,'宋词/ci.song.17000.json','["一雁斜阳，乱蛩衰草，天净秋远。", "独立西风，星星鬓影，疑被蕖霜染。", "蹇修何处，秋深湘水，隐约数峰青浅。", "想而今，亭亭皓月，共谁倚阑凄惋。", "瑶箱翠袭，玉奁芸剪，暗里泪化偷溅。", "一日思量，十年瘦削，春色回眸减。", "雕鸾好在，文箫重许，罍酒试香庭苑。", "正销魂，馀霞散碧，暮鸦数点。"]'),
('song-ci-140','宴瑶池・越江吟','奚岊','宋','宋词','song-ci','宴瑶池・越江吟','[]','紫鸾飞舞，又东华宴罢，归步凝碧。',122,'宋词/ci.song.17000.json','["紫鸾飞舞，又东华宴罢，归步凝碧。", "缥缈天风吹送处，泠泠珮声清逸。", "青童两两，争笑拈、琪花半折。", "羽衣寒露香披，翠幢珠辂去云疾。", "西真还又传帝敕。", "霞城检校，问学仙消息。", "玉府高寒，有不老丹容，自然琼液。", "人间尘梦，应误认、烟痕雾迹。", "洞云依约开时，丹华飞素白。"]'),
('song-ci-141','齐天乐','奚岊','宋','宋词','song-ci','齐天乐','[]','金飙吹净人间暑。',123,'宋词/ci.song.17000.json','["金飙吹净人间暑。", "连朝弄凉新雨。", "万宝功成，无人解得，秋入天机深处。", "闲中自数。", "几心酌乾坤，手斟霜露。", "护了山河，共看元影在银兔。", "而今神仙正好，向青空觅个，冲澹襟宇。", "帝念群生，如何便肯，从我乘风归去。", "夷游洞府。", "把月抒云机，教他儿女。", "水逸山明，此情天付与。"]'),
('song-ci-142','芳草','奚岊','宋','宋词','song-ci','芳草','[]','笑湖山、纷纷歌舞，花边如梦如薰。',124,'宋词/ci.song.17000.json','["笑湖山、纷纷歌舞，花边如梦如薰。", "响烟惊落日，长桥芳草外，客愁醒。", "天风送远，向两山、唤醒痴云。", "犹自有、迷林去鸟，不信黄昏。", "销凝。", "油车归后，一眉新月，独印湖心。", "蕊宫相答处，空岩虚谷应，猿语香林。", "正酣红紫梦，便市朝、有耳谁听。", "怪玉兔、金乌不换，只换愁人。"]'),
('song-ci-143','华胥引','奚岊','宋','宋词','song-ci','华胥引','[]','澄空无际，一幅轻绡，素秋弄色。',105,'宋词/ci.song.17000.json','["澄空无际，一幅轻绡，素秋弄色。", "翦翦天风，飞飞万里，吹净遥碧。", "想玉杵芒寒，听珮环无迹。", "圆缺何心，有心偏向歌席。", "多少情怀，甚年年、共怜今夕。", "蕊宫珠殿，还吟飘香秀笔。", "隐约霓裳声度，认紫霞楼笛。", "独鹤归来，更无清梦成觅。"]'),
('song-ci-144','玉漏迟','赵闻礼','宋','宋词','song-ci','玉漏迟','[]','絮花寒食路。',115,'宋词/ci.song.17000.json','["絮花寒食路。", "晴丝罥日，绿阴吹雾。", "客帽欺风，愁满画船烟浦。", "彩柱秋千散后，恨尘锁、燕帘莺户。", "从间阻。", "梦云无准，鬓霜如许。", "夜永绣阁藏娇，记掩扇传歌，剪灯留语。", "月约星期，细把花须频数。", "弹指一襟幽恨，谩空倩、啼鹃声诉。", "深院宇。", "黄昏杏花微雨。"]'),
('song-ci-145','法曲献仙音','赵闻礼','宋','宋词','song-ci','法曲献仙音','[]','花匣么弦，象奁双陆，旧日留欢情意。',113,'宋词/ci.song.17000.json','["花匣么弦，象奁双陆，旧日留欢情意。", "梦别银屏，恨裁兰烛，香篝夜闲鸳被。", "料燕子重来地，桐阴琐窗绮。", "倦梳洗。", "量芳钿、自羞鸳镜，罗袖冷，烟柳画兰半倚。", "浅雨压荼䕷，指东风、芳事馀几。", "院落黄昏，怕春莺、惊笑憔悴。", "倩柔红约定，唤取玉箫同醉。"]'),
('song-ci-146','瑞鹤仙','赵闻礼','宋','宋词','song-ci','瑞鹤仙','[]','客边情味恶。',127,'宋词/ci.song.17000.json','["客边情味恶。", "花漏远、春静风鸣凤铎。", "空梁燕泥落。", "映柔红微罥，海棠帘箔。", "愁钟恨角。", "怕催人、黄昏索寞。", "拥吟袍、凭暖阑干，醉怯冷香罗薄。", "阿鹊。", "幽芳月淡，紫曲云昏，有人说著。", "名缰易缚。", "归鞭杳，误期约。", "记金泥卜画，银屏娱夜，弹指忽忽恨错。", "为情多、搀尽芳春，带围瘦觉。"]'),
('song-ci-147','瑞鹤仙','赵闻礼','宋','宋词','song-ci','瑞鹤仙','[]','冻痕消梦草。',127,'宋词/ci.song.17000.json','["冻痕消梦草。", "又招得春归，旧家池沼。", "园扉掩寒悄。", "倩谁将花信，偏传深窈。", "追游趁早，便裁却、春衫短帽。", "任残梅、飞满溪桥，和月醉眠清晓。", "年少。", "青丝织手，彩胜娇环，赋情谁表。", "南楼信杳。", "江云重，雁归少。", "记冲香嘶马，流红回岸，几度绿杨残照。", "想暗黄、依旧东风，灞陵古道。"]'),
('song-ci-148','好事近','赵闻礼','宋','宋词','song-ci','好事近','[]','人去绿屏闲，逗晓柳丝风急。',53,'宋词/ci.song.17000.json','["人去绿屏闲，逗晓柳丝风急。", "帘外杏花微雨，罥春红愁湿。", "单衣催赐曲尘罗，中酒病无力。", "应是绣床慵困，倚秋千斜立。"]'),
('song-ci-149','好事近','赵闻礼','宋','宋词','song-ci','好事近','[]','小枕梦催闲，飞雨时鸣高屋。',53,'宋词/ci.song.17000.json','["小枕梦催闲，飞雨时鸣高屋。", "挂起西窗人静，听春禽声续。", "鸭塘溪绿涨轻痕，烟柳媚新绿。", "谁伴瘦筇尊酒，弄岩泉飞瀑。"]'),
('song-ci-150','鱼游春水','赵闻礼','宋','宋词','song-ci','鱼游春水','[]','青楼临远水。',105,'宋词/ci.song.17000.json','["青楼临远水。", "楼上东风飞燕子。", "玉钩珠箔，密密锁红藏翠。", "剪胜裁幡春日戏。", "簇柳簪梅元夜醉。", "闲忆旧欢，暗弹新泪。", "罗帕啼痕未洗。", "愁见同心双凤翅。", "长安十日轻寒，春衫未试。", "过尽征鸿知几许，不寄萧娘书一纸。", "愁肠断也，那人知未。"]'),
('song-ci-151','千秋岁','赵闻礼','宋','宋词','song-ci','千秋岁','[]','莺啼晴昼，南国春如绣。',87,'宋词/ci.song.17000.json','["莺啼晴昼，南国春如绣。", "飞絮眼，凭阑袖。", "日长花片落，睡起眉山斗。", "无个事，沉烟一缕腾金兽。", "千里空回首。", "两地厌厌瘦。", "春去也，归来否。", "五更楼外月，双燕门前柳。", "人不见，秋千院落清明后。"]'),
('song-ci-152','风入松','赵闻礼','宋','宋词','song-ci','风入松','[]','曲尘风雨乱春晴。',88,'宋词/ci.song.17000.json','["曲尘风雨乱春晴。", "花重寒轻。", "珠帘卷上还重下，怕东风、吹散歌声。", "棋倦杯频昼永，粉香花艳清明。", "十分无处著闲情。", "来觅娉婷。", "蔷薇误罥寻春袖，倩柔荑、为补香痕。", "苦恨啼鹃惊梦，何时翦烛重盟。"]'),
('song-ci-153','水龙吟','赵闻礼','宋','宋词','song-ci','水龙吟','[]','几年埋玉蓝田，绿云翠水烘春暖。',126,'宋词/ci.song.17000.json','["几年埋玉蓝田，绿云翠水烘春暖。", "衣薰麝馥，袜罗尘沁，凌波步浅。", "钿碧搔头，腻黄冰脑，参差难翦。", "乍声沉素瑟，天风佩冷，蹁跹舞、霓裳遍。", "湘浦盈盈月满。", "抱相思、夜寒肠断。", "含香有恨，招魂无路，瑶琴写怨。", "幽韵凄凉，暮江空渺，数峰清远。", "粲迎风一笑，持花酹酒，结南枝伴。"]'),
('song-ci-154','隔浦莲近・隔浦莲近拍','赵闻礼','宋','宋词','song-ci','隔浦莲近・隔浦莲近拍','[]','愁红飞眩醉眼。',89,'宋词/ci.song.17000.json','["愁红飞眩醉眼。", "日淡芭蕉卷。", "帐掩屏香润，杨花扑、春云暖。", "啼鸟惊梦远。", "芳心乱。", "照影收奁晚。", "画眉懒。", "微醒带困，离情中酒相半。", "裙腰粉瘦，怕按六么歌板。", "帘卷层楼探旧燕。", "肠断。", "花枝和闷重拈。"]'),
('song-ci-155','贺新郎','赵闻礼','宋','宋词','song-ci','贺新郎','[]','池馆收新雨。',142,'宋词/ci.song.17000.json','["池馆收新雨。", "耿幽丛、流光几点，半侵疏户。", "入夜凉风吹不减，冷焰微茫暗度。", "碎影落、仙盘秋露。", "漏断长门空照泪，袖纱寒、映竹无心顾。", "孤枕掩，残灯炷。", "练囊不照诗人苦。", "夜沉沉、拍手相亲，呆儿痴女。", "栏外扑来罗扇小，谁在风廊笑语。", "竞戏踏、金钗双股。", "故苑荒凉悲旧赏，怅寒芜、衰草隋宫路。", "同磷火，遍秋圃。"]'),
('song-ci-156','谒金门','赵闻礼','宋','宋词','song-ci','谒金门','[]','人病酒。',53,'宋词/ci.song.17000.json','["人病酒。", "生怕日高催绣。", "昨夜新翻花样瘦。", "旋描双蝶凑。", "慵凭绣床呵手。", "却说新愁还又。", "门外东风吹绽柳。", "海棠花厮勾。"]'),
('song-ci-157','踏莎行','赵闻礼','宋','宋词','song-ci','踏莎行','[]','照眼菱花，剪情菰叶。',68,'宋词/ci.song.17000.json','["照眼菱花，剪情菰叶。", "梦云吹散无踪迹。", "听郎言语识郎心，当时一点谁消得。", "柳暗花明，萤飞月黑。", "临窗滴泪研残墨。", "合欢带上旧题诗，如今化作相思碧。"]'),
('song-ci-158','摸鱼儿','叶阊','宋','宋词','song-ci','摸鱼儿','[]','倚薰风、画阑亭午。',140,'宋词/ci.song.17000.json','["倚薰风、画阑亭午。", "采莲柔橹如语。", "红裙溅水鸳鸯湿，几度云朝雨暮。", "游冶处。", "是好是、小桥芳树寻幽趣。", "绣帘低护。", "任凉入霜纨，月侵冰簟，长夏等闲度。", "都如梦，怅望游仙旧侣。", "遗踪今在何许。", "愁予渺渺潇湘浦。", "槛竹空敲朱户。", "黯无绪。", "念多情文园，曾草长门赋。", "酒酣自舞。", "笑满袖缁尘，数茎霜鬓，羞杀照溪鹭。"]'),
('song-ci-159','三姝媚','杜良臣','宋','宋词','song-ci','三姝媚','[]','花浮深岸树。',121,'宋词/ci.song.17000.json','["花浮深岸树。", "迎新曦窗影，细触游尘。", "映叶青梅，记共折南枝，又及尝新。", "驻屐危亭，烟墅杳、风物撩人。", "虹外斜阳留晚，莺边落絮催春。", "心事应辜桃叶，但自把新诗，遍写修筠。", "恨满芳洲，倩晚风吹梦，暗逐江云。", "慢拈轻拢，幽思切、清音谁闻。", "谩有鸳鸯结带，双垂绣巾。"]'),
('song-ci-160','齐天乐','曹邍','宋','宋词','song-ci','齐天乐','[]','翠箫声断青鸾翼，心期破钗谁表。',123,'宋词/ci.song.17000.json','["翠箫声断青鸾翼，心期破钗谁表。", "夜烛银屏，春风粉袖，犹记琵琶斜抱。", "瑶池路杳。", "恨巫女回云，月娥沉照。", "谩说蓬莱，玉环花貌梦难到。", "严花亭院乍冷，更蛩吟风碎，鸿飞烟渺。", "绿玉弹棋，红牙按拍，乐事欢情终少。", "刘郎未老。", "要鬓翼堆玄，腕酥凝皓。", "莫忘香荐，绿罗裙带草。"]'),
('song-ci-161','瑞鹤仙','曹邍','宋','宋词','song-ci','瑞鹤仙','[]','炉烟销篆碧。',127,'宋词/ci.song.17000.json','["炉烟销篆碧。", "对院落秋千，昼永人寂。", "浓春透花骨。", "正长红小白，晕香涂色。", "铜驼巷陌。", "想游丝、飞絮无力。", "念绣窗、深锁红鸾，虚度禁烟寒食。", "空忆。", "象床沉水，凤枕屏山，殢欢尤惜。", "粉香狼藉。", "海棠下、东风急。", "自秦台箫咽，汉皋珮冷，断雨零云难觅。", "但杏梁、双燕归来，似曾旧识。"]'),
('song-ci-162','兰陵王','曹邍','宋','宋词','song-ci','兰陵王','[]','杏花坼。',158,'宋词/ci.song.17000.json','["杏花坼。", "烟柳藏鸦翠陌。", "苏堤上、人正踏青，嫩草茸茸衬罗袜。", "游丝挂晴塔。", "十里酣红艳白。", "秋千外，娇靥笑春，一片笙箫绮霞碧。", "阿香妒倾国。", "把镜日深奁，丝雨愁织。", "崇桃积李无颜色。", "但蝶粉香渍，燕泥芹冷，紫钱芳晕翳宝瑟。", "怅还近寒食。", "岑寂。", "恨无极。", "更酒驿孤烟，棋院长日。", "梨花满地春狼藉。", "望凤阙波渺，燕楼云隔。", "凭阑干晚，吟袖湿，但笑拍。"]'),
('song-ci-163','玲珑四犯','曹邍','宋','宋词','song-ci','玲珑四犯','[]','一架幽芳，自过了梅花，独占清绝。',123,'宋词/ci.song.17000.json','["一架幽芳，自过了梅花，独占清绝。", "露叶檀心，香满万条晴雪。", "肌素净冼铅华，似弄玉、乍离瑶阙。", "看翠蛟、白凤飞舞，不管暮烟啼鴂。", "酒中风格天然别。", "记唐宫、赐樽芳冽。", "玉蕤唤得馀春住，犹醉迷飞蝶。", "天气乍雨乍晴，长是伴、牡丹时节。", "夜散琼楼宴，金铺深掩，一庭香月。"]'),
('song-ci-164','惜馀妍・惜余妍','曹邍','宋','宋词','song-ci','惜馀妍・惜余妍','[]','同根异色，看镂玉雕檀，芳艳如簇。',116,'宋词/ci.song.17000.json','["同根异色，看镂玉雕檀，芳艳如簇。", "秀叶玲珑，嫩条下垂修绿。", "禁华深锁清妍，香满架、风梳露浴。", "轻盈，便似觉、酴醿格调粗俗。", "蜂黄间涂蝶粉，疑旧日二乔，各样妆束。", "费却春工，斗合靓芳浓馥。", "翠华临槛清赏，飞凤斝、休辞醉玉。", "晴昼，镇贮春、瑶台金屋。"]'),
('song-ci-165','宴山亭・燕山亭','曹邍','宋','宋词','song-ci','宴山亭・燕山亭','[]','香月玲珑，柔风镂刻，嫩绿枝头圆腻。',123,'宋词/ci.song.17000.json','["香月玲珑，柔风镂刻，嫩绿枝头圆腻。", "绯桃院宇，絮柳池塘，独立万红尘外。", "戏舞千团，讶粉羽、留连春媚。", "非是。", "看滚雪抛琼，镜鸾相倚。", "唐昌仙观风流，有霞洞藏花，绀环玉蕊。", "雕阑占赏，禁苑承恩，难比太平瑶卉。", "遍插金瓶，更移近、宝猊烟翠。", "堪爱。", "只少个、鸳鸯绣带。"]'),
('song-ci-166','水调歌头','郑雪岩','宋','宋词','song-ci','水调歌头','[]','甫营亭子小，花柳斩新裁。',114,'宋词/ci.song.17000.json','["甫营亭子小，花柳斩新裁。", "衰翁馀暇，何妨领客少徘徊。", "堪叹人生离合，恰似燕莺来往，光景暗中催。", "芦荻晚风起，明月满沙堆。", "去年秋，如此夜，有谁陪。", "欲挽天河无路，满眼总尘埃。", "未了痴儿官事，行止从来难定，又趣到苏台。", "不作别离句，共醉十分杯。"]'),
('song-ci-167','清平乐','赵汝','宋','宋词','song-ci','清平乐','[]','锦屏香褪。',54,'宋词/ci.song.17000.json','["锦屏香褪。", "寒隐轻衫嫩。", "燕子护泥飞不稳。", "庭掩百花难认。", "双双绣带微风。", "海棠此夜帘栊。", "愁损一番寒食，小窗淡月残红。"]'),
('song-ci-168','恋绣衾','赵汝','宋','宋词','song-ci','恋绣衾','[]','柳丝空有千万条。',70,'宋词/ci.song.17000.json','["柳丝空有千万条。", "系不住、溪头画桡。", "想今宵、也对新月，过轻寒、何处小桥。", "玉箫台榭春多少，溜啼红、脸霞未消。", "怪别来、胭脂慵传，被东风、偷在杏梢。"]'),
('song-ci-169','浣溪沙','赵汝','宋','宋词','song-ci','浣溪沙','["\u592a\u6e56"]','笑摘青梅傍绮疏。',48,'宋词/ci.song.17000.json','["笑摘青梅傍绮疏。", "数枝花影漾前除。", "太湖石畔看金鱼。", "笋指晓寒慵出袖，翠鬟春懒不成梳。", "为君缝狭绣罗襦。"]'),
('song-ci-170','梅花引','赵汝','宋','宋词','song-ci','梅花引','[]','对花时节不曾忺。',110,'宋词/ci.song.17000.json','["对花时节不曾忺。", "见花残。", "任花残。", "小约帘栊，一面受春寒。", "题破玉笺双喜鹊，香烬冷，绕银屏，浑是山。", "待眠。", "未眠。", "事万千。", "也问天。", "也恨天。", "髻儿半偏。", "绣裙儿、宽了还宽。", "自取红毡，重坐暖金船。", "惟有月知君去处，今夜月，照秦楼，第几间。"]'),
('song-ci-171','摘红英','赵汝','宋','宋词','song-ci','摘红英','[]','东风冽。',68,'宋词/ci.song.17000.json','["东风冽。", "红梅拆。", "画帘几片飞来雪。", "银屏悄。", "罗裙小。", "一点相思，满塘春草。", "空愁切。", "何年彻。", "不归也合分明说。", "长安道。", "箫声闹。", "去时骢马，谁家系了。"]'),
('song-ci-172','梦江南・忆江南','赵汝','宋','宋词','song-ci','梦江南・忆江南','[]','帘不卷，细雨熟樱桃。',63,'宋词/ci.song.17000.json','["帘不卷，细雨熟樱桃。", "数点霁霞山又晚，一痕凉月酒初消。", "风紧絮花高。", "闲处少，磨尽少年豪。", "昨梦醉骑白鹿，满湖春水段家桥。", "濯发听吹箫。"]'),
('song-ci-173','谒金门','赵汝','宋','宋词','song-ci','谒金门','[]','羞说起。',53,'宋词/ci.song.17000.json','["羞说起。", "嚼破白桃花蕊。", "人在夕阳深巷里。", "燕儿来也未。", "一样半红半紫。", "双凤同心结子。", "分在郎边郎不记。", "为郎今拆碎。"]'),
('song-ci-174','如梦令','赵汝','宋','宋词','song-ci','如梦令','[]','小砑红绫笺纸。',40,'宋词/ci.song.17000.json','["小砑红绫笺纸。", "一字一行春泪。", "封了更亲题，题了又还坼起。", "归未。", "归未。", "好个瘦人天气。"]'),
('song-ci-175','汉宫春','赵汝','宋','宋词','song-ci','汉宫春','["\u897f\u6e56"]','著破荷衣，笑西风吹我，又落西湖。',118,'宋词/ci.song.17000.json','["著破荷衣，笑西风吹我，又落西湖。", "湖间旧时饮者，今与谁俱。", "山山映带，似携来、画卷重舒。", "三十里、芙蓉步障，依然红翠相扶。", "一目清无留处，任屋浮天上，身集空虚。", "残烧夕阳过雁，点点疏疏。", "故人老大，好襟怀、消减全无。", "慢赢得、秋声两耳，冷泉亭下骑驴。"]'),
('song-ci-176','摸鱼儿','谭宣子','宋','宋词','song-ci','摸鱼儿','[]','掩朱弦、住听金缕。',140,'宋词/ci.song.17000.json','["掩朱弦、住听金缕。", "天涯同是羁旅。", "多情记把香罗袖，残粉半粘荆树。", "还信否。", "便忍道、石台暗寂春无主。", "分明间阻。", "那睡鸭嘘云，翔鸳溜月，此际更休语。", "人间世，谁识缄愁最苦。", "轻帆重解烟雨。", "而今翻笑周郎误。", "挑剔寒缸寻谱。", "游倦处。", "果因甚、亭亭瘦影如前度。", "无由寄与。", "待谢却梅花，东风为我，吹梦过淮浦。"]'),
('song-ci-177','西窗烛','谭宣子','宋','宋词','song-ci','西窗烛','[]','春江骤涨，晓陌微乾，断云如梦相逐。',107,'宋词/ci.song.17000.json','["春江骤涨，晓陌微乾，断云如梦相逐。", "料应怪我频来去，似千里迢遥，伤心极目。", "为楚腰、惯舞东风，芳草萋萋衬绿。", "燕飞独。", "知是谁家箫声多事，吹咽寻常怨曲。", "尽教衿袖香泥涴，君不见、扬州三生杜牧。", "待泪华、暗落铜盘，甚夜西窗剪烛。"]'),
('song-ci-178','侧犯','谭宣子','宋','宋词','song-ci','侧犯','[]','素秋渐爽，倚香曲枕情依旧。',94,'宋词/ci.song.17000.json','["素秋渐爽，倚香曲枕情依旧。", "怀袖。", "浸数尺湘漪、簟纹皱。", "悲欢尽梦里，玉骨从消瘦。", "空又。", "思太液芙蓉未央柳。", "翔凤何在，乐府传孤奏。", "人病酒。", "有鸳鸯双字倩谁绣。", "拜月西楼，几声滴漏。", "应恐纨洁，已疏郎手。"]'),
('song-ci-179','春声碎','谭宣子','宋','宋词','song-ci','春声碎','[]','津馆贮轻寒，脉脉离情如水。',94,'宋词/ci.song.17000.json','["津馆贮轻寒，脉脉离情如水。", "东风不管，垂杨无力，总雨颦烟寐。", "栏干外。", "怕春燕掠天，疏鼓叠、春声碎。", "刘郎易憔悴。", "况是恹恹病起。", "蛮笺漫展，便写就新词，倩谁将寄。", "当此际。", "浑似梦峡啼湘，一寸相思千里。"]'),
('song-ci-180','长相思','谭宣子','宋','宋词','song-ci','长相思','[]','去路遥。',44,'宋词/ci.song.17000.json','["去路遥。", "归路遥。", "灯月光中立小桥。", "魂萦紫玉箫。", "风萧萧。", "雨萧萧。", "此夜相思空寂寥。", "梅花落丽谯。"]'),
('song-ci-181','长相思','谭宣子','宋','宋词','song-ci','长相思','[]','净亭亭。',44,'宋词/ci.song.17000.json','["净亭亭。", "步盈盈。", "蝉影明绡傅体轻。", "水边无限情。", "翠尊倾。", "翠环倾。", "归去如何睡得成。", "西风吹酒醒。"]'),
('song-ci-182','谒金门','谭宣子','宋','宋词','song-ci','谒金门','[]','银漏滴。',53,'宋词/ci.song.17000.json','["银漏滴。", "午夜平康巷陌。", "双掩兽环人语寂。", "馀香无处觅。", "回首旧游踪迹。", "绀碧染衣犹湿。", "一饷沉吟谁会得。", "月明春店笛。"]'),
('song-ci-183','谒金门','谭宣子','宋','宋词','song-ci','谒金门','[]','人病酒。',53,'宋词/ci.song.17000.json','["人病酒。", "生怕日高催绣。", "昨夜新翻花样瘦。", "旋描双蝶凑。", "闲凭绣床呵手。", "却说春愁还又。", "门外东风吹绽柳。", "海棠花厮勾。"]'),
('song-ci-184','浣溪沙','谭宣子','宋','宋词','song-ci','浣溪沙','[]','欲展吴笺咏杜娘。',48,'宋词/ci.song.17000.json','["欲展吴笺咏杜娘。", "为停楚棹觅秦郎。", "藕花三十六湖香。", "珠颗翠檠饶宿泪，玉痕红退怯晨妆。", "小桥风月思凄凉。"]'),
('song-ci-185','玲珑四犯','谭宣子','宋','宋词','song-ci','玲珑四犯','[]','碧黯塞榆，黄销堤柳，危栏谁料重抚。',121,'宋词/ci.song.17000.json','["碧黯塞榆，黄销堤柳，危栏谁料重抚。", "才情犹未减，指点惊如许。", "当时共伊东顾。", "为辞家、怕吟鹦鹉。", "衮衮波光，悠悠云气，陶写几今古。", "生尘每怜微步。", "渺江空岁晚，知在何处。", "土花封玉树。", "恨极山阳赋。", "吹芗扇底馀欢断，怎忘得、阴移庭午。", "离别苦。", "那堪听、敲窗冻雨。"]'),
('song-ci-186','鸣梭','谭宣子','宋','宋词','song-ci','鸣梭','[]','织绡机上度鸣梭。',105,'宋词/ci.song.17000.json','["织绡机上度鸣梭。", "年光容易过。", "萦萦情绪，似水烟山雾两相和。", "谩道当时何事，流盼动层波。", "巫影嵯峨。", "翠屏牵薜萝。", "不须微醉自颜酡。", "如今难凭麽。", "烛花销艳，但替人、垂泪满铜荷。", "赋罢西城残梦，犹问夜如何。", "星耿斜河。", "候虫声更多。"]'),
('song-ci-187','江城子','谭宣子','宋','宋词','song-ci','江城子','[]','嫩黄初染绿初描。',86,'宋词/ci.song.17000.json','["嫩黄初染绿初描。", "倚春娇。", "索春饶。", "燕外莺边，想见万丝摇。", "便作无情终软美，天赋与，眼眉腰。", "短长亭外短长桥。", "驻金镳。", "系兰桡。", "可爱风流，年纪可怜宵。", "辨得重来攀折后，烟雨暗，不辞遥。"]'),
('song-ci-188','渔家傲','谭宣子','宋','宋词','song-ci','渔家傲','[]','深意缠绵歌宛转。',72,'宋词/ci.song.17000.json','["深意缠绵歌宛转。", "横波停眼灯前见。", "最忆来时门半掩。", "春不暖。", "犁花落尽成秋苑。", "叠鼓收声帆影乱。", "燕飞又趁东风软。", "目力漫长心力短。", "消息断。", "青山一点和烟远。"]'),
('song-ci-189','南乡子','薛燧','宋','宋词','song-ci','南乡子','[]','柳色锁重楼。',66,'宋词/ci.song.17000.json','["柳色锁重楼。", "楼上轻寒不满钩。", "堆径落红深半指，悠悠。", "飞絮帘栊几许愁。", "逐日望归舟。", "暖藕全宽玉臂韝。", "待得君来春去也，休休。", "未老鸳鸯早白头。"]'),
('song-ci-190','伊州三台令・伊州三台','杨韶父','宋','宋词','song-ci','伊州三台令・伊州三台','[]','水村月淡云低。',58,'宋词/ci.song.17000.json','["水村月淡云低。", "为爱寒香晚吹。", "瘦马立多时。", "是谁家、茅舍竹篱。", "三三两两芳蕤。", "未放琼铺雪堆。", "只这一些儿。", "胜东风、千枝万枝。"]'),
('song-ci-191','如梦令','杨韶父','宋','宋词','song-ci','如梦令','[]','凉月薄阴犹殢。',40,'宋词/ci.song.17000.json','["凉月薄阴犹殢。", "红豆一枝秋思。", "门外几重山，山外行人千里。", "归未。", "归未。", "又是菊花天气。"]'),
('song-ci-192','长相思','杨韶父','宋','宋词','song-ci','长相思','[]','溪水清。',44,'宋词/ci.song.17000.json','["溪水清。", "溪水浑。", "溪上人家数亩园。", "垂杨深闭门。", "青罗裙。", "白罗裙。", "采尽青蘩到白苹。", "江南三月春。"]'),
('song-ci-193','玉漏迟','史深','宋','宋词','song-ci','玉漏迟','[]','绿树深庭院。',114,'宋词/ci.song.17000.json','["绿树深庭院。", "侵帘暝草，沿砌幽藓。", "问讯馀芳，糁迳碎红千点。", "暗有芹香坠几，认杏栋、营巢新燕。", "晴思软。", "春光几许，费人裁翦。", "梅阴地湿无尘，但密袖薰虬，静看诗卷。", "半掬羁心，似翠蕉难展。", "花事因循过了，渐愁人、薰风团扇。", "屏昼掩。", "屏上数峰青远。"]'),
('song-ci-194','木兰花慢','史深','宋','宋词','song-ci','木兰花慢','[]','画楼帘半卷，倩谁觅、凤箫音。',123,'宋词/ci.song.17000.json','["画楼帘半卷，倩谁觅、凤箫音。", "记待月梅边，笼香酒后，私语屏阴。", "忽忽佩珠暗解，断归鸿、消息两沉沉。", "前度刘郎易老，旧时飞燕难寻。", "罗襟。", "薄有泪痕侵。", "钗股暗黄金。", "向宝奁密看，绫笺小字，长是惊心。", "登临漫劳眺远，但青山、杳隔暮云深。", "曾傍湾桥系马，紫骝嘶度平林。"]'),
('song-ci-195','花心动','史深','宋','宋词','song-ci','花心动','[]','肌雪浮香，见梅花清姿，漫劳凝伫。',127,'宋词/ci.song.17000.json','["肌雪浮香，见梅花清姿，漫劳凝伫。", "淡粉最娇，羞把春□，长记寿阳眉妩。", "绿苔深迳寻幽地，谁相伴、凌波微步。", "翠鸳冷，芳尘路杳，旧游何处。", "不信重城间阻。", "终没个因由，寄声传语。", "宝炬凝珠，彩笔呵冰，密写断肠新句。", "月寒烟瞑孤山下，羞吟□、断桥边去。", "遮愁绪。", "丹青怎生画取。"]'),
('song-ci-196','齐天乐','丁默','宋','宋词','song-ci','齐天乐','[]','两株烟柳荒城外，依依暮帆曾驻。',123,'宋词/ci.song.17000.json','["两株烟柳荒城外，依依暮帆曾驻。", "小扇障尘，轻舆贴岸，谁料重行吟处。", "流光暗度。", "怅兰溆春移，苇汀秋聚。", "可奈清愁，快呼艇子载将去。", "中年怀抱易感，甚风花水叶，犹似孤旅。", "伴鹤幽期，随莺乐事，还是情乖意负。", "衣尘帽土。", "但杜镜堪羞，贺囊偏□。", "待报山灵，莫教云壑妒。"]'),
('song-ci-197','华胥引','丁默','宋','宋词','song-ci','华胥引','[]','论交眉语，惜别心啼，费情不少。',105,'宋词/ci.song.17000.json','["论交眉语，惜别心啼，费情不少。", "蕙渺溱期，苹深汜约轻误了。", "几度金铸相思，又燕归鸿杳。", "谁料如今，被莺闲占春草。", "频把愁勾，惜鸦云、娇红犹绕。", "浑拚如梦，争奈枕酲屏晓。", "欲寄芙蓉香半握，怕不禁秋恼。", "重是亲逢，片帆双度天杪。"]'),
('song-ci-198','齐天乐','丁默','宋','宋词','song-ci','齐天乐','[]','倦云休雨风还作，交相醒花苏柳。',123,'宋词/ci.song.17000.json','["倦云休雨风还作，交相醒花苏柳。", "字满吟灰，痕添坐席，赢得新愁痴守。", "归期未有。", "负小院移兰，故园尝韭。", "谩道春来，沉腰惟觉似秋瘦。", "烧灯时候是也，楚津留野艇，曾趁芳友。", "问月赊晴，凭春买夜，明月添香解酒。", "□知别久。", "怅帝陌论心，客尘侵首。", "戏鼓声中，旧情犹在否。"]'),
('song-ci-199','浣溪沙','曾栋','宋','宋词','song-ci','浣溪沙','[]','落日蒸红山欲烧。',48,'宋词/ci.song.17000.json','["落日蒸红山欲烧。", "短筇行药过山腰。", "松声隐隐晚来潮。", "矮树依严无败叶，梅花当路少全梢。", "水村时有短长桥。"]'),
('song-ci-200','过秦楼','曾栋','宋','宋词','song-ci','过秦楼','[]','曙色开晴，轻飔敷暖，日影才经檐角。',135,'宋词/ci.song.17000.json','["曙色开晴，轻飔敷暖，日影才经檐角。", "倦来芳径，且倚阑干，独地新愁粘著。", "长日如年，可堪恨雨丝丝，梦云漠漠。", "见鸣禽递响，乳莺梳翅，痴愁方觉。", "凝望处，初绿呈新，陈柯拆旧，忘了一春归却。", "不伤花老，只怕花开，解使朱颜销铄。", "宝扇轻摇，乱抛花片教飞，迎风低掠。", "忍重携素手，骤觉一分瘦落。"]'),
('song-ci-201','玉楼春','江开','宋','宋词','song-ci','玉楼春','[]','风前帘幕沾飞絮。',64,'宋词/ci.song.17000.json','["风前帘幕沾飞絮。", "家在垂杨深处住。", "倚楼无语忆郎时，恰是去年今日去。", "帝城箫鼓青春暮。", "应有多情游治处。", "争知日日小阑干，望断斜阳芳草路。"]'),
('song-ci-202','菩萨蛮','江开','宋','宋词','song-ci','菩萨蛮','[]','春时江上廉纤雨。',52,'宋词/ci.song.17000.json','["春时江上廉纤雨。", "张帆打鼓开船去。", "秋晚恰归来。", "看看船又开。", "嫁郎如未嫁。", "长是凄凉夜。", "情少利心多。", "郎如年少何。"]'),
('song-ci-203','浣溪沙','江开','宋','宋词','song-ci','浣溪沙','[]','手拈花枝忆小苹。',48,'宋词/ci.song.17000.json','["手拈花枝忆小苹。", "绿窗空锁旧时春。", "满楼飞絮一筝尘。", "素约未传双燕语，离愁还入卖花声。", "十分春事倩行云。"]'),
('song-ci-204','杏花天','江开','宋','宋词','song-ci','杏花天','[]','谢娘庭院通芳径。',65,'宋词/ci.song.17000.json','["谢娘庭院通芳径。", "四无人、花梢转影。", "几番心事无凭准。", "等得青春过尽。", "秋千下、佳期又近。", "算毕竟、沉吟未稳。", "不成又是教人恨。", "待倩杨花去问。"]'),
('song-ci-205','鹧鸪天','戴平之','宋','宋词','song-ci','鹧鸪天','[]','笑擘黄柑酒半醒。',64,'宋词/ci.song.17000.json','["笑擘黄柑酒半醒。", "玉壶金斗夜生冰。", "开窗尽见千山雪，雪未消时月正明。", "兰烬短，麝煤轻。", "画楼钟鼓已三更。", "倚兰谁唱清真曲，人与梅花一样清。"]'),
('song-ci-206','汉宫春','王□□','宋','宋词','song-ci','汉宫春','[]','手拈黄花，对西风无语，双鬓萧萧。',118,'宋词/ci.song.17000.json','["手拈黄花，对西风无语，双鬓萧萧。", "韶华暗中过眼，零落心交。", "登临把酒，更谁伴、破橘持螯。", "惟只有，湖边鸥鹭，飞来如受人招。", "往事不禁重省，料绾罗分钿，翠减香销。", "空向画桥古树，犹系轻桡。", "西兴渡口，误归帆、几信寒潮。", "伤情处，淡烟残照，倚兰人共秋高。"]'),
('song-ci-207','念奴娇','程武','宋','宋词','song-ci','念奴娇','[]','蜀江城远，想连云危栈，接天穷处。',120,'宋词/ci.song.17000.json','["蜀江城远，想连云危栈，接天穷处。", "惆怅烟尘回首地，双阙觚棱犹故。", "龙扈星联，羽林风肃，未放鸾駣去。", "不堪掩面，泪沾宸袖如雨。", "底事当日昭阳，吹羌鸣羯，涴却霓裳舞。", "三十六宫春满眼，曾把色嗔香妒。", "芳草埋情，飞花陨怨，翻被蛾眉误。", "画图惊见，黯然魂断今古。"]'),
('song-ci-208','清平乐','程武','宋','宋词','song-ci','清平乐','[]','曳云摇玉。',54,'宋词/ci.song.17000.json','["曳云摇玉。", "裙蹙秋绡幅。", "学得琵琶依约熟。", "贪按雁沙新曲。", "曲终满院春闲。", "清颦移上眉山。", "心事怕人猜破，折花背插云环。"]'),
('song-ci-209','小重山','程武','宋','宋词','song-ci','小重山','[]','香减鲛绡添泪痕。',70,'宋词/ci.song.17000.json','["香减鲛绡添泪痕。", "彩云长是恨，等闲心。", "玉笙犹记夜深闻。", "湘水杳，寂寞隔巫云。", "翠被冷重熏。", "做成归梦了，却销魂。", "垂杨浓处著朱门。", "依然是，风雨掩黄昏。"]'),
('song-ci-210','齐天乐','王月山','宋','宋词','song-ci','齐天乐','[]','夜来疏雨鸣金井，一叶舞空红浅。',123,'宋词/ci.song.17000.json','["夜来疏雨鸣金井，一叶舞空红浅。", "莲渚收香，兰皋浮爽，凉思顿欺班扇。", "秋光苒苒。", "任老却芦花，西风不管。", "清兴难磨，几回有句到诗卷。", "长安故人别后，料征鸿声里，画阑凭遍。", "横竹吹商，疏砧点月，好梦又随云远。", "闲愁似线。", "甚系损柔肠，不堪裁翦。", "听著鸣蛩，一声声是怨。"]'),
('song-ci-211','踏莎行','王万之','宋','宋词','song-ci','踏莎行','[]','柳外寒轻，水边亭小。',68,'宋词/ci.song.17000.json','["柳外寒轻，水边亭小。", "昨朝燕子归来了。", "天涯无数旧愁根，东风种得成芳草。", "亭畔秋千，当时欢笑。", "香肌不满和衣抱。", "那堪别后更思量，春来瘦得知多少。"]'),
('song-ci-212','踏莎行','钱宀孙','宋','宋词','song-ci','踏莎行','[]','征雁云深，乱蛩寒浅。',68,'宋词/ci.song.17000.json','["征雁云深，乱蛩寒浅。", "惊心怕见年华晚。", "萧疏堤柳不禁霜，江梅瘦影清相伴。", "舞暗香茵，歌阑团扇。", "月明梦绕天涯远。", "断肠人在画楼中，东风不放珠帘卷。"]'),
('song-ci-213','踏莎行','陈璧','宋','宋词','song-ci','踏莎行','[]','江阔天低，楼高思迥。',68,'宋词/ci.song.17000.json','["江阔天低，楼高思迥。", "春烟蘸淡如秋景。", "今年芳草去年愁，分明又报明年信。", "燕子还来，归期未定。", "可堪醉梦红尘境。", "世间万事尽消磨，水流不尽青山影。"]'),
('song-ci-214','多丽','赵时奚','宋','宋词','song-ci','多丽','[]','敛吴云，翠奁推上红晴。',173,'宋词/ci.song.17000.json','["敛吴云，翠奁推上红晴。", "渺澄流、鳞光寒碎，远峰螺绀低凝。", "杏香引、画船影湿，柳阴趁、骄马蹄轻。", "桥限宽平，堤横南北，去来人入绣围行。", "渐际晚，梅妆游困，十里曳歌声。", "苍烟润，飞鸦妒春，一梦催醒。", "认名园、当时宴幸，缆痕犹在危亭。", "露花浓、静迎直砌，雾藓冷、淡护飞甍。", "几对东风，留连丽景，年□□老越山青。", "夜深月、照人依旧，何处最关情。", "欢娱地，星移世换，客恨还盈。"]'),
('song-ci-215','汉宫春','赵时奚','宋','宋词','song-ci','汉宫春','[]','霜皎千林，正石桥人静，春满横塘。',118,'宋词/ci.song.17000.json','["霜皎千林，正石桥人静，春满横塘。", "寒花自开自落，晓色昏黄。", "明沙暗草，对东风、深锁闲堂。", "金漏短，江南路远，梦回云冷潇湘。", "重到旧时花下，按玉笙歌彻，月正西廊。", "亭亭爱伊素影，粉薄新妆。", "经年瘦损，漫谁知、心事凄凉。", "休更听，城头画角，一声声断人肠。"]'),
('song-ci-216','恋绣衾','赵时奚','宋','宋词','song-ci','恋绣衾','[]','迢迢江路日又曛。',68,'宋词/ci.song.17000.json','["迢迢江路日又曛。", "为春迟、长是怨春。", "小立马、千林下，寄寒香、归赠故人。", "相逢细说经年恨，早忽忽、吹散霁云。", "算惆怅、芳菲事，粉蝶知、应自魂断。"]'),
('song-ci-217','恋绣衾','赵时奚','宋','宋词','song-ci','恋绣衾','[]','江南烟水几万重。',68,'宋词/ci.song.17000.json','["江南烟水几万重。", "记玉人、花底旧容。", "待欲寄、飞鸿信，望前山、夕照冷红。", "塞笳月下声凄楚，怨百花、春事梦空。", "倩谁共、东君说，把阳和、分付朔风。"]'),
('song-ci-218','祝英台近','向希尹','宋','宋词','song-ci','祝英台近','[]','晓帘栊，晴院宇，空鸭冷沉水。',95,'宋词/ci.song.17000.json','["晓帘栊，晴院宇，空鸭冷沉水。", "翠被欺寒，娇困未忺起。", "厌厌两点眉峰，一痕酒晕，正人在、温柔乡里。", "甚情味。", "羞对钗燕筝鸿，胭脂暗弹泪。", "欲写吴笺，无处问双鲤。", "倩他轻薄杨花，与愁结伴，直吹到，那人根底。"]'),
('song-ci-219','浪淘沙','向希尹','宋','宋词','song-ci','浪淘沙','[]','结客去登楼。',64,'宋词/ci.song.17000.json','["结客去登楼。", "谁系兰舟。", "半稿清涨雨初收。", "把酒留春春不住，柳暗江头。", "老去怕闲愁。", "莫莫休休。", "晚来风恶下帘钩。", "试问落花随水去，还解西流。"]'),
('song-ci-220','渡江云','萧元之','宋','宋词','song-ci','渡江云','[]','流苏垂翠幰，高低一色，红紫等泥沙。',124,'宋词/ci.song.17000.json','["流苏垂翠幰，高低一色，红紫等泥沙。", "香山居士老，柳枝桃叶，飞梗属谁家。", "好音过耳，任啼鸟、怨入芳华。", "心情懒，笔床吟卷，醉墨戏翻鸦。", "堪嗟。", "雕弓快马，敕勒追踪，向夕阳坡下。", "休更忆，青丝络辔，红袖裁纱。", "司空见惯浑如梦。", "笑几回、索苇吹葭。", "山中乐，从渠恣赏莺花。"]'),
('song-ci-221','菩萨蛮','萧元之','宋','宋词','song-ci','菩萨蛮','[]','断红流水香难觅。',52,'宋词/ci.song.17000.json','["断红流水香难觅。", "行云一去无踪迹。", "杨柳漫遮阑。", "闲愁付远山。", "玉筝弹未了。", "倚柱人空老。", "青子摘来酸。", "酸心有几般。"]'),
('song-ci-222','水龙吟','萧元之','宋','宋词','song-ci','水龙吟','[]','人生何必求名，身闲便是名高处。',126,'宋词/ci.song.17000.json','["人生何必求名，身闲便是名高处。", "卧云衣袂，何因自染，修涂尘土。", "世路羊肠，人情狙赋，翻云覆雨。", "把从前旧梦，倚阑重省，休更错、添笺注。", "况是吾庐江上，也抵得、封侯千户。", "高眠闲听，邻舟渔唱，倚阑农语。", "休望当年，溪边俱载，隆中三顾。", "怕群鸥微觉，见人欲起，背人飞去。"]'),
('song-ci-223','小重山','陈成之','宋','宋词','song-ci','小重山','[]','恨入眉尖熨不开。',70,'宋词/ci.song.17000.json','["恨入眉尖熨不开。", "日高犹未肯，傍妆台。", "玉郎嘶骑不归来。", "梁间燕，犹自及时回。", "粉泪污香腮。", "纤腰成瘦损，有人猜。", "一春那识下香阶。", "春又去，花落满苍苔。"]'),
('song-ci-224','如梦令','王师锡','宋','宋词','song-ci','如梦令','[]','竹上一楼凤翠。',40,'宋词/ci.song.17000.json','["竹上一楼凤翠。", "竹下一渠春水。", "中有隐人居，破屋数间而已。", "无事。", "无事。", "静夜月明千里。"]'),
('song-ci-225','望江南・忆江南','赵时行','宋','宋词','song-ci','望江南・忆江南','[]','霜月湿，人睡矮篷秋。',32,'宋词/ci.song.17000.json','["霜月湿，人睡矮篷秋。", "惊觉夜深儿女梦，渔歌风起白苹洲。", "别岸又潮头。"]'),
('song-ci-226','菩萨蛮','郭□□','宋','宋词','song-ci','菩萨蛮','[]','卖饧天气箫声软。',52,'宋词/ci.song.17000.json','["卖饧天气箫声软。", "午院水沉烟未断。", "睡起补残眉。", "红绵入镜迟。", "霎时开笑靥。", "花上看双蝶。", "新月上帘钩。", "相思不断头。"]'),
('song-ci-227','浣溪沙','王大简','宋','宋词','song-ci','浣溪沙','[]','拂面凉生酒半醒。',48,'宋词/ci.song.17000.json','["拂面凉生酒半醒。", "廉纤小雨晚初晴。", "过云无定月亏盈。", "庭户不关春悄悄，阑干倚遍夜深深。", "几回风竹误人听。"]'),
('song-ci-228','更漏子','王大简','宋','宋词','song-ci','更漏子','[]','梦期疏，书约误。',58,'宋词/ci.song.17000.json','["梦期疏，书约误。", "肠断夜窗风雨。", "灯晕冷，漏声遥。", "酒消愁未消。", "想天涯，芳草碧。", "人与芳春俱客。", "凭杜宇，向江城。", "好啼三两声。"]'),
('song-ci-229','蓦山溪','刘菊房','宋','宋词','song-ci','蓦山溪','[]','醉魂离梦，捻合难成片。',102,'宋词/ci.song.17000.json','["醉魂离梦，捻合难成片。", "恶味怕黄昏，更西风，梧桐深院。", "蝉松翠妩，记那日相逢，情缱绻。", "语玲珑，人静凌波见。", "香云曾约，念阻题红怨。", "应是绿窗寒，也思郎、云衣谁换。", "郎今销黯，步楚竹江空，云缥缈，水弥茫，不抵相思半。"]'),
('song-ci-230','谒金门','杜龙沙','宋','宋词','song-ci','谒金门','[]','阶露重。',53,'宋词/ci.song.17000.json','["阶露重。", "浥透寻花双凤。", "天色晴明风不动。", "薄衫金络缝。", "午枕高云斜纵。", "一觉风流春梦。", "起看翻翻帘影弄。", "夕阳归燕共。"]'),
('song-ci-231','踏莎行','杜龙沙','宋','宋词','song-ci','踏莎行','[]','波暖芹汀，风香兰圃。',68,'宋词/ci.song.17000.json','["波暖芹汀，风香兰圃。", "清尘几点茸茸雨。", "画船丝竹载梁州，彩旗绳板欢游女。", "修禊初三，禁烟百五。", "年华恰到风流处。", "一生只当百回春，一回春到休轻负。"]'),
('song-ci-232','斗鸡回','杜龙沙','宋','宋词','song-ci','斗鸡回','[]','莺啼人起，花露真珠洒。',64,'宋词/ci.song.17000.json','["莺啼人起，花露真珠洒。", "白苎衫，青骢马。", "绣陌相将，斗鸡寒食下。", "回廊瞑色愔愔，应是待、归来也。", "月渐高，门犹亚。", "闷剔银缸，漏声初入夜。"]'),
('song-ci-233','雨淋铃','杜龙沙','宋','宋词','song-ci','雨淋铃','[]','窗影珑璁，画楼平晓，翳柳啼鸦。',125,'宋词/ci.song.17000.json','["窗影珑璁，画楼平晓，翳柳啼鸦。", "门巷渐有新烟，东风定、人扫桐花。", "峭寒斗减，看旅雁、争起蒹葭。", "溯断云，多少悲鸣，数行又下远汀沙。", "应是故园桃李谢。", "送清江、一曲阑干下。", "染翰为赋春羁，嗟双鬓、客舍成华。", "绣鞭绮陌，强携酒、来觅吴娃。", "听扇底、凄惋新声，醉里翻念家。"]'),
('song-ci-234','诉衷情','王苍','宋','宋词','song-ci','诉衷情','[]','补成团扇绣残工。',54,'宋词/ci.song.17000.json','["补成团扇绣残工。", "并蒂瑞芙蓉。", "花心欲就针折，赪玉唾残茸。", "寻断绪，怨西风。", "寂寥中。", "两般时候，旧月新霜，晓角昏钟。"]'),
('song-ci-235','阮郎归','宋德广','宋','宋词','song-ci','阮郎归','[]','好风吹月过楼西。',56,'宋词/ci.song.17000.json','["好风吹月过楼西。", "楼前人影稀。", "杜鹃啼断绿杨枝。", "行人知不知。", "红叶字，断肠诗。", "从今懒再题。", "后园零落淡胭脂。", "似君初去时。"]'),
('song-ci-236','谒金门','李好古2','宋','宋词','song-ci','谒金门','[]','花过雨。',53,'宋词/ci.song.17000.json','["花过雨。", "又是一番红素。", "燕子归来愁不语。", "旧巢无觅处。", "谁在玉关劳苦。", "谁在玉楼歌舞。", "若使胡尘吹得去。", "东风侯万户。"]'),
('song-ci-237','解连环','黄廷','宋','宋词','song-ci','解连环','[]','乍寒帘幕。',132,'宋词/ci.song.17000.json','["乍寒帘幕。", "愁灯花正结，又还轻落。", "弄瘦影、瓶里梅梢，为谁缀陇头，向来新萼。", "万古千今，算惟有、别情难托。", "把潘郎鬓绿，尽付雁声，几度寥寞。", "扁舟暮江旧泊。", "记携觞就折，烟翠犹弱。", "漫过却、歌夕吟朝，问天道何时，素纤重握。", "想得文姬，近更苦、云衣香薄。", "待更阑、试寻梦境，梦回更恶。"]'),
('song-ci-238','忆旧游','黄廷璹','宋','宋词','song-ci','忆旧游','[]','乍梅黄雨过，遍倚层楼，时舞垂阳。',124,'宋词/ci.song.17000.json','["乍梅黄雨过，遍倚层楼，时舞垂阳。", "暗绿知谁换，似烟浓雾薄，望眼偏妨。", "昔人画鹢无数，相引入横塘。", "纵细切香蒲，重开绛蕊，懒向清觞。", "凄凉。", "旧游地，谩赋减兰成，才退周郎。", "总把芳辰误，念纱窗深静，冰簟流光。", "凤笺试写新句，青羽碧天长。", "又隐隐城头，随风断角斜照黄。"]'),
('song-ci-239','宴清都','黄廷','宋','宋词','song-ci','宴清都','[]','坠叶窥檐语。',126,'宋词/ci.song.17000.json','["坠叶窥檐语。", "风帘薄，递来幽恨无数。", "牙签倦展，银缸细剔，悄然归旅。", "声传漏阁偏长，更奈向、潇潇乱雨。", "想近日，舞袖翻云，吟笺度雪谁愿。", "当时翠缕吹花，东城绣陌，双燕何许。", "香罗唾碧，晴纱印粉，甚缘重睹。", "蓝桥镇隔芳梦，念骑省、悲秋漫赋。", "待倚阑，或遇宾鸿，殷勤寄与。"]'),
('song-ci-240','兰陵王','黄廷','宋','宋词','song-ci','兰陵王','[]','絮花弱。',159,'宋词/ci.song.17000.json','["絮花弱。", "吹满斜阳院落。", "秋千外，无数小舟，绿水溶溶带城郭。", "流光漫暗觉。", "辜却。", "莺呼燕诺。", "欢游地，都在梦中，双蝶翩翩度帘幕。", "凭谁问康乐。", "又粉过新梢，红退残萼。", "阑干休倚东风恶。", "怜瑟韵空在，鉴容偷改，青青洲渚遍杜若。", "故交半廖寞。", "漂泊。", "镇如昨。", "念玉指频弹，珠泪还阁。", "孤灯隐隐巫云薄。", "奈别遽无语，恨深谁托。", "明朝何处，夜渐短，听画角。"]'),
('song-ci-241','琐窗寒','黄廷','宋','宋词','song-ci','琐窗寒','[]','驻马林塘，还寻旧迹，雨收秋晚。',122,'宋词/ci.song.17000.json','["驻马林塘，还寻旧迹，雨收秋晚。", "残蕉映牖，强把碧心偷展。", "记相逢、画堂宴开，乱花影入帘初卷。", "正小池涨绿，丝纶曾试，事随鸿远。", "凄断。", "情何限。", "料素扇尘深，怨娥碧浅。", "清宫丽羽，漫有苔笺题满。", "问低墙、双柳尚存，几时艳烛亲共剪。", "但凝眸，数点遥峰，春色青如染。"]'),
('song-ci-242','齐天乐','黄廷','宋','宋词','song-ci','齐天乐','[]','十年汉上东风梦，依然淡烟莺晓。',123,'宋词/ci.song.17000.json','["十年汉上东风梦，依然淡烟莺晓。", "系马桥空，维舟岸易，谁识当时苏小。", "筹花斗草。", "任波浴斜阳，絮迷芳岛。", "笑底歌边，黛娥娇聚怕归早。", "京尘衣袂易染，旧游随雾散，新恨难表。", "燕子朱扉，梨英翠箔，留得春光多少。", "晴丝漫绕。", "料带角香销，扇阴诗杳。", "细倚秋千，片云天共渺。"]'),
('song-ci-243','塞翁吟','陈坦之','宋','宋词','song-ci','塞翁吟','[]','远碧秋痕瘦，楚玉恨赋凄凉。',115,'宋词/ci.song.17000.json','["远碧秋痕瘦，楚玉恨赋凄凉。", "荷雨碎，泣残妆。", "系愁在垂阳。", "秋衣拂叠仙栀露，裁云刀尺犹香。", "诗锦字，献明珰。", "肯容易相忘。", "思量。", "空掩抑，分宵缓枕，终不敌、凉谯漏长。", "自解珮、兰皋去后，渐消灭、香梅酝藉，小杜疏狂。", "年华驶水，鬓影西风，都付清觞。"]'),
('song-ci-244','沁园春','陈坦之','宋','宋词','song-ci','沁园春','[]','睡起闻莺，卷帘微雨，黄昏递愁。',140,'宋词/ci.song.17000.json','["睡起闻莺，卷帘微雨，黄昏递愁。", "正青翰音断，离怀几摺，碧云暮合，千里双眸。", "思发花前，人归雁后，误记归帆天际舟。", "浑无据，但馀香绕梦，频到西楼。", "风流。", "翻是花讐。", "谩长遣眉山翠不流。", "想哀筝绕指，鸿移凤咽，残灯背泣，玉沁春柔。", "夜月精神，朝阳微艳，何处瑶台轻驻留。", "愁无际，被东风吹去，绿黯芳洲。"]'),
('song-ci-245','柳梢青','陈坦之','宋','宋词','song-ci','柳梢青','[]','绿弱红臞。',61,'宋词/ci.song.17000.json','["绿弱红臞。", "暖云沁雨，乍有还无。", "破晓幽禽，平渠流水，春响庭除。", "梅酸初著花跗。", "似滴滴、新愁未舒。", "几信花风，一痕青烧，万里秦吴。"]'),
('song-ci-246','谒金门','陈坦之','宋','宋词','song-ci','谒金门','[]','归未卜。',53,'宋词/ci.song.17000.json','["归未卜。", "频倒金彄纤玉。", "明月绡窗停剪烛。", "搦愁题蠹绿。", "秋水娟娟鱼目。", "腰素几分销缩。", "接得云笺无意读。", "雕鞍何处宿。"]'),
('song-ci-247','夜飞鹊・夜飞鹊慢','张艾','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','霓裳按歌地，凉影参差。',129,'宋词/ci.song.17000.json','["霓裳按歌地，凉影参差。", "还是佩解江湄。", "沧波正洗袜尘恨，流霞空沁铢衣。", "盈盈半输笑，向朱阑凝伫，欲诉心期。", "碧筒唤酒，恐娇娥、来下瑶池。", "未许西风吹断，环步障千重，镇护金猊。", "落晚文禽点镜，分香窃翠，却念幽羁。", "彩云惊散，暗伤情、不似芳时。", "待清歌招些，怜心问的，水杳舟移。"]'),
('song-ci-248','解语花','张艾','宋','宋词','song-ci','解语花','[]','轻雷殷殷，小枕惊回，帘影摇庭户。',124,'宋词/ci.song.17000.json','["轻雷殷殷，小枕惊回，帘影摇庭户。", "嫩凉遥度。", "江云堕、结作西窗暗雨。", "闲阶静伫。", "叹疏袂、愁宽一缕。", "凭画栏，润叶鸣条，总是安秋处。", "因唤扁舟晚渡。", "渐闻歌招得，采菱俦侣。", "临平归路。", "花无数、应识汀洲倦旅。", "飞红怨暮。", "长趁得、断鸿南浦。", "闲枕衾，谁更无聊，应最怜纨素。"]'),
('song-ci-249','绕佛阁','张艾','宋','宋词','song-ci','绕佛阁','[]','渚云弄湿，烟缕际晚，江国遥碧。',121,'宋词/ci.song.17000.json','["渚云弄湿，烟缕际晚，江国遥碧。", "鸿过无迹。", "怕闻野寺孤钟动凄恻。", "小桥路窄。", "疏袖暗拂衰草，愁听蛩语还寂。", "可堪过了，龟纱负瑶席。", "荏苒露华白。", "一夜秋窗惊晓色。", "柳影孤危，残蝉空抱叶。", "想摇落关情，归梦频折。", "物华消歇。", "尽倒断寒塘，幽香先灭。", "怨红供、拒霜啼颊。"]'),
('song-ci-250','真珠帘','徐□','宋','宋词','song-ci','真珠帘','[]','落红几阵清明雨。',123,'宋词/ci.song.17000.json','["落红几阵清明雨。", "忆花期、半被晴悭寒阻。", "新柳著春浓，早翠池波妒。", "粉雨香云消息远，漫旧日、秋千庭宇。", "凝伫。", "正春醒帘外，一声莺语。", "尘锁宝筝弦柱。", "自眉峰惹恨。", "六么慵舞。", "深院不成妆，有泪弹谁与。", "记得踏青归去后，细共说、花阴深处。", "心愫。", "怕当时飞燕，知人分付。"]'),
('song-ci-251','桂枝香','施翠岩','宋','宋词','song-ci','桂枝香','[]','西风满目。',124,'宋词/ci.song.17000.json','["西风满目。", "渐院落悄清，愁近银烛。", "多少虫书堕翠，又随波縠。", "姮娥半露扶疏影，向虚檐、似知幽独。", "浦鸿声断，枝乌漏永，芳梦难续。", "记旧日、离亭细嘱。", "早归趁香边，频泛醽醁。", "谁遣而今，对景黛娥双蹙。", "玉鞭但共秋光远，漫空怜、如许金粟。", "露零襟冷，萧萧更兼，数竿修竹。"]'),
('song-ci-252','沁园春','施翠岩','宋','宋词','song-ci','沁园春','["\u957f\u6c5f"]','披紫菟裘，上白鹭亭，看吹洞箫。',140,'宋词/ci.song.17000.json','["披紫菟裘，上白鹭亭，看吹洞箫。", "望长江庚鲸过，江横素练，回仙鹤度，月在青霄。", "依约淮山，清冷风露，如到瀛洲听海涛。", "浮图近，更玉铃金铎，初奏琅玕。", "人间梦境廖廖。", "问故国繁华能几朝。", "有千年枯井，龙沉凤怨，数邱黄壤，兔走猿嗥。", "莫问荣华，不如归去。", "短棹孤篷乘夜潮。", "翠岩下，耕白云二顷，胜种仙苗。"]'),
('song-ci-253','念奴娇','续雪谷','宋','宋词','song-ci','念奴娇','[]','砌红慵扫，问东风、应念西园廖落。',120,'宋词/ci.song.17000.json','["砌红慵扫，问东风、应念西园廖落。", "帘卷垂阳莺啭巧，才见还因飞却。", "拈指光阴，关心节序，总在秋千索。", "翻翻双蝶，傍人争趁行乐。", "曾记步月归来，秦筝弹遍，共倚阑干角。", "别后池亭谁斗草，多少芳游担阁。", "世事升沈，人生聚散，俯仰空如昨。", "馀香犹在，绣帏清晓寒薄。"]'),
('song-ci-254','南歌子','续雪谷','宋','宋词','song-ci','南歌子','[]','眼媚双波溜，腰柔一搦纤。',62,'宋词/ci.song.17000.json','["眼媚双波溜，腰柔一搦纤。", "问伊何事放珠帘。", "笑道篆香销尽、要重添。", "数日宽金钏，梳云拂翠奁。", "梅妆依旧落虚檐。", "题起一春心事、两眉尖。"]'),
('song-ci-255','长相思','续雪谷','宋','宋词','song-ci','长相思','[]','心悠悠。',44,'宋词/ci.song.17000.json','["心悠悠。", "恨悠悠。", "谁剪青山两点愁。", "笙寒燕子楼。", "晓星稀。", "暮云飞。", "织就回文不下楼。", "花飞人未归。"]'),
('song-ci-256','水调歌头','荣樵仲','宋','宋词','song-ci','水调歌头','[]','既难求富贵，何处没溪山。',114,'宋词/ci.song.17000.json','["既难求富贵，何处没溪山。", "不成天也，不容我去乐清闲。", "短褐宽裁疏葛，柱杖横拖瘦玉，著个竹皮冠。", "弄影碧霞里，长啸翠微间。", "醉时歌，狂时舞，困时眠。", "け然自得，了无一点俗相干。", "拟把清风明月，剪作长篇短阕，留与世人看。", "待倩月边女，归去借青鸾。"]'),
('song-ci-257','贺新凉・贺新郎','陆象泽','宋','宋词','song-ci','贺新凉・贺新郎','["\u5e90\u5c71"]','笛唤春风起。',142,'宋词/ci.song.17000.json','["笛唤春风起。", "向湖边、腊前折柳，问君何意。", "孤负梅花立晴昼，一舸凄凉雪底。", "但小阁、琴棋而已。", "佳客清明留不住，为匡庐、只在家窗里。", "湓浦去，两程耳。", "草堂旧日谈经地。", "更从容、南山北水，庾楼重倚。", "万卷心胸几千古，仰首骎骎紫气。", "正江上、风寒如此。", "且趁霜天鲈鱼好，把貂裘、换酒长安市。", "明夜去，月千里。"]'),
('song-ci-258','桂枝香','鞠华翁','宋','宋词','song-ci','桂枝香','[]','丁丁起处。',124,'宋词/ci.song.17000.json','["丁丁起处。", "在纵牧九京，经烧残树。", "时见鸟鸢饥噪，鸺鶹妖呼。", "数间老屋团荒堵。", "算何人、瓣香来注。", "淡烟斜照，闲花野棠，杳杳年度。", "世事几、番云覆雨，独此道嫌人，抛弃尘土。", "眼里长青，谁也解如山否。", "三三五五骑牛伴，望前村、吹笛归去。", "柳青梨白，春浓月淡，蹋歌椎鼓。"]'),
('song-ci-259','绮寮怨','鞠华翁','宋','宋词','song-ci','绮寮怨','[]','又见花阴如水，两心犹未平。',127,'宋词/ci.song.17000.json','["又见花阴如水，两心犹未平。", "正坐久、主客成三，空无语、影落秋枰。", "千年人间事业，垂成处、一著容易倾。", "便解围、小住何妨，机锋在，瞬息天又明。", "甚似汉吴对营。", "纷纷不了，孤光照彻连城。", "又似残星，向零落，有馀情。", "姮娥笑人迟暮，念才力、底须争。", "从亏又成。", "何人正听隔壁声。"]'),
('song-ci-260','贺新郎','曾晞颜','宋','宋词','song-ci','贺新郎','[]','富贵人间有。',142,'宋词/ci.song.17000.json','["富贵人间有。", "就如今，秤量阴德，还公最厚。", "一郡鹘崙全似旧，春满霜畴稻亩。", "近帐外、干将夜吼。", "直指禾川弄霆雷，从山阴、鹿健那能走。", "都算计，怎担负。", "单车曲曲穿岩窦。", "向迷途、分明一呼，散渠回首。", "夹路香花迎拜了，见说家家举酒。", "道公是、再生父母。", "活一口还添一岁，这一回、活几千千口。", "只此事，是公寿。"]'),
('song-ci-261','好事近','曾颜','宋','宋词','song-ci','好事近','[]','昨夜探寒梅，先报一阳消息。',53,'宋词/ci.song.17000.json','["昨夜探寒梅，先报一阳消息。", "天遣花神妆点，衬贤侯清白。", "试将玉蕊比修龄，算枝头千百。", "更有不凡风味，付调羹仙客。"]'),
('song-ci-262','谒金门','朱子厚','宋','宋词','song-ci','谒金门','[]','风动竹。',54,'宋词/ci.song.17000.json','["风动竹。", "清遍一窗梅溽。", "闻道小乔乘凤玉。", "仙裳飘雾縠。", "来嫁吾门公瑾叔。", "天上人间愿足。", "浓缭水沉燃宝烛。", "鬓长相对绿。"]'),
('song-ci-263','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','朝朝暮，云雨定何如。',32,'宋词/ci.song.17000.json','["朝朝暮，云雨定何如。", "花日穿窗梅小小，雪风洒雨柳疏疏。", "人唱晚晴初。"]'),
('song-ci-264','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','春悄悄，春雨不须晴。',32,'宋词/ci.song.17000.json','["春悄悄，春雨不须晴。", "天上未知灯有禁，人间转似月无情。", "村市学箫声。"]'),
('song-ci-265','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','梧桐子，看到月西楼。',32,'宋词/ci.song.17000.json','["梧桐子，看到月西楼。", "醋酽橙黄分蟹壳，麝香荷叶剥鸡头。", "人在御街游。"]'),
('song-ci-266','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','梧桐子，人在御街游。',32,'宋词/ci.song.17000.json','["梧桐子，人在御街游。", "凤宿云绡金缕带，龙池翠帐玉香球。", "宫女后庭秋。"]'),
('song-ci-267','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','长欲语，欲语又蹉跎。',64,'宋词/ci.song.17000.json','["长欲语，欲语又蹉跎。", "已是厌听夷甫颂，不堪重省越人歌。", "孤负水云多。", "羞拂拂，懊恼自摩挲。", "残烛不教人径去，断云时有泪相和。", "恨恨欲如何。"]'),
('song-ci-268','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','前之夕，织女渡河边。',64,'宋词/ci.song.17000.json','["前之夕，织女渡河边。", "天上一朝元五日，人间小住亦千年。", "相合降神仙。", "当富贵，掩鼻正高眠。", "欲语会稽仍小待，不知文举更堪怜。", "蔗境在顽坚。"]'),
('song-ci-269','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','添一岁，减一岁愁眉。',64,'宋词/ci.song.17000.json','["添一岁，减一岁愁眉。", "若待一生昏嫁了，更须采药十年迟。", "昏嫁已随时。", "东家者，俎豆伴儿嬉。", "幸自少年场屋了，谁能匊淅数还炊。", "千岁是灵龟。"]'),
('song-ci-270','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','盘之所，春蝶舞晴暄。',64,'宋词/ci.song.17000.json','["盘之所，春蝶舞晴暄。", "溪傍野梅根种玉，墙围修竹笋生鞭。", "深院待回仙。", "嘉熙好，四十二年前。", "犹记五星丁卯聚，更迟几岁甲申连。", "快活共千年。"]'),
('song-ci-271','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','齐眉举，彩侍紫霞卮。',64,'宋词/ci.song.17000.json','["齐眉举，彩侍紫霞卮。", "天上九朝凫冉冉，尊前一笑玉差差。", "人唱自家词。", "篱下菊，醉把一枝枝。", "花水乞君三十斛，秋风记我一联诗。", "留看晚香时。"]'),
('song-ci-272','望江南・忆江南','刘辰翁','宋','宋词','song-ci','望江南・忆江南','[]','七日后，重会是星前。',64,'宋词/ci.song.17000.json','["七日后，重会是星前。", "二月之间浑似此，馀年何止万三千。", "日拟醉华筵。", "歌白雪，除是雪儿传。", "看取长生瓢屡倒，眼前橘粟术何玄。", "自唱鹊桥仙。"]'),
('song-ci-273','南乡子','刘辰翁','宋','宋词','song-ci','南乡子','[]','宽处略从容。',66,'宋词/ci.song.17000.json','["宽处略从容。", "华水华山自不同。", "旧日诸贤携手恨，匆匆。", "只说明年甚处重。", "几岁避辽东。", "茅竹秋风一并空。", "欲望辽东何处是，濛濛。", "也似秦楼一梦中。"]'),
('song-ci-274','南乡子','刘辰翁','宋','宋词','song-ci','南乡子','[]','香雪碎团团。',66,'宋词/ci.song.17000.json','["香雪碎团团。", "便合枝头带露餐。", "笑倒那人和玉屑，金丹。", "不在仙人掌上盘。", "千树碧阑干。", "山崦朱门梦里残。", "花下主人都在此，谁看。", "天上人间一样寒。"]'),
('song-ci-275','南乡子','刘辰翁','宋','宋词','song-ci','南乡子','[]','去似赏花移。',66,'宋词/ci.song.17000.json','["去似赏花移。", "处处开尊亦不辞。", "梨栗又空醅又尽，方知。", "旧日骊驹劝客归。", "归路月相随。", "儿子门生个个迟。", "坐久不知无可待，堪疑。", "向道儿痴直是痴。"]'),
('song-ci-276','浪淘沙','刘辰翁','宋','宋词','song-ci','浪淘沙','[]','无叶著秋声。',64,'宋词/ci.song.17000.json','["无叶著秋声。", "凉鬓堪惊。", "满城明月半窗横。", "惟有老人心似醉，未晓偏醒。", "起舞故无成。", "此恨难平。", "正襟危坐二三更。", "除却故人曹孟德，更与谁争。"]'),
('song-ci-277','浪淘沙','刘辰翁','宋','宋词','song-ci','浪淘沙','[]','卷海海翻杯。',64,'宋词/ci.song.17000.json','["卷海海翻杯。", "倾动蓬莱。", "似嫌到处马头埃。", "雨洗御街流到我，吹向潮回。", "寒似雪天梅。", "安石榴开。", "绣衾重暖笑炉灰。", "料想东风还忆我，昨夜归来。"]'),
('song-ci-278','浪淘沙','刘辰翁','宋','宋词','song-ci','浪淘沙','[]','无谓两眉攒。',64,'宋词/ci.song.17000.json','["无谓两眉攒。", "风雨春寒。", "池塘小小水漫漫。", "只为柳花无一点，忘了临安。", "何许牡丹残。", "客倚屏看。", "小楼面面是春山。", "日暮不知春去路，一带阑干。"]'),
('song-ci-279','如梦令','刘辰翁','宋','宋词','song-ci','如梦令','[]','比似寻芳娇困。',40,'宋词/ci.song.17000.json','["比似寻芳娇困。", "不是弓弯拍衮。", "无物倚春慵，三寸袜痕新紧。", "羞褪。", "羞褪。", "忽忽心情未稳。"]'),
('song-ci-280','如梦令','刘辰翁','宋','宋词','song-ci','如梦令','[]','寂历柳风斜倚。',40,'宋词/ci.song.17000.json','["寂历柳风斜倚。", "错莫梦云难记。", "花影为谁重，一握鲛人丝泪。", "何事。", "何事。", "历历脸潮羞起。"]'),
('song-ci-281','如梦令','刘辰翁','宋','宋词','song-ci','如梦令','[]','睡眼青阴欲午。',40,'宋词/ci.song.17000.json','["睡眼青阴欲午。", "当户小风轻暑。", "倦近碧阑干，斜影却扶人去。", "无绪。", "无绪。", "落落一襟轻举。"]'),
('song-ci-282','如梦令','刘辰翁','宋','宋词','song-ci','如梦令','[]','落叶西风满地。',40,'宋词/ci.song.17000.json','["落叶西风满地。", "独宿琼楼丹桂。", "孤影抱蟾寒，寄与月明千里。", "休寄。", "休寄。", "粟粟蕊珠心碎。"]'),
('song-ci-283','江城子','刘辰翁','宋','宋词','song-ci','江城子','[]','涌金门外上船场。',86,'宋词/ci.song.17000.json','["涌金门外上船场。", "湖山堂。", "众贤堂。", "到几凄凉，城角夜吹霜。", "谁识两峰相对语，天惨惨，水茫茫。", "月移疏影傍人墙。", "怕昏黄。", "又昏黄。", "旧日朱门，四圣暗飘香。", "驿使不来春又老，南共北，断人肠。"]'),
('song-ci-284','江城子','刘辰翁','宋','宋词','song-ci','江城子','[]','一年春事几何空。',86,'宋词/ci.song.17000.json','["一年春事几何空。", "杏花红。", "海棠红。", "看取枝头，无语怨天公。", "幸自一晴晴太暖，三日雨，五更风。", "山中长自忆城中。", "到城中。", "望水东。", "说尽闲情，无日不忽忽。", "昨日也同花下饮，终有恨，不曾浓。"]'),
('song-ci-285','江城子','刘辰翁','宋','宋词','song-ci','江城子','["\u6d1e\u5ead\u6e56"]','书题拂拂洞庭香。',86,'宋词/ci.song.17000.json','["书题拂拂洞庭香。", "孕云黄。", "粲珠光。", "唤谪仙人，除是贺知章。", "未老得闲闲到老，无一事，和诗忙。", "是中曾著老人双。", "送千觞。", "乐谁妨。", "世上输赢，不似烂柯长。", "晚入耆英年最少，空结客，少年场。"]'),
('song-ci-286','江城子','刘辰翁','宋','宋词','song-ci','江城子','[]','红敧醉袖殢阑干。',86,'宋词/ci.song.17000.json','["红敧醉袖殢阑干。", "夜将阑。", "去难拚。", "烧蜜调蜂，重照锦团栾。", "春到洞房深处暖，方知道，月宫寒。", "枝枝红泪不曾乾。", "背人弹。", "语羞檀。", "欲睡心情，一似梦惊残。", "正自朦胧花下好，银烛里，几人看。"]'),
('song-ci-287','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','小阁横窗，倩谁画得梅梢远。',50,'宋词/ci.song.17000.json','["小阁横窗，倩谁画得梅梢远。", "那回半面。", "曾向屏间见。", "风雪空山，怀抱无荀倩。", "春堪恋。", "自羞片片。", "更逐东风转。"]'),
('song-ci-288','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','一雪蹉跎，蹇驴不载吟鞭去。',50,'宋词/ci.song.17000.json','["一雪蹉跎，蹇驴不载吟鞭去。", "夜听春雨。", "踏雪差无苦。", "待得花晴，总是游人处。", "梅应许。", "小桥延伫。", "蜂蝶先成路。"]'),
('song-ci-289','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','醉里瞢腾，昨宵不记归时候。',50,'宋词/ci.song.17000.json','["醉里瞢腾，昨宵不记归时候。", "自疑中酒。", "耿耿还依旧。", "恨不能言，只是天相负。", "天知否。", "卷中人瘦。", "一似章台柳。"]'),
('song-ci-290','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','燕子池塘，乱红过尽秋千晚。',50,'宋词/ci.song.17000.json','["燕子池塘，乱红过尽秋千晚。", "絮飞欲倦。", "正是帘初卷。", "睡起无情，犹道天涯远。", "羞匀面。", "乍惊红浅。", "梦自无人见。"]'),
('song-ci-291','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','韝指春寒，陇禽一片飞来雪。',50,'宋词/ci.song.17000.json','["韝指春寒，陇禽一片飞来雪。", "无言可说。", "暗啄相思结。", "双影年深，也作关山别。", "翻成拙。", "落花时节。", "倩子规声绝。"]'),
('song-ci-292','点绛唇','刘辰翁','宋','宋词','song-ci','点绛唇','[]','虹玉横箫，纤纤指按新声作。',50,'宋词/ci.song.17000.json','["虹玉横箫，纤纤指按新声作。", "参差重约。", "昨夜梁伊错。", "几许闲愁，品字都忘却。", "沉吟觉。", "一声哀角。", "满院残花落。"]'),
('song-ci-293','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','高卧何须说打乖。',48,'宋词/ci.song.17000.json','["高卧何须说打乖。", "小篱过雨翠长街。", "缃桃定有踏青鞋。", "晴日又思花处所，东风绝似柳情怀。", "人间安得酒如淮。"]'),
('song-ci-294','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','身是去年人尚健。',48,'宋词/ci.song.17000.json','["身是去年人尚健。", "心知十日事如常。", "眼前杯酒是重阳。", "破帽簪萸携素手，长歌藉草慰寒香。", "儿童怪我老来狂。"]'),
('song-ci-295','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','春日春风掠鬓须。',48,'宋词/ci.song.17000.json','["春日春风掠鬓须。", "乱山相对拥寒炉。", "彩鞭金胜一时无。", "自缕青丝成细柳，更堆残雪当凝酥。", "儿童且莫唱皇都。"]'),
('song-ci-296','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','身是高人欲寝冰。',48,'宋词/ci.song.17000.json','["身是高人欲寝冰。", "引年可待进豨苓。", "无忧无患也身轻。", "雪里放囚天亦喜，平安骑鹤到家庭。", "今年春早为长生。"]'),
('song-ci-297','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','十日千机可复谐。',48,'宋词/ci.song.17000.json','["十日千机可复谐。", "郭郎感运岂仙才。", "人间自是少行媒。", "直上扶摇须九万，满前星斗共昭回。", "又传贾客向曾来。"]'),
('song-ci-298','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','暮暮相望夕甫谐。',48,'宋词/ci.song.17000.json','["暮暮相望夕甫谐。", "针楼巧巧似身材。", "下头无数老人媒。", "昨夜竹林那得见，朝来乾鹊是空回。", "人间五日后能来。"]'),
('song-ci-299','摊破浣溪沙・山花子','刘辰翁','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','醉里微寒著面醒。',56,'宋词/ci.song.17000.json','["醉里微寒著面醒。", "天风不展帽敧倾。", "行过溪深松雪下，夜三更。", "白白野田铺似月，瑽瑽沙路踏如冰。", "不见剡溪三百曲，一舟横。"]'),
('song-ci-300','摊破浣溪沙・山花子','刘辰翁','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','澹澹胭脂浅著梅。',56,'宋词/ci.song.17000.json','["澹澹胭脂浅著梅。", "温柔不上避风台。", "若比杏桃真未识，夺银胎。", "汗面试来慵传粉，酒香浓后暗潮腮。", "娇嫩不应醒似醉，倩谁猜。"]'),
('song-ci-301','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','柳梢欲雪。',53,'宋词/ci.song.17000.json','["柳梢欲雪。", "十里烟明灭。", "曲曲阑干转影，教人忆、夜来月。", "家人相对说。", "灯花还又结。", "冻雨村村□鼓，终不似、上元节。"]'),
('song-ci-302','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','乌云汗漫。',53,'宋词/ci.song.17000.json','["乌云汗漫。", "浊浪翻河汉。", "过尽千重魔障，堂堂地、一轮满。", "秋光还又半。", "檐声初漏断。", "不管满身花露，已办著、二更看。"]'),
('song-ci-303','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','骑台千骑。',53,'宋词/ci.song.17000.json','["骑台千骑。", "有菊知何世。", "想见登高无处，淮以北、是平地。", "老来无复味。", "老来无复泪。", "多谢白衣迢递，吾病矣、不能醉。"]'),
('song-ci-304','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','经年寂寞。',53,'宋词/ci.song.17000.json','["经年寂寞。", "已负花前约。", "忽向红梅侧畔，开点雪、有人觉。", "不开何似莫。", "百梢才一萼。", "欲问寿阳宫额，两三蕊、怎能著。"]'),
('song-ci-305','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','臞然如竹。',53,'宋词/ci.song.17000.json','["臞然如竹。", "自是天仙福。", "小小画堂锦样，听人唱、鹤飞曲。", "橙橘黄又绿。", "蟹到新篘熟。", "便做月三十斛，饮不尽、菊潭菊。"]'),
('song-ci-306','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','朝来微雪。',53,'宋词/ci.song.17000.json','["朝来微雪。", "又近长生节。", "造就一枝清绝，梅与雪、怎分别。", "两年心似月。", "除是天知得。", "手种春风千树，一颗颗、待儿摘。"]'),
('song-ci-307','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','明年七十。',53,'宋词/ci.song.17000.json','["明年七十。", "歌彩桥仙夕。", "见说严君平道，年年是、月初一。", "同时同里密。", "后今今又昔。", "便做伏生年纪，也未到、蹇吃吃。"]'),
('song-ci-308','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','良宵七七。',53,'宋词/ci.song.17000.json','["良宵七七。", "又近中元日。", "桥上老人有约，后五日、重来觅。", "婵娟银海出。", "木犀新雨湿。", "惟有延平剑气，箕斗外、广寒逼。"]'),
('song-ci-309','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','["\u5e90\u5c71"]','归来把菊。',53,'宋词/ci.song.17000.json','["归来把菊。", "春瓮今朝熟。", "苦苦留君不得，携孺子、到汾曲。", "庐山真面目。", "冰清还映玉。", "长笑欧公老懒，君且住，饮螺绿。"]'),
('song-ci-310','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','问春来未。',53,'宋词/ci.song.17000.json','["问春来未。", "也似辛壬癸。", "如此男儿五十，又过却、孔融二。", "画堂孙子子。", "新桃如故垒。", "不管明朝后日，春满眼、是千岁。"]'),
('song-ci-311','霜天晓角','刘辰翁','宋','宋词','song-ci','霜天晓角','[]','□□□□。',53,'宋词/ci.song.17000.json','["□□□□。", "□□□□□。", "□□□□□□，□□□、□□□。", "治中心似佛。", "治中心似日。", "人祝治中千岁，似翁福、似翁德。"]'),
('song-ci-312','卜算子','刘辰翁','宋','宋词','song-ci','卜算子','[]','不是重看灯，重见河边女。',52,'宋词/ci.song.17000.json','["不是重看灯，重见河边女。", "长是蛾儿作队行，路转风吹去。", "十载废元宵，满耳番腔鼓。", "欲识尊前太守谁，起向尊前舞。"]'),
('song-ci-313','卜算子','刘辰翁','宋','宋词','song-ci','卜算子','[]','早已是三年，父老依依借。',52,'宋词/ci.song.17000.json','["早已是三年，父老依依借。", "顾与天公借几年，保我鸡豚社。", "□□□□□，□□□□□。", "□□□□□□□，□□□□□。"]'),
('song-ci-314','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','[]','芭蕉叶上三更雨。',52,'宋词/ci.song.17000.json','["芭蕉叶上三更雨。", "人生只合随他去。", "便不到天涯。", "天涯也是家。", "屏山三五叠。", "处处飞胡蝶。", "正是菊堪看。", "东篱独自寒。"]'),
('song-ci-315','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','[]','黄鸡喔喔催人起。',52,'宋词/ci.song.17000.json','["黄鸡喔喔催人起。", "困不成眠窗似水。", "清露不曾寒。", "朝来起自难。", "家人当睡美。", "又忆归程几。", "不管湿阑干。", "芙蓉花自看。"]'),
('song-ci-316','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','[]','画梁语透帘栊晓。',52,'宋词/ci.song.17000.json','["画梁语透帘栊晓。", "坼桐风送杨花老。", "细雨绿阴寒。", "罗襟只似单。", "青门三里道。", "个个游芳草。", "比似嫁来看。", "踏青难更难。"]'),
('song-ci-317','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','["\u897f\u6e56"]','江波何似西湖曲。',52,'宋词/ci.song.17000.json','["江波何似西湖曲。", "村烟相对峰南北。", "何处不青青。", "青青是汉茔。", "长亭芳草路。", "寒食谁家墓。", "旧日厌残红。", "人行九里松。"]'),
('song-ci-318','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','[]','殷勤欲送春归去。',52,'宋词/ci.song.17000.json','["殷勤欲送春归去。", "白首题将断肠句。", "春去自依依。", "欲归无处归。", "天涯同是寓。", "握手留春住。", "小住碧桃枝。", "桃根不属谁。"]'),
('song-ci-319','菩萨蛮','刘辰翁','宋','宋词','song-ci','菩萨蛮','[]','八仙名姓当时少。',52,'宋词/ci.song.17000.json','["八仙名姓当时少。", "污尊牛饮同倾倒。", "惟有我公荣。", "旁人笑独醒。", "多年村落走。", "泥饮无升斗。", "入了玉门关。", "人生一醉难。"]'),
('song-ci-320','好事近','刘辰翁','宋','宋词','song-ci','好事近','[]','□后百年闲，元度自伤来暮。',53,'宋词/ci.song.17000.json','["□后百年闲，元度自伤来暮。", "打破虚空无碍，共乘龙飞去。", "更参末后句如何，此事未能付。", "前遇小桥风雪，是君诗成处。"]'),
('song-ci-321','谒金门','刘辰翁','宋','宋词','song-ci','谒金门','[]','娇点点。',53,'宋词/ci.song.17000.json','["娇点点。", "困倚春光欲软。", "滴尽守宫难可染。", "浓欺红烛艳。", "寂寂露珠啼脸。", "翠袖不禁风飐。", "芳径相逢惊笑靥。", "日长初睡转。"]'),
('song-ci-322','谒金门','刘辰翁','宋','宋词','song-ci','谒金门','[]','花露湿。',53,'宋词/ci.song.17000.json','["花露湿。", "红泪裛成珠粒。", "比似昭阳恩未得。", "睡来添醉色。", "一笑娇波滴滴。", "再顾羞潮拂拂。", "恨血千年明的皪。", "千年人共忆。"]'),
('song-ci-323','谒金门','刘辰翁','宋','宋词','song-ci','谒金门','[]','游赏竞。',53,'宋词/ci.song.17000.json','["游赏竞。", "看取落红阵阵。", "花睡不成娇似病。", "春寒空受尽。", "旧日不知繁盛。", "欲饮如今无兴。", "恨满东风无绿鬓。", "东风还自恨。"]'),
('song-ci-324','长相思','刘辰翁','宋','宋词','song-ci','长相思','[]','上元晴。',44,'宋词/ci.song.17000.json','["上元晴。", "上元晴。", "待得晴时坐触屏。", "山禽三两声。", "欲归城。", "未归城。", "见说城中处处灯。", "明年处处行。"]'),
('song-ci-325','忆秦娥','刘辰翁','宋','宋词','song-ci','忆秦娥','[]','烧灯节。',56,'宋词/ci.song.17000.json','["烧灯节。", "朝京道上风和雪。", "风和雪。", "江山如旧，朝京人绝。", "百年短短兴亡别。", "与君犹对当时月。", "当时月。", "照人烛泪，照人梅发。"]'),
('song-ci-326','忆秦娥','刘辰翁','宋','宋词','song-ci','忆秦娥','[]','惊雷节。',56,'宋词/ci.song.17000.json','["惊雷节。", "梅花冉冉销成雪。", "销成雪。", "一年一度，为君肠绝。", "古人长恨中年别。", "馀年又过新正月。", "新正月。", "不堪临镜，不堪垂发。"]'),
('song-ci-327','忆秦娥','刘辰翁','宋','宋词','song-ci','忆秦娥','[]','梅花节。',56,'宋词/ci.song.17000.json','["梅花节。", "白头卧起餐毡雪。", "餐毡雪。", "上林雁断，上林书绝。", "伤心最是河梁别。", "无人共拜天边月。", "天边月。", "一尊对影，一编残发。"]'),
('song-ci-328','忆秦娥','刘辰翁','宋','宋词','song-ci','忆秦娥','[]','收灯节。',56,'宋词/ci.song.17000.json','["收灯节。", "霖铃又似龟山雪。", "龟山雪。", "今宵清绝，今宵愁绝。", "老人似少终然别。", "痴痴更望春三月。", "春三月。", "花如人面，自羞余发。"]'),
('song-ci-329','忆秦娥','刘辰翁','宋','宋词','song-ci','忆秦娥','[]','春如昨。',56,'宋词/ci.song.17000.json','["春如昨。", "晓风吹透胭脂阁。", "胭脂阁。", "满园茅草，冷烟城郭。", "青衫泪尽楼头角。", "佳人梦断花间约。", "花间约。", "黄昏细雨，一枝零落。"]'),
('song-ci-330','西江月','刘辰翁','宋','宋词','song-ci','西江月','[]','天上低昂似旧，人间儿女成狂。',58,'宋词/ci.song.17000.json','["天上低昂似旧，人间儿女成狂。", "夜来处处试新妆。", "却是人间天上。", "不觉新凉似水，相思两鬓如霜。", "梦从海底跨枯桑。", "阅尽银河风浪。"]'),
('song-ci-331','西江月','刘辰翁','宋','宋词','song-ci','西江月','[]','曾与回翁把手，自宜老子如龙。',58,'宋词/ci.song.17000.json','["曾与回翁把手，自宜老子如龙。", "怀胎不敢问春冬。", "等待鞭鸾笞凤。", "昨夜又迟黄石，今朝重叩鸿濛。", "碧桃花下醉相逢。", "说尽鹏游蝶梦。"]'),
('song-ci-332','西江月','刘辰翁','宋','宋词','song-ci','西江月','[]','玉帐传心如镜，青龙绕指成轮。',58,'宋词/ci.song.17000.json','["玉帐传心如镜，青龙绕指成轮。", "尘中多少白头人。", "乾里寻壬难认。", "世事说来都了，鬼神见也须瞋。", "迷槎问我是何津。", "向道先生昼困。"]'),
('song-ci-333','清平乐','刘辰翁','宋','宋词','song-ci','清平乐','[]','深红半面。',54,'宋词/ci.song.17000.json','["深红半面。", "一似墙头见。", "草树池塘青一片。", "独倚阑干几遍。", "更谁绛袖朱唇。", "火云相对英英。", "笑杀牡丹正午，离披不任看承。"]'),
('song-ci-334','清平乐','刘辰翁','宋','宋词','song-ci','清平乐','[]','君词为寿。',54,'宋词/ci.song.17000.json','["君词为寿。", "绝妙孙辛妇。", "但恨杯无露添酒。", "空等待梅花久。", "喜君白首还玄。", "人间合信天缘。", "如此相从至老，我亦何倦馀年。"]'),
('song-ci-335','归国遥','刘辰翁','宋','宋词','song-ci','归国遥','[]','初雨歇。',40,'宋词/ci.song.17000.json','["初雨歇。", "照水绿腰裙带熟。", "杨花不做人情雪。", "风流欲过前村蝶。", "羞成别。", "回头却恨春三月。"]'),
('song-ci-336','昭君怨','刘辰翁','宋','宋词','song-ci','昭君怨','[]','月出东山之上。',48,'宋词/ci.song.17000.json','["月出东山之上。", "长忆御街人唱。", "恨我不能琴。", "有琴心。", "徙倚秋波平莹。", "渐久玉肌清冷。", "待更下阑干。", "起来看。"]'),
('song-ci-337','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','远远游蜂不记家。',48,'宋词/ci.song.17000.json','["远远游蜂不记家。", "数行新柳自啼鸦。", "寻思旧事即天涯。", "睡起有情和画卷，燕归无语傍人斜。", "晚风吹落小瓶花。"]'),
('song-ci-338','浣溪沙','刘辰翁','宋','宋词','song-ci','浣溪沙','[]','点点疏林欲雪天。',48,'宋词/ci.song.17000.json','["点点疏林欲雪天。", "竹篱斜闭自清妍。", "为伊憔悴得人怜。", "欲与那人携素手，粉香和泪落君前。", "相逢恨恨总无言。"]'),
('song-ci-339','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','何须翦纸。',52,'宋词/ci.song.17000.json','["何须翦纸。", "依旧一团圆照水。", "莫倚空寒。", "柳下池边也只般。", "君何忽忽。", "宇宙人生都是客。", "月在云端。", "人自愁人不解看。"]'),
('song-ci-340','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','旧游山路。',52,'宋词/ci.song.17000.json','["旧游山路。", "落在秋阴最深处。", "风雨重阳。", "无蝶无花更断肠。", "天知老矣。", "莫累门生与儿子。", "不用登高。", "高处风吹帽不牢。"]'),
('song-ci-341','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','东风似客。',52,'宋词/ci.song.17000.json','["东风似客。", "醉里落花南又北。", "客似东风。", "携手斜阳一笑中。", "佳人怨我。", "不寄江南春一朵。", "我怨佳人。", "憔悴江南不似春。"]'),
('song-ci-342','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','腊销三五。',52,'宋词/ci.song.17000.json','["腊销三五。", "月向雪山云外吐。", "烟水黄昏。", "梅柳依稀笛断魂。", "今宵豫赏。", "便作香尘随步想。", "莫待元宵。", "灯火零星雨寂寥。"]'),
('song-ci-343','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','无灯可看。',52,'宋词/ci.song.17000.json','["无灯可看。", "雨水从教正月半。", "探茧推盘。", "探得千秋字字看。", "铜驼故老。", "说著宣和似天宝。", "五百年前。", "曾向杭州看上元。"]'),
('song-ci-344','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','送春待晓。',52,'宋词/ci.song.17000.json','["送春待晓。", "春是五更先去了。", "我醉方知。", "春正怜伊怕别伊。", "留君不可。", "归到海边方忆我。", "做尽花归。", "欲赠君时少一枝。"]'),
('song-ci-345','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','相州锦好。',52,'宋词/ci.song.17000.json','["相州锦好。", "待到相州人已老。", "颍水归田。", "白鹭惊猜已十年。", "太师尚父。", "晚遇明时方用武。", "大笑相逢。", "把酒家乡是客中。"]'),
('song-ci-346','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','不能管得。',52,'宋词/ci.song.17000.json','["不能管得。", "欲雨能教天地黑。", "待得开晴。", "不用吾言也自行。", "一杯亦醉。", "万事无能吾欲睡。", "旧亦能诗。", "说旧时诗问是谁。"]'),
('song-ci-347','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','清欢昨日。',52,'宋词/ci.song.17000.json','["清欢昨日。", "十事不如人六七。", "试数从前。", "素素相从得几年。", "子兮子兮。", "再拣一枝何处起。", "翠斧峰驼。", "客好其如良夜何。"]'),
('song-ci-348','减字木兰花','刘辰翁','宋','宋词','song-ci','减字木兰花','[]','脾神喜乐。',52,'宋词/ci.song.17000.json','["脾神喜乐。", "寿酒一杯胜服药。", "过却明朝。", "顶上新霜也合销。", "小春三日。", "便觉春暄梅影出。", "醉把梅看。", "比似茱萸更耐寒。"]'),
('song-ci-349','山花子','刘辰翁','宋','宋词','song-ci','山花子','[]','东风解手即天涯。',56,'宋词/ci.song.17000.json','["东风解手即天涯。", "曲曲青山不可遮。", "如此苍茫君莫怪，是归家。", "阊阖相迎悲最苦，英雄知道鬓先华。", "更欲徘徊春尚肯，已无花。"]'),
('song-ci-350','山花子','刘辰翁','宋','宋词','song-ci','山花子','[]','此处情怀欲问天。',56,'宋词/ci.song.17000.json','["此处情怀欲问天。", "相期相就复何年。", "行过章江三十里，泪依然。", "早宿半程芳草路，犹寒欲雨暮春天。", "小小桃花三两处，得人怜。"]'),
('song-ci-351','柳梢青','刘辰翁','宋','宋词','song-ci','柳梢青','[]','铁马蒙毡，银花洒泪，春人愁城。',61,'宋词/ci.song.17000.json','["铁马蒙毡，银花洒泪，春人愁城。", "笛里番腔，街头戏鼓，不是歌声。", "那堪独坐青灯。", "想故国、高台月明。", "辇下风光，山中岁月，海上心情。"]'),
('song-ci-352','南歌子','刘辰翁','宋','宋词','song-ci','南歌子','[]','搔困麻仙爪，含暄忍客衣。',31,'宋词/ci.song.17000.json','["搔困麻仙爪，含暄忍客衣。", "夜长窗月露成帏。", "不说明朝风雨、自当归。"]'),
('song-ci-353','南歌子','刘辰翁','宋','宋词','song-ci','南歌子','[]','篘熟双投美，香飘一缕丝。',31,'宋词/ci.song.17000.json','["篘熟双投美，香飘一缕丝。", "霜前雁到蟹螯持。", "自试小窗醉墨、作新诗。"]'),
('song-ci-354','朝中措','刘辰翁','宋','宋词','song-ci','朝中措','[]','炼花为露玉为瓶。',57,'宋词/ci.song.17000.json','["炼花为露玉为瓶。", "佳客为频倾。", "耐得风霜满鬓，此身合是金茎。", "墙头竹外，洞房初就，画阁新成。", "嚼得梅花透骨，何愁不会长生。"]'),
('song-ci-355','太常引','刘辰翁','宋','宋词','song-ci','太常引','[]','便晴也是不曾晴。',61,'宋词/ci.song.17000.json','["便晴也是不曾晴。", "不怕金吾禁行。", "风雨动乡情。", "梦灯火、扬州化城。", "少年跌宕，谁家娇小，绕带到天明。", "昨夜月还生。", "但惊破、霓裳数声。"]'),
('song-ci-356','太常引','刘辰翁','宋','宋词','song-ci','太常引','[]','此公去暑似新秋。',60,'宋词/ci.song.17000.json','["此公去暑似新秋。", "吏毒一句句。", "行县胜监州。", "觉甘雨、随车应求。", "鹭清为酒，螺清为寿，起舞祝君侯。", "急召也须留。", "廿四考、中书到头。"]'),
('song-ci-357','玉楼春','刘辰翁','宋','宋词','song-ci','玉楼春','[]','霜风不动晴明好。',64,'宋词/ci.song.17000.json','["霜风不动晴明好。", "探梅有约城东道。", "桥边失却老仙期，城门落日人归早。", "野田一望迷芳草。", "除是腾空君后到。", "立马三周黛佛头，参差中路令人老。"]'),
('song-ci-358','玉楼春','刘辰翁','宋','宋词','song-ci','玉楼春','[]','龙山歌舞无人道。',64,'宋词/ci.song.17000.json','["龙山歌舞无人道。", "只说先生狂落帽。", "秋风亦是可怜人，要令天意知人老。", "菊花不为重阳早。", "自爱古人诗句恼。", "与君郑重说□□，残年惟有重阳好。"]'),
('song-ci-359','乌夜啼','刘辰翁','宋','宋词','song-ci','乌夜啼','[]','犹疑薰透帘栊。',45,'宋词/ci.song.17000.json','["犹疑薰透帘栊。", "是东风。", "不分榴花更胜、一春红。", "新雨过，绿连空。", "蝶飞慵。", "间过绿阴深院、小花浓。"]'),
('song-ci-360','乌夜啼','刘辰翁','宋','宋词','song-ci','乌夜啼','[]','素娥醉语曾留。',45,'宋词/ci.song.17000.json','["素娥醉语曾留。", "又中秋。", "待得重圆谁妒、两悠悠。", "向愁旱，今愁水，没中洲。", "看取明朝晴去、不须愁。"]'),
('song-ci-361','乌夜啼','刘辰翁','宋','宋词','song-ci','乌夜啼','[]','何年似永和年。',45,'宋词/ci.song.17000.json','["何年似永和年。", "记湖船。", "如此晴天无处、望新烟。", "江南女，裙四尺，合秋千。", "昨日老人曾见、久潸然。"]'),
('song-ci-362','行香子','刘辰翁','宋','宋词','song-ci','行香子','[]','雪履无痕。',84,'宋词/ci.song.17000.json','["雪履无痕。", "溪影传神。", "著坡诗、请自清温。", "朝朝不去，夕夕空勤。", "似梦中云，云外雪，雪中春。", "四野昏昏。", "匹马巡巡。", "拣一枝、寄与芳尊。", "更谁兴到，於我情真。", "是白家宾，江南路，陇头人。"]'),
('song-ci-363','行香子','刘辰翁','宋','宋词','song-ci','行香子','[]','玉立风尘。',84,'宋词/ci.song.17000.json','["玉立风尘。", "光动黄银。", "便谈文、也到夜分。", "无人烛下，壁上传神。", "记老婆心，寒士语，道人身。", "极意形容，下语难亲。", "更万分、无一分真。", "醉翁去后，往往愁人。", "顾滴山泉，衔丘冢，化龙云。"]'),
('song-ci-364','行香子','刘辰翁','宋','宋词','song-ci','行香子','[]','海水成尘。',84,'宋词/ci.song.17000.json','["海水成尘。", "河水无银。", "恨幽明、我与公分。", "青山独往，回首伤神。", "叹魏阙心，磻石魄，汨罗身。", "除却相思，四海无亲。", "识风流、还贺季真。", "而今天上，笑谪仙人。", "但病伤春，愁厌雨，泪看云。"]'),
('song-ci-365','行香子','刘辰翁','宋','宋词','song-ci','行香子','[]','月露吾痕。',84,'宋词/ci.song.17000.json','["月露吾痕。", "雪得吾神。", "更荒寒、不傍人温。", "山人去后，车马来勤。", "但梦朝云，愁暮雨，怨阳春。", "说著东昏。", "记著南巡。", "泪盈盈、檀板金尊。", "怜君素素，念我真真。", "叹古来言，新样客，旧时人。"]'),
('song-ci-366','品令','刘辰翁','宋','宋词','song-ci','品令','[]','满庭芳草。',66,'宋词/ci.song.17000.json','["满庭芳草。", "更昨日、落红如扫。", "绿阴正似人怀抱。", "一声睍睆，春色何曾老。", "幸自不须人起早。", "寂寞如相恼。", "旧时闻处青门道。", "禁烟时候，柳下人家好。"]'),
('song-ci-367','鹊桥仙','刘辰翁','宋','宋词','song-ci','鹊桥仙','[]','乘鸾著色，痴蝇误拂。',68,'宋词/ci.song.17000.json','["乘鸾著色，痴蝇误拂。", "不及羲之醉墨。", "偶然入手送东阳，便看取、薰时清适。", "清风去暑，闲题当日。", "宰相纱笼谁识。", "封丘门外定何人，这一点、瞒他不得。"]'),
('song-ci-368','鹊桥仙','刘辰翁','宋','宋词','song-ci','鹊桥仙','[]','看人掷果，看人罢织。',68,'宋词/ci.song.17000.json','["看人掷果，看人罢织。", "难得团栾七夕。", "蟠桃只在屋东头，庆西母、年开八ど。", "去年今日。", "今年今日。", "添个曾孙抱膝。", "人间乐事有多般，算此乐、人间第一。"]'),
('song-ci-369','鹊桥仙','刘辰翁','宋','宋词','song-ci','鹊桥仙','[]','轻风澹月，年年去路。',68,'宋词/ci.song.17000.json','["轻风澹月，年年去路。", "谁识小年初度。", "桥边曾弄碧莲花，悄不记、人间今古。", "吹箫江上，沾衣微露。", "依约凌波曾步。", "寒机何意待人归，但寂历、小窗斜雨。"]'),
('song-ci-370','鹊桥仙','刘辰翁','宋','宋词','song-ci','鹊桥仙','[]','天香吹下，烟霏成路。',68,'宋词/ci.song.17000.json','["天香吹下，烟霏成路。", "飒飒神光暗度。", "桥边犹记泛槎人，看赤岸、苔痕如古。", "长空皓月，小风斜露。", "寂寞江头独步。", "人间何处得飘然，归梦入、梨花春雨。"]'),
('song-ci-371','一翦梅','刘辰翁','宋','宋词','song-ci','一翦梅','[]','万事如花不可期。',72,'宋词/ci.song.17000.json','["万事如花不可期。", "花不堪持。", "酒不堪持。", "江天雪意使人迷。", "翦一枝枝。", "歌一枝枝。", "歌者不来今几时。", "姜影无词。", "张影无词。", "不歌不醉不成诗。", "歌也迟迟。", "雪也迟迟。"]'),
('song-ci-372','一翦梅','刘辰翁','宋','宋词','song-ci','一翦梅','[]','人生总受业风吹。',72,'宋词/ci.song.17000.json','["人生总受业风吹。", "三岁儿儿。", "八十儿儿。", "深闺空谷把还持。", "啼看人知。", "啼怕人知。", "客中自种绿猗猗。", "月下横枝。", "雪下横枝。", "尊前百岁且开眉。", "今岁今时。", "前岁今时。"]'),
('song-ci-373','夜飞鹊・夜飞鹊慢','刘辰翁','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','何曾见飞渡，年又年痴。',130,'宋词/ci.song.17000.json','["何曾见飞渡，年又年痴。", "今古相望犹疑。", "朱颜一去似流水，断桥魂梦参差。", "何堪更嗟迟暮，听旁人说与，此夕佳期。", "深深代籍，盼悠悠、北地胭脂。", "谁寄扬州破镜，遍海角天涯，空待人归。", "自小秦楼望巧，吴机回锦，歌舞为谁。", "星萍耿耿，算欢娱，未省流离。", "但秋衾梦浅，云闲曲远，薄命同时。"]'),
('song-ci-374','疏影','刘辰翁','宋','宋词','song-ci','疏影','[]','香篝素被。',134,'宋词/ci.song.17000.json','["香篝素被。", "听花犯低低，瑶花开未。", "长记那时，炽炭围炉，瘦妻换酒行试。", "当家人在销金帐，约莫是、打围归际。", "又谁知、别忆烹茶，冷落故家愁思。", "闻道滕骄巽懒，今朝待檄与，翻云须易。", "白白不成，又不教晴，做尽黄昏情味。", "银河本是冰冰底。", "怎忍向、东风成水。", "待满城、玉宇琼楼，却报卧庐人起。"]'),
('song-ci-375','摘红英','刘辰翁','宋','宋词','song-ci','摘红英','[]','花朝月。',68,'宋词/ci.song.17000.json','["花朝月。", "朦胧别。", "朦胧也胜檐声咽。", "亲曾说。", "令人悦。", "落花情绪，上坟时节。", "花阴雪。", "花阴灭。", "柳风一似秋千掣。", "晴未决。", "晴还缺。", "一番寒食，满村啼鴂。"]'),
('song-ci-376','千秋岁','刘辰翁','宋','宋词','song-ci','千秋岁','[]','新篘熟也，借问谁家早。',87,'宋词/ci.song.17000.json','["新篘熟也，借问谁家早。", "梅影里，蜂儿绕。", "三更残月上，一夜霜天晓。", "溪桥小，春风有意年年到。", "当年青鸟去，落叶无人扫。", "铜柱仄，瑶池老。", "残钟长乐树，坠马咸阳道。", "空回首，御街人卖南京枣。"]'),
('song-ci-377','促拍丑奴儿','刘辰翁','宋','宋词','song-ci','促拍丑奴儿','[]','送岁可无诗。',76,'宋词/ci.song.17000.json','["送岁可无诗。", "得团栾、忍不开眉。", "不记去年今夕梦，江东怀抱，江西信息，舍北妻儿。", "五十扊扅炊。", "待五十、富贵成痴。", "百年苦乐乘除看，今年一半，明年一半，更似儿时。"]'),
('song-ci-378','促拍丑奴儿','刘辰翁','宋','宋词','song-ci','促拍丑奴儿','[]','世事莫寻思。',76,'宋词/ci.song.17000.json','["世事莫寻思。", "待说来、天也应悲。", "百年已是中年后，西州垂泪，东山携手，几个斜晖。", "也莫苦吟诗。", "苦吟诗，待有谁知。", "多□不是无才气，文时不遇，武时不遇，更说今时。"]'),
('song-ci-379','最高楼','刘辰翁','宋','宋词','song-ci','最高楼','[]','银河水，洗得世间清。',100,'宋词/ci.song.17000.json','["银河水，洗得世间清。", "山色雨馀青。", "老子纶巾棋别墅，人家鼾睡柝秋城。", "定谁劳，定谁福，定谁能。", "常恨著、景升儿不似。", "又恨著、景升牛小耳。", "空相望，愧平生。", "我欲临风扶玉树，自攀承露酌金茎。", "看昆明，鳞石长，海桑晴。"]'),
('song-ci-380','最高楼','刘辰翁','宋','宋词','song-ci','最高楼','[]','朱顶字，八十正平头。',100,'宋词/ci.song.17000.json','["朱顶字，八十正平头。", "添作八千秋。", "无能也自收郿坞，到今恨不贬潮州。", "看几人，炎又冷，老还羞。", "也不学、太公忙把火。", "也不学、申公轮转磨。", "休莫莫，莫休休。", "小迟授业何曾吃，更迟食乳不须愁。", "且从容，某水钓，某丘游。"]'),
('song-ci-381','最高楼','刘辰翁','宋','宋词','song-ci','最高楼','[]','非是雪，只是玉楼成。',100,'宋词/ci.song.17000.json','["非是雪，只是玉楼成。", "屑不尽云英。", "东边老树颓然折，西头稚柳爆然声。", "试平安，松丈丈，竹兄兄。", "有谁向、金船呼小玉，又谁怜、纸帐梦飞琼。", "怪疏影，坠娉婷。", "唤起老张寒蔌蔌，好歌白雪与君听。", "但党家，人笑道，太粗生。"]'),
('song-ci-382','最高楼','刘辰翁','宋','宋词','song-ci','最高楼','[]','花上雪。',100,'宋词/ci.song.17000.json','["花上雪。", "信手捻来成。", "屑不就琼英。", "昨朝已见诗成卷，今朝又试曲成声。", "更催催，莫不做，水仙兄。", "终须待、晴时携斗酒。", "更须待、老夫吟数首。", "休更叠，□娉婷。", "已无翠鸟传花信，又无羯鼓与花听。", "更催催，迟数日，是春生。"]'),
('song-ci-383','桂枝香','刘辰翁','宋','宋词','song-ci','桂枝香','[]','吹箫人去。',124,'宋词/ci.song.17000.json','["吹箫人去。", "但桂影徘徊，荒杯承露。", "东望鞭芙缥缈，寒光如注。", "去年夜半横江梦，倚危樯，参差曾赋。", "茫茫角动，回舟尽兴，未惊鸥鹭。", "情知道、明年何处。", "漫待客黄楼，尘波前度。", "二十四桥，颇有杜书记否。", "二三字者今如此，看使君、角巾东路。", "人间俯仰，悲欢何限，团圆如故。"]'),
('song-ci-384','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','丞相衮衣朝戏彩，年年庆事如新。',70,'宋词/ci.song.17000.json','["丞相衮衣朝戏彩，年年庆事如新。", "尊前一笑共儿孙。", "人间传寿酒，天上送麒麟。", "缥缈祥烟连北阙，天颜有喜生春。", "蓬莱清浅海光平。", "今年初甲子，重试碧桃根。"]'),
('song-ci-385','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','闻道城东鹤会，欣然一笑乘风。',68,'宋词/ci.song.17000.json','["闻道城东鹤会，欣然一笑乘风。", "不知一鹤在墙东。", "神仙人不识，未始出吾宗。", "弟子有年於此，先生之道如龙。", "碧桃花子落壶中。", "化为三五粒，元是北边松。"]'),
('song-ci-386','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','天际何分南与北，五更纵又成横。',69,'宋词/ci.song.17000.json','["天际何分南与北，五更纵又成横。", "夜来拾得断河星。", "化为一片石，持去问君平。", "老大看天一笑，儿童问我须应。", "向来牛女本无名。", "要知天上事，亦似谤先生。"]'),
('song-ci-387','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','二十年前此日，女兄庆我生儿。',68,'宋词/ci.song.17000.json','["二十年前此日，女兄庆我生儿。", "簪萱弄彩听孙啼。", "典衣沽美酒，数待冠昏时。", "乱后飘零独在，紫荆墓棘风吹。", "尊前万事莫寻思。", "儿童看有子，白发故应衰。"]'),
('song-ci-388','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','旧日诗肠论斗酒，风流怀抱如倾。',69,'宋词/ci.song.17000.json','["旧日诗肠论斗酒，风流怀抱如倾。", "几年不听渭城声。", "尊前无贺老，卷里少弥明。", "闻说语言都好，便应步履全轻。", "长生第一是风僧。", "额前书八十，能说又能行。"]'),
('song-ci-389','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','西曲罥衣迷去路，雪销断岸无痕。',70,'宋词/ci.song.17000.json','["西曲罥衣迷去路，雪销断岸无痕。", "寻花不拟到前村。", "暖风初转袖，小径忽开门。", "却忆临塘桥下马，暗香不是黄昏。", "人生南北与谁论。", "岭梅花树下，闲听蜜蜂喧。"]'),
('song-ci-390','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','老去尚呼张丈，醉中自惜熊儿。',68,'宋词/ci.song.17000.json','["老去尚呼张丈，醉中自惜熊儿。", "越王台上鹧鸪啼。", "三朝臣不遇，无复好文时。", "情绪幽幽似结，鬓丝索索禁吹。", "病来魂不到相思。", "散人腰已散，倚杖叹吾衰。"]'),
('song-ci-391','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','海日轻红通似脸，小窗明丽新晴。',70,'宋词/ci.song.17000.json','["海日轻红通似脸，小窗明丽新晴。", "满怀著甚是真情。", "不知春睡美，为爱晓寒轻。", "说似吴山楼万叠，雪销未尽宫城。", "湖边柳色渐啼莺。", "才听朝马动，一巷卖花声。"]'),
('song-ci-392','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','过雁天边信息，两宫池上心情。',68,'宋词/ci.song.17000.json','["过雁天边信息，两宫池上心情。", "沉思海角愤难平。", "山风欺客梦，耿耿到天明。", "幸自不争名利，闲愁夜夜如惊。", "明朝鬓白两三茎。", "世人都不念，似汝复何成。"]'),
('song-ci-393','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','["\u897f\u6e56"]','睡过花阴一丈，愁深酒力千锺。',68,'宋词/ci.song.17000.json','["睡过花阴一丈，愁深酒力千锺。", "梦魂不得似游蜂。", "瓶花无密约，到处自神通。", "天上西湖似锦，人间骄马如龙。", "今年不与去年同。", "飘零终不恨，难与故人逢。"]'),
('song-ci-394','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','幸自不须端帖子，闲中一句如无。',69,'宋词/ci.song.17000.json','["幸自不须端帖子，闲中一句如无。", "爱他午日午时书。", "惟应三五字，便是辟兵符。", "久雨石鲸未没，小风纨扇相疏。", "邀朋一笑共菖蒲。", "去年初禁酒，今日漫提壶。"]'),
('song-ci-395','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','我去就他甚易，他来认我良难。',68,'宋词/ci.song.17000.json','["我去就他甚易，他来认我良难。", "悟时到处是壶天。", "古诗寻一句，危坐看香烟。", "金玉满堂不守，菁华岁月空迁。", "从今饱饭更安眠。", "丹经都不看，闲坐一千年。"]'),
('song-ci-396','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','旧日采莲羞半面，至今回首忽忽。',70,'宋词/ci.song.17000.json','["旧日采莲羞半面，至今回首忽忽。", "梦穿斜日水云红。", "痴心犹独自，等待郑公风。", "海上颓云潮不返，侧身空坠辽东。", "人间天上几时同。", "宫衣元不遇，无语醉醒中。"]'),
('song-ci-397','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','昔走都门终夜雨，明朝泥淖堪惊。',70,'宋词/ci.song.17000.json','["昔走都门终夜雨，明朝泥淖堪惊。", "疏疏点点忽难鸣。", "数峰青似染，快活早来晴。", "十五年间春梦断，乱山寒食清明。", "无人挑菜踏青行。", "青鸠啼雨外，闲听寺中声。"]'),
('song-ci-398','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','白白江南一信霜。',64,'宋词/ci.song.17000.json','["白白江南一信霜。", "过都字不到衡阳。", "老嘉破帽并吹却，未省西风似此狂。", "攀北斗，酌天浆。", "月香满似菊花黄。", "神仙暗度龙山劫，鸡犬人间百战场。"]'),
('song-ci-399','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','白发平津起褎然。',64,'宋词/ci.song.17000.json','["白发平津起褎然。", "燕飞定远望生还。", "世间最有团栾乐，又是平平过一年。", "银信近，玉鞭先。", "东来西去爵衔鳝。", "人生有命迟迟好，且喜称觞寿母前。"]'),
('song-ci-400','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','占得春风五日先。',64,'宋词/ci.song.17000.json','["占得春风五日先。", "至今住处是开元。", "写真若遇丹元子，只著当时宫锦船。", "松戴雪，自苍然。", "八公花下少如前。", "看来天上多辛苦，且住人间五百年。"]'),
('song-ci-401','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','自入孤山分外香。',64,'宋词/ci.song.17000.json','["自入孤山分外香。", "南枝不改旧时妆。", "为曾盘里承青眼，一见溪头道胜常。", "商山乐，又相羊。", "上方不复记传觞。", "橘中个个盘深窈，依倚东风局意长。"]'),
('song-ci-402','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','去年太岁田间土，明日香烟壁下尘。',64,'宋词/ci.song.17000.json','["去年太岁田间土，明日香烟壁下尘。", "马上新人红又紫，眼前歌妓送还迎。", "钗头燕，胜金紃。", "燕歌赵舞动南人。", "遗民植杖唐巾起，闲伴儿童看立春。"]'),
('song-ci-403','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','旧日桃符管送迎。',64,'宋词/ci.song.17000.json','["旧日桃符管送迎。", "灯毯爆竹斗先嬴。", "鹿门乱走团栾久，才到城门有鼓声。", "梅弄雪，柳窥晴。", "残年犹自冷如冰。", "欲知春色招人醉，须是元宵与踏青。"]'),
('song-ci-404','鹧鸪天','刘辰翁','宋','宋词','song-ci','鹧鸪天','[]','暖逼酥枝渐渐融。',64,'宋词/ci.song.17000.json','["暖逼酥枝渐渐融。", "双飞谁识蝶雌雄。", "歌声已逐行云去，花片偏来酒盏中。", "眉月冷，画楼空。", "酒阑犹未见情锺。", "直须把烛穿花帐，方见佳人玉面红。"]'),
('song-ci-405','青玉案','刘辰翁','宋','宋词','song-ci','青玉案','[]','稠塘旧是花千树。',80,'宋词/ci.song.17000.json','["稠塘旧是花千树。", "曾泛入、溪深误。", "前度刘郎重唤渡。", "漫山寂寂，年时花下，往往无寻处。", "一年一度相思苦。", "恨不抛人过江去。", "及至来时春未暮。", "兔葵燕麦，冷风斜雨，长恨稠塘路。"]'),
('song-ci-406','青玉案','刘辰翁','宋','宋词','song-ci','青玉案','[]','雪销未尽残梅树。',80,'宋词/ci.song.17000.json','["雪销未尽残梅树。", "又风送、黄昏雨。", "长记小红楼畔路。", "杵歌串串，鼓声叠叠，预赏元宵舞。", "天涯客鬓愁成缕。", "海上传柑梦中去。", "今夜上元何处度。", "乱山茅屋，寒炉败壁，渔火青荧处。"]'),
('song-ci-407','青玉案','刘辰翁','宋','宋词','song-ci','青玉案','[]','里中上大人谁大。',80,'宋词/ci.song.17000.json','["里中上大人谁大。", "人上大、仁难作。", "八十六翁闲处坐。", "小生懒惰。", "近来高卧。", "忘却今朝贺。", "甲申还是连珠麽。", "胜有老人星一个。", "白发朱颜堪婆娑。", "灵光殿火。", "昆明劫过。", "角绮园黄我。"]'),
('song-ci-408','青玉案','刘辰翁','宋','宋词','song-ci','青玉案','[]','无肠可断听花雨。',80,'宋词/ci.song.17000.json','["无肠可断听花雨。", "沉沉已是三更许。", "如此残红那得住。", "一春情绪。", "半生羁旅。", "寂寞空山语。", "霖铃不是相思阻。", "四十平分犹过五。", "渐远不知何杜宇。", "不如归去。", "不如归去。", "人在江南路。"]'),
('song-ci-409','踏莎行','刘辰翁','宋','宋词','song-ci','踏莎行','[]','命薄佳人，情锺我辈。',68,'宋词/ci.song.17000.json','["命薄佳人，情锺我辈。", "海棠开后心如碎。", "斜风细雨不曾晴，倚阑滴尽胭脂泪。", "恨不能开，开时又背。", "春寒只了房栊闭。", "待他晴后得君来，无言掩帐羞憔悴。"]'),
('song-ci-410','踏莎行','刘辰翁','宋','宋词','song-ci','踏莎行','[]','壁彩笼尘，金吾掠路。',68,'宋词/ci.song.17000.json','["壁彩笼尘，金吾掠路。", "海风吹断楼台雾，无人知是上元时，一夜月明无著处。", "早是禁烟，朝来冻雨。", "东风自放银花树。", "雪晴须有踏青时，不成也待明年去。"]'),
('song-ci-411','踏莎行','刘辰翁','宋','宋词','song-ci','踏莎行','[]','北望蝶山，西迷凤苑。',68,'宋词/ci.song.17000.json','["北望蝶山，西迷凤苑。", "忽忽醉里题诗满。", "黄花只似去年黄，去年人去黄花远。", "雨压城荒，丘园路断。", "却晴又恨公来晚。", "依稀自唱古人诗，明年此会知谁健。"]'),
('song-ci-412','踏莎行','刘辰翁','宋','宋词','song-ci','踏莎行','[]','松偃成阴，荷香去暑。',68,'宋词/ci.song.17000.json','["松偃成阴，荷香去暑。", "过溪似是东林路。", "不知宿昔有谁来，寺门同听催诗雨。", "北马依风，凉蝉咽暮。", "城门半带东陵圃。", "江南不是米元晖，无人更得沧洲趣。"]'),
('song-ci-413','踏莎行','刘辰翁','宋','宋词','song-ci','踏莎行','[]','珠压相於，胭脂同傅。',68,'宋词/ci.song.17000.json','["珠压相於，胭脂同傅。", "樊家更共谁家语。", "梢头结取一番愁，玉箫不会双双侣。", "风送流莺，前歌后舞。", "并桃欲吐含来往。", "双飞燕子自相衔，会教唇舌调鹦鹉。"]'),
('song-ci-414','烛影摇红','刘辰翁','宋','宋词','song-ci','烛影摇红','[]','老子婆娑，那回也上南楼去。',116,'宋词/ci.song.17000.json','["老子婆娑，那回也上南楼去。", "素娥有恨隐云屏，元是娇痴故。", "惊扇徘徊未许。", "耿多情、为谁堪诉。", "使君愁绝，独倚阑干，后期无据。", "有酒如船，片云扫尽霓裳露。", "他时与客更携鱼，犹记临皋路。", "因念南羁北旅。", "醉乌乌、凭君楚舞。", "问君不见，璧月词成，楼西沉处。"]'),
('song-ci-415','烛影摇红','刘辰翁','宋','宋词','song-ci','烛影摇红','[]','明月如冰，乱云飞下斜河去。',116,'宋词/ci.song.17000.json','["明月如冰，乱云飞下斜河去。", "旋呼艇子载箫声，风景还如故。", "袅袅余怀何许。", "听尊前、呜呜似诉。", "近年潮信，万里阴晴，和天无据。", "有客秋风，去时留下金盘露。", "少年终夜奏胡笳，谁料归无路。", "同是江南倦旅。", "封婵娟、君歌我舞。", "醉中休问，明月明年，人在何处。"]'),
('song-ci-416','烛影摇红','刘辰翁','宋','宋词','song-ci','烛影摇红','[]','春日江郊，素娥吹下银幡舞。',116,'宋词/ci.song.17000.json','["春日江郊，素娥吹下银幡舞。", "东风点点乱茶烟，留到明朝否。", "掩袖凝寒不语。", "漫粘酥、枝枝缕缕。", "断肠何似，飞絮多时，落梅深处。", "仙掌擎来，翠眉敛半看成露。", "惊沙马上面帘轻，谁贵毡庐主。", "多少高阳伴侣。", "到如今、沉冥几许。", "乘槎相问，万里银河，欲归无路。"]'),
('song-ci-417','念奴娇','刘辰翁','宋','宋词','song-ci','念奴娇','[]','先生自寿，拥衾寒，重赋凌云游意。',120,'宋词/ci.song.17000.json','["先生自寿，拥衾寒，重赋凌云游意。", "我有大儿孔文举，弱冠骎骎暮齿。", "桃已三偷，树犹如此，前度花开几。", "蓬莱可塞，还童却老无计。", "为此授笔翩翩，大江东去，好似歌头起。", "寄与两家孙又子，长看以文为戏。", "某所某公，同年同月，谁翦招魂纸。", "前三例好，不须举后三例。"]'),
('song-ci-418','念奴娇','刘辰翁','宋','宋词','song-ci','念奴娇','[]','枯寒生晚，复何似、张绪少年时意。',120,'宋词/ci.song.17000.json','["枯寒生晚，复何似、张绪少年时意。", "薄命不逢何至此，满眼啼妆龋齿。", "城是城非，年来年去，万八千能几。", "半痴半了，更痴儿计孙计。", "回首仕已半生，仕何如已，已矣羞拈起。", "幸有橘丸丸日大，且复从公围戏。", "若论弹文，更书谤箧，吾历无馀纸。", "多年致仕，大都有甚恩例。"]'),
('song-ci-419','念奴娇','刘辰翁','宋','宋词','song-ci','念奴娇','[]','吾年如此，更梦里、犹作狼居胥意。',120,'宋词/ci.song.17000.json','["吾年如此，更梦里、犹作狼居胥意。", "千首新诗千斛酒，管甚侯何侯齿。", "员峤波翻，瀛洲尘败，吾屐能销几。", "经丘寻壑，是他早计迟计。", "犹记辰巳嗟嗟，故人贺我，且勉呼君起。", "五十不来来过二，方悟人言都戏。", "以我情怀，借公篇韵，恨不天为纸。", "馀生一笑，不须邴曼容例。"]'),
('song-ci-420','念奴娇','刘辰翁','宋','宋词','song-ci','念奴娇','[]','沧洲一叶，待借君、回我炉亭春意。',119,'宋词/ci.song.17000.json','["沧洲一叶，待借君、回我炉亭春意。", "突兀灵光无立壁，八面江风寒齿。", "乡屐廊深，笼门槛赤，数月才几。", "千年未论，岂无数十年计。", "我本高卧墙东，何知人事，推枕为君起。", "憔悴庚寅何足记，不觉联翩宾戏。", "白雪阳春，黄鸡唱日，绝少澄心纸。", "我歌草草，和章有例还例。"]'),
('song-ci-421','念奴娇','刘辰翁','宋','宋词','song-ci','念奴娇','[]','两丸日月，细看来、也是樊笼中物。',120,'宋词/ci.song.17000.json','["两丸日月，细看来、也是樊笼中物。", "点点山河经过了，拔帜几番残壁。", "白是沙堤，苍然吴楚，一片成毡雪。", "此时把酒，旧词还是坡杰。", "歌罢公瑾当年，天长地久，柳与梅都发。", "几许闲愁斜照里，掌上沤生沤灭。", "沧海桑枯，东陵瓜远，总不关渠发。", "簪花起舞，可怜今夕无月。"]'),
('song-ci-422','乳燕飞・贺新郎','刘辰翁','宋','宋词','song-ci','乳燕飞・贺新郎','[]','赤壁之游乐。',142,'宋词/ci.song.17000.json','["赤壁之游乐。", "但古今、风清月白，更无坡作。", "矫首中洲公何许，共我横江孤鹤。", "把手笑、孙刘寂寞。", "颇有使君如今否，看青山、似我多前却。", "几见我、伴清酌。", "江心旧岂非城郭。", "抚千年、桑田海水，神游非昨。", "对影三人成六客，更倚归舟夜泊。", "尚听得、江城愁角。", "渺渺美人兮南浦，耿余怀、感泪伤离索。", "天正北，绕飞鹊。"]'),
('song-ci-423','乳燕飞・贺新郎','刘辰翁','宋','宋词','song-ci','乳燕飞・贺新郎','[]','曾授茅山记。',142,'宋词/ci.song.17000.json','["曾授茅山记。", "共当年、二百七十，又三甲子。", "昨上云台占云物，占得景风南至。", "又恰是、封侯千岁。", "行遍神州河洛外，早归来、庭下槐阴翠。", "春万户，共生意。", "溪翁图是参同契。", "想金丹、圆成功行，活人相似。", "顾我尊前歌赤壁，生子当如此耳。", "笑华发、东坡年几。", "弟不如人今老矣，看龙头、霄汉雌龙尾。", "呼白石，为公起。"]'),
('song-ci-424','乳燕飞・贺新郎','刘辰翁','宋','宋词','song-ci','乳燕飞・贺新郎','["\u897f\u6e56"]','过雨城西路。',142,'宋词/ci.song.17000.json','["过雨城西路。", "看轻云、弄日花间，微寒如雾。", "谁是宣华门守者，报我十分开五。", "便痛饮、能销几度。", "寄语后来看花客，待看花、莫待开成树。", "成树也，半为土。", "佺巢蜀锦今何许。", "记西湖、聚景村庄，王亭谢墅。", "冷落柯丘二三子，更问何园韩圃。", "悄一笑、回车竹所。", "点点守宫包红泪，纵倾城、一顾倾城顾。", "家国事，正何与。"]'),
('song-ci-425','瑞鹤仙','刘辰翁','宋','宋词','song-ci','瑞鹤仙','[]','正丹翁初度。',127,'宋词/ci.song.17000.json','["正丹翁初度。", "对花满江城，晓莺欲语。", "崆峒在何处。", "渐雨过农郊，劝耕问路。", "州人争观。", "问坡老、重来是否。", "把看灯、传说风流，八境尽图新句。", "如许。", "老子文章，挥毫立马，脱靴嫌污。", "太平易作。", "听父老，歌襦裤。", "愿使君小住，五风十雨。", "重见一麸三黍。", "又天边、飞诏殷勤，说相将去。"]'),
('song-ci-426','高阳台','刘辰翁','宋','宋词','song-ci','高阳台','[]','雨枕莺啼，露班烛散，御街人卖花窠。',122,'宋词/ci.song.17000.json','["雨枕莺啼，露班烛散，御街人卖花窠。", "过眼无情，而今魂梦年多。", "百钱曳杖桥边去，问几时、重到明河。", "便人问，无了东风，此恨难磨。", "落红点点入颓波。", "任归春到海，海又成涡。", "江上儿童，抱茅笑我重过。", "蓬莱不涨枯鱼泪，但荒村、败壁悬梭。", "对残阳，往往无成，似我蹉跎。"]'),
('song-ci-427','声声慢','刘辰翁','宋','宋词','song-ci','声声慢','[]','西风坠绿。',119,'宋词/ci.song.17000.json','["西风坠绿。", "唤起春娇，嫣然困倚修竹。", "落帽人来，花艳乍惊郎目。", "相思尚带旧子，甚凄凉、未忺妆束。", "吟鬓底，伴寒香一朵，并簪黄菊。", "却待金盘华屋。", "园林静、多情怎禁幽独。", "蛱蝶应愁，明日落红难触。", "那堪雁霜渐重，怕黄昏、欲睡未足。", "翠袖冷，且莫辞、花下秉烛。"]'),
('song-ci-428','汉宫春','刘辰翁','宋','宋词','song-ci','汉宫春','[]','雨入轻寒，但新篘未试，荒了东篱。',118,'宋词/ci.song.17000.json','["雨入轻寒，但新篘未试，荒了东篱。", "朝来暗惊翠袖，重倚屏帏。", "明窗丽阁，为何人、冷落多时。", "催重顿，妆台侧畔，画堂未怕春迟。", "漫省茸香粉晕，记去年醉里，题字倾敧。", "红炉未深乍暖，儿女成围。", "茶香疏处，画残灰、自说心期。", "容膝好，团栾分芋，前村夜雪初归。"]'),
('song-ci-429','汉宫春','刘辰翁','宋','宋词','song-ci','汉宫春','[]','疏影横斜，似故人安道，只在前溪。',118,'宋词/ci.song.17000.json','["疏影横斜，似故人安道，只在前溪。", "年年望雪待月，漫倚吟矶。", "千红万紫，到春来、也是寻思。", "君不见，永阳江上，残梅冷雨丝丝。", "有几情人似我，漫骑牛卧笛，乱插繁枝。", "市门索笑憔悴，便作新知。", "城楼画角，又无花、只落空悲。", "但传说，寿阳一片，何曾迎面看飞。"]'),
('song-ci-430','洞仙歌','刘辰翁','宋','宋词','song-ci','洞仙歌','[]','也曾海上，啖如瓜大枣。',102,'宋词/ci.song.17000.json','["也曾海上，啖如瓜大枣。", "海上归来相公老。", "画堂深、满引明月清风，家山好、一笑尘生蓬岛。", "六年春易过，赢得清阴，到处持杯藉芳草。", "看明年此日，人在黄金台上，早整顿、乾坤事了。", "但细数斋年几人存，更宰相高年，几人能到。"]'),
('song-ci-431','洞仙歌','刘辰翁','宋','宋词','song-ci','洞仙歌','[]','有客从余，不计余无酒。',101,'宋词/ci.song.17000.json','["有客从余，不计余无酒。", "袖有蟠桃为君寿。", "叹此桃再熟，也须年后。", "甚辨得，转盼个偷桃手。", "菊潭三十斛，月又月添，天赋先生日更久。", "但黄杨长寸，闰年倒寸，似凭得到梧宫甚时候。", "客又道奇特是阳生，后七日相看，醉春风柳。"]'),
('song-ci-432','齐天乐','刘辰翁','宋','宋词','song-ci','齐天乐','[]','枝头雨是青梅泪。',123,'宋词/ci.song.17000.json','["枝头雨是青梅泪。", "翻作一江春水。", "鱼腹魂销，龙舟叫彻，不了湖亭张戏。", "满庭芳芷。", "正艾日高高，葛风细细。", "试比陈人，人间除我更谁似。", "浮沉君共我里。", "记薰廊待对，闻鸡蹴起。", "昨日蟾蜍，明朝蝇虎，身与渠衰更悴。", "老夫病已。", "任采绿采苓，为师为帝。", "但有昌阳，倩酤扶路醉。"]'),
('song-ci-433','齐天乐','刘辰翁','宋','宋词','song-ci','齐天乐','[]','海枯泣尽天吴泪。',123,'宋词/ci.song.17000.json','["海枯泣尽天吴泪。", "又涨经天河水。", "万古鱼龙，雷收电卷，宇宙刹那间戏。", "沉兰坠芷。", "想重整荷衣，顿惊腰细。", "尚有干将，冲牛射斗定何似。", "成都桥动万里。", "叹何时重见，鹃啼人起。", "孤竹双清，紫荆半落，到此吟枯神瘁。", "对床永已。", "但梦绕青神，尘昏白帝。", "重反离骚，众醒吾独醉。"]'),
('song-ci-434','齐天乐','刘辰翁','宋','宋词','song-ci','齐天乐','[]','蒋陵故是簪花路。',123,'宋词/ci.song.17000.json','["蒋陵故是簪花路。", "风烟奈何秋暑。", "候馆凋梧，宫墙断柳，谁识当年倦旅。", "余怀何许。", "想上马人扶，翠眉愁聚。", "旧日方回，而今能赋断肠语。", "登高能赋最苦。", "叹高高难问，欲望迷处。", "蝶绕东篱，鸿翻上苑，那更画梁辞主。", "来今往古。", "漫湛辈同来，远公回去。", "我醉安归，黄花扶路舞。"]'),
('song-ci-435','江城梅花引','刘辰翁','宋','宋词','song-ci','江城梅花引','[]','几年城中无看灯。',108,'宋词/ci.song.17000.json','["几年城中无看灯。", "夜三更。", "月空明。", "野庙残梅，村鼓自春声。", "长笑儿童忙踏舞，何曾见，宣德棚，不夜城。", "去年今年又伤心。", "去年晴。", "去年曾。", "不似今年，闲坐处、却不曾行。", "忆去年人、弹烛泪纵横。", "想见西窗窗下月，窗下月，是无情，是有情。"]'),
('song-ci-436','江城梅花引','刘辰翁','宋','宋词','song-ci','江城梅花引','[]','相思无处著春寒。',108,'宋词/ci.song.17000.json','["相思无处著春寒。", "傍阑干。", "湿阑干。", "似我情怀，处处忆临安。", "想见夜深村鼓静，灯晕碧，为傍人，说上元。", "是花是雪无意看。", "雨摧残。", "雨摧残。", "探春未还。", "到春还、似不如闲。", "感恨千般、憔悴做花难。", "不惜与君同一醉，君不见，铜雀台，望老瞒。"]'),
('song-ci-437','兰陵王','刘辰翁','宋','宋词','song-ci','兰陵王','[]','雁归北。',160,'宋词/ci.song.17000.json','["雁归北。", "渺渺茫茫似客。", "春湖里，曾见去帆，谁遣江头絮风息。", "千年记当日。", "难得。", "宽闲抱膝。", "兴亡事，马上飞花，看取残阳照亭驿。", "哀拍。", "愿归骨。", "怅毡帐何匹，湩酪何食。", "相思青冢头应白。", "想荒坟酹酒，过车回首，香魂携手抱相泣。", "但青草无色。", "语绝。", "更愁极。", "漫一番青青，一番陈迹。", "瑶池黄竹哀离席。", "约八骏犹到，露桃重摘。", "金铜知道，忍去国，忍去国。"]'),
('song-ci-438','兰陵王','刘辰翁','宋','宋词','song-ci','兰陵王','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','送春去。',159,'宋词/ci.song.17000.json','["送春去。", "春去人间无路。", "秋千外、芳草连天，谁遣风沙暗南浦。", "依依甚意绪。", "漫忆海门飞絮。", "乱鸦过，斗转城荒，不见来时试灯处。", "春去。", "最谁苦。", "但箭雁沉边，梁燕无主。", "杜鹃声里长门暮。", "想玉树凋土，泪盘如露。", "咸阳送客屡回顾。", "斜日未能度。", "春去。", "尚来否。", "正江令恨别，庾信愁赋。", "苏堤尽日风和雨。", "叹神游故国，花记前度。", "人生流落，顾孺子，共夜雨。"]'),
('song-ci-439','琐窗寒','刘辰翁','宋','宋词','song-ci','琐窗寒','[]','嫩绿如新，娇莺似旧，今吾非故。',120,'宋词/ci.song.17000.json','["嫩绿如新，娇莺似旧，今吾非故。", "空山过雨，睍睆留春春去。", "似尊前曲曲阳关，行人回首江南处。", "漫停云低黯，征衫憔悴，酒痕犹污。", "欲语。", "浑未住。", "记匹马经行，风林烟树。", "家山何在，想见绿窗啼雾。", "又何堪满目凄凉，故园梦里能归否。", "但数声、惊觉行云，重省佳期误。"]'),
('song-ci-440','归朝歌','刘辰翁','宋','宋词','song-ci','归朝歌','[]','最是一人称好处。',122,'宋词/ci.song.17000.json','["最是一人称好处。", "昨日小春留得住。", "梅花信信望东风，须待公归香满路。", "年时今已度。", "长是巴山深夜雨。", "宣又召，凯还簇簇，要见寿觞举。", "扫尽窝蜂闲绣斧。", "叠鼓春声欢岁暮。", "燕台剑履趣锋车，银信低低传好语。", "紫貂裘脱与。", "肘印累累映三组。", "但重省，西来斗水，忘却爱卿取。"]'),
('song-ci-441','大圣乐','刘辰翁','宋','宋词','song-ci','大圣乐','[]','芳草如云，飞红似雨，卖花声过。',135,'宋词/ci.song.17000.json','["芳草如云，飞红似雨，卖花声过。", "况回首、洗马塍荒，更寒食、宫人斜闭，烟雨铜驼。", "提壶卢何所得酒，泥滑滑、行不得也哥哥。", "伤心处，斜阳巷陌，人唱西河。", "天下事，不如意十常八九，无奈何。", "论兵忍事，对客称好，面皱如靴。", "广武噫嘻，东陵反覆，欢乐少兮哀怨多。", "休眉锁。", "问朱颜去也，还更来麽。"]'),
('song-ci-442','宝鼎现','刘辰翁','宋','宋词','song-ci','宝鼎现','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','红妆春骑。',192,'宋词/ci.song.17000.json','["红妆春骑。", "踏月影、竿旗穿市。", "望不尽、楼台歌舞，习习香尘莲步底。", "箫声断、约彩鸾归去，未怕金吾呵醉。", "甚辇路、喧阗且止。", "听得念奴歌起。", "父老犹记宣和事。", "抱铜仙、清泪如水。", "还转盼、沙河多丽。", "滉漾明光连邸第。", "帘影冻、散红光成绮。", "月浸葡萄十里。", "看往来、神仙才子。", "肯把菱花扑碎。", "肠断竹马儿童，空见说、三千乐指。", "等多时春不归来，到春时欲睡。", "又说向、灯前拥髻。", "暗滴鲛珠坠。", "便当日、亲见霓裳，天上人间梦里。"]'),
('song-ci-443','祝英台近','刘辰翁','宋','宋词','song-ci','祝英台近','[]','昨朝晴，今朝雨。',95,'宋词/ci.song.17000.json','["昨朝晴，今朝雨。", "渺莽遽如许。", "厌听儿童，总是涨江语。", "是谁力挽天河，误他仙客，并失却、乘槎来路。", "断肠苦。", "翦烛深夜巴山，酒醒听如故。", "勃窣荷衣，堕泪少乾土。", "从初错铸鸱夷，不如归去，到今此、欲归何处。"]'),
('song-ci-444','祝英台近','刘辰翁','宋','宋词','song-ci','祝英台近','[]','看师师、成蝶蝶。',95,'宋词/ci.song.17000.json','["看师师、成蝶蝶。", "蹙尽不成叠。", "欲试搔头，花重怎堪捻。", "是谁抛过东墙，今无赤凤，梦得似、那人身捷。", "年时腊。", "曾笑梅梢和豆，去月忽如荚。", "便向龙门，无复钏金接。", "待教开到琼林，阆仙重见，又谁念、昆明前劫。"]'),
('song-ci-445','忆旧游','刘辰翁','宋','宋词','song-ci','忆旧游','[]','渺山城故苑，烟横绿野，林胜青油。',122,'宋词/ci.song.17000.json','["渺山城故苑，烟横绿野，林胜青油。", "甚相思只在，华清泉侧，凝碧池头。", "故人念我何处，坠泪水西流。", "念寒食如君，江南似我，花絮悠悠。", "不知身南北，对断烟禁火，蹇六年留。", "恨听莺不见，到而今又恨，睍睆成愁。", "去年相携流落，回首隔芳洲。", "但行去行来，春风春水无过舟。"]'),
('song-ci-446','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','["\u957f\u6c5f"]','明月满沧洲。',74,'宋词/ci.song.17000.json','["明月满沧洲。", "长江一意流。", "更何人、横笛危楼。", "天地不知兴废事，三十万、八千秋。", "落叶女墙头。", "铜驼无恙不。", "看青山、白骨堆愁。", "除却月宫花树下，尘坱莽、欲何游。"]'),
('song-ci-447','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','["\u592a\u6e56"]','风露小瀛洲。',74,'宋词/ci.song.17000.json','["风露小瀛洲。", "斜河倒海流。", "人间尘、不到琼楼。", "错向五陵陵上望，几回月、几回秋。", "落日太湖头。", "垂虹今是不。", "醉尊前、往往成愁。", "便有扁舟西子在，无汗漫、与君游。"]'),
('song-ci-448','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','寒雁下荒洲。',74,'宋词/ci.song.17000.json','["寒雁下荒洲。", "寒声带影流。", "便寄书、不到红楼。", "如此月明如此酒，无一事、但悲秋。", "万弩落潮头。", "灵胥还怒不。", "满湖山、犹是春愁。", "欲向涌金门外去，烟共草、不堪游。"]'),
('song-ci-449','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','日落紫霞洲。',74,'宋词/ci.song.17000.json','["日落紫霞洲。", "兰舟稳放流。", "玉虹仙、如在黄楼。", "何必锦袍吹玉笛，听欸乃、数声秋。", "赤壁舞涛头。", "周郎还到不。", "倚西风、袅袅余愁。", "唤起横江飞道士，来伴我、月中游。"]'),
('song-ci-450','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','零露下长洲。',73,'宋词/ci.song.17000.json','["零露下长洲。", "云翻海倒流。", "素娥深、不到西楼。", "忽觉断潮归去也，饮不尽、一轮秋。", "城外土馒头。", "人能饮恨不。", "古人不见使吾愁，莫有横江孤鹤过，来伴我、醉中游。"]'),
('song-ci-451','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','明月满河洲。',74,'宋词/ci.song.17000.json','["明月满河洲。", "星河带月流。", "料素娥、独倚琼楼。", "竟是何年何药误，魂梦冷、不禁秋。", "少日梦龙头。", "知君犹梦不。", "算虚名、不了闲愁。", "便有鹄袍三万辈，应不是、旧京游。"]'),
('song-ci-452','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','残日下瓜洲。',74,'宋词/ci.song.17000.json','["残日下瓜洲。", "平安火又流。", "月高高、挂古城楼。", "回首少年真可笑，无一事、又悲秋。", "天在海边头。", "天风有意不。", "结桂枝、袅袅余愁。", "不是银河无去路，先不去、后难游。"]'),
('song-ci-453','唐多令','刘辰翁','宋','宋词','song-ci','唐多令','[]','春雨满江城。',73,'宋词/ci.song.17000.json','["春雨满江城。", "汀洲春水生。", "更悲久雨似春酲。", "犹有一般天富贵，夜来雨、早来晴。", "年少总看灯。", "老来犹故情。", "便无灯、也自盈盈。", "说著春情谁不爱，今夜月、有人行。"]'),
('song-ci-454','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','空明一朵扬州白。',66,'宋词/ci.song.17000.json','["空明一朵扬州白。", "红紫无□色。", "是谁唤作水晶球。", "惹起高烧银烛、上元愁。", "去年一捧飞来雪。", "不似渠千叶。", "狂风一蹴过秋千。", "憔悴玉人和泪、望婵娟。"]'),
('song-ci-455','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','天香国色辞脂粉。',66,'宋词/ci.song.17000.json','["天香国色辞脂粉。", "肯爱红衫嫩。", "け然自取玉为衣。", "似是银河水皱、织成机。", "寒欺薄薄春无力。", "月浸霓裳湿。", "一窠香雪世间稀。", "可惜不教留到、布衣时。"]'),
('song-ci-456','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','寿安楼子重重蕊。',66,'宋词/ci.song.17000.json','["寿安楼子重重蕊。", "少见如鱼尾。", "向来染得渭脂红。", "又自细摇花浪、动春风。", "赪鳞似是人谁信。", "但向残红认。", "若教随水去悠然。", "为报沙头玉鹭、莫贪鲜。"]'),
('song-ci-457','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','花心定有何人捻。',66,'宋词/ci.song.17000.json','["花心定有何人捻。", "晕晕如娇靥。", "一痕明月老春宵。", "正似酥胸潮脸、不曾销。", "当年掌上开元宝。", "半是杨妃爪。", "若教此掏到痴人。", "任是高墙无路、蝶翻身。"]'),
('song-ci-458','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','无花敢与姚黄比。',66,'宋词/ci.song.17000.json','["无花敢与姚黄比。", "对对鸳鸯起。", "识他金带万钉垂。", "谁向麒麟楦里、卸猴绯。", "潜溪以上难为说。", "自是君恩别。", "后来西子避无盐。", "又道君王捉鼻、又何嫌。"]'),
('song-ci-459','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','魏家品是君王后。',66,'宋词/ci.song.17000.json','["魏家品是君王后。", "岂比昭容袖。", "风吹满院绣囊香。", "谁赐大师师号、退昭阳。", "飞霞一落无根蒂。", "空坠重华泪。", "离披正午盛时休。", "闲为思王重赋、洛神愁。"]'),
('song-ci-460','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','犹疑绿萼花微甚。',66,'宋词/ci.song.17000.json','["犹疑绿萼花微甚。", "难与青莲并。", "青莲朵朵是天人。", "又向天人想见、洛阳春。", "多情素质尘生步。", "况被潘妃污。", "此花仍是□微赪。", "却似娇波波外、两眉青。"]'),
('song-ci-461','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','楼台烟雨朱门悄。',66,'宋词/ci.song.17000.json','["楼台烟雨朱门悄。", "乔木芳云杪。", "半窗天晓又闻莺。", "比似当年春尽、最关情。", "客中自被啼鹃恼。", "况落春归道。", "满怀憔悴有谁知。", "犹记涌金门外、送人时。"]'),
('song-ci-462','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','黄柑擘破传春雾。',66,'宋词/ci.song.17000.json','["黄柑擘破传春雾。", "新酒如清露。", "城中也是几分灯。", "自爱城山堂上、两三星。", "枝头未便风和雨。", "寂寞无歌舞。", "天公肯放上元晴。", "自是六街三市、少人行。"]'),
('song-ci-463','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','徐家破镜昏如雾。',66,'宋词/ci.song.17000.json','["徐家破镜昏如雾。", "半面人间露。", "等闲相约是看灯。", "谁料人间天上、似流星。", "朱门帘影深深雨。", "憔悴新人舞。", "天涯海角赏新晴。", "惟有桥边卖镜、是闲行。"]'),
('song-ci-464','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','黄帘绿幕窗垂雾。',66,'宋词/ci.song.17000.json','["黄帘绿幕窗垂雾。", "表立如承露。", "夕郎偷看御街灯。", "归奔河边残点、乱如星。", "开园蒋李游春雨。", "蛱蝶穿人舞。", "如今烟草锁春晴。", "并与苏堤葛岭、不堪行。"]'),
('song-ci-465','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','鞓红乾色无光霁。',66,'宋词/ci.song.17000.json','["鞓红乾色无光霁。", "须是鲜鲜翠。", "け然一点系裙腰。", "不著人间金屋、恐难销。", "英英肯似焉支贵。", "漫脱红霞帔。", "落时且勿涴尘泥。", "留向天台洞口、泛吾诗。"]'),
('song-ci-466','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','湿云待向三更吐。',66,'宋词/ci.song.17000.json','["湿云待向三更吐。", "更是沉沉雨。", "眼前儿女意堪怜。", "不说明朝后日、说明年。", "当年知道晴三鼓。", "便似佳期误。", "笑他拜月不曾圆。", "只是今朝北望、也凄然。"]'),
('song-ci-467','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','梅梢腊尽春归了。',66,'宋词/ci.song.17000.json','["梅梢腊尽春归了。", "毕竟春寒少。", "乱山残烛雪和风。", "犹胜阴山海上、窖群中。", "年光老去才情在。", "惟有华风改。", "醉中幸自不曾愁。", "谁唱春花秋叶、泪偷流。"]'),
('song-ci-468','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','情知是梦无凭了。',66,'宋词/ci.song.17000.json','["情知是梦无凭了。", "好梦依然少。", "单于吹尽五更风。", "谁见梅花如泪、不言中。", "儿童问我今何在。", "烟雨楼台改。", "江山画出古今愁。", "人与落花何处、水空流。"]'),
('song-ci-469','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','轻衫倚望春晴稳。',66,'宋词/ci.song.17000.json','["轻衫倚望春晴稳。", "雨压青梅损。", "皱绡池影泛红蔫。", "看取断云来去、似炉烟。", "愁春来暮仍愁暮。", "受却寒无数。", "年来无地卖花栽。", "向道明年花信、莫须来。"]'),
('song-ci-470','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','娟娟二八清明了。',66,'宋词/ci.song.17000.json','["娟娟二八清明了。", "犹说淮阳早。", "钱欧陆谱遍花光。", "红到寿阳、也不说淮阳。", "此花地望元非薄。", "回首伤流落。", "洛阳闲岁断春风。", "怎不当时道是、洛阳红。"]'),
('song-ci-471','虞美人','刘辰翁','宋','宋词','song-ci','虞美人','[]','秋阴团扇如人老。',66,'宋词/ci.song.17000.json','["秋阴团扇如人老。", "渐近中秋好。", "新凉远忆小楼边。", "自在一窗明月、傍人眠。", "多情谁到星河晓。", "只道圆时少。", "他年几处与君看。", "长是成愁成恨、不成欢。"]'),
('song-ci-472','恋绣衾','刘辰翁','宋','宋词','song-ci','恋绣衾','[]','胭脂不涴紫玉箫。',68,'宋词/ci.song.17000.json','["胭脂不涴紫玉箫。", "认宫中、银字未销。", "但凤去、台空古，比落花、无第二朝。", "天涯流落哀声在，听乌乌、不似内娇。", "漫身似、商人妇，泣孤舟、长夜寂寥。"]'),
('song-ci-473','恋绣衾','刘辰翁','宋','宋词','song-ci','恋绣衾','[]','困如宿酒犹未销。',67,'宋词/ci.song.17000.json','["困如宿酒犹未销。", "满华堂、羞见目招。", "忽折向、西邻去，教旁人、看上马娇。", "肉色似花难可得，但花如、肉色妖娆。", "谁说汉宫飞燕，到而今、犹带脸潮。"]'),
('song-ci-474','恋绣衾','刘辰翁','宋','宋词','song-ci','恋绣衾','[]','当年三五舞太平。',68,'宋词/ci.song.17000.json','["当年三五舞太平。", "醉归来、花影满庭。", "办永夜、重开宴，笑姑苏、万眼未明。", "而今绕市歌儿马，客黄昏、细雨满城。", "十年事、去如水，想家人、村庙看灯。"]'),
('song-ci-475','花犯','刘辰翁','宋','宋词','song-ci','花犯','[]','海山昏，寒云欲下，低低压吹帽。',125,'宋词/ci.song.17000.json','["海山昏，寒云欲下，低低压吹帽。", "平沙浩浩。", "想关塞无烟，时动衰草。", "苏郎卧处愁难扫。", "江南春不到。", "但怅望、雪花夜白，人间憔悴好。", "谁知广寒梦无憀，丁宁白玉炼，不关怀抱。", "看清浅、桑田外，尘生热恼。", "待说与、天公知道。", "期腊尽春来事宜早。", "更几日、银河信断，梅花容易老。"]'),
('song-ci-476','花犯','刘辰翁','宋','宋词','song-ci','花犯','[]','甚天花、纷纷坠也，偏偏著余帽。',124,'宋词/ci.song.17000.json','["甚天花、纷纷坠也，偏偏著余帽。", "乾坤清皓。", "任海角荒荒，都变瑶草。", "落梅天上无人扫。", "角吹吹不到。", "想特为、东皇开宴，琼林依旧好。", "看儿贪耍不知寒，须塑就玉狮，置儿怀抱。", "奈转眼、今何在，泪痕成恼。", "白发翁翁向儿道。", "那曲巷袁安爱晴早。", "便把似、一年春看，惜花花自老。"]'),
('song-ci-477','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','冰肌玉骨，笑嫣然、总是风尘中物。',121,'宋词/ci.song.17000.json','["冰肌玉骨，笑嫣然、总是风尘中物。", "谁扫一枝，流落到、绝域高台素壁。", "匹马南来，千山万水，为访林间雪。", "渊明爱菊，不知谁是花杰。", "憔悴梦断吴山，有何人报我，前村夜发。", "蜡屐霜泥烟步外，转入波光明灭。", "雪后风前，水边竹外，岁晚华余发。", "戴花人去，江妃空弄明月。"]'),
('song-ci-478','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','四无谁语，待推窗、初见江南风物。',121,'宋词/ci.song.17000.json','["四无谁语，待推窗、初见江南风物。", "索笑巡檐无奈处，悄隔东邻一壁。", "有酒如船，招呼满载，只欠枝头雪。", "疏花冷眼，坐中都是词杰。", "堪恨几日西郊，寻消问息，肯向吟边发。", "著意相看，又恐是、六出幻成还灭。", "恼恨儿童，攀翻顶戴，不到先生发。", "明朝重省，初三知属谁月。"]'),
('song-ci-479','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','五朝寿俊，算生平占得、淳熙四四。',120,'宋词/ci.song.17000.json','["五朝寿俊，算生平占得、淳熙四四。", "三万六千三万了，剩有一千饶底。", "三百年间，和风丽日，几个能销此。", "约山山笑，先生不负山矣。", "今岁甲子重阳，待重数，五百十三甲子。", "吟万首诗更自和，岁岁寿诗自喜。", "若比潞公，如今年纪，犹是平章事。", "先生抚掌，问他闲日能几。"]'),
('song-ci-480','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','西风处士，例一枝团月，咸平印印。',120,'宋词/ci.song.17000.json','["西风处士，例一枝团月，咸平印印。", "千古诗宗传不绝，至竟被渠道尽。", "雪返香魂，霜吹晓怨，肯受东君聘。", "罗浮梦转，兔环知是谁孕。", "未说烟雨江南，垂垂青子，须要调金鼎。", "愁绝西山明秀处，依旧鹤南飞影。", "我白君元，君词我和，各自为长庆。", "后来桃李，遥遥别是花信。"]'),
('song-ci-481','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','棹歌齐发，江云暮、吹得湘愁成雨。',121,'宋词/ci.song.17000.json','["棹歌齐发，江云暮、吹得湘愁成雨。", "小酌千年，知他是、阿那年时沈午。", "日落长沙，风回极浦，黯不堪延伫。", "吴头楚尾，非关四面为楚。", "几度唤起醒累，淋漓痛饮，不学愁余句。", "踏鲤从鼋胥涛上，怎不化成龙去。", "越女吴船，燕歌赵舞，世世悠悠许。", "明朝寂寂，双双飞下鸣鹭。"]'),
('song-ci-482','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','岁寒相命，算人间、除了梅花无物。',120,'宋词/ci.song.17000.json','["岁寒相命，算人间、除了梅花无物。", "窥宋三年又不是，草草东邻凿壁。", "偃蹇风前，沉吟竹外，直待天骄雪。", "白家人至，一枝横出终杰。", "寂寞小小疏篱，探花使断，知复何时发。", "北驿不来春又远，只向窗前埋灭。", "好在冰花，著些风筱，怎不清余发。", "补之去后，墨梅又有明月。"]'),
('song-ci-483','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','遥怜儿女，未解忆长安、十年前月。',120,'宋词/ci.song.17000.json','["遥怜儿女，未解忆长安、十年前月。", "徙倚桂枝空延伫，无物同心堪结。", "冷落江湖，萧条门巷，犹著西楼客。", "恨无铁笛，一声吹裂山石。", "休说起舞登楼，那人已先我，渡江横楫。", "圆缺不销青冢恨，漠漠风沙如雪。", "西母长生，素娥好在，何皓当时发。", "山河如此，月中定是何物。"]'),
('song-ci-484','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','[]','团团桂影，怕人道、大地山河里许。',120,'宋词/ci.song.17000.json','["团团桂影，怕人道、大地山河里许。", "旧日影娥池未缺，惊断霓裳歌舞。", "雪白长城，金明古驿，尽是乘槎路。", "少年白发，自无八骏能去。", "犹记流落荒滨，故人相过，共吹箫前度。", "无酒无鱼空此客，昨夜留之不住。", "睡起披衣，行吟坐对，又有重圆处。", "不知今夕，那人有甚佳句。"]'),
('song-ci-485','酹江月・念奴娇','刘辰翁','宋','宋词','song-ci','酹江月・念奴娇','["\u6d1e\u5ead\u6e56"]','城中十万，有何人、和我乌乌鸣瑟。',120,'宋词/ci.song.17000.json','["城中十万，有何人、和我乌乌鸣瑟。", "对影姮娥成三处，谁料尊中无月。", "翦纸吹成，长梯摘取，儿戏那堪惜。", "洞庭夜白，一声聊破空阔。", "休说二十四桥，便一分无赖，有谁谁识。", "一枕秋衾南北梦，好好娟娟成雪。", "旧日少游，锦袍玉笛，醉卧藤阴石。", "萧然今夕，无鱼无酒无客。"]'),
('song-ci-486','满江红','刘辰翁','宋','宋词','song-ci','满江红','[]','淡淡胭脂，似褪向、景阳鸳石。',115,'宋词/ci.song.17000.json','["淡淡胭脂，似褪向、景阳鸳石。", "依然是、春睡未足，捧心犹癖。", "藉甚不禁君再顾，嫣然却记渠初拆。", "黯销魂、欲尽更堪怜，终难得。", "犹记是，卿卿惜。", "空复见，谁谁摘。", "但当时一笑，也成陈迹。", "我懒花残都已往，诗朋酒伴犹相觅。", "听连宵、又雨又还晴，鸠鸣寂。"]'),
('song-ci-487','满江红','刘辰翁','宋','宋词','song-ci','满江红','[]','何许相求，且不是、南温北石。',115,'宋词/ci.song.17000.json','["何许相求，且不是、南温北石。", "也欲学、绝交高论，自陈余癖。", "万里鱼书长记忆，十年波浪伤离拆。", "算此舟、不是剡溪舟，空回得。", "非出处，何须惜。", "非瑕颣，何须摘。", "看雪销鸿去，有何留迹。", "安石岂无同乐意，玄真不是朝廷觅。", "但眼前、真率暂相违，歌声寂。"]'),
('song-ci-488','满江红','刘辰翁','宋','宋词','song-ci','满江红','[]','莺语依然，但春去、人间无约。',115,'宋词/ci.song.17000.json','["莺语依然，但春去、人间无约。", "谁念我、吟情憔悴，醉魂落魄。", "尽日只将行卷续，有时自整残棋著。", "向黄昏、细雨闷无憀，青梅落。", "南又北，相思错。", "朝异暮，人情薄。", "漫踌躇在目，奢华如昨。", "海底月沉天上兔，辽东人化扬州鹤。", "记龙云、波浪岂能平，天难托。"]'),
('song-ci-489','满江红','刘辰翁','宋','宋词','song-ci','满江红','[]','十岁儿童，看骑竹、花阴满城。',115,'宋词/ci.song.17000.json','["十岁儿童，看骑竹、花阴满城。", "与新第、桐乡孙子，高下齐生。", "倚枕不寻柯下梦，举头自爱橘中名。", "但有时、米价问如何，公助平。", "东西塾，听书声。", "长短卷，和诗成。", "总神仙清福，前辈家庭。", "试问凌烟图相国，何如洛寺写耆英。", "甚天公、属意富民侯，银信青。"]'),
('song-ci-490','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','["\u957f\u6c5f"]','问海棠花下，又何如、玄都观中游。',119,'宋词/ci.song.17000.json','["问海棠花下，又何如、玄都观中游。", "叹佺巢蜀锦，常时不数，前度何稠。", "谁见宣华故事，歌舞簇遨头。", "共是西江水，不解西流。", "在处繁华如梦，梦占人年少，生死堪羞。", "任倾城倾国，风雨一春休。", "醉逢君、何须有约，醉留君、系不住扁舟。", "空又失，花前一笑，绿尽芳洲。"]'),
('song-ci-491','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','[]','看团团、一物大如杯，时复几何秋。',119,'宋词/ci.song.17000.json','["看团团、一物大如杯，时复几何秋。", "俯天涯海角，今来古往，人物如流。", "想见霓裳歌罢，无物与浇愁。", "惟有当时树，香满琼楼。", "谁念南楼老子，倚西风尘满，心事悠悠。", "便班姬袖里，明月一时休。", "叹年年、吹箫有约，又一番、鹤梦雪堂舟。", "池上久，满身风露，还索衣裘。"]'),
('song-ci-492','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','[]','记前朝、鹤会又重来，攀翻第三桃。',119,'宋词/ci.song.17000.json','["记前朝、鹤会又重来，攀翻第三桃。", "看云华授策，麻姑擘脯，嬴女吹箫。", "寻思曲江旧事，宫锦胜龙标。", "奏罢清华梦，独立春宵。", "不数相州锦样，是调羹御手，重解金貂。", "但今年此日，疏了醉葡萄。", "闻老仙、衣冠皓伟，又丁宁、天语著儿招。", "都人望，回班赐第，赤舄飞朝。"]'),
('song-ci-493','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','但秋风、年又一年深，不禁长年悲。',119,'宋词/ci.song.17000.json','["但秋风、年又一年深，不禁长年悲。", "自景阳钟断，馆娃宫闭，冷落心知。", "千树西湖杨柳，更管别人离。", "看取茂陵客，一去无归。", "都是旧时行乐，漫烟销日出，水绕山围。", "看人情荏苒，不似鹧鸪飞。", "听砧声、遥连塞外，问三衢、道上去人稀。", "销凝久，残阳短笛，似我歔欷。"]'),
('song-ci-494','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','[]','看飘飘、万里去东流，道伊去如风。',119,'宋词/ci.song.17000.json','["看飘飘、万里去东流，道伊去如风。", "便锦缆危潮，青山御宿，烟雨啼红。", "愁是明朝酒醒，听著返魂钟。", "留得春如故，了不关侬。", "春亦去人远矣，是别情何薄，归兴何浓。", "但江南好□，未便到芙蓉。", "念今夜、初程何处，有何人、垂袖舞行宫。", "青青柳，留君如此，如此匆匆。"]'),
('song-ci-495','八声甘州','刘辰翁','宋','宋词','song-ci','八声甘州','[]','甚花间、儿女笑盈盈。',119,'宋词/ci.song.17000.json','["甚花间、儿女笑盈盈。", "人添雪狮成。", "任踏青无路，凌波有地，步步光尘。", "招得梅妃魂也，好似去年春。", "柳亦何曾絮，都是云英。", "休道东皇诞漫，到茶烟歇后，谁浊谁清。", "赖谢娘好语，端胜解围兵。", "看昨朝、天公雨粟，定大家、快活社翁平。", "春晴好，溶溶雨尽，听卖花声。"]'),
('song-ci-496','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','何须银烛红妆，菜花总是曾留处。',126,'宋词/ci.song.17000.json','["何须银烛红妆，菜花总是曾留处。", "流觞事远，绕梁歌断，题红人去。", "绕蝶东墙，啼莺修竹，疏蝉高树。", "叹一春风雨，归来抱膝，怀往昔、自凄楚。", "遥望东门柳下，梦参差、欲归幽路。", "断红芳草，连空积水，凭高坠雾。", "水洗铜驼，天清华表，升平重遇。", "但相如老去，江淹才尽，有何人赋。"]'),
('song-ci-497','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','多年袖瓣心香，重新拈出为公寿。',126,'宋词/ci.song.17000.json','["多年袖瓣心香，重新拈出为公寿。", "唤起老龙，如今正是，欠伸时候。", "弱语闻莺，轻阴转柳，弦薰未透。", "信江南，自有真孺未用，须待见、衮和绣。", "闻说锋车在道，更四辈、传宣来骤。", "蟠胸何限，天门夜对，春宫晨奏。", "梅子阴浓，菖蒲花老，枯槔闲后。", "但北关下泽，遗民社在，贺公归昼。"]'),
('song-ci-498','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','看人削树成槎，布帆海上秋风浪。',126,'宋词/ci.song.17000.json','["看人削树成槎，布帆海上秋风浪。", "白头坡老，知津水手，倚桄榔杖。", "九点齐州，半生髀肉，烟尘苍莽。", "但北窗梦转，青阴满眼，抚陈迹、玩新涨。", "世事艰难已遍，笑而今、不堪重想。", "龙筋虎骨，根深伏兔，擎空千丈。", "礼乐文章，终须梦卜，南人为相。", "问凌烟生面，他时彷佛，似何人像。"]'),
('song-ci-499','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','闲思十八年前，依稀正是公年纪。',126,'宋词/ci.song.17000.json','["闲思十八年前，依稀正是公年纪。", "铜驼陌上，乌衣巷口，臣清如水。", "是处风筝，满城昼锦，儿郎俊伟。", "但幅巾藜杖，低垂白鬓，用与绮、问何里。", "最忆他年甘旨。", "也曾经、三仕三已。", "至今结习，馀年未了，业多生绮。", "安得滕廛，移将近市，长薰晋鄙。", "望福星炯炯，西江千里，待公来社。"]'),
('song-ci-500','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','多年绿幕黄帘，瓶花黯黯无谁主。',126,'宋词/ci.song.17000.json','["多年绿幕黄帘，瓶花黯黯无谁主。", "荀陈迹远，燕吴路断，何人星聚。", "四圣楼台，水仙华表，冷烟和雨。", "但徘徊梦想，美人不见，空犹记、铁炉步。", "过尽凉风天末，坠华笺、行行飞翥。", "一端翠织，锦鲸茅屋，天吴惊舞。", "念我何辰，涸阴冰子，生怜金虎。", "恨儿痴不了，山川悠缅，共君黉宇。"]'),
('song-ci-501','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','征衫春雨纵横，可曾湿得飞花透。',126,'宋词/ci.song.17000.json','["征衫春雨纵横，可曾湿得飞花透。", "知君念我，溪南徙倚，谁家红袖。", "藉草成眠，簪花倚醉，狂歌扶手。", "叹故人何处，闻鹃堕泪，春去也、到家否。", "说与东风情事，怕东风、似人眉皱。", "乱山华屋，残邻废里，不堪回首。", "寒食江村，牛羊丘陇，茅檐酤酒。", "笑周秦来往，与谁同梦，说开元旧。"]'),
('song-ci-502','水龙吟','刘辰翁','宋','宋词','song-ci','水龙吟','[]','孤烟澹澹无情，角声正送层城暮。',126,'宋词/ci.song.17000.json','["孤烟澹澹无情，角声正送层城暮。", "伤怀绝似，龙山罢后，骑台沉处。", "珠履三千，金人十二，五陵无树。", "叹岐王宅里，黄公垆下，空鼎鼎、记前度。", "几许英雄文武。", "酒不到、故人坟土。", "平生破帽，几番摇落，受西风侮。", "昨日如今，明年此会，俯然怀古。", "便东篱甲子，花开花谢，不堪重数。"]'),
('song-ci-503','宴春台','刘辰翁','宋','宋词','song-ci','宴春台','[]','五十三年，韶华刚度，今年夏五十三。',122,'宋词/ci.song.17000.json','["五十三年，韶华刚度，今年夏五十三。", "瑞鹤朝来，待公弥月重探。", "人生贵寿多男。", "看斓斑室，添个荷衫。", "□□□，亭亭八面，醉倚红酣。", "承平故事，暇日清谈。", "云龙风虎，塞北江南。", "午桥午枕，羲皇白日如惔。", "手种蟠桃，明年看取，实大如柑。", "奈何堪。", "天妒人睡美，趣趁朝参。"]'),
('song-ci-504','扫花游・扫地游','刘辰翁','宋','宋词','song-ci','扫花游・扫地游','[]','春台路古，想店月潭云，鸡鸣关候。',117,'宋词/ci.song.17000.json','["春台路古，想店月潭云，鸡鸣关候。", "巾车尔久。", "记湘累降日，留词劝酒。", "不是行边，待与持杯论斗。", "算吾寿。", "已待得河清，万古晴昼。", "京国事转手。", "漫宫粉堆黄，髻妆啼旧。", "瑶池在否。", "自刘郎去后，宴期重负。", "解事天公，道是全无又有。", "浯溪友。", "笑浯溪、至今聱叟。"]'),
('song-ci-505','忆江南','刘辰翁','宋','宋词','song-ci','忆江南','[]','花几许，已报八分催。',64,'宋词/ci.song.17000.json','["花几许，已报八分催。", "却问主人何处去，且容老子个中来。", "花外主人回。", "年时客，如今安在哉。", "正喜锦宫城烂漫，忽惊花鸟使摧颓。", "世事只添杯。"]'),
('song-ci-506','梅花引','刘辰翁','宋','宋词','song-ci','梅花引','[]','酒熟未。',70,'宋词/ci.song.17000.json','["酒熟未。", "梅开未。", "去年迟待重来醉。", "笑当筵。", "舞当筵。", "惟有今年。", "八十是开年。", "参差野袂成归鹤。", "石鼎未开容剥啄。", "岁开尊。", "岁添孙。", "孙又开尊。", "福曜萃高门。"]'),
('song-ci-507','蝶恋花','刘辰翁','宋','宋词','song-ci','蝶恋花','[]','过雨新荷生水气。',70,'宋词/ci.song.17000.json','["过雨新荷生水气。", "高影参差，无谓思量睡。", "梦里不知轻别意。", "醒来竟是谁先起。", "去路夕阳芳草际。", "不论阑干，处处情怀似。", "记得分明羞掷蕊。", "自知不是天仙子。"]'),
('song-ci-508','蝶恋花','刘辰翁','宋','宋词','song-ci','蝶恋花','[]','八九十翁嬉入市。',70,'宋词/ci.song.17000.json','["八九十翁嬉入市。", "把菊簪萸，共说新篘美。", "何以祝公千百岁。", "寿潭自酌花间水。", "白鹭沉沉飞复起。", "杜老江头，不恨秋风里。", "欲种蟠根天上李。", "三千年看青青子。"]'),
('song-ci-509','霓裳中序第一','刘辰翁','宋','宋词','song-ci','霓裳中序第一','[]','银河下若木。',125,'宋词/ci.song.17000.json','["银河下若木。", "暖涨一川春雾绿。", "白凤徘徊清淑。", "似沉水无烟，礜汤千斛。", "柔肌暗粟。", "想临流、娇喷轻触。", "空恨恨，何人热恼，却忆冷泉掬。", "酥玉。", "未谙汤沐。", "深又浅、荡摇心目。", "云蒸雨渍翻覆。", "泛影浮红，飘飘相逐。", "裳衣还未欲。", "蓦自怪、野鸳双浴。", "华清远，寒猿夜绕，落月可能漉。"]'),
('song-ci-510','瑞龙吟','刘辰翁','宋','宋词','song-ci','瑞龙吟','[]','老人语。',163,'宋词/ci.song.17000.json','["老人语。", "曾见昨日开炉，坠天花否。", "生年不合荒荒，枯根薄命，婵娟误汝。", "那知许。", "女乐如烟点点，江南处处。", "何时重到湖堧，淋漓载酒，依稀吊古。", "终待胭脂露掌，弄鸥招鹤，凭君画取。", "万柳漫堤，一丝一泪垂雨。", "濛濛絮里，又送金铜去。", "漫肠断、王孙望帝，呕心囊句。", "市隐今成趣。", "袖回地狭，天吴凤舞。", "莫是青州谱。", "怎不早，翩翩向青州住。", "回头蜃海，已沉花雾。"]'),
('song-ci-511','满庭芳','刘辰翁','宋','宋词','song-ci','满庭芳','[]','千骑家山，一觞父老，前有韩魏公来。',117,'宋词/ci.song.17000.json','["千骑家山，一觞父老，前有韩魏公来。", "青原上巳，才见寿筵开。", "欧公云间还见，忆相州、更自迟回。", "公知否，福星分野，飞骑不须排。", "留春亭下草，雪霜过了，依旧春荄。", "待留春千岁，日醉千杯。", "却怕催归丹诏，栋明堂、须要雄材。", "趋朝去，西风便面，只手障浮埃。"]'),
('song-ci-512','满庭芳','刘辰翁','宋','宋词','song-ci','满庭芳','[]','空谷无花，新篘有酒，去年穷胜今年。',118,'宋词/ci.song.17000.json','["空谷无花，新篘有酒，去年穷胜今年。", "蛩吟蛩和，且省费蛮笺。", "闻说先生去也，江南岸、缚草为船。", "依然在，山栖寒食，路断却归廛。", "老人，三又两，清风作供，晴日生烟。", "但高高杜宇，不办行缠。", "几度披衣教我，二升内、煮石烧铅。", "休重道，玉龙无孔，夜夜叫穿天。"]'),
('song-ci-513','木兰花慢','刘辰翁','宋','宋词','song-ci','木兰花慢','[]','午桥清夜饮，花露重、烛光寒。',123,'宋词/ci.song.17000.json','["午桥清夜饮，花露重、烛光寒。", "约处处行歌，朝朝买酒，典却朝衫。", "尊前自堪一醉，但落红、枝上不堪安。", "归去柳阴行月，酒醒画角声残。", "王宫。", "难得似君闲。", "闲我见君难。", "记李陌看花，光阴冉冉，风雨番番。", "相逢故人又别，送君归、斜日万重山。", "江上愁思满目，离离芳草平阑。"]'),
('song-ci-514','木兰花慢','刘辰翁','宋','宋词','song-ci','木兰花慢','[]','自崆峒麦熟，耕犊满、桔槔闲。',123,'宋词/ci.song.17000.json','["自崆峒麦熟，耕犊满、桔槔闲。", "笑吾党清谈，长衣櫑具，更进贤冠。", "仓皇庇公宇下，便秋风、江上不惊寒。", "雪夜入三城易，槐阴护一家难。", "东山。", "零雨几时还。", "领客竹林间。", "看满座空尊，轻裘缓带，绿鬓朱颜。", "风流一笑余事，定碑金、无恙庾家完。", "又赋南烹初食，明朝餐玉何山。"]'),
('song-ci-515','永遇乐','刘辰翁','宋','宋词','song-ci','永遇乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','璧月初晴，黛云远澹，春事谁主。',128,'宋词/ci.song.17000.json','["璧月初晴，黛云远澹，春事谁主。", "禁苑娇寒，湖堤倦暖，前度遽如许。", "香尘暗陌，华灯明昼，长是懒携手去。", "谁知道，断烟禁夜，满城似愁风雨。", "宣和旧日，临安南渡，芳景犹自如故。", "缃帙流离，风鬟三五，能赋词最苦。", "江南无路，鄜州今夜，此苦又谁知否。", "空相对，残釭无寐，满村社鼓。"]'),
('song-ci-516','永遇乐','刘辰翁','宋','宋词','song-ci','永遇乐','[]','灯舫华星，崖山碇口，官军围处。',128,'宋词/ci.song.17000.json','["灯舫华星，崖山碇口，官军围处。", "璧月辉圆，银花焰短，春事遽如许。", "麟洲清浅，鳌山流播，愁似汨罗夜雨。", "还知道，良辰美景，当时邺下仙侣。", "而今无奈，元正元夕，把似月朝十五。", "小庙看灯，团街转鼓，总是添恻楚。", "传柑袖冷，吹藜漏尽，又见岁来岁去。", "空犹记，弓弯一句，似虞兮语。"]'),
('song-ci-517','内家娇','刘辰翁','宋','宋词','song-ci','内家娇','[]','结客少年场。',135,'宋词/ci.song.17000.json','["结客少年场。", "携高李、闻笛赋游梁。", "看汉水淮山，高楼共卧，融尊郑驿，飞盖相望。", "春风里，种他红与白，笑我懒中忙。", "供奉后来，玄都桃改，佳人好在，庾岭梅香。", "何处最难忘。", "会稽归鬓晚，空带吴霜。", "赢得黄冠野服，笑傲羲皇。", "看花外小车，出长生洞，橘中二老，斗智琼黄。", "称寿堂添十字，孙认三房。"]'),
('song-ci-518','六州歌头','刘辰翁','宋','宋词','song-ci','六州歌头','[]','向来人道，真个胜周公。',182,'宋词/ci.song.17000.json','["向来人道，真个胜周公。", "燕然眇。", "浯溪小。", "万世功。", "再建隆。", "十五年宇宙，宫中膺。", "堂中伴。", "翻虎鼠，搏鸇雀，覆蛇龙。", "鹤发庞眉，憔悴空山久，来上东封。", "便一朝符瑞，四十万人同。", "说甚东风。", "怕西风。", "甚边尘起，渔阳惨。", "霓裳断。", "广寒宫。", "青楼杳。", "朱门悄。", "镜湖空。", "里湖通。", "大纛高牙去，人不见，港重重。", "斜阳外，芳草碧，落花红。", "抛尽黄金无计，方知道、前此和戎。", "但千年传说，夜半一声铜。", "何面江东。"]'),
('song-ci-519','六丑','刘辰翁','宋','宋词','song-ci','六丑','[]','看东风海底，送落日、飞空如掷。',171,'宋词/ci.song.17000.json','["看东风海底，送落日、飞空如掷。", "醉游暮归，怕西州堕策。", "归路偏失。", "记上元时节，千门立马，望金坡残雪。", "素娥推下团栾辙。", "塞草惊尘，河水渡楫。", "悠悠雨丝风拂。", "但相随断雁，时度荒泽。", "回头紫陌。", "梦归归未得。", "憔悴江南，秋风旧客。", "去年说著今日。", "漫故人相命，玳筵鸣瑟。", "愁汗漫、全林杯窄。", "况飘泊相遇，当时老叟，梨园歌籍。", "高歌为我几回阕。", "似子规、落月啼乌悄，傍人泪滴。"]'),
('song-ci-520','百字令・念奴娇','刘辰翁','宋','宋词','song-ci','百字令・念奴娇','[]','少微星小。',120,'宋词/ci.song.17000.json','["少微星小。", "抚剑气横空，隐见林杪。", "夜来宋都如雨，更长得奇哉懰皎。", "与汝三龄，览余初度，一语占先兆。", "暮年喜见，甲申聚五星照。", "堪叹亡国馀民，老人孺子，尔汝霜桥晓。", "骑马听鸡朝寂寞，梦入南枝三绕。", "洛社耆英，行窝真率，著我真堪笑。", "与公试数，开禧嘉定宝绍。"]'),
('song-ci-521','百字令・念奴娇','刘辰翁','宋','宋词','song-ci','百字令・念奴娇','[]','洞房停烛，似新岁，数到上元时节。',120,'宋词/ci.song.17000.json','["洞房停烛，似新岁，数到上元时节。", "一盏屠苏千岁酒，添得新人罗列。", "昨日迎长，今朝献寿，尝团团佳月。", "永和春好，用之不竭嘉客。", "见说海上归来，有如瓜大枣，无人分得。", "六十二三刘梦得，输与香山乐色。", "菱谷二绡，杨枝春草，歌舞琵琶笛。", "只愁元日，玉龙催上金驿。"]'),
('song-ci-522','莺啼序','刘辰翁','宋','宋词','song-ci','莺啼序','[]','匆匆何须惊觉，唤草庐人起。',291,'宋词/ci.song.17000.json','["匆匆何须惊觉，唤草庐人起。", "算成败利钝，非臣逆睹，至死后已。", "又何似、采桑八百，看蚕夜织小窗里。", "漫二升自苦，教人吊卧龙里。", "别有佳人，追桃恨李。", "拥凝香绣被。", "争知道、壮士悲歌，萧萧正度寒水。", "问荆卿、田横古墓，更谁载酒为君酹。", "过霜桥落月，老人不见遗履。", "置之勿道，逝者如斯，甚矣衰久矣。", "君其为吾归计，为耕计。", "但问某所泉甘，何乡鱼美。", "此生不愿多才艺。", "功名马上兜鍪出，莫书生、误尽了人间事。", "昔年种柳江潭，攀枝折条，噫嘻树犹如此。", "登高一笑，把菊东篱，且复聊尔耳。", "试回首、龙山路断，走马台荒，渭水秋风，沙河夜市。", "休休莫莫，毋多酌我，我狂最喜高歌去，但高歌、不是番腔底。", "此时对影成三，呼娥起舞，为何人喜。"]'),
('song-ci-523','莺啼序','刘辰翁','宋','宋词','song-ci','莺啼序','[]','闷如愁红著雨，卷地吹不起。',292,'宋词/ci.song.17000.json','["闷如愁红著雨，卷地吹不起。", "便故人渺渺，相逢前事，欲语还已。", "凝望久、荒城落日，五湖四海烟浪里。", "问而今何处，寄声旧时邻里。", "闲说那回，海上苏李。", "雪深夜如被。", "想携手、汉天不语，叫□不应疑水。", "待河梁、一尊落月，生非死别君如酹。", "望故人阁上，依稀长剑方履。", "古人已矣，垂名青史，谓当如此矣。", "又谁料浮沈，自得鱼计。", "赏心乐事，良辰美景，撞钟舞女，朱门大第。", "雕鞍骏马番装笠，笑虚名何与身前事。", "区区相望，饿死西山，悬目东门，人生何乐为此。", "古人已矣，天下英雄，使君与操耳。", "听喔喔、鸡鸣早起，屡舞徘徊，痛饮高楼，狂歌过市。", "苍苍万古，羲农周孔，文章事业星辰上，到而今、枯见银河底。", "笑他黄纸除君，红旗报我，为君助喜。"]'),
('song-ci-524','莺啼序','刘辰翁','宋','宋词','song-ci','莺啼序','[]','愁人更堪秋日，长似岁难度。',295,'宋词/ci.song.17000.json','["愁人更堪秋日，长似岁难度。", "相携去、晼晚登高，高极正犯愁处。", "常是恨、古人无计，看今人痴绝如许。", "但东篱半醉，残灯自修菊谱。", "归去来兮，怨调又苦。", "有寒螀余赋。", "湖山外、风笛阑干，胡床夜月谁据。", "恨当时、青云跌宕，天路断、险艰如许。", "便桥边，卖镜重圆，断肠无数。", "是谁玉斧，惊堕团团，失上界楼宇。", "甚天误、婵娟余误。", "悔却初念，不合梦他，霓裳楚楚。", "而今安在，枫林关塞，回头忆著神仙处，漫断魂飞过湖江去。", "时时说与，地上群儿，青琐瑶台，阆风悬圃。", "琵琶往往，凭鞍劝酒，千载能胡语。", "叹自古、宫花薄命，汉月无情，战地难青，故人成土。", "江南憔悴，荒村流落，伤心自失梨园部，渺空江、泪隔芦花雨。", "相逢司马风流，湿尽青衫，欲归无路。"]'),
('song-ci-525','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','六十一翁，垂银带鱼，插四角轮。',139,'宋词/ci.song.17000.json','["六十一翁，垂银带鱼，插四角轮。", "把百个今朝，重排花甲，十年前事，似臼齑辛。", "骰选功名，酒中富贵，管取当筵满劝旬。", "槐知道，待二郎做甚，父子封申。", "便应际会昌辰。", "怕林下相逢未是真。", "看焚芰裂荷，起锺山笑，卖田僦马，堕贡生贫。", "后六十年，有无穷事，是宰官身是报身。", "年来好，莫做他宰相，便是全人。"]'),
('song-ci-526','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','刘子生时，当月下弦，输大半轮。',140,'宋词/ci.song.17000.json','["刘子生时，当月下弦，输大半轮。", "记孤馆望云，朝饥讽午，寒炉拥雪，岁晚盘辛。", "比似先生，两壬相望，岂止参差一二旬。", "明年好，算乞浆得酒，酉胜如申。", "吾辰。", "定是雌辰。", "听穷鬼揶揄数得真。", "但鹤唳华亭，贵何似贱，珠沈金谷，富不如贫。", "明月清风，晴春暖日，出入千重云水身。", "吾老矣，叹臣之少也，已不如人。"]'),
('song-ci-527','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','成佛生天，自是两途，任祖生先。',139,'宋词/ci.song.17000.json','["成佛生天，自是两途，任祖生先。", "看二三大老，依稀吾榜，几多新进，小少齐年。", "紫陌相逢，青山独往，倚杖鹤鸣听布泉。", "百年里，但儿时难得，老后依然。", "吾牛已不耕田。", "更雨滑泥深自在鞭。", "叹十年波浪，悠悠何补，三生石上，种种无缘。", "白发来呵，朱颜去也，一曲狂歌落酒边。", "谁似我，似官奴出籍，散圣安禅。"]'),
('song-ci-528','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','十八年间，黄公垆下，崔九堂前。',139,'宋词/ci.song.17000.json','["十八年间，黄公垆下，崔九堂前。", "叹人生何似，飘花陌上，妾身难托，卖镜桥边。", "隔幔云深，绕梁声彻，不负杨枝旧日传。", "主人好，但留髡一石，空恼彭宣。", "不因浩叹明年。", "也不为青衫怆四筵。", "念故人何在，旧游如梦，清风明月，野草荒田。", "俯仰无情，高歌有恨，四壁萧条久绝弦。", "秋江晚，但一声河满，我自潸然。"]'),
('song-ci-529','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','九日黄花，渊明之后，谁当汝俦。',139,'宋词/ci.song.17000.json','["九日黄花，渊明之后，谁当汝俦。", "记龙山昨夜，寒泉九井，帽轻似叶，须戟如虬。", "庾扇西风，孔林落照，银海横波十二楼。", "闲笑道，那华亭上蔡，再见何由。", "人生似我何求。", "算惟有高人高处游。", "笑如今别驾，前时方外，尘埃半百，岁月如流。", "如此连墙，今年不见，一首犹胜万户侯。", "偷闲好，便明朝有约，莫莫休休。"]'),
('song-ci-530','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','春汝归欤，风雨蔽江，烟尘暗天。',139,'宋词/ci.song.17000.json','["春汝归欤，风雨蔽江，烟尘暗天。", "况雁门厄塞，龙沙渺莽，东连吴会，西至秦川。", "芳草迷津，飞花拥道，小为蓬壶借百年。", "江南好，问夫君何事，不少留连。", "江南正是堪怜。", "但满眼杨花化白毡。", "看兔葵燕麦，华清宫里，蜂黄蝶粉，凝碧池边。", "我已无家，君归何里，中路徘徊七宝鞭。", "风回处，寄一声珍重，两地潸然。"]'),
('song-ci-531','沁园春','刘辰翁','宋','宋词','song-ci','沁园春','[]','笑贡生狂，日日弹冠，西望王阳。',137,'宋词/ci.song.17000.json','["笑贡生狂，日日弹冠，西望王阳。", "待泥封屡下，蒲轮不至，卖琅琊产，办舍人装。", "厚绿故人，黄金有术，何不分伊肘后方。", "他年老，三千里外，八十思乡。", "何如吾寿华堂。", "在丞相东山旧第旁。", "任王人亲至，不妨高枕，吾州盛事，更短邻墙。", "我学希夷，邀公共坐，游戏壶中日月长。", "山僧道，成仙未晚，救火须忙。"]'),
('song-ci-532','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','棠阴日，棠阴日，清美近花朝。',72,'宋词/ci.song.17000.json','["棠阴日，棠阴日，清美近花朝。", "共喜治中持福笔，春当霄汉布宽条。", "兰蕙雪初销。", "和气满，和气满，生意到渔樵。", "清彻已倾螺子水，黑头宜著侍中貂。", "天马拟归朝。"]'),
('song-ci-533','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','蟠桃熟，蟠桃熟，一熟一千年。',72,'宋词/ci.song.17000.json','["蟠桃熟，蟠桃熟，一熟一千年。", "比似相公正年少，朱颜绿鬓锦蝉连。", "肉色更光鲜。", "西江好，西江好，春雨碧黏天。", "见说内家消息近，佳人拜舞寿觞前。", "扶醉起金鞭。"]'),
('song-ci-534','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','儿童喜，儿童喜，献寿摘仙桃。',72,'宋词/ci.song.17000.json','["儿童喜，儿童喜，献寿摘仙桃。", "篁峒鸣狐成鬼火，花村买犊卖蛮刀。", "惟有使君劳。", "燕山桂，燕山桂，犹带窦家香。", "月殿一枝金粟满，囊中玉屑捣成霜。", "和露入霞觞。"]'),
('song-ci-535','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','金茎露，金茎露，绝胜九霞觞。',72,'宋词/ci.song.17000.json','["金茎露，金茎露，绝胜九霞觞。", "挼碎菊花如玉屑，满盘和月咽风香。", "不老是丹方。", "六十七，六十七，七岁见端平。", "记得是秋除目好，近年大路到南京。", "楚制起诸生。"]'),
('song-ci-536','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','春小小，春小小，梅见著些些。',72,'宋词/ci.song.17000.json','["春小小，春小小，梅见著些些。", "未必神仙无白发，依然林下有黄花。", "潭影浸流霞。", "冬十十，冬十十，亥字雁斜斜。", "不用瑶池偷碧实，不须句漏博丹砂。", "阴德遍人家。"]'),
('song-ci-537','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','臣尚少，臣尚少，少似此翁些。',72,'宋词/ci.song.17000.json','["臣尚少，臣尚少，少似此翁些。", "点半点斑今似雪，飞来飞去自如花。", "醉眼看红霞。", "人间事，人间事，倒杖柱颐斜。", "冷冷清清冰下水，吞吞忍忍饭中砂。", "选到老人家。"]'),
('song-ci-538','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','天正子，天正子，亥正较差些。',72,'宋词/ci.song.17000.json','["天正子，天正子，亥正较差些。", "床下玉灵头戴九，手中铜叶锦添花。", "乞汝作飞霞。", "辽东鹤，辽东鹤，无语鹤头斜。", "尘土不知灰变缟，周遭会见顶成砂。", "城郭待还家。"]'),
('song-ci-539','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','盘之水，盘之水，清可濯吾缨。',72,'宋词/ci.song.17000.json','["盘之水，盘之水，清可濯吾缨。", "我与盘山疏一月，黄花满意绕荒城。", "怀抱向谁倾。", "十之十，十之十，十十到千龄。", "我与盘山同一月，不占甲子后先晴。", "携手看升平。"]'),
('song-ci-540','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','东风雨，东风雨，河汉洗蓬莱。',72,'宋词/ci.song.17000.json','["东风雨，东风雨，河汉洗蓬莱。", "只见丹山高万丈，不知古驿路傍埃。", "到海几时回。", "二月八，二月八，长见醉桃腮。", "天上玉堂怀旧草，面对金鼎又无梅。", "除是老翁来。"]'),
('song-ci-541','法驾导引','刘辰翁','宋','宋词','song-ci','法驾导引','[]','五月五，五月五，细雨绿菖蒲。',72,'宋词/ci.song.17000.json','["五月五，五月五，细雨绿菖蒲。", "早是高花开九节，花堪结子节堪扶。", "持此揆□初。", "长命缕，长命缕，儿女漫区区。", "何似屏星南极里，清如寒露在冰壶。", "一府号仙儒。"]'),
('song-ci-542','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','鹤会正阳后，又为此公来。',114,'宋词/ci.song.17000.json','["鹤会正阳后，又为此公来。", "向时圯上，不似魁梧出尘埃。", "少日河东赋手，醉里新丰对草，谈笑上金台。", "太子少灵气，马客岂仙才。", "紫貂裘，骇犀剑，鹦鹉杯。", "龙涎沈水是浅，薄命有人猜。", "闻说老仙清健，想见风姿皓伟，天语快行催。", "凫舄看双去，槐第似亲栽。"]'),
('song-ci-543','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','五五复五五，二八且重重。',114,'宋词/ci.song.17000.json','["五五复五五，二八且重重。", "后天先甲如此，满月喜相逢。", "一日须倾三百，月小又输一日，不满九千锺。", "但愿客常满，莫问海尊空。", "赋长篇，赓短韵，剩谈丛。", "乱来风日自美，一橘两衰翁。", "几见东陵瓜好，又看西邻葵烂，半醉半醒中。", "偶得洞宾象，混混起相从。"]'),
('song-ci-544','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','夫子惠收我，谓我古心徒。',114,'宋词/ci.song.17000.json','["夫子惠收我，谓我古心徒。", "闲居有客无酒，有酒又无鱼。", "报道犀兵远坠，问讯陈人何似，陈似隔年萸。", "天壤亦大矣，知有孔融乎。", "白雪歌，丹元赞，赫蹄书。", "洪崖何自过我，便作授经图。", "教我天根骑月，规我扶摇去意，餐我白芝符。", "从此须溪里，更著赤松湖。"]'),
('song-ci-545','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','先生岂我辈，造物乃其徒。',114,'宋词/ci.song.17000.json','["先生岂我辈，造物乃其徒。", "荷衣自放林壑，亦未弃银鱼。", "留得东篱晚节，笑倒龙山秃帽，一醉插茱萸。", "天下有大老，携手盍归乎。", "别头经，三昼梦，一编书。", "向之麟者止矣，且看老溪图。", "历遍后天既未，依约明朝三五，乾体适当符。", "还以奉公寿，不是讲鹅湖。"]'),
('song-ci-546','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','似似不常似，似我一生徒。',114,'宋词/ci.song.17000.json','["似似不常似，似我一生徒。", "画工自画龙种，忽近海飞鱼。", "大笑北宫称弟，遂使西河疑女，同气自椒萸。", "且谓杜公者，即是老君乎。", "日给华，芎蓏本，薛羊书。", "马师真只这是，可是躄浮图。", "大小卢同马异，天下使君与操，但欠虎铜符。", "说甚左眼痣，已过洞庭湖。"]'),
('song-ci-547','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','不成三五夜，不放霎时晴。',114,'宋词/ci.song.17000.json','["不成三五夜，不放霎时晴。", "长街灯火三两，到此眼方明。", "把似每时庭院，传说个般障子，无路与君行。", "推手复却手，都付断肠声。", "漏通晓，灯收市，人下棚。", "中山铁马何似，遗恨杳难平。", "一落掺挝声愤，再见大晟舞罢，乐事总伤情。", "便有尘随马，也任雨霖铃。"]'),
('song-ci-548','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','明月几万里，与子共中秋。',114,'宋词/ci.song.17000.json','["明月几万里，与子共中秋。", "古今良夜如此，寂寂几时留。", "何处胡笳三弄，尚有南楼馀兴，风起木飕飕。", "白石四山立，玉露下平洲。", "醉青州，歌赤壁，赋黄楼。", "人间安得十客，谭笑发中流。", "看取横江皓彩，犹似沈河白璧，光气彻天浮。", "举首快哉去，灯火见神州。"]'),
('song-ci-549','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','群动各已息，在汝梦中游。',114,'宋词/ci.song.17000.json','["群动各已息，在汝梦中游。", "尘埃大地如水，儿女不堪愁。", "寂寂古人安在，冉冉吾年如此，何处有高楼。", "客有洞箫者，泪下不能收。", "庾楼坠，秦楼渺，楚楼休。", "知公所恨何事，不是为封侯。", "自有此山此月，说甚何年何处，重泛木兰舟。", "起舞酹英魄，馀愤海西流。"]'),
('song-ci-550','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','寂寂复寂寂，此月古时明。',114,'宋词/ci.song.17000.json','["寂寂复寂寂，此月古时明。", "银河也变成陆，灰劫断槎横。", "历落英雄孺子，灭没龙光牛斗，胜败黯然平。", "玉笛叫空阔，终有故人情。", "雁南飞，乌绕树，鹤归城。", "问君有酒，何不鼓瑟更吹笙。", "我饮呜呜起舞，我舞僛僛白发，顾影可怜生。", "旧日中秋客，几处几回晴。"]'),
('song-ci-551','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','此夕酹江月，犹记濯缨秋。',114,'宋词/ci.song.17000.json','["此夕酹江月，犹记濯缨秋。", "濯缨又去如水，安得主人留。", "旧日登楼长笑，此日新亭对泣，秃鬓冷飕飕。", "木落下极浦，渔唱发中洲。", "芙蓉阙，鸳鸯阁，凤凰楼。", "夜深白露纷下，谁见湿萤流。", "自有此生有客，但恨有鱼无酒，不了一生浮。", "重省看潮去，今夕是杭州。"]'),
('song-ci-552','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','不饮强须饮，不饮奈何明。',114,'宋词/ci.song.17000.json','["不饮强须饮，不饮奈何明。", "也曾劬秃当了，依旧滑如冰。", "一吸金波荡漾，再吸琼楼倾倒，吾杓亦长盈。", "试入壶中看，只似世间晴。", "饮连江，江连月，月连城。", "十年离合老矣，悲喜得无情。", "想见凄然北望，欲说明年何处，衣露为君零。", "同此大圆镜，握手认环瀛。"]'),
('song-ci-553','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','仙掌下驰道，清露滴芙蓉。',114,'宋词/ci.song.17000.json','["仙掌下驰道，清露滴芙蓉。", "无憀似酒初醒，身世笑颦中。", "万朵花灯夜宴，一叶扁舟海岛，寂寂五更风。", "误赏明妆靓，愁思满青铜。", "陂六六，三十六，渺何穷。", "江南曲曲烟雨，谁是醉施翁。", "但恨才情都老，无复风流曾梦，缥缈赋惊鸿。", "寄语清净社，小饮合相容。"]'),
('song-ci-554','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','不饮强须饮，今日是重阳。',114,'宋词/ci.song.17000.json','["不饮强须饮，今日是重阳。", "向来健者安在，世事两茫茫。", "叔子去人远矣，正复何关人事，堕泪忽成行。", "叔子泪自堕，烟没使人伤。", "燕何归，鸿欲断，蝶休忙。", "渊明自无可奈，冷眼菊花黄。", "看取龙山落日，又见骑台荒草，谁弱复谁强。", "酒亦何有好，暂醉得相忘。"]'),
('song-ci-555','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','山水无宿约，村暗自当还。',114,'宋词/ci.song.17000.json','["山水无宿约，村暗自当还。", "不知有客乘兴，载我弄沧湾。", "酒吸明河欲尽，月落三星在下，未放水风闲。", "影转松起舞，扶步入林间。", "恨无人，横野笛，叫关山。", "知君慷慨何事，惜得米阳关。", "看取大江东去，把酒凄然北望，说著泪潺湲。", "我饮自须尽，君唱有何难。"]'),
('song-ci-556','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','两声深院里，歌扇小楼中。',114,'宋词/ci.song.17000.json','["两声深院里，歌扇小楼中。", "当时飞燕马上，妖艳为谁容。", "娇颤须扶未稳，腰袅轻笼小驻，玉女最愁峰。", "掠鬓过车骤，回首意冲冲。", "宝钗斜，云鬓乱，几曾逢。", "谁知去三步远，此痛与君同。", "玉箸残妆谁见，獭髓轻痕妙补，粉黛不须浓。", "重见为低诉，馀恨更匆匆。"]'),
('song-ci-557','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','未信仙都子，曾识老仙翁。',114,'宋词/ci.song.17000.json','["未信仙都子，曾识老仙翁。", "卿卿少年去后，心与道人同。", "挥麈不须九锡，开阁苦无长物，闲日醉千锺。", "一笑欠伸起，儿戏大槐中。", "友彭聃，招园绮，傲乔松。", "年来多惯世事，莫莫恼司空。", "等得三朝好老，恰则而今虚左，梅信已先通。", "富贵正不免，从此学痴聋。"]'),
('song-ci-558','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','百千孙子子，八十老翁翁。',114,'宋词/ci.song.17000.json','["百千孙子子，八十老翁翁。", "人间天下清福，阅世苦难同。", "谁叹东门猎倦，谁笑南阳舞罢，万事五更钟。", "但愿人长久，聊复进杯中。", "故侯瓜，丞相柏，大夫松。", "诸公健者安在，春梦转头空。", "可笑先生无病，病在枕流漱石，福至自然通。", "聋者固多笑，一笑更治聋。"]'),
('song-ci-559','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','我有此客否，难作主人翁。',114,'宋词/ci.song.17000.json','["我有此客否，难作主人翁。", "小年自不相似，偶与大年同。", "见说东厢诸少，正拥家君胜会，二八舞歌钟。", "亦欲得公重，公在画堂中。", "笑青蒿，真小草，倚长松。", "典衣欲作汤饼，家酿愧瓶空。", "公有潭州百斛，公有秫田二顷，贺客万钱通。", "小大不相似，但可似公聋。"]'),
('song-ci-560','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','明月隔千里，风动帐纹开。',114,'宋词/ci.song.17000.json','["明月隔千里，风动帐纹开。", "故人锦字如梦，梦转雁初来。", "倚遍西山朝爽，行过石头旧渡，久别忽经怀。", "不得与之语，日夕独持杯。", "调绿水，歌白雪，有心哉。", "也知尻高啄俯，无计脱尘埃。", "狗尾貂蝉满座，贝带鵕鸃弄粉，一舆一臣台。", "岁晚不如愿，谁更忿灰堆。"]'),
('song-ci-561','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','落日半亭榭，山影没壶中。',114,'宋词/ci.song.17000.json','["落日半亭榭，山影没壶中。", "苍然欲不可极，迢递未归鸿。", "锦织家人何在，春寄故人不到，寂寞听疏钟。", "木末见江去，无雪著渔翁。", "词舂容，歌慷慨，语玲珑。", "岁云暮矣相见，明日是东风。", "远想使君台上，携手与人同乐，中夜说元龙。", "世事无足语，且看烛花红。"]'),
('song-ci-562','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','不见古时月，何似汉时秋。',114,'宋词/ci.song.17000.json','["不见古时月，何似汉时秋。", "朱陈村里新样，新妇又骑牛。", "欲脱参前氐后，又说河边河鼓，此会没来由。", "何处设瓜果，香动帻沟窭。", "郭郎老，谁为理，岂情流。", "人间□睡五日，五日复何悠。", "吾腹空虚久矣，子有满堂锦绣，犊鼻若为酬。", "玉友此时好，空负葛巾篘。"]'),
('song-ci-563','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','天地有中气，第一是中元。',114,'宋词/ci.song.17000.json','["天地有中气，第一是中元。", "新秋七七，月出河汉斗牛间。", "正是使君初度，如见中州河岳，绿鬓又朱颜。", "茎露一杯酒，清彻瑞人寰。", "大暑退，潢潦净，彩云斑。", "三壬三甲厚重，屹不动如山。", "从此五风十雨，自可三年一日，香寝镇狮蛮。", "起舞愿公寿，未可愿公还。"]'),
('song-ci-564','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','夜看二星度，高会列群英。',114,'宋词/ci.song.17000.json','["夜看二星度，高会列群英。", "苍颜白发乌帽，风入古槐清。", "客有羽衣来者，仍是寻常百姓，坐觉孟公惊。", "且勿多酌我，未压我狂醒。", "金瓯启，银信喜，衮衣新。", "向来淮浙草木，隐隐有馀声。", "闻说井阑沙语，感念石壕村事，倾耳发惊霆。", "举酒奉公寿，天意厚苍生。"]'),
('song-ci-565','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','["\u94b1\u5858\u6c5f"]','造物反乎覆，白首困耆英。',114,'宋词/ci.song.17000.json','["造物反乎覆，白首困耆英。", "吟风赏月石上，一笑再河清。", "一百八盘道路，二十四桥歌舞，身世梦堪惊。", "独酌未能醉，已醉蓦然醒。", "别与老，惊相见，几回新。", "来时燕栖未稳，满耳又蝉声。", "闲忆钱塘江上，两点青山欲白，血石起鞭霆。", "此事复安在，相对说平生。"]'),
('song-ci-566','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','["\u957f\u6c5f"]','晓殿龙光起。',142,'宋词/ci.song.17000.json','["晓殿龙光起。", "御香浓、新诗写就，云飞相第。", "一自骑箕承帝赉，千载君臣鱼水。", "端不负、当年弧矢。", "赤壁周郎神游处，料羞看、故垒斜阳里。", "今共看，更无比。", "尊前若说平生事。", "叹长江、几番风浪，几人胆碎。", "数载太平丰年瑞。", "三百年间又几。", "想皇揆、初心应喜。", "渐近中秋团团月，算人间天上、俱清美。", "祝千岁，似甲子。"]'),
('song-ci-567','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','秋老寒香圃。',142,'宋词/ci.song.17000.json','["秋老寒香圃。", "自春来、桔槔闲了，去天尺五。", "陌上踏歌来何暮，收得黄云如土。", "但稽首、福星初度。", "不是使君人间佛，甚今朝、欲雨今朝雨。", "持寿酒，为公舞。", "虎头画手谁甚许。", "写天人、方瞳红颊，共宾笑语。", "卫戟连营三千士，簇簇满城箫鼓。", "早恐是、留公不住。", "飞去翩翩嫌白鹭，算来年、稀姓多登府。", "祝千岁，奉明主。"]'),
('song-ci-568','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','春入番江雨。',142,'宋词/ci.song.17000.json','["春入番江雨。", "满湖山、莺啼燕雨，前歌后舞。", "闻道行骢行且止，却听谯楼更鼓。", "正未卜，阴晴同否。", "老子胸中高小范，这精神、堪更开封府。", "新治足，旧民苦。", "扁舟浩荡乘风去。", "看莱衣、思贤堂上，寿觞朝举。", "六十二三前度者，敢望香山老傅。", "又过了、午年端午。", "采采菖蒲三三节，寄我公、矫矫扶天路。", "重归衮，到相圃。"]'),
('song-ci-569','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','我误留公住。',142,'宋词/ci.song.17000.json','["我误留公住。", "看人间、犹是重阳，满城风雨。", "父老堂阴携孺子，记得元宵歌舞。", "但稽首、乌乌无语。", "我有桓筝千年恨，为谢公、目送还云抚。", "公不乐，尚何苦。", "吾侬心事凭谁诉。", "有谁知、闭户穷愁，欲从之去。", "闻道明朝生申也，满酌一杯螺浦。", "又知复、明年何处。", "天若有情西江者，便使君、骢马来当路。", "香瓣起，胜金缕。"]'),
('song-ci-570','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','忘却来时路。',142,'宋词/ci.song.17000.json','["忘却来时路。", "恨苍苍、寒冰弃我，江南闲处。", "世事早知今如此，何不老农老圃。", "更种个、梅花深住。", "冻雨前朝浯溪石，对苍苔、堕泪怜臣甫。", "山似我，两眉聚。", "岁云暮矣如何度。", "但多情、寂寥相念，二三君子。", "越石暮年扶风赋，犹解闻鸡起舞。", "恨不减、二三十岁。", "一曲相思碧云合，醉凭君、为我歌如缕。", "君念我，似同祖。"]'),
('song-ci-571','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','昨醉君家酒。',141,'宋词/ci.song.17000.json','["昨醉君家酒。", "从今十万八千场，未疏老友。", "人道水仙标格俊，不许梅花殿后。", "但赢得、一年年瘦。", "迤逦聚星楼上雪，待天风、浩荡重携手。", "酌君酒，献君寿。", "年前春入燕台柳。", "看联翩、四辈金鞭，长楸承受。", "岂有中朝瓯覆久，更落闽山海口。", "端自有、玉堂金斗。", "我喜明年申又酉，但乞浆、所得皆醇酎。", "拚醉里，送行昼。"]'),
('song-ci-572','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','七十三年矣。',143,'宋词/ci.song.17000.json','["七十三年矣。", "记小人、四百四十，五番甲子。", "看到蓬莱水清浅，休说树犹日如此。", "但梦梦、昨非今是。", "一曲尊前离鸾操，抚铜仙、清泪如铅水。", "歌未断，我先醉。", "新来画得耆英似。", "似灞桥、风雪吟肩，水仙梅弟。", "里巷依稀灵光在，飞过劫灰如洗。", "笑少伴、乌衣馀几。", "老子平生何曾默，暮年诗、句句皆成史。", "个亥字，甲申起。"]'),
('song-ci-573','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','["\u6d1e\u5ead\u6e56"]','拍瓮春醅动。',142,'宋词/ci.song.17000.json','["拍瓮春醅动。", "洞庭霜、压绿堆黄，林苞堪贡。", "况有老人潭边菊，摇落赏心入梦。", "数百岁、半来许中。", "儿女牵衣团栾处，绕公公、愿献生申颂。", "公性歰，待重风。", "人生一笑何时重。", "奈今朝、有客无鱼，有鱼留冻。", "何似尊前斑斓起，低唱浅斟齐奉。", "也不待、烹龙炰凤。", "此会明年知谁健，说边愁、望断先生宋。", "醒最苦，醉聊共。"]'),
('song-ci-574','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','绝北寒声动。',142,'宋词/ci.song.17000.json','["绝北寒声动。", "渺黄昏、叶满长安，云迷章贡。", "最苦周公千年后，正与莽新同梦。", "五十国、纷纷入中。", "摇颺都人歌郿坞，问何如、昨日菘高颂。", "胪九锡，竟谁风。", "当初共道擎天重。", "奈天教、垓下风寒，滹沱兵冻。", "寂寞放翁南园记，带得园柑进奉。", "怅回首、何人修凤。", "寄语权门趋炎者，这朝廷、不是邦昌宋。", "真与赝，可能共。"]'),
('song-ci-575','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','吾鬓如霜蕊。',141,'宋词/ci.song.17000.json','["吾鬓如霜蕊。", "自江南、西风尘起，倒骑秃尾。", "旧日汾阳中书令，何限门生儿子。", "到今也、陆沈草昧。", "醉里不行西州路，但斗间、看望成龙气。", "聊寂寞，自相慰。", "夫君自是人间瑞。", "叹生儿、当如异日，孙仲谋耳。", "健笔风云蛟龙起，人物山川形势。", "犹有封、狼居胥意。", "伐木嘤嘤出幽谷，问天之将丧斯文未。", "吾待子，望如岁。"]'),
('song-ci-576','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','["\u897f\u6e56"]','何处从头说。',141,'宋词/ci.song.17000.json','["何处从头说。", "但倾尊、淋漓醉墨，疏疏密密。", "看取两轮东西者，也是樊笼中物。", "这光景、年来都别。", "白发道人隆中像，笑相逢、对拥炉边雪。", "又过了，上元节。", "纸窗旋补寒穿穴。", "柳黏窗、青青过雨，劝君休折。", "睡不成酣酒先醒，花底东风又别。", "夜复夜、吟魂飞越。", "典却西湖东湖住，十三年不出今朝出。", "容易得，二三月。"]'),
('song-ci-577','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','岁事峥嵘甚。',142,'宋词/ci.song.17000.json','["岁事峥嵘甚。", "是当年、爆竹驱傩，插金幡胜。", "忽晓阑街儿童语，不为上元灯近。", "但笑拣、梅簪公鬓。", "莫恨青青如今白，愿年年、语取东君信。", "巾未堕，笑重整。", "他年不信东风冷。", "鼓连天、银烛花光，柳芽催迸。", "漫说沈香亭羯鼓，自著锦袍吟凭。", "待吹彻、玉箫人醒。", "不带汝阳天人福，便不教、百又馀年剩。", "歌此曲，休辞饮。"]'),
('song-ci-578','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','叶叶跳珠雨。',142,'宋词/ci.song.17000.json','["叶叶跳珠雨。", "里湖通、十里红香，画桡齐举。", "昨梦天风高黄鹄，下俯人间何许。", "但动地、潮声如鼓。", "竹阁楼台青青草，问木棉、羁客魂归否。", "盘泣露，寺钟语。", "梦回酷似灵均苦。", "叹神游、前度都非，明朝重五。", "满眼离骚无人赋，忘却君愁吊古。", "任醉里、乌乌缕缕。", "渺渺茂陵安期叟，共鄗池、夜别还于楚。", "采涧绿，久延伫。"]'),
('song-ci-579','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','襟泪涔涔雨。',142,'宋词/ci.song.17000.json','["襟泪涔涔雨。", "料骚魂、水解千年，依然轻举。", "还看吴儿胥涛上，高出浪花几许。", "绝倒是、东南旗鼓。", "风雨蛟龙争何事，问彩丝、香粽犹存否。", "溪女伴，采莲语。", "古人不似今人苦。", "漫追谈、少日风流，三三五五。", "谁似鄱阳鸱夷者，相望怀沙终古。", "待唤醒、重听金缕。", "尚有远游当年恨，恨南公、不见秦为楚。", "天又暮，黯凝伫。"]'),
('song-ci-580','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','锦岸吴船鼓。',142,'宋词/ci.song.17000.json','["锦岸吴船鼓。", "问沙鸥、当日沈湘，是何端午。", "长恨青青朱门艾，结束腰身似虎。", "空泪落、婵媛嬃女。", "我醉招累清醒否，算平生、清又醒还误。", "累笑我，醉中语。", "黄头舞棹临江处。", "向人间、独竞南风，叫云激楚。", "笑倒两崖人如蚁，不管颓波千屡。", "忽惊抱、汨罗无柱。", "欸乃渔歌斜阳外，几书生、能办投湘赋。", "歌此恨，泪如缕。"]'),
('song-ci-581','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','破帽吹愁去。',142,'宋词/ci.song.17000.json','["破帽吹愁去。", "绕郊墟、残灰败壁，冷烟斜雨。", "舞马梦惊城乌起，散作童妖灶语。", "漫说与、谢仙一句。", "犹记醉归西州路，问行人、望望骊烽误。", "几未失，丧公屦。", "高高况是兴亡处。", "望平沙、落日湖光，暗淮沈楚。", "寂寞西陵歌又舞，疑冢嵯峨新土。", "黯牛笛、参差归路。", "试问文君容赊否，待东篱、更就黄花浦。", "拚酩酊，涴蓝缕。"]'),
('song-ci-582','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','风雨东篱晚。',142,'宋词/ci.song.17000.json','["风雨东篱晚。", "渺人间、南北东西，平芜烟远。", "旧日携壶吹帽处，一色沈冥何限。", "天不遣、魂销肠断。", "不是苦无看山分，料青山、也自羞人面。", "秋后瘦，老来倦。", "惊回昨梦青山转。", "恨一林、金粟都空，静无人见。", "默默黄花明朝有，只待插花寻伴。", "又谁笑、今朝蝶怨。", "潦倒玉山休重醉，到簪萸、忍待人频劝。", "今又惜，几人健。"]'),
('song-ci-583','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','与客携壶去。',142,'宋词/ci.song.17000.json','["与客携壶去。", "望高高、半山失却，满城风雨。", "何许白衣人邂逅，小立东篱共语。", "未怪是、催租断句。", "寂寞午鸡啼三四，悄老人、桥上前期误。", "卿且去，整吾屦。", "寒空旧是题诗处。", "莽云烟、缠蛟舞凤，东吴西楚。", "千古新亭英雄梦，泪湿神州块土。", "叹落日、鸿沟无路。", "一片沙场君不去，空平生、恨恨王夷甫。", "凭半醉，付金缕。"]'),
('song-ci-584','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','["\u6d1e\u5ead\u6e56"]','携手登高赋。',142,'宋词/ci.song.17000.json','["携手登高赋。", "望前山、山色如烟，烟光如雨。", "少日凭阑峰南北，谁料美人迟暮。", "漫回首、残基冷绪。", "长恨中原无人问，到而今、总是经行处。", "书易就，雁难付。", "斜阳日日长亭路。", "倚秋风、洞庭一剑，故人何许。", "寂寞柴桑塞花外，还有白衣来否。", "但哨遍、长歌归去。", "尚有孔明英英者，怅孔明、自是英英误。", "歌未断，鬓成缕。"]'),
('song-ci-585','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','问何年种植。',142,'宋词/ci.song.17000.json','["问何年种植。", "独成蹊、秾花烂漫，锦开千步。", "花下老人犹记我，不似那回赏处。", "并吹却、道边谢墅。", "黄四娘家今何在，也飘零、偎向前村住。", "千万恨，寄红雨。", "携壶藉草行歌暮。", "记前宵、深盟止酒，况堪扶路。", "破手一杯花浮面，不觉二三四五。", "更竹里、颠狂崔护。", "试语看花诸君子，但如今、俯仰成前度。", "君不见，曲江树。"]'),
('song-ci-586','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','少日都门路。',142,'宋词/ci.song.17000.json','["少日都门路。", "听长亭、青山落日，不如归去。", "十八年间来往断，白首人间今古。", "又惊绝、五更一句。", "道是流离蜀天子，甚当初、一似吴儿语。", "臣再拜，泪如雨。", "画堂客馆真无数。", "记画桥、黄竹歌声，桃花前度。", "风雨断魂苏季子，春梦家山何处。", "谁不愿、封侯万户。", "寂暮江南轮四角，问长安、道上无人住。", "啼尽血，向谁诉。"]'),
('song-ci-587','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','一笑披衣起。',142,'宋词/ci.song.17000.json','["一笑披衣起。", "笑昨宵、东风似梦，韩张卢李。", "白发红云溪上叟，不记儿孙年齿。", "但回首、秦亡汉驶。", "苦苦渔郎留不住，约扁舟、后日重来此。", "吾已老，尚能俟。", "少年未解留人意。", "恍出山、红尘吹断，落花流水。", "天上玉堂人间改，漫欸乃声千里。", "更说似、玄都君子。", "闻道酿桃堪为酒，待酿桃、千石成千醉。", "春有尽，瓮无底。"]'),
('song-ci-588','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','灯共墙檠语。',142,'宋词/ci.song.17000.json','["灯共墙檠语。", "记昨朝、芒鞋蓑笠，冷风斜雨。", "月入宫槐槐影澹，化作槐花无数。", "恍不记、鳌头压处。", "不恨扬州吾不梦，恨梦中、不醉琼花露。", "空耿耿，吊终古。", "千蜂万蝶春为主。", "怅何人、老忆江南，北朝开府。", "看取当年风景在，不待花奴催鼓。", "且未说、春丁分俎。", "一曲沧浪邀吾和，笑先生、尚是邯郸步。", "如秉苘，续残炬。"]'),
('song-ci-589','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','["\u897f\u6e56"]','渐无多、诗朋酒伴，东林复几人许。',140,'宋词/ci.song.17000.json','["渐无多、诗朋酒伴，东林复几人许。", "旧时船子西湖柳，词与东风尘土。", "重记否。", "那月月下旬，且避何人疏。", "当朝自负。", "甚堕髻愁眉，滕韝短后，一往似伧父。", "当年事，伤心说庾开府。", "人生无百年虑。", "虎头燕颔人间肉，不是蜜翁翁做。", "今又古。", "是楚对凡亡，为是凡亡楚。", "朝朝暮暮。", "听画角楼头，呜咽未断，重数五更鼓。"]'),
('song-ci-590','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','记玄都、看花君子，一生恨奈何许。',140,'宋词/ci.song.17000.json','["记玄都、看花君子，一生恨奈何许。", "青云紫陌悠悠者，几个玉人成土。", "今在否。", "但四海九州，屈指从头疏。", "吾年空负。", "看射虎南山，遭逢醉尉，何须饮田父。", "神清梦，也是堂堂欧府。", "此中无破头虑。", "种槐不隔鞭蛆恶，更祝二郎儿做。", "苍苍古。", "漫年又一年，老却南公楚。", "池塘春暮。", "笑步步鸣蛙，看成两部，正似未忘鼓。"]'),
('song-ci-591','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','三百年、人间天上，遽如许、遽如许。',141,'宋词/ci.song.17000.json','["三百年、人间天上，遽如许、遽如许。", "落花寒食东风雨，漠漠长陵抔土。", "魂归否。", "怕些不分明，又堕人笺疏。", "且无相负。", "记昔与诸贤，共谈洛下，曾识老人父。", "牛衣泪，冷落闻鸡东府。", "风尘曾独深虑。", "子规声断长门晓，春梦不堪重做。", "千万古。", "但目极心伤，宛转虞兮楚。", "江东日暮。", "想野草荒田，而今何处，不待雍门鼓。"]'),
('song-ci-592','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','道醉乡、无边无岸，一尊到彼殊径。',140,'宋词/ci.song.17000.json','["道醉乡、无边无岸，一尊到彼殊径。", "是间转海人知处，尺地不教渠剩。", "尊亦瘿。", "问一斗消酲，一石犹难信。", "临风小等。", "记我友醒狂，相从有意，中路恨羌永。", "梅花晚，早已雪堆余鬓。", "此花宁复风韵。", "空寒独倚天为主，天又几时曾定。", "今为晋。", "看秦女山中，绿发垂垂顶。", "百年一瞬。", "叹高卧北窗，闲过五十，无说答形影。"]'),
('song-ci-593','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','记歌头、辛壬癸甲，乌乌能知谁晓。',140,'宋词/ci.song.17000.json','["记歌头、辛壬癸甲，乌乌能知谁晓。", "梅花不待元宵好，雪月交光独照。", "愁未老。", "更老似渠□，冷面迎相笑。", "君词定峭。", "但减十年前，偎桃傍李，肯独为梅好。", "山中好。", "可但一枝春早。", "道边无限花草。", "米嘉荣共何戡在，还忆永新娇小。", "明年了。", "又唤起流莺，又自愁鹃叫。", "东皇太昊。", "更不是琼花，香无半点，一笑使人倒。"]'),
('song-ci-594','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','懒能看、海桑世界，风花过眼如传。',140,'宋词/ci.song.17000.json','["懒能看、海桑世界，风花过眼如传。", "月明昨夜庭流水，天色朝来都变。", "尘石烂。", "铢衣坏，和衣减尽谁能怨。", "秦亡楚倦。", "但翦烛西窗，秋声入竹，点点已如霰。", "当年事，本是泗亭沛县。", "却教绵蕝成殿。", "暮年八阵那曾用，付与江流石转。", "前楚辩。", "今哨遍，是乌乌者灯前劝。", "乾坤较健。", "叹君已归休，吾方俯仰，种种未曾见。"]'),
('song-ci-595','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','渺斜阳、村烟酒市，独教王谢如此。',140,'宋词/ci.song.17000.json','["渺斜阳、村烟酒市，独教王谢如此。", "渔翁梦入江头絮，寂寂平安西子。", "东风起。", "东风起。", "种桃千树皆流水。", "桥边万里。", "甚老子情锺，明朝后日，又洒送春泪。", "春过雨，历历远山如洗。", "暮云堪共谁倚。", "诸贤洛下风流散，轻薄纷纷馀几。", "聊尔尔。", "问世事。", "何如自嗅残花蕊。", "金铜剑履。", "但陌上相逢，摩挲一笑，铸此几时矣。"]'),
('song-ci-596','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','又非他、今年晴少，海棠也恁空过。',140,'宋词/ci.song.17000.json','["又非他、今年晴少，海棠也恁空过。", "清羸欲与花同梦，不似蝶深深卧。", "春怜我。", "我又自、怜伊不见侬赓和。", "已无可奈。", "但愁满清漳，君归何处，无泪与君堕。", "春去也，尚欲留春可可。", "问公一醉能颇。", "锺情剩有词千首，待写大招招些。", "休阿那。", "阿那看、荒荒得似江南麽。", "老夫婆娑。", "问篱下闲花，残红有在，容我更簪朵。"]'),
('song-ci-597','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','是他家、绛唇翠袖，可容卿有功否。',140,'宋词/ci.song.17000.json','["是他家、绛唇翠袖，可容卿有功否。", "相思不到胭脂井，只隔东林烟柳。", "春去又。", "漫一夜东风，吹得花成旧。", "无人举酒。", "但照影堤流，图他红泪，飘洒到襟袖。", "人间事，大半归谋诸妇。", "不如意十八九。", "敲门夜半窥园李，赤脚玉川惊走。", "何处有。", "更炙烛风流，看到人归后。", "休休回首。", "笑旧日园林，佺巢蜀锦，处处可携手。"]'),
('song-ci-598','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','怎知他、春归何处，相逢且尽尊酒。',140,'宋词/ci.song.17000.json','["怎知他、春归何处，相逢且尽尊酒。", "少年袅袅天涯恨，长结西湖烟柳。", "休回首。", "但细雨断桥，憔悴人归后。", "东风似旧。", "问前度桃花，刘郎能记，花复认郎否。", "君且住，草草留君翦韭。", "前宵更恁时候。", "深杯欲共歌声滑，翻湿春衫半袖。", "空眉皱。", "看白发尊前，已似人人有。", "临分把手。", "叹一笑论文，清狂顾曲，此会几时又。"]'),
('song-ci-599','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','正何须、阳关肠断，吴姬苦劝人酒。',140,'宋词/ci.song.17000.json','["正何须、阳关肠断，吴姬苦劝人酒。", "中年怀抱萦萦处，看取伴烟和柳。", "柳摇首。", "笑飞到家山，已是酴醿后。", "留连话旧。", "问溪上儿童，颇曾见我，有此故人否。", "相逢地，还忆今宵三韭。", "青山知了迎候。", "东风自送归帆去，吹得乱红沾袖。", "暮云皱。", "听杜宇高高，啼向无何有。", "江花垂手。", "任春色重来，江花更好，难可少年又。"]'),
('song-ci-600','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','待欲□、家山未得，方知名不如酒。',140,'宋词/ci.song.17000.json','["待欲□、家山未得，方知名不如酒。", "丹砂便做金句漏，难遣鬓青似柳。", "试搔首。", "记移竹南塘，又是三年后。", "情怀非旧。", "叹少日相如，垆边老去，能赋上林否。", "种兰处，赢得青青种韭。", "渊明中路相候。", "何须更待三三径，也自长拖衫袖。", "青袍皱。", "便持当金貂，赊取邻家有。", "小儿拍手。", "笑昨醉如泥，盟言止酒，何事醒来又。"]'),
('song-ci-601','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','更比他、东风前度，依然一榻如许。',140,'宋词/ci.song.17000.json','["更比他、东风前度，依然一榻如许。", "深深旧是谁家府，落日画梁燕语。", "帘半雨。", "记湖海平生，相遇忘宾主。", "阑珊春暮。", "看城郭参差，长空澹澹，沙鸟自来去。", "江山好，立马白云飞处。", "秦川终是吾土。", "登临笑傲西山笏，烟树高高杜宇。", "君且住。", "况双井泉甘，汲遍茶堪煮。", "歌残金缕。", "恰黄鹤飞来，月明三弄，仍是岳阳吕。"]'),
('song-ci-602','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','是疑他、春来倏忽，是疑岁别人去。',140,'宋词/ci.song.17000.json','["是疑他、春来倏忽，是疑岁别人去。", "古今守岁言无说，长是酒阑情绪。", "堪恨处。", "曾亲见都人，户户银花树。", "星河未曙。", "听朝马笼街，火城簇仗，御笔已题露。", "人间事，空忆桃符旧句。", "三茅钟自朝暮。", "严城夜禁故如鬼，况敢凭陵大呼。", "冬冬鼓。", "但画角声残，已是新人故。", "休思前度。", "叹五十加三，明朝领取，闲看五星聚。"]'),
('song-ci-603','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','醒复醒、行吟泽畔，焉能忍此终古。',140,'宋词/ci.song.17000.json','["醒复醒、行吟泽畔，焉能忍此终古。", "招魂过海枫林暝，招得魂归无处。", "朝又暮。", "但依旧，禁街人静冬冬鼓。", "画船沈雨。", "听欸乃渔歌，兴亡事远，咽咽未能句。", "君且住。", "能歌吾不如汝。", "悠悠鼓枻而去。", "沧洲揽结芳成艾，唤作张三李五。", "羌自苦。", "更闲却，玉堂端帖多多许。", "无人自语。", "把画扇鸾边，香罗雪底，题作午年午。"]'),
('song-ci-604','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','想幼安、辽东归后，自羞年少龙首。',140,'宋词/ci.song.17000.json','["想幼安、辽东归后，自羞年少龙首。", "长安市上垆边卧，枉却快行家走。", "空两袖。", "染醉墨淋漓，把似天香透。", "功名邂逅。", "便六一词高，君谟字伟，但见说行昼。", "人间事，苦似成丹无候。", "神清苔字如镂。", "明年六十闻歌后，颇记薄醺醺否。", "儿拍手。", "笑马上葛疆，也作家山友。", "烦伊起寿。", "更待复一中，毋多酌我，疏影共三嗅。"]'),
('song-ci-605','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','也何须、晴如那日，欣然且过江去。',140,'宋词/ci.song.17000.json','["也何须、晴如那日，欣然且过江去。", "玄都纵有看花便，耿耿自羞前度。", "堪恨处。", "人道是，漫山先落坡翁句。", "东风绮语。", "但适意当前，来寻须赋，此土亦吾圃。", "海山石，犹记芙蓉城主。", "弹过飞种成土。", "是间便作仙客杏，谁与一栽千树。", "朝又暮。", "怅二十五年，临路花如故。", "人生自苦。", "只唤渡观桃，侵寻至此，世事奈何许。"]'),
('song-ci-606','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','醉与君、狂歌又笑，不知当日何调。',141,'宋词/ci.song.17000.json','["醉与君、狂歌又笑，不知当日何调。", "孤山梅下吟魂冷，说甚那时苏小。", "沧波眇。", "奈此岛，累累竟是谁家表。", "归欤白鸟。", "看四圣飘香，朱门金榜，化作竺飞峤。", "衰也久，旧游梦翠禽绕。", "坱兮轧、皎兮窈。", "相思一夜窗前白，谁识余怀渺渺。", "残年了。", "听画角，悲凉又是霜天晓。", "馀音杳缈。", "叹五十之年，我加八九，君隔几科诏。"]'),
('song-ci-607','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','是耶非、吾年如此，更痴更悔今昨。',140,'宋词/ci.song.17000.json','["是耶非、吾年如此，更痴更悔今昨。", "狂吟近日疏于酒，转似秋山瘦削。", "浑未觉。", "恁儿子门生，前度登高弱。", "情怀又恶。", "叹亲友中年，不堪离别，况复久零落。", "长生乐。", "有分神仙难学。", "人生聊复行乐。", "百年半梦随流水，半在南枝北萼。", "妾命薄。", "但寂寞黄昏，时听城楼角。", "愁无可著。", "且取醉尊前，明朝休问，昨日已忘却。"]'),
('song-ci-608','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','对尊前、簪花骑竹，老胡起起能舞。',140,'宋词/ci.song.17000.json','["对尊前、簪花骑竹，老胡起起能舞。", "春风浩荡天涯去，惟有薰吟自语。", "槐正午。", "看万户蜂脾，帘幕双双乳。", "娇儿呆女。", "漫学得琵琶，依稀马上，总是主恩处。", "凌烟像，空倚临风玉树。", "升沈事遽如许。", "刘郎贯是瑶池客，又醉碧桃三度。", "花下数。", "记三度三千，结子多红雨。", "年年五五。", "共准拟阶庭，钗符献酒，袅袅缀双虎。"]'),
('song-ci-609','摸鱼儿','刘辰翁','宋','宋词','song-ci','摸鱼儿','[]','待借留、几曾留得，来鸿空怨秋老。',140,'宋词/ci.song.17000.json','["待借留、几曾留得，来鸿空怨秋老。", "至今父老依依恨，犹说李将军好。", "东门草。", "早不为东风，遮却长安道。", "馀民如槁。", "愿金印重来，洪都开府，定复几时到。", "秋江鹭，尤记当年潦倒。", "沧洲无复华皓。", "朝饥堕泪荒田雨，洗忆窝蜂败扫。", "天能报。", "看凤烛亭亭，玉树宽人抱。", "风霜善保。", "但逢驿寄书，无书寄语，要说趋朝早。"]'),
('song-ci-610','金缕曲・贺新郎','刘辰翁','宋','宋词','song-ci','金缕曲・贺新郎','[]','世事如何说。',142,'宋词/ci.song.17000.json','["世事如何说。", "似举鞍、回头笑问，并州儿葛。", "手障尘埃黄花路，千里龙沙如雪。", "著破帽、萧萧馀发。", "行过故人柴桑里，抚长松、老倒山间月。", "聊共舞，命相瑟。", "春风五老多年别。", "看使君、神交意气，依然晚合。", "袖有玉龙提携去，满眼黄金台骨。", "说不尽、古人痴绝。", "我醉看天天看我，听秋风、吹动檐间铁。", "长啸起，两山裂。"]'),
('song-ci-611','意难忘','刘辰翁','宋','宋词','song-ci','意难忘','[]','角动寒谯。',114,'宋词/ci.song.17000.json','["角动寒谯。", "看雨中灯市，雪意潇潇。", "星球明戏马，歌管杂鸣刁。", "泥没膝，舞停腰。", "焰蜡任风销。", "更可怜、红啼桃槛，绿暗杨桥。", "当年乐事朝朝。", "曾锦鞍呼妓，金屋藏娇。", "围香春斗酒，坐月夜吹箫。", "今老矣，倦歌谣。", "嫌杀杜家乔。", "漫三杯、踞炉觅句，断送春宵。"]'),
('song-ci-612','大','刘辰翁','宋','宋词','song-ci','大','[]','任琐窗深、重帘闭，春寒知有人处。',164,'宋词/ci.song.17000.json','["任琐窗深、重帘闭，春寒知有人处。", "常年笑花信，问东风情性，是娇是妒。", "冰柳成须，吹桃欲削，知更海堂堪否。", "相将燕归又，看香泥半雪，欲归还误。", "漫低回芳草，依稀寒食，朱门封絮。", "少年惯羁旅。", "乱山断，敧树唤船渡。", "正暗想、鸡声落月，梅影孤屏，更梦衾、千重似雾。", "相如倦游去。", "掩四壁、凄其春暮。", "休回首、都门路。", "几番行晓，个个阿娇深贮。", "而今断烟细雨。"]'),
('song-ci-613','谒金门','刘辰翁','宋','宋词','song-ci','谒金门','[]','风又雨。',53,'宋词/ci.song.17000.json','["风又雨。", "春事自无多许。", "欲待柳花团作絮。", "柳花冰未吐。", "翠袖不禁春误。", "沈却绿烟红雾。", "将谓花寒留得住，一晴春又暮。"]'),
('song-ci-614','临江仙','刘辰翁','宋','宋词','song-ci','临江仙','[]','过眼纷纷遥集，来归往往羝儿。',68,'宋词/ci.song.17000.json','["过眼纷纷遥集，来归往往羝儿。", "草间塞口裤间啼。", "提携都不是，何似未生时。", "城上胡笳自怨，楼头画角休吹。", "谁人不动故乡思。", "江南秋尚可，塞外草先衰。"]'),
('song-ci-615','水调歌头','刘辰翁','宋','宋词','song-ci','水调歌头','[]','坐久语寂寞，泉响忽翻空。',114,'宋词/ci.song.17000.json','["坐久语寂寞，泉响忽翻空。", "不知龙者为雨，雨者为成龙。", "看取交流万壑，不数飞来千丈，高屋总淙淙。", "是事等恶剧，裂石敢争雄。", "敲铿訇，扪滑仄，藉蒙茸。", "苍浪向来半掩，厚意复谁容。", "欲说正元旧事，未必玄都千树，得似洞中红。", "檐语亦颠倒，洗尔不平胸。"]'),
('song-ci-616','绮寮怨','刘辰翁','宋','宋词','song-ci','绮寮怨','["\u897f\u6e56"]','漫道十年前事，闷怀天又阴。',128,'宋词/ci.song.17000.json','["漫道十年前事，闷怀天又阴。", "何须恨、典了西湖，更笑君、宴罢琼林。", "闲时数声啼鸟，凄然似、上阳宫女心。", "记断桥、急管危弦，歌声远，玉树金缕沈。", "看万年枝上禽。", "徊徨落月，断肠理绝弦琴。", "魂梦追寻。", "挥泪赋白头吟。", "当年未知行乐，无日夜、望乡音。", "何期至今。", "绿杨外、芳草庭院深。"]'),
('song-ci-617','失调名','吴蒙庵','宋','宋词','song-ci','失调名','[]','忽忽早睡。',5,'宋词/ci.song.17000.json','["忽忽早睡。"]'),
('song-ci-618','醉太平','颜奎','宋','宋词','song-ci','醉太平','["\u9ec4\u6cb3"]','茶边水经。',46,'宋词/ci.song.17000.json','["茶边水经。", "琴边鹤经。", "小窗甲子初晴。", "报梅花小春。", "小冠晋人。", "小车洛人。", "醉扶儿子门生。", "指黄河解清。"]'),
('song-ci-619','清平乐','颜奎','宋','宋词','song-ci','清平乐','[]','留君少住。',54,'宋词/ci.song.17000.json','["留君少住。", "且待晴时去。", "夜深水鹤云间语。", "明日棠梨花雨。", "尊前不尽馀情。", "都上鸣弦细声。", "二十四番风后，绿阴芳草长亭。"]'),
('song-ci-620','归平遥・归国遥','颜奎','宋','宋词','song-ci','归平遥・归国遥','[]','春□□拂拂。',51,'宋词/ci.song.17000.json','["春□□拂拂。", "檐花双燕入。", "少年湖上风日。", "问天何处觅。", "湖山画屏晴碧。", "梦华知夙昔。", "东风忘了前迹。", "上青芜半壁。"]'),
('song-ci-621','浣溪沙','颜奎','宋','宋词','song-ci','浣溪沙','[]','梦泊游丝画影移。',48,'宋词/ci.song.17000.json','["梦泊游丝画影移。", "水沈香宛紫烟微。", "玉笙才过画楼西。", "天上人间花事苦，镜中翠压四山低。", "又成春过据莺啼。"]'),
('song-ci-622','菩萨蛮','颜奎','宋','宋词','song-ci','菩萨蛮','[]','燕姬越女初相见。',52,'宋词/ci.song.17000.json','["燕姬越女初相见。", "鬓云翻覆随风转。", "日日转如云。", "朝朝白发新。", "江南古佳丽。", "只绾年时髻，信手绾将成。", "从来懒学人。"]'),
('song-ci-623','忆秦娥','颜奎','宋','宋词','song-ci','忆秦娥','[]','水云幽。',56,'宋词/ci.song.17000.json','["水云幽。", "怕黄霜竹生新愁。", "生新愁。", "如今何处，倚月明楼。", "龙吟杳杳天悠悠。", "腾蛟起舞鸣箜篌。", "鸣箜篌。", "听吹短气，江上无秋。"]'),
('song-ci-624','大','颜奎','宋','宋词','song-ci','大','[]','唱古荼䕷，新荷叶，谁向重帘深处。',163,'宋词/ci.song.17000.json','["唱古荼䕷，新荷叶，谁向重帘深处。", "东风三十六，向园林都过，馀寒犹妒。", "公子狐裘，佳人翠袖，怎见此时情否。", "天上知音杳，怪参差律吕，世间多误。", "记画扇题诗，单衣试酒，梦归泥絮。", "嗟春如逆旅。", "送无路、远涉前无渡。", "回首住、凌波亭馆，待月楼台，满身花气凝香雾。", "度入南薰去。", "留燕伴、不教迟暮。", "但一点、芳心苦。", "生怕摇落，分付荷房收贮。", "晚妆又随过雨。"]'),
('song-ci-625','摸鱼儿','颜奎','宋','宋词','song-ci','摸鱼儿','[]','对琴台、不堪尘涴，春风微露纤指。',140,'宋词/ci.song.17000.json','["对琴台、不堪尘涴，春风微露纤指。", "峥嵘鹤膝翘空势，取次著花安蕊。", "偏有意。", "把竹外一枝，飞洒轻烟里。", "月痕如洗。", "又底事丹青，何须水墨，虚白阚清泚。", "华堂暮，珍重休弹麈尾。", "静中留此佳致。", "桥西几度香浮处，回首都随流水。", "闲徙倚。", "叹汨没黄埃，变幻皆如此。", "蜚廉莫起。", "待别有神人，风斤一运，和影上窗纸。"]'),
('song-ci-626','木兰花慢','尹济翁','宋','宋词','song-ci','木兰花慢','[]','渺渺怀芳意，苦对景、可怜生。',121,'宋词/ci.song.17000.json','["渺渺怀芳意，苦对景、可怜生。", "记燕外莺边，柳深竹嫩，度密穿青。", "如今淡烟细雨，正午窗半梦酒初醒。", "乐事怎堪重省，起来一饷愁萦。", "悠然又把酒壶倾。", "摆不动离情。", "想闲却春游，绿阴深院，芳草长亭。", "乾愁有谁解得，傍晚来，风起碎池萍。", "坐待晴云四卷，依然月上疏櫺。"]'),
('song-ci-627','玉蝴蝶','尹济翁','宋','宋词','song-ci','玉蝴蝶','[]','几许暮春清思，未知芍药，先拟荼蘼。',124,'宋词/ci.song.17000.json','["几许暮春清思，未知芍药，先拟荼蘼。", "老却东风，春去不与人期。", "似情多、何曾荀倩，便梦断、不为崔徽。", "且衔杯。", "暖风袭袭，淡日晖晖。", "怎知。", "怀芳心在，树花露泣，叶竹烟啼。", "满目青红，新愁成阵恨成围。", "画帘空、龙媒独倚，午阴静、燕子双飞。", "任春归。", "寻人柳下，梦句堂西。"]'),
('song-ci-628','声声慢','尹济翁','宋','宋词','song-ci','声声慢','[]','雕鞍芳径，翠管长亭，春酲不负妍华。',119,'宋词/ci.song.17000.json','["雕鞍芳径，翠管长亭，春酲不负妍华。", "几丈闲愁，寄风吹落天涯。", "深深小帘朱户，是何人、重整香车。", "愁未醒，记竹西歌吹，柳下人家。", "眉锁何曾舒展，看行人都是，醉眼横斜。", "寄语高阳，从今休唤流霞。", "残春又能几许，但相从、评水观茶。", "清梦远，怕东风、犹在杏花。"]'),
('song-ci-629','风入松','尹济翁','宋','宋词','song-ci','风入松','[]','曾闻几度说京华。',90,'宋词/ci.song.17000.json','["曾闻几度说京华。", "愁压帽檐斜。", "朝衣熨贴天香在，如今但、弹指兰闍。", "不是柴桑心远，等闲过了元嘉。", "长生休说枣如瓜。", "壶日自无涯。", "河倾南纪明奎璧，长教见、寿气成霞。", "但得重携溪上，年年人共梅花。"]'),
('song-ci-630','一萼红','尹济翁','宋','宋词','song-ci','一萼红','[]','玉搔头。',132,'宋词/ci.song.17000.json','["玉搔头。", "是何人敲折，应为节秦讴。", "棐几朱弦，剪灯雪藕，几回数尽更筹。", "草草又、一番春梦，梦觉了、风雨楚江秋。", "却恨闲身，不如鸿雁，飞过妆楼。", "又是山枯水瘦，叹回肠难贮，万斛新愁。", "懒复能歌，那堪对酒，物华冉冉都休。", "江上柳、千丝万缕，恼乱人、更忍凝眸。", "犹怕月来弄影，莫上帘钩。"]'),
('song-ci-631','诉衷情','郑楷','宋','宋词','song-ci','诉衷情','[]','酒旗摇曳柳花天。',54,'宋词/ci.song.17000.json','["酒旗摇曳柳花天。", "莺语软於绵。", "碎绿未盈芳沼，倒影蘸秋千。", "奁玉燕，套金蝉。", "负华年。", "试问归期，是酴醿后，是牡丹前。"]'),
('song-ci-632','谒金门','赵淇','宋','宋词','song-ci','谒金门','[]','吟望直。',53,'宋词/ci.song.17000.json','["吟望直。", "春在阑干咫尺。", "山插玉壶花倒立。", "雪明天混碧。", "晓露丝丝琼滴。", "虚揭一帘云湿。", "犹有残梅黄半壁。", "香随流水急。"]'),
('song-ci-633','绮罗香','张磐','宋','宋词','song-ci','绮罗香','[]','浦月窥檐，松泉漱枕，屏里吴山何处。',128,'宋词/ci.song.17000.json','["浦月窥檐，松泉漱枕，屏里吴山何处。", "暗粉疏红，依旧为谁匀注。", "都负了、燕约莺期，更闲却、柳烟花雨。", "纵十分、春到邮亭，赋怀应是断肠句。", "青青原上荠麦，还被东风无赖，翻成离绪。", "望极天西，惟有陇云江树。", "斜照带、一缕新愁，尽分付、暮潮归去。", "步闲阶、待卜心期，落花空细数。"]'),
('song-ci-634','浣溪纱・浣溪沙','张磐','宋','宋词','song-ci','浣溪纱・浣溪沙','[]','习习轻风破海棠。',48,'宋词/ci.song.17000.json','["习习轻风破海棠。", "秋千移影上回廊。", "昼长蝴蝶为谁忙。", "度柳早莺分暖绿，过花小燕带春香。", "满庭芳草又斜阳。"]'),
('song-ci-635','唐多令','张林','宋','宋词','song-ci','唐多令','[]','金勒鞚花骢。',74,'宋词/ci.song.17000.json','["金勒鞚花骢。", "故山云雾中。", "翠苹洲、先有西风。", "可惜嫩凉时枕簟，都付与、旧山翁。", "双翠合眉峰。", "泪华分脸红。", "向尊前、何太匆匆。", "才是别离情便苦，都莫问、淡和浓。"]'),
('song-ci-636','柳梢青','张林','宋','宋词','song-ci','柳梢青','[]','白玉枝头，忽看蓓蕾，金粟珠垂。',61,'宋词/ci.song.17000.json','["白玉枝头，忽看蓓蕾，金粟珠垂。", "半颗安榴，一枝秾杏，五色蔷薇。", "何须羯鼓声催。", "银釭里、春工四时。", "却笑灯蛾，学他蝴蝶，照影频飞。"]'),
('song-ci-637','江城子','曹良史','宋','宋词','song-ci','江城子','[]','夜香烧了夜寒生。',86,'宋词/ci.song.17000.json','["夜香烧了夜寒生。", "掩银屏。", "理银筝。", "一曲春风，都是断肠声。", "杜宇欲啼杨柳外，愁似海，思如云。", "背灯暗卸乳鹅裙。", "酒初酲。", "梦初醒。", "兰炷香篝，谁为暖罗衾。", "二十四帘人悄悄，花影碎，月痕深。"]'),
('song-ci-638','柳梢青','赵与仁','宋','宋词','song-ci','柳梢青','[]','露冷仙梯。',61,'宋词/ci.song.17000.json','["露冷仙梯。", "霓裳散舞，记取人归。", "月度层霄，雨连深夜，谁管花飞。", "金铺满地苔衣。", "似一片、斜阳未移。", "生怕清香，又随凉信，吹过东篱。"]'),
('song-ci-639','相思引','赵与仁','宋','宋词','song-ci','相思引','[]','冰箔纱帘小院清。',54,'宋词/ci.song.17000.json','["冰箔纱帘小院清。", "晴尘不动地花平。", "昨宵风雨，凉到木樨屏。", "香月照妆秋粉薄，水云飞佩藕丝轻。", "好天良夜，闲理玉靴笙。"]'),
('song-ci-640','西江月','赵与仁','宋','宋词','song-ci','西江月','[]','夜半河痕依约，雨馀天气冥濛。',66,'宋词/ci.song.17000.json','["夜半河痕依约，雨馀天气冥濛。", "起行微月遍池东。", "水影浮花、花影动帘栊。", "量减难追醉白，恨长莫尽题红。", "雁声能到画楼中。", "也要玉人、知道有秋风。"]'),
('song-ci-641','清平乐','赵与仁','宋','宋词','song-ci','清平乐','[]','柳丝摇露。',54,'宋词/ci.song.17000.json','["柳丝摇露。", "不绾兰舟住。", "人宿溪桥知那处。", "一夜风声千树。", "晓楼望断天涯。", "过鸿影落寒沙。", "可惜些儿秋意，等闲过了黄花。"]'),
('song-ci-642','好事近','赵与仁','宋','宋词','song-ci','好事近','[]','春色醉酴醿，昼永篆烟初绝。',53,'宋词/ci.song.17000.json','["春色醉酴醿，昼永篆烟初绝。", "临水杨花千树，尽一时飞雪。", "穿帘度竹弄轻盈，东风老犹劣。", "睡起凭栏无绪，听几声啼鴂。"]'),
('song-ci-643','乌夜啼','陈逢辰','宋','宋词','song-ci','乌夜啼','[]','月痕未到朱扉。',45,'宋词/ci.song.17000.json','["月痕未到朱扉。", "送郎时。", "暗里一汪儿泪、没人知。", "搵不住。", "收不聚。", "被风吹。", "吹作一天愁雨、损花枝。"]'),
('song-ci-644','西江月','陈逢辰','宋','宋词','song-ci','西江月','[]','杨柳雪融滞雨，酴醿玉软欺风。',58,'宋词/ci.song.17000.json','["杨柳雪融滞雨，酴醿玉软欺风。", "飞英簌簌扣调栊。", "残蝶归来粉重。", "罨画扇题尘掩，绣花纱带寒笼。", "送春先自费啼红。", "更结疏云秋梦。"]'),
('song-ci-645','菩萨蛮','史介翁','宋','宋词','song-ci','菩萨蛮','[]','柳丝轻颺黄金缕。',52,'宋词/ci.song.17000.json','["柳丝轻颺黄金缕。", "织成一片沙窗雨。", "斗合做春愁。", "困慵熏玉篝。", "暮寒罗袖薄。", "社雨催花落。", "先自为诗忙。", "蔷薇一阵香。"]'),
('song-ci-646','谒金门','何光大','宋','宋词','song-ci','谒金门','[]','天似水。',53,'宋词/ci.song.17000.json','["天似水。", "池上藕花风起。", "隔岸垂杨青到地。", "乱萤飞又止。", "露湿玉阑闲倚。", "人静自生凉意。", "泛碧沈朱供晚醉。", "月斜才去睡。"]'),
('song-ci-647','霓裳中序第一','应法孙','宋','宋词','song-ci','霓裳中序第一','[]','愁云翠万叠。',124,'宋词/ci.song.17000.json','["愁云翠万叠。", "露柳残蝉空抱叶。", "帘卷流苏宝结。", "乍庭户嫩凉，阑干微月。", "玉纤胜雪。", "委素纨、尘锁香箧。", "思前事、莺期燕约，寂寞向谁说。", "悲切。", "漏签声咽。", "渐寒炧、兰缸未灭。", "良宵长是闲别。", "恨酒凝红绡，纷涴瑶玦。", "镜盟鸾影缺。", "吹笛西风数阕。", "无言久，和衣成梦，睡损缕金蝶。"]'),
('song-ci-648','贺新郎','应法孙','宋','宋词','song-ci','贺新郎','[]','宿雾楼台湿。',142,'宋词/ci.song.17000.json','["宿雾楼台湿。", "晓清初、花明柳润，燕飞莺集。", "旧约重来歌舞地，留得艳香娇色。", "又梦草、东风吹碧。", "午困腾腾春欲醉，对文楸、玉子无心拾。", "看蝶舞，傍花立。", "酒痕未醒愁先入。", "记年时、翠楼寒浅，宝笙慵吸。", "想驻马河桥分别，恨轻竹风帆烟笠。", "早尘暗、华堂帘隙。", "倚尽黄昏人独自，望江南回雁归云急。", "凭付与，锦笺墨。"]'),
('song-ci-649','高阳台','王亿之','宋','宋词','song-ci','高阳台','[]','双桨敲冰，低篷护冷，扁舟晓渡西泠。',122,'宋词/ci.song.17000.json','["双桨敲冰，低篷护冷，扁舟晓渡西泠。", "回首吴山，微茫遥带重城。", "堤边几树垂杨柳，早嫩黄、摇动春情。", "问孤鸿，何处飞来，共唤飘零。", "轻帆初落沙洲暝，渐潮痕雨渍，面色风皴。", "旅思羁愁，偏能老大行人。", "姮娥不管征途苦，甚夜深、尽照孤衾。", "想玉楼，犹凭栏干，为我销凝。"]'),
('song-ci-650','高阳台','王茂孙','宋','宋词','song-ci','高阳台','[]','迟日烘晴，轻烟缕昼，琐窗雕户慵开。',122,'宋词/ci.song.17000.json','["迟日烘晴，轻烟缕昼，琐窗雕户慵开。", "人独春闲，金猊暖透兰煤。", "山屏缓倚珊瑚畔，任翠阴、移过瑶阶。", "悄无声，彩翅翩翩，何处飞来。", "片时千里江南路，被东风误引，还近阳台。", "腻雨娇云，多情恰喜徘徊。", "无端枝上啼鸠唤，便等闲、孤枕惊回。", "恶情怀，一院杨花，一径苍苔。"]'),
('song-ci-651','点绛唇','王茂孙','宋','宋词','song-ci','点绛唇','[]','折断烟痕，翠蓬初离鸳鸯浦。',50,'宋词/ci.song.17000.json','["折断烟痕，翠蓬初离鸳鸯浦。", "玉纤相妒。", "翻被专房误。", "乍脱青衣，犹著轻罗护。", "多情处。", "芳心一缕。", "都为相思苦。"]'),
('song-ci-652','真珠帘','朱孙','宋','宋词','song-ci','真珠帘','[]','春云做冷春知未。',123,'宋词/ci.song.17000.json','["春云做冷春知未。", "春愁在、碎雨敲花声里。", "海燕已寻踪，到画溪沙际。", "院落秋千杨柳外。", "待天气、十分晴霁。", "春市。", "又青帘巷陌，红芳歌吹。", "须这处处东风，又何妨对此，笼香觅醉。", "曲尽索馀情，奈夜航催离。", "梦满冰衾身似寄。", "算几度、吴乡烟水。", "无寐。", "试明朝说与，西园桃李。"]'),
('song-ci-653','新荷叶','郑斗焕','宋','宋词','song-ci','新荷叶','[]','乳鸭池塘，晴波漾绿鳞鳞。',100,'宋词/ci.song.17000.json','["乳鸭池塘，晴波漾绿鳞鳞。", "宿藕根香，夏来生意还新。", "蚨钱小、钿花贴翠，相间萍星。", "一番雨过，一番暗展圆青。", "鱼戏龟游，看来犹未胜情。", "因忆年时，垂钓曾约轻盈。", "玉人何处，关情是、半卷芳心。", "帘风一棹，鸳鸯催起歌声。"]'),
('song-ci-654','市桥柳','蜀中妓','宋','宋词','song-ci','市桥柳','[]','欲寄意、浑无所有。',69,'宋词/ci.song.17000.json','["欲寄意、浑无所有。", "折尽市桥官柳。", "看君著上征衫，又相将，放船楚江口。", "后会不知何日又。", "是男儿、休要镇长相守。", "苟富贵、无相忘，若相忘，有如此酒。"]'),
('song-ci-655','小重山','周容','宋','宋词','song-ci','小重山','[]','谢了梅花恨不禁。',70,'宋词/ci.song.17000.json','["谢了梅花恨不禁。", "小楼羞独倚，暮云平。", "夕阳微放柳梢明。", "东风冷，眉岫翠寒生。", "无限远山青。", "重重遮不断，旧离情。", "伤春还上去年心。", "怎禁得，时节又烧灯。"]'),
('song-ci-656','祝英台近','张涅','宋','宋词','song-ci','祝英台近','[]','一番风，连夜雨。',95,'宋词/ci.song.17000.json','["一番风，连夜雨。", "收拾做春暮。", "艳冷香销，莺燕惨无语。", "晓来绿水桥边，青门陌上，不忍见、落红无数。", "怎分付。", "独倚红药栏边，伤春甚情绪。", "若取留春，欲去去何处。", "也知春亦多情，依依欲住。", "子规道、不如归去。"]'),
('song-ci-657','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','恰芳菲梦醒，漾残月、转湘帘。',125,'宋词/ci.song.17000.json','["恰芳菲梦醒，漾残月、转湘帘。", "正翠崦收钟，彤墀放仗，台榭轻烟。", "东园。", "夜游乍散，听金壶、逗晓歇花签。", "宫柳微开露眼，小莺寂妒春眠。", "冰奁。", "黛浅红鲜。", "临晓鉴、竞晨妍。", "怕误却佳期，宿妆旋整，忙上雕軿。", "都缘探芳起早，看堤边、早有已开船。", "薇帐残香泪蜡，有人病酒恹恹。"]'),
('song-ci-658','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','碧霄澄暮霭，引琼驾、碾秋光。',126,'宋词/ci.song.17000.json','["碧霄澄暮霭，引琼驾、碾秋光。", "看翠阕风高，珠楼夜午，谁捣玄霜。", "沧茫。", "玉田万顷，趁仙查、咫尺接天潢。", "彷佛凌波步影，露浓佩冷衣凉。", "明珰。", "净洗新妆。", "随皓彩、过西厢。", "正雾衣香润，云鬟绀湿，私语相将。", "鸳鸯。", "误惊梦晓，掠芙蓉、度影入银塘。", "十二栏干伫立，凤箫怨彻清商。"]'),
('song-ci-659','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','觅梅花信息，拥吟袖、暮鞭寒。',126,'宋词/ci.song.17000.json','["觅梅花信息，拥吟袖、暮鞭寒。", "自放鹤人归，月香水影，诗冷孤山。", "等闲。", "冸寒睍暖，看融城、御水到人间。", "瓦陇竹根更好，柳边小驻游鞍。", "琅玕。", "半倚云湾。", "孤棹晚、载诗还。", "是醉魂醒处，画桥第二，奁月初三。", "东阑。", "有人步玉，怪冰泥、沁湿锦鹓斑。", "还见晴波涨绿，谢池梦草相关。"]'),
('song-ci-660','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','塔轮分断雨，倒霞影、漾新晴。',126,'宋词/ci.song.17000.json','["塔轮分断雨，倒霞影、漾新晴。", "看满鉴春红，轻桡占岸，叠鼓收声。", "帘旌。", "半钩待燕，料香浓、径远趱蜂程。", "芳陌人扶醉玉，路旁懒拾遗簪。", "郊坰。", "未厌游情。", "云暮合、谩消凝。", "想罢歌停舞，烟花露柳，都付栖莺。", "重闉。", "已催凤钥，正钿车、绣勒入争门。", "银烛擎花夜暖，禁街淡月黄昏。"]'),
('song-ci-661','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','软尘飞不到，过微雨、锦机张。',126,'宋词/ci.song.17000.json','["软尘飞不到，过微雨、锦机张。", "正荫绿池幽，交枝径窄，临水追凉。", "宫妆。", "盖罗障暑，泛青苹、乱舞五云裳。", "迷眼红绡绛彩，翠深偷见鸳鸯。", "湖光。", "两岸潇湘。", "风荐爽、扇摇香。", "算恼人偏是，萦丝露藕，连理秋房。", "涉江。", "采芳旧恨，怕红衣、夜冷落横塘。", "折得荷花忘却，棹歌唱入斜阳。"]'),
('song-ci-662','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','六桥春浪暖，涨桃雨、鳜初肥。',126,'宋词/ci.song.17000.json','["六桥春浪暖，涨桃雨、鳜初肥。", "正短棹轻蓑，牵筒荇带，萦网莼丝。", "依稀。", "岸红溯远，漾仙舟、误入武陵溪。", "何处金刀脍玉，画船傍柳频催。", "芳堤。", "渐满斜晖。", "舟叶乱、浪花飞。", "听暮榔声合，鸥沈暗渚，鹭起烟矶。", "忘机。", "夜深浪静，任烟寒、自载月明归。", "三十六鳞过却，素笺不寄相思。"]'),
('song-ci-663','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','疏钟敲暝色，正远树、绿愔愔。',126,'宋词/ci.song.17000.json','["疏钟敲暝色，正远树、绿愔愔。", "看渡水僧归，投林鸟聚，烟冷秋屏。", "孤云。", "渐沈雁影，尚残箫、倦鼓别游人。", "宫柳栖鸦未稳，露梢已挂疏星。", "重城。", "禁鼓催更。", "罗袖怯、暮寒轻。", "想绮疏空掩，鸾绡翳锦，鱼钥收银。", "兰灯。", "伴人夜语，怕香消、漏永著温存。", "犹忆回廊待月，画阑倚遍桐阴。"]'),
('song-ci-664','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','晴空摇翠浪，昼禽静、霁烟收。',126,'宋词/ci.song.17000.json','["晴空摇翠浪，昼禽静、霁烟收。", "听暗柳啼莺，新簧弄巧，如度秦讴。", "谁紬。", "翠丝万缕，颺金梭、宛转织芳愁。", "风袅馀音甚处，絮花三月宫沟。", "扁舟。", "缆系轻柔。", "沙路远、倦追游。", "望断桥斜日，蛮腰竞舞，苏小墙头。", "偏忧。", "杜鹃唤去，镇绵蛮、竟日挽春留。", "啼觉琼疏午梦，翠丸惊度西楼。"]'),
('song-ci-665','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','游船人散后，正蟾影、印寒湫。',126,'宋词/ci.song.17000.json','["游船人散后，正蟾影、印寒湫。", "看冷沁鲛眠，清宜兔浴，皓彩轻浮。", "扁舟。", "泛天镜里，溯流光、澄碧浸明眸。", "栖鹭空惊碧草，素鳞远避金钩。", "临流。", "万象涵秋。", "怀渺渺、水悠悠。", "念汉皋遗佩，湘波步袜，空想仙游。", "风收。", "翠奁乍启，度飞星、倒影入芳洲。", "瑶瑟谁弹古怨，渚宫夜舞潜虬。"]'),
('song-ci-666','木兰花慢','周密','宋','宋词','song-ci','木兰花慢','[]','碧尖相对处，向烟外、挹遥岑。',126,'宋词/ci.song.17000.json','["碧尖相对处，向烟外、挹遥岑。", "记舞鹫啼猿，天香桂子，曾去幽寻。", "轻阴。", "易晴易雨，看南峰、淡日北峰云。", "双塔秋擎露冷，乱钟晓送霜清。", "登临。", "望眼增明。", "沙路白、海门青。", "正地幽天迥，水鸣山籁，风奏松琴。", "虚楹。", "半空聚远，倚栏干、暮色与云平。", "明月千岩夜午，溯风跨鹤吹笙。"]'),
('song-ci-667','失调名','周密','宋','宋词','song-ci','失调名','[]','商，西风只在垂杨外。',10,'宋词/ci.song.17000.json','["商，西风只在垂杨外。"]'),
('song-ci-668','浪淘沙','周密','宋','宋词','song-ci','浪淘沙','[]','新雨洗晴空。',64,'宋词/ci.song.17000.json','["新雨洗晴空。", "碧浅眉峰。", "翠楼西畔画桥东。", "柳线嫩黄才半染，眼眼东风。", "绣户掩芙蓉。", "帐减香筒。", "远烟轻霭弄春容。", "雁雁又归莺未到，谁寄愁红。"]'),
('song-ci-669','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','几点红香入玉壶。',48,'宋词/ci.song.17000.json','["几点红香入玉壶。", "几枝红影上金铺。", "昼长人困斗樗蒱。", "花径日迟蜂课蜜，杏梁风软燕调雏。", "荼䕷开了有春无。"]'),
('song-ci-670','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','波影摇花碎锦铺。',48,'宋词/ci.song.17000.json','["波影摇花碎锦铺。", "竹风清泛玉扶疏。", "画屏纹枕小纱幮。", "合色麝囊分翠绣，夹罗萤扇缕金书。", "十分凉意淡妆梳。"]'),
('song-ci-671','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','浅色初栽试暖衣。',48,'宋词/ci.song.17000.json','["浅色初栽试暖衣。", "画帘斜日看花飞。", "柳摇蛾绿妒春眉。", "象局懒拈双陆子，宝弦愁按十三徽。", "试凭新燕问归期。"]'),
('song-ci-672','东风第一枝','周密','宋','宋词','song-ci','东风第一枝','[]','草梦初回，柳眠未起，新阴才试花讯。',123,'宋词/ci.song.17000.json','["草梦初回，柳眠未起，新阴才试花讯。", "雏鸳迎晓偎香，小蝶舞晴弄影。", "飞梭庭院，早已觉、日迟人静。", "画帘轻、不隔春寒，旋减酒红香晕。", "吟欲就、远烟催暝。", "人欲醉、晚风吹醒。", "瘦肌羞怯金宽，笑靥暖融粉沁。", "珠歌缓引。", "更巧试、杏妆梅鬓。", "怕等闲、虚度芳期，老却翠娇红嫩。"]'),
('song-ci-673','楚宫春・楚宫春慢','周密','宋','宋词','song-ci','楚宫春・楚宫春慢','[]','香迎晓白。',132,'宋词/ci.song.17000.json','["香迎晓白。", "看烟佩霞绡，弄妆金谷。", "倦倚画阑，无语情深娇足。", "云拥瑶房翠暖，绣帐卷、东风倾国。", "半捻愁红，念旧游、凝伫兰翘，瑞鸾低舞庭绿。", "犹想沈香亭北。", "人醉里，芳笔曾题新曲。", "自翦露痕，移取春归华屋。", "丝障银屏静掩，悄未许、莺窥蝶宿。", "绛蜡良宵，酒半阑、重绕鸳机，醉靥争妍红玉。"]'),
('song-ci-674','大圣乐','周密','宋','宋词','song-ci','大圣乐','[]','娇绿迷云，倦红颦晓，嫩晴芳树。',130,'宋词/ci.song.17000.json','["娇绿迷云，倦红颦晓，嫩晴芳树。", "渐午阴、帘影移香，燕语梦回，千点碧桃吹雨。", "冷落锦宫人归后，记前度兰桡停翠浦。", "凭栏久，谩凝想凤翘，慵听金缕。", "留春问谁最苦。", "奈花自无言莺自语。", "对画楼残照，东风吹远，天涯何许。", "怕折露条愁轻别，更烟暝长亭听杜宇。", "垂杨晚，但罗袖、暗沾飞絮。"]'),
('song-ci-675','三犯渡江云・渡江云','周密','宋','宋词','song-ci','三犯渡江云・渡江云','[]','冰溪空岁晚，苍茫雁影，浅水落寒沙。',124,'宋词/ci.song.17000.json','["冰溪空岁晚，苍茫雁影，浅水落寒沙。", "那回乘夜兴，云雪孤舟，曾访故人家。", "千林未绿，芳信暖、玉照霜华。", "共凭高，联诗唤酒，暝色夺昏鸦。", "堪嗟。", "澌鸣玉佩，山护云衣，又扁舟东下。", "想故园、天寒倚竹，袖薄笼纱。", "诗筒已是经年别，早暖律、春动香葭。", "愁寄远，溪边自折梅花。"]'),
('song-ci-676','露华','周密','宋','宋词','song-ci','露华','[]','暖消蕙雪，渐水纹漾锦，云淡波溶。',115,'宋词/ci.song.17000.json','["暖消蕙雪，渐水纹漾锦，云淡波溶。", "岸香弄蕊，新枝轻袅条风。", "次第燕归将近，爱柳眉、桃靥烟浓。", "鸳径小，芳屏聚蝶，翠渚飘鸿。", "六桥旧情如梦，记扇底宫眉，花下游骢。", "选歌试舞，连宵恋醉珍丛。", "怕里早莺啼醒，问杏钿、谁点愁红。", "心事悄，春娇又入翠峰。"]'),
('song-ci-677','桃源忆故人','周密','宋','宋词','song-ci','桃源忆故人','[]','流苏静掩罗屏小。',56,'宋词/ci.song.17000.json','["流苏静掩罗屏小。", "春梦苦无分晓。", "一缕旧情谁表。", "暗逐馀响袅。", "相思谩寄流红杳。", "人瘦花枝多少。", "郎马未归春老。", "空怨王孙草。"]'),
('song-ci-678','糖多令・唐多令','周密','宋','宋词','song-ci','糖多令・唐多令','[]','丝雨织莺梭。',76,'宋词/ci.song.17000.json','["丝雨织莺梭。", "浮钱点细荷。", "燕风轻、庭宇正清和。", "苔面唾茸堆绣径，春去也、奈春何。", "宫柳老青娥。", "题红隔翠波。", "扇鸾孤、尘暗合欢罗。", "门外绿阴深似海，应未比、旧愁多。"]'),
('song-ci-679','西江月','周密','宋','宋词','song-ci','西江月','[]','波影暖浮玉甃，柳阴深锁金铺。',58,'宋词/ci.song.17000.json','["波影暖浮玉甃，柳阴深锁金铺。", "湘桃花褪燕调雏。", "又是一番春暮。", "碧柱情深凤怨，云屏梦浅莺呼。", "绣窗人倦冷熏垆。", "帘影摇花亭午。"]'),
('song-ci-680','菩萨蛮','周密','宋','宋词','song-ci','菩萨蛮','[]','霜风渐入龙香被。',52,'宋词/ci.song.17000.json','["霜风渐入龙香被。", "夜寒微涩宫壶水。", "滴滴是愁声。", "声声滴到明。", "梦魂随雁去。", "飞到颦眉处。", "雁已过西楼。", "又还和梦愁。"]'),
('song-ci-681','绣鸾凤花犯・花犯','周密','宋','宋词','song-ci','绣鸾凤花犯・花犯','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楚江湄，湘娥乍见，无言洒清泪。',126,'宋词/ci.song.17000.json','["楚江湄，湘娥乍见，无言洒清泪。", "淡然春意。", "空独倚东风，芳思谁寄。", "凌波路冷秋无际。", "香云随步起。", "谩记得，汉宫仙掌，亭亭明月底。", "冰弦写怨更多情，骚人恨，枉赋芳兰幽芷。", "春思远，谁叹赏、国香风味。", "相将共、岁寒伴侣。", "小窗净、沈烟熏翠袂。", "幽梦觉，涓涓清露，一枝灯影里。"]'),
('song-ci-682','探春慢','周密','宋','宋词','song-ci','探春慢','[]','彩胜宜春，翠盘消夜，客里暗惊时候。',125,'宋词/ci.song.17000.json','["彩胜宜春，翠盘消夜，客里暗惊时候。", "翦燕心情，呼卢笑语，景物总成怀旧。", "愁鬓妒垂杨，怪稚眼、渐浓如豆。", "尽教宽尽春衫，毕竟为谁消瘦。", "梅浪半空如绣。", "便管领芳菲，忍孤诗酒。", "映烛占花，临窗卜镜，还念嫩寒宫袖。", "箫鼓动春城，竞点缀、玉梅金柳。", "厮句元宵，灯前共谁携手。"]'),
('song-ci-683','瑶花慢','周密','宋','宋词','song-ci','瑶花慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','朱钿宝玦。',126,'宋词/ci.song.17000.json','["朱钿宝玦。", "天上飞琼，比人间春别。", "江南江北，曾未见，谩拟梨云梅雪。", "淮山春晚，问谁识、芳心高洁。", "消几番、花落花开，老了玉关豪杰。", "金壶翦送琼枝，看一骑红尘，香度瑶阙。", "韶华正好，应自喜、初识长安蜂蝶。", "杜郎老矣，想旧事、花须能说。", "记少年，一梦扬州，二十四桥明月。"]'),
('song-ci-684','玉京秋','周密','宋','宋词','song-ci','玉京秋','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','烟水阔。',113,'宋词/ci.song.17000.json','["烟水阔。", "高林弄残照，晚蜩凄切。", "碧砧度韵，银床飘叶。", "衣湿桐阴露冷，采凉花、时赋秋雪。", "叹轻别。", "一襟幽事，砌蛩能说。", "客思吟商还怯。", "怨歌长、琼壶暗缺。", "翠扇恩疏，红衣香褪，翻成消歇。", "玉骨西风，恨最恨、闲却新凉时节。", "楚箫咽。", "谁倚西楼淡月。"]'),
('song-ci-685','鹧鸪天','周密','宋','宋词','song-ci','鹧鸪天','[]','燕子时时度翠帘。',64,'宋词/ci.song.17000.json','["燕子时时度翠帘。", "柳寒犹未褪香绵。", "落花门巷家家雨，新火楼台处处烟。", "情默默，恨恹恹。", "东风吹动画秋千。", "拆桐开尽莺声老，无奈春何只醉眠。"]'),
('song-ci-686','夜行船','周密','宋','宋词','song-ci','夜行船','[]','蛩老无声深夜静。',68,'宋词/ci.song.17000.json','["蛩老无声深夜静。", "新霜桀、一帘灯影。", "妒梦鸿高，烘愁月浅，萦乱恨丝难整。", "笙字娇娥谁为靓。", "香襟冷、怕看妆印。", "绣阁藏春，海棠偷暖，还似去年风景。"]'),
('song-ci-687','采绿吟','周密','宋','宋词','song-ci','采绿吟','[]','采绿鸳鸯浦，画舸水北云西。',122,'宋词/ci.song.17000.json','["采绿鸳鸯浦，画舸水北云西。", "槐薰入扇，柳阴浮桨，花露侵诗。", "点尘飞不到，冰壶里、绀霞浅压玻璃。", "想明珰、凌波远，依依心事寄谁。", "移棹舣空明，苹风度、琼丝霜管清脆。", "咫尺挹幽香，怅岸隔红衣。", "对沧洲、心与鸥闲，吟情渺、莲叶共分题。", "停杯久，凉月渐生，烟合翠微。"]'),
('song-ci-688','解语花','周密','宋','宋词','song-ci','解语花','[]','晴丝罥蝶，暖蜜酣蜂，重檐卷春寂寂。',122,'宋词/ci.song.17000.json','["晴丝罥蝶，暖蜜酣蜂，重檐卷春寂寂。", "雨萼烟梢，压阑干、花雨染衣红湿。", "金鞍误约，空极目、天涯草色。", "阆苑玉箫人去后，惟有莺知得。", "馀寒犹掩翠户，梁燕乍归，芳信未端的。", "浅薄东风，莫因循、轻把杏钿狼藉。", "尘侵锦瑟。", "残日绿窗春梦窄。", "睡起折花无意绪，斜倚秋千立。"]'),
('song-ci-689','曲游春','周密','宋','宋词','song-ci','曲游春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楚苑东风外，颺暖丝情絮，春思如织。',128,'宋词/ci.song.17000.json','["楚苑东风外，颺暖丝情絮，春思如织。", "燕约莺期，恼芳情偏在，翠深红隙。", "漠漠香尘隔。", "沸十里、乱弦丛笛。", "看画船，尽入西泠，闲却半湖春色。", "柳陌。", "新烟凝碧。", "映帘底宫眉，堤上游勒。", "轻暝笼寒，怕梨云梦冷，杏香愁幂。", "歌管酬寒食。", "奈蝶怨、良宵岑寂。", "正满湖、碎月摇花，怎生去得。"]'),
('song-ci-690','大圣乐','周密','宋','宋词','song-ci','大圣乐','["\u897f\u6e56"]','虹雨霉风，翠萦苹渚，锦翻葵径。',130,'宋词/ci.song.17000.json','["虹雨霉风，翠萦苹渚，锦翻葵径。", "正小亭、曲沼幽深，簟枕梦回，苔色槐阴清润。", "暗忆兰汤初洗玉，衬碧雾笼绡垂蕙领。", "轻妆了，袅凉花绛缕，香满鸾镜。", "人闲午迟漏永。", "看双燕将雏穿藻井。", "喜玉壶无暑，凉涵荷气，波摇帘影。", "画舸西湖浑如旧，又菰冷蒲香惊梦醒。", "归舟晚，听谁家、紫箫声近。"]'),
('song-ci-691','桂枝香','周密','宋','宋词','song-ci','桂枝香','[]','岩霏逗绿。',122,'宋词/ci.song.17000.json','["岩霏逗绿。", "又凉入小山，千树幽馥。", "仙影悬霜粲夜，楚宫六六。", "明霞洞窅珊瑚冷，对清商、吟思堪掬。", "麝痕微沁，蜂黄浅约，数枝秋足。", "别有雕阑翠屋。", "任满帽珠尘，拼醉香玉。", "瘦倚西风，谁见露侵肌粟。", "好秋能几花前笑，绕凉云、重唤银烛。", "宝瓶空晓，珍丛怨月，梦回金谷。"]'),
('song-ci-692','杏花天','周密','宋','宋词','song-ci','杏花天','[]','瑞云盘翠侵妆额。',65,'宋词/ci.song.17000.json','["瑞云盘翠侵妆额。", "眉柳嫩、不禁愁积。", "返魂谁染东风笔。", "写出郢中春色。", "人去后、垂杨自碧。", "歌舞梦、欲寻无迹。", "愁随两桨江南北。", "日暮石城风急。"]'),
('song-ci-693','杏花天','周密','宋','宋词','song-ci','杏花天','[]','汉宫乍出慵梳掠。',65,'宋词/ci.song.17000.json','["汉宫乍出慵梳掠。", "关月冷、玉沙飞幕。", "龙香拨重春葱弱。", "一曲哀弦谩托。", "君恩厚、空怜命薄。", "青冢远、几番花落。", "丹青自是难描摸。", "不是当时画错。"]'),
('song-ci-694','南楼令・唐多令','周密','宋','宋词','song-ci','南楼令・唐多令','[]','桂影满空庭。',74,'宋词/ci.song.17000.json','["桂影满空庭。", "愁更廿五声。", "一声声、都是消凝。", "新雁旧蛩相应和。", "禁不过、冷清清。", "酒与梦俱醒。", "病因愁做成。", "展红绡、犹有馀馨。", "暗想芙蓉城下路，花可可、雾冥冥。"]'),
('song-ci-695','南楼令・唐多令','周密','宋','宋词','song-ci','南楼令・唐多令','[]','敧沈听西风。',74,'宋词/ci.song.17000.json','["敧沈听西风。", "蛩阶月正中。", "弄秋声、金井孤桐。", "闲省十年吴下路，船几度、系江枫。", "辇路又迎逢。", "秋如归兴浓。", "叹淹留、还见新冬。", "湖外霜林秋似锦，一片片、忍题红。"]'),
('song-ci-696','秋霁','周密','宋','宋词','song-ci','秋霁','[]','重到西冷，记芳园载酒，画船横笛。',128,'宋词/ci.song.17000.json','["重到西冷，记芳园载酒，画船横笛。", "水曲芙蓉，渚边鸥鹭，依依似曾相识。", "年芳易失。", "段桥几换垂杨色。", "谩自惜。", "愁损庾郎，霜点鬓华白。", "残蛩露草，怨蝶寒花，转眼西风，又成陈迹。", "叹如今、才消量减，尊前孤负醉吟笔。", "欲寄远情秋水隔。", "旧游空在，凭高望极斜阳，乱山浮紫，暮云凝碧。"]'),
('song-ci-697','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','宫檐融暖晨妆懒。',123,'宋词/ci.song.17000.json','["宫檐融暖晨妆懒。", "轻霞未匀酥脸。", "倚竹娇颦，临流瘦影，依约尊前重见。", "盈盈笑靥。", "映珠络玲珑，翠绡葱茜。", "梦入罗浮，满衣清露暗香染。", "东风千树易老，怕红颜旋减，芳意偷变。", "赠远天寒，吟香夜永，多少江南新怨。", "琼疏静掩。", "任翦雪栽云，竞夸轻艳。", "画角黄昏，梦随春共远。"]'),
('song-ci-698','忆旧游','周密','宋','宋词','song-ci','忆旧游','[]','念芳钿委路，粉浪翻空，谁补春痕。',123,'宋词/ci.song.17000.json','["念芳钿委路，粉浪翻空，谁补春痕。", "伫立伤心事，记宫檐点鬓，候馆沾襟。", "东君护香情薄，不管径云深。", "叹金谷楼危，避风台浅，消瘦飞琼。", "梨云已成梦，谩蝶恨凄凉，人怨黄昏。", "拈残枝重嗅，似徐娘虽老，犹有风情。", "不禁许多芳思，青子渐成阴。", "怕酒醒歌阑，空庭夜月羌管清。"]'),
('song-ci-699','一枝春','周密','宋','宋词','song-ci','一枝春','[]','碧淡春姿，柳眠醒、似怯朝来酥雨。',116,'宋词/ci.song.17000.json','["碧淡春姿，柳眠醒、似怯朝来酥雨。", "芳程乍数。", "唤起探花情绪。", "东风尚浅，甚先有、翠娇红妩。", "应自把、罗绮围春，占得画屏春聚。", "留连绣丛深处。", "爱歌云袅袅，低随香缕。", "琼窗夜暖，试与细评新谱。", "妆梅媚晚，料无那、弄颦佯妒。", "还怕里、帘外笼莺，笑人醉语。"]'),
('song-ci-700','一枝春','周密','宋','宋词','song-ci','一枝春','[]','帘影移阴，杏香寒、乍湿西园丝雨。',116,'宋词/ci.song.17000.json','["帘影移阴，杏香寒、乍湿西园丝雨。", "芳期暗数。", "又是去年心绪。", "金花谩翦，倩谁画、旧时眉妩。", "空自想、杨柳风流，泪滴软绡红聚。", "罗窗那回歌处。", "叹庭花倦舞，香消衣缕。", "楼空燕冷，碎锦懒寻尘谱。", "么弦谩赋，记曾是、倚娇成妒。", "深院悄，闲掩梨花，倩莺寄语。"]'),
('song-ci-701','点绛唇','周密','宋','宋词','song-ci','点绛唇','[]','雪霁寒轻，兴来载酒移吟艇。',50,'宋词/ci.song.17000.json','["雪霁寒轻，兴来载酒移吟艇。", "玉田千顷。", "桥外诗情迥。", "重到孤山，往事何愁醒。", "东风紧。", "水边疏影。", "谁念梅花冷。"]'),
('song-ci-702','恋绣衾','周密','宋','宋词','song-ci','恋绣衾','[]','粉黄衣薄沾麝尘。',66,'宋词/ci.song.17000.json','["粉黄衣薄沾麝尘。", "作南华、春梦乍醒。", "活计一生花里，恨晓房、香露正深。", "芳蹊有恨时时见，趁游丝、高下弄晴。", "生怕被春归了，赶飞红、穿度柳阴。"]'),
('song-ci-703','江城子','周密','宋','宋词','song-ci','江城子','[]','玉肌多病怯残春。',86,'宋词/ci.song.17000.json','["玉肌多病怯残春。", "瘦棱棱。", "睡腾腾。", "清楚衣裳，不受一尘侵。", "香冷翠屏春意靓，明月淡、晓风轻。", "楼中燕子梦中云。", "似多情。", "似无情。", "酒醒歌阑，谁为唤真真。", "尽日琐窗人不到，莺意懒，蝶愁深。"]'),
('song-ci-704','绿盖舞风轻・绿尽舞风轻','周密','宋','宋词','song-ci','绿盖舞风轻・绿尽舞风轻','[]','玉立照新妆，翠盖亭亭，凌波步秋绮。',120,'宋词/ci.song.17000.json','["玉立照新妆，翠盖亭亭，凌波步秋绮。", "真色生香，明珰摇淡月，舞袖斜倚。", "耿耿芳心，奈千缕、情思萦系。", "恨开迟、不嫁东风，颦怨娇蕊。", "花底谩卜幽期，素手采珠房，粉艳初退。", "雨湿铅腮，碧云深、暗聚软绡清泪。", "访藕寻莲，楚江远、相思谁寄。", "棹歌回，衣露满身花气。"]'),
('song-ci-705','玲珑四犯','周密','宋','宋词','song-ci','玲珑四犯','[]','波暖尘香，正嫩日轻阴，摇荡清昼。',122,'宋词/ci.song.17000.json','["波暖尘香，正嫩日轻阴，摇荡清昼。", "几日新晴，初展绮枰纹绣。", "年少忍负韶华，尽占断、艳歌芳酒。", "看翠帘、蝶舞蜂喧，催趁禁烟时候。", "杏腮红透梅钿皱。", "燕将归、海棠厮句。", "寻芳较晚，东风约、还在刘郎后。", "凭问柳陌旧莺，人比似、垂杨谁瘦。", "倚画阑无语，春恨远、频回首。"]'),
('song-ci-706','谒金门','周密','宋','宋词','song-ci','谒金门','[]','花不定。',53,'宋词/ci.song.17000.json','["花不定。", "燕尾翦开红影。", "几点露香蜂赶趁。", "日迟帘幕静。", "试把翠蛾轻晕。", "愁满宝台鸾镜。", "屈指一春将次尽。", "归期犹未稳。"]'),
('song-ci-707','眼儿媚','周密','宋','宋词','song-ci','眼儿媚','[]','飞丝半湿惹归云。',58,'宋词/ci.song.17000.json','["飞丝半湿惹归云。", "愁里又闻莺。", "淡月秋千，落花庭院，几度黄昏。", "十年一梦扬州路，空有少年心。", "不分不晓，恹恹默默，一段伤春。"]'),
('song-ci-708','拜星月慢','周密','宋','宋词','song-ci','拜星月慢','[]','腻叶阴清，孤花香冷，迤逦芳洲春换。',126,'宋词/ci.song.17000.json','["腻叶阴清，孤花香冷，迤逦芳洲春换。", "薄酒孤吟，怅相如游倦。", "想人在、絮幕香帘凝望，误忍几许，烟樯风幔。", "芳草天涯，负华堂双燕。", "记箫声、淡月梨花院。", "砑笺红、谩写东风怨。", "一夜落月啼鹃，唤四桥吟缆。", "荡归心、已过江南岸。", "清宵梦、远逐飞花乱。", "几千万缕垂杨，翦春愁不断。"]'),
('song-ci-709','好事近','周密','宋','宋词','song-ci','好事近','[]','秋水浸芙蓉，清晓绮窗临镜。',53,'宋词/ci.song.17000.json','["秋水浸芙蓉，清晓绮窗临镜。", "柳弱不胜愁重，染兰膏微沁。", "下阶笑折紫玫瑰，蜂蝶扑云鬓。", "回首见郎羞走，罥绣裙微褪。"]'),
('song-ci-710','长亭怨慢','周密','宋','宋词','song-ci','长亭怨慢','[]','记千竹、万荷深处。',120,'宋词/ci.song.17000.json','["记千竹、万荷深处。", "绿净池台，翠凉亭宇。", "醉墨题香，闲箫横玉尽吟趣。", "胜流星聚。", "知几诵、燕台句。", "零落碧云空，叹转眼、岁华如许。", "凝伫。", "望涓涓一水，梦到隔花窗户。", "十年旧事，尽消得、庾郎愁赋。", "燕楼鹤表半飘零，算惟有、盟鸥堪语。", "谩倚遍河桥，一片凉云吹雨。"]'),
('song-ci-711','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','东风又入江南岸，年年汉宫春早。',123,'宋词/ci.song.17000.json','["东风又入江南岸，年年汉宫春早。", "宝屑无痕，生香有韵，消得何郎花恼。", "孤山梦绕。", "记路隔金沙，那回曾到。", "夜月相思，翠尊谁共饮清醥。", "天寒空念赠远，水边凭为问，春得多少。", "竹外凝情，墙阴照影，谁见嫣然一笑。", "吟香未了。", "怕玉管西楼，一声霜晓。", "花自多情，看花人自老。"]'),
('song-ci-712','月边娇','周密','宋','宋词','song-ci','月边娇','[]','酥雨烘晴，早柳盼颦娇，兰芽愁醒。',120,'宋词/ci.song.17000.json','["酥雨烘晴，早柳盼颦娇，兰芽愁醒。", "九街月淡，千门夜暖，十里宝光花影。", "尘凝步袜，送艳笑、争夸轻俊。", "笙箫迎晓，翠幕卷、天香宫粉。", "少年紫曲疏狂，絮花踪迹，夜蛾心性。", "戏丛围锦，灯帘转玉，拚却舞勾歌引。", "前欢谩省。", "又辇路、东风吹鬓。", "醺醺倚醉，任夜深春冷。"]'),
('song-ci-713','宴清都','周密','宋','宋词','song-ci','宴清都','[]','老去闲情懒。',126,'宋词/ci.song.17000.json','["老去闲情懒。", "东风外、菲菲花絮零乱。", "轻鸥涨绿，啼鹃暗碧，一春过半。", "寻芳已是来迟，怕迤逦、华年暗换。", "应怅恨、白雪歌空，秋霜鬓冷谁管。", "凭阑自笑清狂，事随花谢，愁与春远。", "持杯顾曲，登楼赋笔，杜郎才减。", "前欢已隔残照，但耿耿、临高望眼。", "溯流红、一棹归时，半蟾弄晚。"]'),
('song-ci-714','梅花引','周密','宋','宋词','song-ci','梅花引','[]','瑶妃鸾影逗仙云。',110,'宋词/ci.song.17000.json','["瑶妃鸾影逗仙云。", "玉成痕。", "麝成尘。", "露冷鲛房，清泪霰珠零。", "步绕罗浮归路远，楚江晚，赋宫斜，招断魂。", "酒醒。", "梦醒。", "惹新恨。", "褪素妆，愁涴粉。", "翠禽夜冷。", "舞香恼、何逊多情。", "委佩残钿，空想坠楼人。", "欲挽湘裙无处觅，倩谁为，寄江南，万里春。"]'),
('song-ci-715','瑞鹤仙','周密','宋','宋词','song-ci','瑞鹤仙','[]','翠屏围昼锦。',127,'宋词/ci.song.17000.json','["翠屏围昼锦。", "正柳织烟绡，花易春镜。", "层阑几回凭。", "看六桥莺晓，两堤鸥暝。", "晴岚隐隐。", "映金碧、楼台远近。", "谩曾夸、万幅丹青，画笔画应难尽。", "那更。", "波涵月彩，露裛莲妆，水描梅影。", "调朱弄粉，凭谁写，四时景。", "问玉奁西子，山眉波盼，多少浓施浅晕。", "算何如、付与吟翁，缓评细品。"]'),
('song-ci-716','倚风娇近','周密','宋','宋词','song-ci','倚风娇近','[]','云叶千重，麝尘轻染金缕。',84,'宋词/ci.song.17000.json','["云叶千重，麝尘轻染金缕。", "弄娇风软、霞绡舞。", "花国选倾城，暖玉倚银屏，绰约娉婷，浅素宫黄争妩。", "生怕春知，金屋藏娇深处。", "蜂蝶寻芳无据。", "醉眼迷花映红雾。", "修花谱。", "翠毫夜湿天香露。"]'),
('song-ci-717','祝英台近','周密','宋','宋词','song-ci','祝英台近','[]','烛摇花，香袅穗，独自奈春冷。',95,'宋词/ci.song.17000.json','["烛摇花，香袅穗，独自奈春冷。", "过了收灯，才始作花信。", "无端雨外馀酲，莺边残梦，又还动、惜芳心性。", "忍重省。", "几多绿意红情，吟笺倩谁整。", "香减春衫，老却旧荀令。", "小楼深闭东风，曲屏斜倚，知他是、为谁成病。"]'),
('song-ci-718','浪淘沙','周密','宋','宋词','song-ci','浪淘沙','[]','芳草碧茸茸。',64,'宋词/ci.song.17000.json','["芳草碧茸茸。", "染恨无穷。", "一春心事雨声中。", "窄索宫罗寒尚峭，闲倚熏笼。", "犹记粉阑东。", "同醉香丛。", "金鞍何处骤骅骢。", "袅袅绿窗残梦断，红杏东风。"]'),
('song-ci-719','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','不下竹帘怕燕瞋。',48,'宋词/ci.song.17000.json','["不下竹帘怕燕瞋。", "旋移芳槛引流莺。", "春光却早又中分。", "杏火无烟然绿暗，梨云如雪冷清明。", "冶游天气冶游心。"]'),
('song-ci-720','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','丝雨笼烟织晚晴。',48,'宋词/ci.song.17000.json','["丝雨笼烟织晚晴。", "睡馀春酒未全醒。", "翠钿轻脱隐香痕。", "生怕柳绵萦舞蝶，戏抛梅弹打啼莺。", "最难消遣是残春。"]'),
('song-ci-721','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','清溪数点芙蓉雨，苹飙泛凉吟艗。',123,'宋词/ci.song.17000.json','["清溪数点芙蓉雨，苹飙泛凉吟艗。", "洗玉空明，浮珠沆瀣，人静籁沈波息。", "仙潢咫尺。", "想翠宇琼楼，有人相忆。", "天上人间，未知今夕是何夕。", "此生此夜此景，自仙翁去后，清致谁识。", "散发吟商，簪花弄水，谁伴凉宵横笛。", "流年暗惜。", "怕一夕西风，井梧吹碧。", "底事闲愁，醉歌浮大白。"]'),
('song-ci-722','大','周密','宋','宋词','song-ci','大','[]','又子规啼，荼䕷谢，寂寂春阴池阁。',163,'宋词/ci.song.17000.json','["又子规啼，荼䕷谢，寂寂春阴池阁。", "罗窗人病酒，奈牡丹初放，晚风还恶。", "燕燕归迟，莺莺声懒，闲罥秋千红索。", "三分春过二，尚剩寒犹凝，翠衣香薄。", "傍鸳径鹦笼，一池萍碎，半檐花落。", "最怜春梦弱。", "楚台远、空负朝云约。", "谩念想、清歌锦瑟，翠管瑶尊，几回沈醉东园酌。", "燕麦兔葵恨，倩谁访、画阑红药。", "况多病、腰如削。", "相如老去，赋笔吟笺闲却。", "此情怕人问著。"]'),
('song-ci-723','霓裳中序第一','周密','宋','宋词','song-ci','霓裳中序第一','[]','湘屏展翠叠。',125,'宋词/ci.song.17000.json','["湘屏展翠叠。", "恨入宫沟流怨叶。", "釭冷金花暗结。", "又雁影带霜，蛩音凄月。", "珠宽腕雪。", "叹锦笺、芳宇盈箧。", "人何在，玉箫旧约，忍对素娥说。", "愁切。", "夜砧幽咽。", "任帐底、沈烟渐灭。", "红兰谁采赠别。", "洛汜分绡，汉浦遗玦。", "舞鸾光半缺。", "最怕听、离弦乍阕。", "凭阑久，一庭香露，桂影弄栖蝶。"]'),
('song-ci-724','过秦楼','周密','宋','宋词','song-ci','过秦楼','[]','绀玉波宽，碧云亭小，苒苒水枫香细。',135,'宋词/ci.song.17000.json','["绀玉波宽，碧云亭小，苒苒水枫香细。", "鱼牵翠带，燕掠红衣，雨急万荷喧睡。", "临槛自采瑶房，铅粉沾襟，雪丝萦指。", "喜嘶蝉树远，盟鸥乡近，镜奁光里。", "帘户悄、竹色侵棋，槐影移漏，昼永簟花铺水。", "清眠乍足，晚浴初慵，瘦约楚裙尺二。", "曲砌虚庭夜深，月透龟纱，凉生蝉翅。", "看银潢泻露，金井啼鸦渐起。"]'),
('song-ci-725','声声慢','周密','宋','宋词','song-ci','声声慢','[]','瑶台月冷，佩渚烟深，相逢共话凄凉。',119,'宋词/ci.song.17000.json','["瑶台月冷，佩渚烟深，相逢共话凄凉。", "曳雪牵云，一般淡雅梳妆。", "樊姬岁寒旧约，喜玉儿、不负萧郎。", "临水镜，看清铅素靥，真态生香。", "长记湘皋春晓，仙路迥，冰钿翠带交相。", "满引台杯，休待怨笛吟商。", "凌波又归甚处，问兰昌、何似唐昌。", "春梦好，倩东风、留驻琐窗。"]'),
('song-ci-726','声声慢','周密','宋','宋词','song-ci','声声慢','[]','妆额黄轻，舞衣红浅，西风又到人间。',119,'宋词/ci.song.17000.json','["妆额黄轻，舞衣红浅，西风又到人间。", "小雨新霜，萍池藓径生寒。", "输它汉宫姊妹，粲星钿、霞佩珊珊。", "凉意早，正金盘露洁，翠盖香残。", "三十六宫秋好，看扶疏仙影，伴月长闲。", "宝络风流，何如细蕊堪餐。", "幽香未应便减，傲清霜、正自宜看。", "吟思远，负东篱、还赋小山。"]'),
('song-ci-727','风入松','周密','宋','宋词','song-ci','风入松','[]','柳梢烟软已璁珑。',90,'宋词/ci.song.17000.json','["柳梢烟软已璁珑。", "娇眼试东风。", "情思又逐青丝乱，剩寒轻、犹恋芳栊。", "笋玉新栽早燕，杏钿时引晴蜂。", "当时兰柱系花骢。", "人在小楼东。", "莺娇戏索迎春句，爱露笺、新染香红。", "未信闲情便懒，探花拚醉琼锺。"]'),
('song-ci-728','浪淘沙','周密','宋','宋词','song-ci','浪淘沙','[]','柳色淡如秋。',64,'宋词/ci.song.17000.json','["柳色淡如秋。", "蝶懒莺羞。", "十分春事九分休。", "开尽楝花寒尚在，怕上帘钩。", "京洛少年游。", "谁念淹留。", "东风吹雨过西楼。", "残梦宿酲相合就，一段新愁。"]'),
('song-ci-729','鹧鸪天','周密','宋','宋词','song-ci','鹧鸪天','[]','相傍清明晴便悭。',64,'宋词/ci.song.17000.json','["相傍清明晴便悭。", "闭门空自惜花残。", "海棠半坼难禁雨，燕子初归不耐寒。", "金鸭冷，锦鹓闲。", "银缸空照小屏山。", "翠罗袖薄东风峭，独倚西楼第几阑。"]'),
('song-ci-730','夜行船','周密','宋','宋词','song-ci','夜行船','[]','寒菊敧风栖小蝶。',68,'宋词/ci.song.17000.json','["寒菊敧风栖小蝶。", "帘栊静、半规凉月。", "梦不分明，恨无凭据，肠断锦笺盈箧。", "哀角吹霜寒正怯。", "倚瑶筝、暗愁谁说。", "宝兽频添，玉虫时翦，长记旧家时节。"]'),
('song-ci-731','齐天乐','周密','宋','宋词','song-ci','齐天乐','[]','曲屏遮断行云梦，西楼怕听疏雨。',123,'宋词/ci.song.17000.json','["曲屏遮断行云梦，西楼怕听疏雨。", "研冻凝华，香寒散雾，呵笔慵题新句。", "长安倦旅。", "叹衣染尘痕，镜添秋缕。", "过尽飞鸿，锦笺谁为寄愁去。", "箫台应是怨别，晓寒梳洗懒，依旧眉妩。", "酒滴垆香，花围坐暖，闲却珠鞲钿柱。", "芳心谩语。", "恨柳外游缰，系情何许。", "暗卜归期，细将梅蕊数。"]'),
('song-ci-732','满庭芳','周密','宋','宋词','song-ci','满庭芳','[]','玉沁唇脂，香迷眼缬，肉红初映仙裳。',118,'宋词/ci.song.17000.json','["玉沁唇脂，香迷眼缬，肉红初映仙裳。", "湘皋春冷，谁翦茜云香。", "疑是潘妃乍起，霞侵脸、微印宫妆。", "还疑是，寿阳凝醉，无语倚含章。", "绛绡，清泪冷，东风寄远，愁损红娘。", "笑李凡桃俗，蝶喜蜂忙。", "莫把杏花轻比，怕杏花、不敢承当。", "飘零处，还随流水，应去误刘郎。"]'),
('song-ci-733','清平乐','周密','宋','宋词','song-ci','清平乐','[]','吹梅声噎。',54,'宋词/ci.song.17000.json','["吹梅声噎。", "帘卷初弦月。", "一寸春霏消蕙雪。", "愁染垂杨带结。", "画桥平接金沙。", "软红浅隔儿家。", "燕子未归门掩，晚妆空对菱花。"]'),
('song-ci-734','清平乐','周密','宋','宋词','song-ci','清平乐','[]','晚莺桥噎。',54,'宋词/ci.song.17000.json','["晚莺桥噎。", "庭户溶溶月。", "一树湘桃飞茜雪。", "红豆相思渐结。", "看看芳草平沙。", "游鞯犹未归家。", "自是萧郎飘荡，错教人恨杨花。"]'),
('song-ci-735','乳燕飞・贺新郎','周密','宋','宋词','song-ci','乳燕飞・贺新郎','["\u6d1e\u5ead\u6e56"]','波影摇涟甃。',142,'宋词/ci.song.17000.json','["波影摇涟甃。", "趁熏风、一舸来时，翠阴清昼。", "去郭轩楹才数里，藓磴松关云岫。", "快屐齿、筇枝先后。", "空半危亭堪聚远，看洞庭、缥缈争奇秀。", "人自老，景如旧。", "来帆去棹还知否。", "问古今、几度斜阳，几番回首。", "晚色一川谁管领，都付雨荷烟柳。", "知我者、燕朋鸥友。", "笑拍阑干呼范蠡，甚平吴、却倩垂纶手。", "吁万古，付卮酒。"]'),
('song-ci-736','扫花游・扫地游','周密','宋','宋词','song-ci','扫花游・扫地游','[]','柳花颺白，又火冷饧香，岁时荆楚。',117,'宋词/ci.song.17000.json','["柳花颺白，又火冷饧香，岁时荆楚。", "海棠似语。", "惜芳情燕掠，锦屏红舞。", "怕里流芳，暗水啼烟细雨。", "带愁去。", "叹寂寞东园，空想游处。", "幽梦曾暗许。", "奈草色迷云，送春无路。", "翠丸荐俎。", "掩清尊谩忆，舞蛮歌素。", "怨碧飘香，料得啼鹃更苦。", "正愁伫。", "暗春阴、倦箫残鼓。"]'),
('song-ci-737','龙吟曲・水龙吟','周密','宋','宋词','song-ci','龙吟曲・水龙吟','[]','仙山非雾非烟，翠微缥缈楼台亚。',126,'宋词/ci.song.17000.json','["仙山非雾非烟，翠微缥缈楼台亚。", "江芜海树，晴光雨色，天开图画。", "两岸潮平，六桥烟霁，晚钩帘挂。", "自玄晖去后，云情雪意，丹青手、应难写。", "花底朝回多暇。", "倚高寒、有人潇洒。", "东山杖屦，西州宾客，笑谈风雅。", "贮月杯宽，护香屏暖，好天良夜。", "乐闲中日月，清时钟鼓，结春风社。"]'),
('song-ci-738','风入松','周密','宋','宋词','song-ci','风入松','[]','枇杷花老洞云深。',88,'宋词/ci.song.17000.json','["枇杷花老洞云深。", "流水泠泠。", "蓝田谁种玲珑玉，土华寒、晕碧云根。", "佳兴秋英春草，好音夜鹤朝禽。", "闲听天籁静看云。", "心境俱清。", "好风不负幽人意，送良宵、一枕松声。", "四友江湖泉石，二并钟鼎山林。"]'),
('song-ci-739','凤栖梧・蝶恋花','周密','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','竹窈花深连别墅。',70,'宋词/ci.song.17000.json','["竹窈花深连别墅。", "曲曲回廊，小小闲庭宇。", "忽地香来无觅处。", "杖藜闲趁游蜂去。", "老桂悬秋森玉树。", "涧底孤芳，苒苒吹诗句。", "一掬幽情知几许。", "钩帘半亩藤花雨。"]'),
('song-ci-740','少年游','周密','宋','宋词','song-ci','少年游','[]','松风兰露滴崖阴。',60,'宋词/ci.song.17000.json','["松风兰露滴崖阴。", "瑶草入帘青。", "玉凤惊飞，翠蛟时舞，喷薄溅春云。", "冰壶不受人间暑，幽碧哢珍禽。", "花外琴台，竹边棋墅，处处是闲情。"]'),
('song-ci-741','西江月','周密','宋','宋词','song-ci','西江月','[]','花气半侵云阁，柳阴近隔春城。',58,'宋词/ci.song.17000.json','["花气半侵云阁，柳阴近隔春城。", "画阑明月按瑶筝。", "醉倚满身芳影。", "翠格素虬晴雪，锦笼紫凤香云。", "东风吹玉满闲庭。", "二十四帘春靓。"]'),
('song-ci-742','清平乐','周密','宋','宋词','song-ci','清平乐','[]','诗情画意。',54,'宋词/ci.song.17000.json','["诗情画意。", "只在阑干外。", "雨露天低生爽气。", "一片吴山越水。", "宫烟醉柳春晴。", "海风洗月秋明。", "唤取九霞飞佩，夜凉跨鹤吹笙。"]'),
('song-ci-743','朝中措','周密','宋','宋词','song-ci','朝中措','[]','桐阴薇影小阑干。',57,'宋词/ci.song.17000.json','["桐阴薇影小阑干。", "昼永琐窗闲。", "当日清谭赌墅，风流犹记东山。", "犀奁象局，惊回槐梦，飞雹生寒。", "自有仙机活著，未应袖手旁观。"]'),
('song-ci-744','闻鹊喜','周密','宋','宋词','song-ci','闻鹊喜','[]','天水碧。',53,'宋词/ci.song.17000.json','["天水碧。", "染就一江秋色。", "鳌戴雪山龙起蛰。", "快风吹海立。", "数点烟鬟青滴。", "一杼霞绡红湿。", "白鸟明边帆影直。", "隔江闻夜笛。"]'),
('song-ci-745','浣溪沙','周密','宋','宋词','song-ci','浣溪沙','[]','竹色苔香小院深。',48,'宋词/ci.song.17000.json','["竹色苔香小院深。", "蒲团茶鼎掩山扃。", "松风吹尽世间尘。", "静养金芽文武火，时调玉轸短长清。", "石床闲卧看秋云。"]'),
('song-ci-746','吴山青・长相思','周密','宋','宋词','song-ci','吴山青・长相思','[]','山青青。',44,'宋词/ci.song.17000.json','["山青青。", "水泠泠。", "养得风烟数亩成。", "乾坤一草亭。", "云无心。", "竹无心。", "我亦无心似竹云。", "岁寒同此盟。"]'),
('song-ci-747','祝英台近','周密','宋','宋词','song-ci','祝英台近','[]','步玲珑，寻窈窕，瑶草四时碧。',95,'宋词/ci.song.17000.json','["步玲珑，寻窈窕，瑶草四时碧。", "小小蓬莱，花气透帘隙。", "几回翠水荷初，苍崖梅小，绮寮掩、玉壶春色。", "柳屏窄。", "芳槛日日东风，几醉几吟笔。", "曲折花房，莺燕似相识。", "最怜灯影才收，歌尘初静，画楼外、一声秋笛。"]'),
('song-ci-748','长相思','周密','宋','宋词','song-ci','长相思','[]','灯辉辉。',44,'宋词/ci.song.17000.json','["灯辉辉。", "月微微。", "帐暖香深春漏迟。", "梦回闻子规。", "欲成诗。", "未成诗。", "生怕春归春又归。", "花飞花未飞。"]'),
('song-ci-749','清平乐','周密','宋','宋词','song-ci','清平乐','[]','小桥萦绿。',54,'宋词/ci.song.17000.json','["小桥萦绿。", "密翠藏吟屋。", "千顷风烟森万玉。", "依约辋川韦曲。", "临流照影何人。", "悠然倚仗看云。", "柳色翠迷山色，泉声清和蝉声。"]'),
('song-ci-750','清平乐','周密','宋','宋词','song-ci','清平乐','[]','锦城春晓。',54,'宋词/ci.song.17000.json','["锦城春晓。", "苑陌芳菲早。", "可是杜陵人未老。", "日日酒迷花恼。", "归鞯困倚芳酲。", "醒来还有新吟。", "人与杏花俱醉，春风一路闻莺。"]'),
('song-ci-751','清平乐','周密','宋','宋词','song-ci','清平乐','[]','静香真色。',54,'宋词/ci.song.17000.json','["静香真色。", "花与人争白。", "属玉双飞烟月夕。", "点波一奁秋碧。", "翠罗袖薄天寒。", "笛声何处关山。", "手拈一枝春色，东风怨入江南。"]'),
('song-ci-752','柳梢青','周密','宋','宋词','song-ci','柳梢青','[]','约略春痕。',61,'宋词/ci.song.17000.json','["约略春痕。", "吹香新句，照影清尊。", "洗尽时妆，效颦西子，不负东昏。", "金沙旧事休论。", "尽消得、东风返魂。", "一段真情，风前孤驿，雪后前村。"]'),
('song-ci-753','柳梢青','周密','宋','宋词','song-ci','柳梢青','[]','万雪千霜。',61,'宋词/ci.song.17000.json','["万雪千霜。", "禁持不过，玉雪生光。", "水部清多，杜郎老去，空恼愁肠。", "天寒野屿空廊。", "静倚竹、无人自香。", "一笑相逢，江南江北，竹屋山窗。"]'),
('song-ci-754','柳梢青','周密','宋','宋词','song-ci','柳梢青','[]','映水穿篱。',61,'宋词/ci.song.17000.json','["映水穿篱。", "新霜微月，小蕊疏枝。", "几许风流，一声龙竹，半幅鹅溪。", "江头怅望多时。", "欲待折、相思寄伊。", "真色真香，丹青难写，今古无诗。"]'),
('song-ci-755','柳梢青','周密','宋','宋词','song-ci','柳梢青','[]','夜鹤惊飞。',61,'宋词/ci.song.17000.json','["夜鹤惊飞。", "香浮翠藓，玉点冰枝。", "古意高风，幽人空谷，静女深帏。", "芳心自有天知。", "任醉舞、花边帽敧。", "最爱孤山，雪初晴后，月未残时。"]'),
('song-ci-756','南楼令・唐多令','周密','宋','宋词','song-ci','南楼令・唐多令','[]','开了木芙蓉。',74,'宋词/ci.song.17000.json','["开了木芙蓉。", "一年秋已空。", "送新愁、千里孤鸿。", "摇落江蓠多少恨，吟不尽、楚云峰。", "往事夕阳红。", "故人江水东。", "翠衾寒、几夜霜浓。", "梦隔屏山飞不去，随夜鹊、绕疏桐。"]'),
('song-ci-757','南楼令・唐多令','周密','宋','宋词','song-ci','南楼令・唐多令','[]','好梦不分明。',74,'宋词/ci.song.17000.json','["好梦不分明。", "楚云千万层。", "带围宽、愁损兰成。", "玉杵玄霜才咫尺，青羽信、便沈沈。", "水调夜楼清。", "清宵谁共听。", "砑笺红、空赋倾城。", "几度欲吟吟不就，可煞是、没心情。"]'),
('song-ci-758','声声慢','周密','宋','宋词','song-ci','声声慢','[]','橙香小院，桂冷闲庭，西风雁影涵秋。',119,'宋词/ci.song.17000.json','["橙香小院，桂冷闲庭，西风雁影涵秋。", "凤拨龙槽，新声小按梁州。", "莺吭夜深啭巧，凝凉云、应为歌留。", "慵顾曲，叹周郎老去，鬓改花羞。", "何事登临感慨，倩金蕉一洗，千古清愁。", "屡舞高歌，作成陶谢风流。", "人生最难一笑，拚尊前、醉倒方休。", "待醉也，带黄花、须带满头。"]'),
('song-ci-759','明月引・江城梅花引','周密','宋','宋词','song-ci','明月引・江城梅花引','[]','舞红愁碧晚萧萧。',108,'宋词/ci.song.17000.json','["舞红愁碧晚萧萧。", "溯回潮。", "伫仙桡。", "风露高寒，飞下紫霞箫。", "一雁远将千万恨，怀渺渺，翦愁云，风外飘。", "酒醒未醒香旋消。", "采江蓠，吟楚招。", "清徽芳笔，梅魂冷、月影空描。", "锦瑟瑶尊，闲度可怜宵。", "二十四阑愁倚遍，空怅望，短长亭，长短桥。"]'),
('song-ci-760','明月引・江城梅花引','周密','宋','宋词','song-ci','明月引・江城梅花引','["\u897f\u6e56"]','雁霜苔雪冷飘萧。',108,'宋词/ci.song.17000.json','["雁霜苔雪冷飘萧。", "断魂潮。", "送清桡。", "翠袖珠楼，清夜梦琼箫。", "江南江北云自碧，人不见，泪花寒，随雨飘。", "愁多病多腰素消。", "倚清琴。", "调大招。", "江空年晚，凄凉句、远意难描。", "月冷花阴，心事负春宵。", "几度问春春不语，春又到，到西湖，第几桥。"]'),
('song-ci-761','六么令','周密','宋','宋词','song-ci','六么令','[]','痴云翦叶，檐滴夜深悄。',112,'宋词/ci.song.17000.json','["痴云翦叶，檐滴夜深悄。", "银城飞捷翠垅，占祥丰年报。", "白战清吟未了。", "寒鹊惊枝晓。", "鹤迷翠表。", "山阴今日，醉卧何人问安道。", "交映虚窗净沼。", "不许游尘到。", "谁念絮帽茸裘，叹幼安今老。", "玉鉴修眉未扫。", "白雪词新草。", "冰蟾光蛟。", "梅心香动，闲看春风上琼岛。"]'),
('song-ci-762','六么令','周密','宋','宋词','song-ci','六么令','[]','回风带雨，冻涩漏声悄。',112,'宋词/ci.song.17000.json','["回风带雨，冻涩漏声悄。", "小窗照影虚白，几误邻鸡报。", "千树天花绽了。", "鹄立通明晓。", "眼空八表。", "宫袍带月，醉里应迷灞陵道。", "风静琼林翠沼。", "片片随春到。", "吟鞯十里新堤，怪四山青老。", "玉唾珠尘怕扫。", "句冷池塘草。", "白天寒蛟。", "飞琼何在，梦觅梨云度仙岛。"]'),
('song-ci-763','谒金门','周密','宋','宋词','song-ci','谒金门','[]','芳事晚。',53,'宋词/ci.song.17000.json','["芳事晚。", "数点杏钿香浅。", "恻恻轻寒风翦翦。", "锦屏春梦远。", "稚柳拖烟娇软。", "花影暗藏深院。", "初试轻衫并画扇。", "牡丹红未展。"]'),
('song-ci-764','好事近','周密','宋','宋词','song-ci','好事近','[]','轻翦楚台云，玉影半分秋月。',53,'宋词/ci.song.17000.json','["轻翦楚台云，玉影半分秋月。", "一饷凄凉无语，对残花么蝶。", "碧天愁雁不成书，郎意似秋叶。", "闲展鸳绡残谱，卷泪花双叠。"]'),
('song-ci-765','声声慢','周密','宋','宋词','song-ci','声声慢','[]','燕泥沾粉，鱼浪吹香，芳堤十里新晴。',119,'宋词/ci.song.17000.json','["燕泥沾粉，鱼浪吹香，芳堤十里新晴。", "静惹游丝，花边袅袅扶春。", "多情最怜飘泊，记章台、曾绾青青。", "堪爱处，是扑帘娇软，随马轻盈。", "长是河桥三月，做一番晴雪，恼乱诗魂。", "带雨沾衣，罗襟点点离痕。", "休缀潘郎鬓影，怕绿窗、年少人惊。", "卷春去，翦东风、千缕碎云。"]'),
('song-ci-766','忆旧游','周密','宋','宋词','song-ci','忆旧游','[]','记花阴映烛，柳影飞梭，庭户东风。',126,'宋词/ci.song.17000.json','["记花阴映烛，柳影飞梭，庭户东风。", "彩笔争春艳，任香迷舞袖，醉拥歌丛。", "画帘静掩芳昼，云翦玉璁珑。", "奈恨绝冰弦，尘消翠谱，别凤离鸿。", "莺笼。", "怨春远，但翠冷闲阶，坠粉飘红。", "事逐华年换，叹水流花谢，燕去楼空。", "绣鸳暗老薇径，残梦绕雕栊。", "怅宝瑟无声，愁痕沁碧，江上孤峰。"]'),
('song-ci-767','水龙吟','周密','宋','宋词','song-ci','水龙吟','[]','燕翎谁寄愁笺，天涯望极王孙草。',126,'宋词/ci.song.17000.json','["燕翎谁寄愁笺，天涯望极王孙草。", "新烟换柳，光风浮蕙，馀寒尚峭。", "倚仗看云，翦灯听雨，几番诗酒。", "叹长安倦客，江南旧恨，飞花乱、清明后。", "堤上垂杨风骤。", "散香绵、轻沾吟袖。", "麴尘两岸，纹波十里，暖蒸香透。", "海阔云深，水流春远，梦魂难句。", "问莺边按谱，花前觅句，解相思否。"]'),
('song-ci-768','水龙吟','周密','宋','宋词','song-ci','水龙吟','[]','舞红轻带愁飞，宝鞯暗忆章台路。',126,'宋词/ci.song.17000.json','["舞红轻带愁飞，宝鞯暗忆章台路。", "吟香醉雨，吹箫门巷，飘梭院宇。", "立尽残阳，眼迷睛树，梦随风絮。", "叹江潭冷落，依依旧恨，人空老、柳如许。", "锦瑟华年暗度。", "赋行云、空题短句。", "情思系燕，么弦弹凤，文君更苦。", "烟水流红，暮山凝紫，是春归处。", "怅江南望远，苹花自采，寄将愁与。"]'),
('song-ci-769','徵招','周密','宋','宋词','song-ci','徵招','[]','江蓠摇落江枫冷，霜空雁程初到。',117,'宋词/ci.song.17000.json','["江蓠摇落江枫冷，霜空雁程初到。", "万景正悲凉，奈曲终人杳。", "登临嗟老矣，问今古、清愁多少。", "一梦东园，十年心事，恍然惊觉。", "肠断，紫霞深，知音远、寂寂怨琴凄调。", "短发已无多，怕西风吹帽。", "黄花空自好。", "问谁识、对花怀抱。", "楚山远，九辩难招，更晚烟残照。"]'),
('song-ci-770','酹江月・念奴娇','周密','宋','宋词','song-ci','酹江月・念奴娇','[]','奁霏净洗，唤素娥睡起，平分秋色。',120,'宋词/ci.song.17000.json','["奁霏净洗，唤素娥睡起，平分秋色。", "雁背风高霜兔冷，露脚侵衣香湿。", "银浦流云，珠房迎晓，鬓影霜争白。", "玉尊良夜，与谁同醉瑶席。", "忍记倚桂分题，簪花筹酒，处处成陈迹。", "十二楼空环佩杳，惟有孤云知得。", "如此江山，依然风月，月底人非昔。", "知音何许，泪痕空沁愁碧。"]'),
('song-ci-771','夜合花','周密','宋','宋词','song-ci','夜合花','[]','月地无尘，珠宫不夜，翠笼谁炼铅霜。',124,'宋词/ci.song.17000.json','["月地无尘，珠宫不夜，翠笼谁炼铅霜。", "南州路杳，仙子误入唐昌。", "零露滴，湿微妆。", "逗清芬、蝶梦空忙。", "梨花云暖，梅花雪冷，应妒秋芳。", "虚庭夜气偏凉。", "曾记幽丛采玉，素手相将。", "青蕤嫩萼，指痕犹映瑶房。", "风透幕，月侵床。", "记梦回、粉艳争香。", "枕屏金络，钗梁绛缕，都是思量。"]');
